/* ============================================================
   Procedure: [dbo].[prc_InsertAdGroup]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[prc_InsertAdGroup] 
 @AdwordGroupId varchar(50)
,@User_ID varchar(50)      
,@CampAd_id varchar(50)      
,@GroupName varchar(1500)     
,@Keyword varchar(2500) 
as      
begin     
if exists(select GroupName from tblAdGroup where GroupName=@GroupName)  
begin  
select 'Group name already exists' as result  
end   
else  
begin  
Insert Into tblAdGroup(AdwordGroupId,User_ID,CampAd_id,GroupName,Keyword)values      
                       (@AdwordGroupId,@User_ID,@CampAd_id,@GroupName,@Keyword)     
select top(1) 'success' as result,AdwordGroupId as LeadId,GroupName,Keyword from tblAdGroup order by AdGroupId desc
end  
End



GO

/* ============================================================
   Procedure: [dbo].[prc_InsertAdGroupData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[prc_InsertAdGroupData]  
(  
 @AdGroupId int                    
 ,@AdwordGroupId varchar(50)                      
,@User_ID varchar(50)                            
,@CampAd_id varchar(50)                            
,@GroupName varchar(1500)                      
--,@Adword_Name  varchar(Max)                       
,@Keyword varchar(2500)                    
,@Keywordid varchar(100)                     
,@opt varchar(10)                    
,@IsActive bit              
,@Status bit          
,@Gender varchar(500)          
,@AgeRanges varchar(500)      
,@Incomepercentilerange varchar(500)          
,@Platform varchar(500)      
,@Parentalstatus varchar(500)          
,@Daysofweek varchar(500)      
,@Affinitycategories varchar(MAX)          
,@InProcess tinyint=0  
)  
as                            
begin                     
declare @match_type as varchar(20)='Broad match'                    
                    
if @opt = 'Active'                     
begin                    
 update tblAdGroup set IsActive=@IsActive where AdGroupId = @AdGroupId                    
end                    
if @opt = 'Edit'                     
begin                    
 update tblAdGroup set Keyword=@Keyword, KeywordId=@Keywordid, match_type= @match_type where                     
 AdGroupId = @AdGroupId                    
end                    
if @opt = 'Insert'
 begin
 --if exists(select GroupName from tblAdGroup where GroupName=@GroupName)                        
 --begin                        
 --select 'Group name already exists' as result                        
 --end                         
 --else                        
 --begin                        
 Insert Into tblAdGroup(AdwordGroupId,User_ID,CampAd_id,GroupName,Keyword, KeywordId,                     
 match_type,InProcess,Status,Gender,AgeRanges,Platform,Incomepercentilerange,Parentalstatus,DaysofWeek,Affinitycategories)       
 values (@AdwordGroupId,@User_ID,@CampAd_id, @GroupName, @Keyword,                     
 @Keywordid,@match_type,@InProcess,@Status,@Gender,@AgeRanges      
 ,@Incomepercentilerange         
,@Platform      
,@Parentalstatus      
,@Daysofweek      
,@Affinitycategories ) --, @Adword_Name)                           
                     
 select @AdGroupId = SCOPE_IDENTITY()                    
                     
                     
 select top(1) 'success' as result,AdGroupId ,GroupName,Keyword                     
 from tblAdGroup where AdGroupId =@AdGroupId
 --end                     
 end                       
End     



