 @User_ID varchar(50)                        
,@AdwordAdsId varchar(50)                   
,@AdwordGroupId varchar(50)                  
,@BusinessName varchar(250)                  
,@Description1 varchar(250)                       
,@Description2 varchar(250)                   
,@DisplayUrl varchar(500)                  
,@opt int    
,@Status bit                
as                        
begin                   
if(@opt=1)                  
begin                  
--declare @campaignid bigint=(select CampAd_id from tblAdGroup where AdwordGroupId=@AdwordGroupId)              
declare @campaignid bigint=(select CampAd_id from tblAdGroup where AdGroupId=@AdwordGroupId)              
          
--Insert Into tblAds(campaignid,User_ID,AdwordAdsId,AdwordGroupId,BusinessName,Description1,Description2,DisplayUrl)values (@campaignid,@User_ID,@AdwordAdsId,@AdwordGroupId,@BusinessName,@Description1,@Description2,@DisplayUrl)                       
--                       select 'success' as result, IDENT_CURRENT('tblAds') as LeadId              
              
Insert Into tblAds(campaignid,User_ID,AdwordAdsId,AdwordGroupId,BusinessName,Description1,Description2,DisplayUrl,Status)values (@campaignid,@User_ID,@AdwordAdsId,'',@BusinessName,@Description1,@Description2,@DisplayUrl,@Status)                       
                       select 'success' as result, IDENT_CURRENT('tblAds') as LeadId                  
          
          
          
