CREATE   PROCEDURE [dbo].[prc_InsertCampaign]
(                                
 @CampaignId int                               
,@CampAd_id varchar(50)                                
,@User_ID varchar(250)                                        
,@CampaignName varchar(250)                                        
,@Location varchar(1000)                                       
,@Budget varchar(50)                                        
,@Bidding varchar(50)                           
,@IPAddress varchar(50)                                     
,@Source varchar(50)                                                 
,@BudgetId varchar(50)                                  
,@BudgetName varchar(50)                              
,@stdate datetime                               
,@endate datetime                          
,@Status bit                          
,@Gcampaignname varchar(250)                           
,@Gbudgetname varchar(250)                             
,@locid varchar(50) = ''      
,@radious varchar(500)      
,@latitude varchar(500)      
,@longitude varchar(500)
,@radunit varchar(3)
,@CampaignType varchar(50)
,@CampaignSubType varchar(50)
 )                               
 as                               
begin                               
if @CampaignId = 0                              
begin                                      
if exists(select CampaignName from tblCampaign where CampaignName=@CampaignName)                                    
begin                                    
select 'Campaign name already exists' as result                                    
end                                     
else
begin
 Declare @SortId varchar(50)                                  
                                 
 set @SortId = (select isnull(max(CampaignId),0)+1 from tblCampaign)                                    
               
 --Insert Into tblCampaign(CampAd_id,BudgetId,User_ID,CampaignName,Location,Budget,                              
 --BiddingClick,Bidding,Source,IPAddress,SortId,CmpStartDate,CmpEndDate,                    
 --Gcampaignname, Status, locid)                              
 --values  (@CampAd_id,@BudgetId,@User_ID,@CampaignName,@Location,@Budget,'Click',                    
 --@Bidding,@Source,                              
 --@IPAddress, @SortId,@stdate,@endate,@Gcampaignname, @Status,@locid )                                     
                                
 Insert Into tblCampaign(CampAd_id,BudgetId,User_ID,CampaignName,Location,CampaignType,CampaignSubType,Budget,                              
 BiddingClick,Bidding,Source,IPAddress,SortId,CmpStartDate,CmpEndDate,                    
 Gcampaignname, Status, locid,radious,latitude,longitude, radunit)                              
 values  (@CampAd_id,@BudgetId,@User_ID,@CampaignName,@Location,@CampaignType,@CampaignSubType,@Budget,'Click',                    
 @Bidding,@Source, @IPAddress, @SortId,@stdate,@endate,
 @Gcampaignname, @Status,@locid,@radious,@latitude,@longitude,@radunit)
               
 --Insert Into tblAdwordBudget(BudgetId,BudgetName,Budgetamt, Gbudgetname)                          
 --values(@BudgetId,@BudgetName,@Budget,@Gbudgetname)               
               
 Insert Into tblAdwordBudget(BudgetId,BudgetName,Budgetamt, Gbudgetname)                          
 values(@BudgetId,@BudgetName,@Budget,@Gbudgetname)               
               
                                  
    set @CampaignId=(select IDENT_CURRENT('tblCampaign'))                                
                      
                        
     update tblCampaign set CampAd_id=@CampaignId ,BudgetId = @CampaignId where CampaignId=@CampaignId                  
     declare @bdgtId bigint = 0                
     set @bdgtId=(select IDENT_CURRENT('tblAdwordBudget'))                
     update tblAdwordBudget set BudgetId = @CampaignId  where id = @bdgtId               
                      
        select 'success' as result,@CampaignId  as CampAd_id                         
end                               
end                               
else                              
begin               
--@CampaignName                         
 update tblCampaign set  Location =@Location,                              
  Budget =@Budget,Bidding=@Bidding,CmpStartDate=@stdate,CmpEndDate=@endate,                          
  Gcampaignname=@Gcampaignname,locid= @locid,Status=@Status,radious=@radious,radunit=@radunit,latitude=@latitude,longitude=@longitude 
  where CampaignId= @CampaignId                              
                               
   --Status = @Status,                            
                               
 update tblAdwordBudget set Budgetamt=@Budget, Gbudgetname=@Gbudgetname                          
  where BudgetId = @BudgetId                              
                               
 select 'success' result                      
end                                  
End   



GO

/* ============================================================
   Procedure: [dbo].[prc_InsertCampaign_INTDateTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC prc_InsertCampaign_INTDateTime             
(              
 @CampaignId int             
, @CampAd_id varchar(50)              
,@User_ID varchar(250)                      
,@CampaignName varchar(250)                      
,@Location varchar(1000)                     
,@Budget varchar(50)                      
,@Bidding varchar(50)         
,@IPAddress varchar(50)                   
,@Source varchar(50)                               
,@BudgetId varchar(50)                
,@BudgetName varchar(50)            
, @stdate datetime             
, @endate datetime        
, @Status bit        
, @Gcampaignname varchar(250)         
, @Gbudgetname varchar(250)           
 ,@locid varchar(50) = ''       
 )             
 as             
begin             
if @CampaignId = 0            
begin                    
if exists(select CampaignName from tblCampaign where CampaignName=@CampaignName)                  
begin                  
select 'Campaign name already exists' as result                  
end                   
else                  
begin                  
 Declare @SortId varchar(50)                
               
 set @SortId = (select isnull(max(CampaignId),0)+1 from tblCampaign)                  
 Insert Into tblCampaign(CampAd_id,BudgetId,User_ID,CampaignName,Location,Budget,            
 BiddingClick,Bidding,Source,IPAddress,SortId,CmpStartDate,CmpEndDate,  
 Gcampaignname, Status, locid)            
 values
 (@CampAd_id,@BudgetId,
 @User_ID,@CampaignName,
 @Location,@Budget,'Click',  
 @Bidding,@Source,         
 @IPAddress, @SortId,
 
 dbo.[fn_getISTtimefromusertime]((select ISNULL(ParentID,0) from user_detail ud where ud.User_ID = @User_ID),@stdate),
 
 dbo.[fn_getISTtimefromusertime]((select ISNULL(ParentID,0) from user_detail ud where ud.User_ID = @User_ID),@endate),
 
 @Gcampaignname,
 @Status,@locid
 
 )                     
              
 Insert Into tblAdwordBudget(BudgetId,BudgetName,Budgetamt, Gbudgetname)        
 values(@BudgetId,@BudgetName,@Budget,@Gbudgetname)                
    set @CampaignId=(select IDENT_CURRENT('tblCampaign'))              
        select 'success' as result,CampAd_id from tblCampaign where CampaignId=@CampaignId              
            
end             
end             
else            
begin            
 update tblCampaign  set 
  CampaignName=@CampaignName,
  Location =@Location,            
  Budget =@Budget,Bidding=@Bidding,
  
  CmpStartDate =  dbo.[fn_getISTtimefromusertime]((select ISNULL(ParentID,0) from user_detail ud where ud.User_ID = User_ID),@stdate),
  
  CmpEndDate = dbo.[fn_getISTtimefromusertime]((select ISNULL(ParentID,0) from user_detail ud where ud.User_ID = User_ID),@endate),        
  
  Gcampaignname=@Gcampaignname, Status = @Status, locid= @locid where CampaignId= @CampaignId            
             
 update tblAdwordBudget set Budgetamt=@Budget, Gbudgetname=@Gbudgetname        
  where BudgetId = @BudgetId            
             
 select 'success' result            
end                
End     
    
select *  from tblCampaign 


