--prc_SelectCampaignReport'335','camp'
CREATE   PROC [dbo].[prc_SelectCampaignReport]
 @User_ID varchar(50)
,@Type varchar(50)=''
As
Begin
if(@Type='camp')
begin
Select c.User_ID,c.Budget,c.BidStrategyType,c.CampaignType,c.CampaignType, cam.* from tblAdwordsCampaignPerformanceRep cam
left join tblCampaign c on cam.campaignId=c.CampAd_ID order by CampaignPerformanceReportId desc-- where User_ID=@User_ID
end
else if(@Type='adgroup')
begin
Select * from tblAdwordsGroupPerformanceRep -- where User_ID=@User_ID
end
else if(@Type='ads')
begin
Select * from tblAdwordsAD_PERFORMANCE_REPORT -- where User_ID=@User_ID
end
End



