CREATE   PROC [dbo].[prc_UpdateAdGroup]     
 @AdGroupId varchar(250)          
,@GroupName varchar(250)          
,@Keyword varchar(1000)         
as          
begin         
if exists(select GroupName from tblAdGroup where GroupName=@GroupName and AdGroupId !=@AdGroupId)      
begin      
select 'Campaign group name already exists' as result      
end       
else      
begin       
Update tblAdGroup set GroupName=@GroupName,Keyword=@Keyword,modifiedDate=getdate() where AdGroupId=@AdGroupId   
       select 'success' as result, IDENT_CURRENT('tblAdGroup') AdGroupId     
end      
End



