/* ============================================================
   Procedure: [dbo].[Prc_usp_UserApplyCoupon]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--declare @tbl table(ProductID bigint,Qty bigint)    
--insert into @tbl values(5,6)    
--exec Prc_usp_UserApplyCoupon @tbl,'Hariom_coupon',335,'9891461152','hariom.sharan@pelsoftlabs.in',250  
    
 CREATE   PROCEDURE [dbo].[Prc_usp_UserApplyCoupon] --'Hariom_coupon',335,'9891461152','testing@gmail.com','250',null              
    --@tblProductSql tbl_PrdSqlType3 readonly ,  
    @tblProductSql tbl_PrdSqlType5 readonly ,  
    @CouponCode VARCHAR(50)=null,                 
    @ParentID BIGINT =null,                 
    @MobileNo VARCHAR(50)= null ,                 
    @EmailID VARCHAR(50) =null,                 
    @BIllAmount VARCHAR(500)= null               
    --@tempproductId varchar (50)=null,             
    AS                 
BEGIN                
SELECT * INTO   #tempcoupon FROM   UserCouponSettings1 AS ucs WHERE  ucs.parentid = @ParentID AND ucs.CouponName = @CouponCode
create table  #tempnew (ProductID  bigint,Qty bigint)        
insert into #tempnew (ProductID,Qty) select ProductID,Qty from @tblProductSql     
declare @couponid int=(select CouponID FROM #tempcoupon)             
                       
----------------- Check Coupon Code is active or Not------------------                 
IF not EXISTS (SELECT 1 FROM   #tempcoupon tt WHERE  tt.Status =1 and GETDATE() between StartDate and ExpiryDate)             BEGIN               
	select case when tt.Status=0 then 'Coupon is not Valid' else 'Coupon has expired' END  FROM   #tempcoupon tt             
    Goto OReturn                       
END         
--Check Bill Applicability--            
if exists(select 1 from #tempcoupon where IsBillApplicability=1)               
	begin               
		if exists(select 1 from #tempcoupon where @BIllAmount between minbillamount and MaxBillAmount)               
		begin 
			goto checkproduct              
		end        
		else        
		Begin        
			Select 'Coupon is applicable only on bill amount between ' + CAST((select minbillamount from #tempcoupon) as nvarchar) + ' and ' + CAST((select MaxBillAmount from #tempcoupon) as nvarchar)  as status             
			GoTo OReturn                              
		ENd         
	End        
	Else        
	Begin        
		goto checkproduct               
End 

--Check if coupon is applicable to produts in cart
CheckProduct:               
if exists(select 1 from #tempcoupon where ISProductApplicability=1)               
begin         
    if exists(select 1 from ProductApplicability p join #tempnew t on p.ProductId=t.ProductID  and t.Qty  between p.minqty and p.maxqty join #tempcoupon tc on p.CouponID=tc.CouponID)                    
    begin        
    Goto Checksegment               
    end              
    else               
    begin               
    Select 'Coupon is not applicable for the products in cart'  as status             
    Goto OReturn               
    end               
end               

--Check if coupon is applicable to the user applying the coupon
CheckSegment:     
if exists(select 1 from #tempcoupon where ISSearchApplicability =1)            
begin
declare @mediumtype nvarchar(20)= (select mediumtype from #tempcoupon)
SELECT	ROW_NUMBER()Over(Order by Ucm.couponID,Ucm.ParentID) AS Id,   
				   Ucm.couponID,                                      
                   Ucm.ParentID,                                      
                   A.[value]  AS IncludeSearches,                                      
                   AGL.[value]         AS IncludeList,                                      
                   EGL.[value]        AS ExclusionsGroupList,                                      
                   case when ucm.Mediumtype = 'Email' then '' else Ucm.ExcludeMobile end as ExcludeMobile,
                   case when ucm.Mediumtype = 'Mobile' then '' else Ucm.Excludemail end as Excludemail,                                          E.[value]           AS Exclusions,                                      
                   case when ucm.Mediumtype = 'Email' then @EmailID else Ucm.ExcludeMobile end as IncludeMail,
                   case when ucm.Mediumtype = 'Mobile' then @MobileNo else Ucm.Excludemail end as IncludeMobile 
            INTO #temptemplate   
            FROM   #tempcoupon Ucm   (nolock)                                       
            OUTER APPLY Dbo.Fn_split(Ucm.IncludeSearches, '#') AS A 
			OUTER APPLY Dbo.Fn_split(Ucm.IncludeList, '#') AS AGL
			OUTER APPLY Dbo.Fn_split(Ucm.ExcludeList, '#') AS  EGL 
			OUTER APPLY Dbo.Fn_split(Ucm.ExcludeSearch, '#') AS E 
--Check medium & Check if contact details are in exclusions--
if @mediumtype='Both' and exists(select 'x' from #temptemplate outer apply dbo.Fn_split(ExcludeMobile, ',')  AS fs outer apply dbo.Fn_split(Excludemail, ',') as fsmail  WHERE  fs.[value]=@MobileNo or fsmail.[value]=@EmailID)  
begin
Select 'Oops! Coupon is not applicable to you'  as status        
goto OReturn                   
end
else if exists(select 'x' from #temptemplate outer apply dbo.Fn_split(ExcludeMobile, ',')  AS fs outer apply dbo.Fn_split(Excludemail, ',') as fsmail  WHERE  fs.[value]=@MobileNo and fsmail.[value]=@EmailID)               
begin
Select 'Oops! Coupon is not applicable to you'  as status        
goto OReturn                   
end
--Check if user is in inclusions
else
begin  
CREATE TABLE #temptablesearchapp                      
     (                                
      campaignid             BIGINT,                                
      searchid               BIGINT,                                
      parentid         BIGINT, 
      userid           bigint,                               
      personname             NVARCHAR(200),                                
      companyname            NVARCHAR(200),                                
      mobileno               NVARCHAR(200),                                
      mobileno1              NVARCHAR(200),                                
      mobileno2              NVARCHAR(200),                                
      emailid                NVARCHAR(200),                                
      emailid1               NVARCHAR(200),                                
      emailid2               NVARCHAR(200),                                
      city                   NVARCHAR(200),                                
      STATE                  NVARCHAR(200),                                
      country                NVARCHAR(200),                                
      countrycode            NVARCHAR(200),                                
      pincode                NVARCHAR(200),                                
      residentialaddress     NVARCHAR(200),                                
      officeaddress          NVARCHAR(200),                                
      sourcename       NVARCHAR(200),                                
      mediumname             NVARCHAR(200),                                
      campaignname           NVARCHAR(200),                                
      initialremarks         NVARCHAR(1000)                                
     )                                
                              
     CREATE TABLE #temptablesearchexc                                
     (                                
      campaignid             BIGINT,                                
      searchid               BIGINT,                                
      parentid               BIGINT,
      userid				 bigint,                 
      personname             NVARCHAR(200),                                
      companyname            NVARCHAR(200),              
      mobileno               NVARCHAR(200),                                
      mobileno1              NVARCHAR(200),                                
      mobileno2              NVARCHAR(200),                                
      emailid                NVARCHAR(200),                                
      emailid1               NVARCHAR(200),                                
      emailid2               NVARCHAR(200),                                
      city                   NVARCHAR(200),                                
      STATE                  NVARCHAR(200),                                
      country                NVARCHAR(200),                                
      countrycode            NVARCHAR(200),                                
      pincode                NVARCHAR(200),                                
      residentialaddress     NVARCHAR(200),                                
      officeaddress          NVARCHAR(200),                                
      sourcename             NVARCHAR(200),                                
      mediumname             NVARCHAR(200),                              
      campaignname           NVARCHAR(200),                                
      initialremarks         NVARCHAR(1000)                 
     )                                
INSERT INTO #temptablesearchapp(mobileno,emailid,ParentID  )                                      
Select ISNULL(Usd.MobileNumber, ''),ISNULL(usd.EmailID,''),Tt.ParentID  
FROM  #temptemplate TT
Inner join  Usersearchdata AS Usd  (nolock)  on Usd.ParentID =  Tt.ParentID AND Usd.ImportedListID = Tt.IncludeList and Tt.IncludeList is not null 

INSERT INTO #temptablesearchexc (mobileno,emailID,ParentID  )          
SELECT ISNULL(Usd.Mobilenumber, ''),usd.emailID, Tt.ParentID FROM #temptemplate TT   Inner join   Usersearchdata AS Usd  (nolock) on Usd.ParentID =  Tt.ParentID AND Usd.ImportedListID = Tt.ExclusionsGroupList and Tt.ExclusionsGroupList is not null
 
 --check if user is included in exclusion list till now
if @mediumtype ='both' and exists(select 1 from #temptablesearchexc ttse where isnull(mobileno,0)=@MobileNo or isnull(emailid,0)=@EmailID)	    
begin
Select 'Oops! Coupon is not applicable to you'  as status        
goto OReturn 
end
if @mediumtype='mobile' and exists(select 1 from #temptablesearchexc ttse where isnull(mobileno,0)=@MobileNo)	    
begin
Select 'Oops! Coupon is not applicable to you'  as status        
goto OReturn 
end
if @mediumtype='email' and exists(select 1 from #temptablesearchexc ttse where isnull(emailid,0)=@EmailID)	    
begin
Select 'Oops! Coupon is not applicable to you'  as status        
goto OReturn 
end

DECLARE @CountCampaign     INT = (Select MAX(Id) from #temptemplate)                                     
DECLARE @Count INT = 1                                                                                                  

WHILE (@Count <= @CountCampaign) or not exists(select 1 from #temptablesearchexc ttse where (isnull(mobileno,0)= @MobileNo or isnull(mobileno1,0)= @MobileNo or isnull(mobileno2,0)= @MobileNo) and (isnull(emailid,0)=@EmailID or isnull(emailid1,0)=@EmailID or isnull(emailid2,0)=@EmailID))
BEGIN                                
DECLARE @Applicability BIGINT,@Exclusions BIGINT
Select @Applicability = tt.IncludeSearches,@Exclusions = tt.Exclusions from #temptemplate tt Where Id = @Count 
If(@Applicability is not null)
Begin                               
INSERT INTO #temptablesearchapp                                      
				   (                                     
					 PersonName,                                      
					 CompanyName,                                      
					 MobileNo,                                      
					 MobileNo1,                                      
					 MobileNo2,                                      
					 EmailID,                                      
					 EmailID1,                                      
					 EmailID2,                                      
					 Country,                                      
					 [STATE],                         
					 City,                                
					 PinCode,                                      
					 ResidentialAddress,                                      
					 OfficeAddress,                                      
					 SourceName,                                      
					 MediumName,                                      
					 CampaignName,                                      
					 InitialRemarks,                                      
					 SearchID,                                      
					 ParentID,                                      
					 CampaignID                                      
				   )                                      
				 EXEC Usp_executeusersearch                                      
					  @ParentId,                                      
					  @Applicability,                                      
					  @Campaignid=NULL
					  
           End                                 
if(@Exclusions is not null)
Begin                                 
INSERT INTO #temptablesearchexc                                      
           (                                      
             PersonName,                                      
             CompanyName,                                      
             MobileNo,                                      
             MobileNo1,                                      
		     MobileNo2,                                      
             EmailID,                                      
             EmailID1,                                      
             EmailID2,                                      
             Country,                                      
             [STATE],                                      
             City,                                      
             PinCode,                                      
             ResidentialAddress,                                      
             OfficeAddress,                                      
             SourceName,                                      
             MediumName,                                      
             CampaignName,                                      
             InitialRemarks,                                      
             SearchID,                                      
             ParentID,                                      
             CampaignID                                      
		  )                                      
         EXEC Usp_executeusersearch                                      
              @Parentid,                                      
              @Exclusions,                                      
              @Campaignid=NULL
		  
		  END
SET @Count = @Count+1
END     
if (@mediumtype='mobile' or @mediumtype='both') and exists(select 1 from #temptablesearchexc ttse where (isnull(mobileno,0)= @MobileNo or isnull(mobileno1,0)= @MobileNo or isnull(mobileno2,0)= @MobileNo))
begin
Select 'Oops! Coupon is not applicable to you'  as status        
goto OReturn
end 
if (@mediumtype='email' or @mediumtype='both') and exists(select 1 from #temptablesearchexc ttse where (isnull(emailid,0)=@EmailID or isnull(emailid1,0)=@EmailID or isnull(emailid2,0)=@EmailID))
begin
Select 'Oops! Coupon is not applicable to you'  as status        
goto OReturn
end
  
if exists(select 'x' from #temptemplate outer apply dbo.Fn_split(IncludeMobile, ',')  AS fs outer apply dbo.Fn_split(Includemail, ',') as fsmail  WHERE  fs.[value]=@MobileNo and fsmail.[value]=@EmailID)  
begin
Goto CouponSuccess
end    
else if @mediumtype='mobile' and exists(select 1 from #temptablesearchapp ttse where (isnull(mobileno,0)= @MobileNo or isnull(mobileno1,0)= @MobileNo or isnull(mobileno2,0)= @MobileNo))
begin
goto CouponSuccess
end 
else if @mediumtype='email' and exists(select 1 from #temptablesearchapp ttse where (isnull(emailid,0)=@EmailID or isnull(emailid1,0)=@EmailID or isnull(emailid2,0)=@EmailID))
begin
goto CouponSuccess
end 
else if @mediumtype='both' and exists(select 1 from #temptablesearchapp ttse where (isnull(mobileno,0)= @MobileNo or isnull(mobileno1,0)= @MobileNo or isnull(mobileno2,0)= @MobileNo) and (isnull(emailid,0)=@EmailID or isnull(emailid1,0)=@EmailID or isnull(emailid2,0)=@EmailID))
begin
goto CouponSuccess
end 
end
end
select * from UserCouponSettings1
CouponSuccess:
declare @discount numeric(18,4),@others nvarchar(400)
if (select isdiscount from #tempcoupon)=1
begin
select @discount=case when DiscountAmount<>0 then DiscountAmount else DiscountPrcnt*@BIllAmount/100 end from #tempcoupon
end
select 'Coupon Applied Successfully'  as status 
select 'Coupon Discount: ' + CAST(@discount as nvarchar)
   
    exec Usp_createProductMasterTable @ParentID  
    --SELECT p.name ,f.ProductId as FreeProduct,f.Qty FROM FreebeeProduct f join ProductMaster p on p.ProductID=f.ProductId where f.CouponID=@couponid        
	
	if((@ParentID is not null) and (@ParentID = 0) )
	 Begin
	   declare @Query nvarchar(max) = N' SELECT p.name ,f.ProductId as FreeProduct,f.Qty FROM FreebeeProduct f join tbl_ProductMaster_'+cast(@ParentID as nvarchar(max))+' (nolock) p on p.ProductID=f.ProductId where f.CouponID=@couponid ' 
	   exec sp_executesql @Query   
	end 
	else
	  Begin
	   SELECT p.name ,f.ProductId as FreeProduct,f.Qty FROM FreebeeProduct f join ProductMaster p on p.ProductID=f.ProductId where f.CouponID=@couponid        
	  End

OReturn:             
END 


