/* ============================================================
   Procedure: [dbo].[prc_ViewCamGroupAds]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec prc_ViewCamGroupAds @Type='camp',@User_ID='335',@CampId=0
-- exec prc_ViewCamGroupAds @Type='group',@User_ID='335',@CampId=0
-- exec prc_ViewCamGroupAds @Type='ads',@User_ID='335',@CampId=0
-- exec prc_ViewCamGroupAds @Type='ads',@User_ID='335',@CampId=24
CREATE   PROC [dbo].[prc_ViewCamGroupAds]  
 @Type varchar(50)                                      
,@User_ID varchar(50),                                
@CampId  bigint                                     
As                                      
Begin
if(@Type='camp')
begin
 Select cmp.CampaignId,CampAd_id, User_ID, CampaignName,Location,Budget,IsActive,
 Status,IsPublished,ISNULL(cmp.InProcess,0) as InProcess, cmp.ApprovalDate,
 cmp.CreatedDate ,BidStrategyType,CampaignType,cmp.radious,cmp.latitude,cmp.longitude,                                    
 Case when Status='0' then 'Pause' else 'Running' end as Status,  cmp.IsDeleted,                                   
 bgt.BudgetId , bgt.BudgetName ,  CmpStartDate,CmpEndDate ,GCampaignName,Gbudgetname                                  
 from tblCampaign cmp inner join tblAdwordBudget bgt                                     
 on bgt.BudgetId = cmp.BudgetId where User_ID=@User_ID and cmp.IsDeleted=0
  order by CampaignId desc                                      
end

if(@Type='group')
begin
if (@CampId = '0')
 Select AdGroupId,CampaignName,Adword_Name, AdwordGroupId,grp.CampAd_id, grp.User_Id, grp.Status, 
  GroupName,KeywordId, Keyword, ISNULL(grp.InProcess,0) as InProcess, grp.IsDeleted,                                   
 grp.IsPublished, grp.IsActive, grp.CreatedDate,grp.Gender,grp.AgeRanges,grp.Incomepercentilerange,        
 grp.DaysofWeek,grp.Parentalstatus,grp.Affinitycategories,grp.Platform, cmp.CampaignType
 from tblAdGroup grp inner join tblCampaign cmp
 on cmp.CampAd_id = grp.CampAd_id                                    
 where grp.User_ID=@User_ID and grp.IsDeleted=0 and cmp.IsDeleted=0
 order by AdGroupId desc                                 
else                                
 Select AdGroupId,CampaignName,Adword_Name, AdwordGroupId,grp.CampAd_id, grp.User_Id, grp.Status,
 GroupName, Keyword,KeywordId,ISNULL(grp.InProcess,0) as InProcess, grp.IsDeleted, 
 grp.IsPublished, grp.IsActive, grp.CreatedDate,grp.Gender,grp.AgeRanges,grp.Incomepercentilerange,        
 grp.DaysofWeek,grp.Parentalstatus,grp.Affinitycategories,grp.Platform, cmp.CampaignType 
 from tblAdGroup grp inner join tblCampaign cmp
 on cmp.CampAd_id = grp.CampAd_id                                    
 where grp.CampAd_id  = @CampId and grp.IsDeleted=0
 order by AdGroupId desc                                     
end                                 
                                   
if(@Type='ads')
begin
if (@CampId = '0')
    Select ads.AdsId, adgrp.GroupName,adgrp.Keyword, ads.BusinessName,ads.Description1,ads.Description2, ads.IsDeleted,
	ads.DisplayUrl,ads.CreatedDate,ads.IsActive, ads.AdwordGroupId, AdwordAdsId,ISNULL(ads.InProcess,0) as InProcess,
    cmp.CampAd_id, CampaignName,GCampaignName, ads.Status, ads.CampaignSubType
    from tblAds ads inner join tblAdGroup adgrp 
    on CampaignId = adgrp.CampAd_id and (ads.AdwordGroupId = adgrp.AdwordGroupId or ads.AdwordGroupId = adgrp.AdGroupId) inner join tblCampaign cmp 
    on cmp.CampAd_id = adgrp.CampAd_id
    where ads.User_Id=@User_ID and ads.IsDeleted=0 and adgrp.IsDeleted=0 and cmp.IsDeleted=0 and ads.CampaignSubType='Text'
    --order by ads.AdsId desc

    union

    Select ads.AdsId, adgrp.GroupName,adgrp.Keyword, rad.BusinessName,rad.ShortHeadline1 as Description1, rad.Description1 as Description2, ads.IsDeleted,
	rad.FinalUrl as DisplayUrl,ads.CreatedDate,ads.IsActive, ads.AdwordGroupId, AdwordAdsId,ISNULL(ads.InProcess,0) as InProcess,
    cmp.CampAd_id, CampaignName,GCampaignName, ads.Status, ads.CampaignSubType
    from tblAds ads inner join tblAdGroup adgrp 
    on CampaignId = adgrp.CampAd_id and (ads.AdwordGroupId = adgrp.AdwordGroupId or ads.AdwordGroupId = adgrp.AdGroupId) inner join tblCampaign cmp 
    on cmp.CampAd_id = adgrp.CampAd_id inner join tblAds_ResponsiveAdForDisplay rad
    on ads.AdsId=rad.Ref_AdsId
    where ads.User_Id=@User_ID and ads.IsDeleted=0 and adgrp.IsDeleted=0 and cmp.IsDeleted=0 and ads.CampaignSubType='RAD'
    order by ads.AdsId desc                              
else                            
    Select ads.AdsId, adgrp.GroupName, adgrp.Keyword, ads.BusinessName, ads.Description1, ads.Description2, ads.DisplayUrl,
	ads.CreatedDate,ads.IsActive,  ads.AdwordGroupId, AdwordAdsId,ISNULL(ads.InProcess,0) as InProcess, ads.IsDeleted, 
	cmp.CampAd_id, CampaignName, ads.Status, ads.CampaignSubType
    from tblAds ads inner join tblAdGroup adgrp 
    on CampaignId = adgrp.CampAd_id and (ads.AdwordGroupId = adgrp.AdwordGroupId or ads.AdwordGroupId = adgrp.AdGroupId) inner join tblCampaign cmp 
    on cmp.CampAd_id = adgrp.CampAd_id
    where ads.CampaignId=@CampId and ads.IsDeleted=0 and adgrp.IsDeleted=0 and ads.CampaignSubType='Text'

    union

    Select ads.AdsId, adgrp.GroupName, adgrp.Keyword, isnull(ads.BusinessName,rad.BusinessName) as BusinessName, isnull(ads.Description1,rad.ShortHeadline1) as Description1, isnull(ads.Description2,rad.Description1) as Description2 , isnull(ads.DisplayUrl,rad.FinalUrl) as DisplayUrl,
	ads.CreatedDate,ads.IsActive,  ads.AdwordGroupId, AdwordAdsId,ISNULL(ads.InProcess,0) as InProcess, ads.IsDeleted, 
	cmp.CampAd_id, CampaignName, ads.Status, ads.CampaignSubType
	-- select * 
    from tblAds ads inner join tblAdGroup adgrp 
    on CampaignId = adgrp.CampAd_id and (ads.AdwordGroupId = adgrp.AdwordGroupId or ads.AdwordGroupId = adgrp.AdGroupId) inner join tblCampaign cmp 
    on cmp.CampAd_id = adgrp.CampAd_id inner join tblAds_ResponsiveAdForDisplay rad
    on ads.AdsId=rad.Ref_AdsId
    where ads.CampaignId=@CampId and ads.IsDeleted=0 and adgrp.IsDeleted=0 and ads.CampaignSubType='RAD'
    order by ads.AdsId desc

end                               
End



GO

/* ============================================================
   Procedure: [dbo].[prc_ViewCamGroupAds_INTDateTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[prc_ViewCamGroupAds_INTDateTime]             
 @Type varchar(50)                      
,@User_ID varchar(50),                
@CampId  varchar(50)                     
As                      
Begin
 declare @ParentID Bigint = 0
 
 select @ParentID = isnull(ParentID,0) From user_detail where USER_ID = @User_ID
                      
if(@Type='camp')                      
begin                      
 Select cmp.CampaignId,CampAd_id, User_ID, CampaignName,Location,Budget,IsActive,          
 Status,IsPublished,
  dbo.[fn_getusertimefromindiantime](@ParentID,cmp.CreatedDate) as CreatedDate
 
 ,BidStrategyType,CampaignType,                    
 Case when Status='0' then 'Pause' else 'Running' end as Status,                    
 bgt.BudgetId , bgt.BudgetName ,
  
 dbo.[fn_getusertimefromindiantime](@ParentID,CmpStartDate) as CmpStartDate,
 
 dbo.[fn_getusertimefromindiantime](@ParentID,CmpEndDate) as CmpEndDate ,
 
 GCampaignName,Gbudgetname                  
 from tblCampaign cmp inner join tblAdwordBudget bgt                     
 on bgt.BudgetId = cmp.BudgetId where User_ID=@User_ID                    
  order by CampaignId desc                      
end                      
if(@Type='group')                      
begin                
if (@CampId = '0')                     
 Select AdGroupId,CampaignName,Adword_Name, AdwordGroupId,grp.CampAd_id, grp.User_Id,            
  GroupName,KeywordId, Keyword,                    
 grp.IsPublished, grp.IsActive, 
 
  
 dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID =  grp.User_Id ),grp.CreatedDate) as CreatedDate
 
 
 
 from tblAdGroup grp inner join tblCampaign cmp                     
 on cmp.CampAd_id = grp.CampAd_id                    
 where grp.User_ID=@User_ID  order by AdGroupId desc                 
else                
 Select AdGroupId,CampaignName,Adword_Name, AdwordGroupId,grp.CampAd_id, grp.User_Id,             
 GroupName, Keyword,KeywordId,                    
 grp.IsPublished, grp.IsActive, 
 
  dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID =  grp.User_Id ),grp.CreatedDate) as CreatedDate
 
 from tblAdGroup grp inner join tblCampaign cmp                     
 on cmp.CampAd_id = grp.CampAd_id                    
 where grp.CampAd_id  = @CampId   order by AdGroupId desc                     
end                 
                   
if(@Type='ads')                      
begin             
if (@CampId = '0')                     
Select ads.AdsId, adgrp.GroupName,adgrp.Keyword, ads.BusinessName,ads.Description1,ads.Description2   
,ads.DisplayUrl,

dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID =  ads.User_Id ),ads.CreatedDate) as CreatedDate,

ads.IsActive, ads.AdwordGroupId, AdwordAdsId,          
cmp.CampAd_id, CampaignName,GCampaignName          
 from tblAds ads                      
left join tblAdGroup adgrp on ads.AdwordGroupId=adgrp.AdwordGroupId           
left outer join tblCampaign cmp on  cmp.CampAd_id = adgrp.CampAd_id             
where ads.User_Id=@User_ID order by ads.AdsId desc              
else            
Select ads.AdsId, adgrp.GroupName,adgrp.Keyword, ads.BusinessName,ads.Description1,ads.Description2     ,ads.DisplayUrl
,

 dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID =  ads.User_Id ),ads.CreatedDate) as CreatedDate

,ads.IsActive
,ads.AdwordGroupId
,AdwordAdsId,          
cmp.CampAd_id, CampaignName            
 from tblAds ads                      
left join tblAdGroup adgrp on ads.AdwordGroupId=adgrp.AdwordGroupId            
left outer join tblCampaign cmp on  cmp.CampAd_id = adgrp.CampAd_id            
where ads.AdwordGroupId=@CampId order by ads.AdsId desc                     
end                      
End  


GO

/* ============================================================
   Procedure: [dbo].[prcAdwords_GetCost]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[prcAdwords_GetCost]
@User_ID varchar(50)
As
Begin
select Sum(camrep.Cost) as Cost,  cam.CampAd_id,cam.User_ID from tblCampaign cam
left join tblAdwordsCampaignPerformanceRep camrep on cam.CampAd_id=camrep.CampaignId where
cam.User_ID=@User_ID GROUP BY cam.CampAd_id,cam.User_ID WITH CUBE HAVING cam.User_ID IS NOT NULL
End



GO

