   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--prcAdwordsAdwordsCalculate'335'
CREATE   PROC [dbo].[prcAdwordsAdwordsCalculate]
@User_ID varchar(50)
As
Begin
Declare @creditid int
set @creditid=(select max(Credit_ID) from View_AdwordsCalculate where User_ID=@User_ID)
select (Balance-Cost) as FBalance, * from View_AdwordsCalculate where User_ID=@User_ID and Credit_ID=@creditid
End



