/* ============================================================
   Procedure: [dbo].[Price_CheckUserSubscriptionValidity]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Price_CheckUserSubscriptionValidity]      
(    
	@UserID as int         
)                    
AS                      
BEGIN      
declare @parentId as int,@retvalue as varchar(10)    
set @retvalue='No'
select @parentId=Parentid from User_Detail(nolock) where User_ID=@UserID                
declare @pEndDate datetime                
select @pEndDate=PlanEndDate from Price_UserSubscriptionDetails(nolock) where UserID=@parentId and IsNewPlan=1    

if(@pEndDate >= FORMAT(getdate(), 'yyyy-MM-dd'))    
 set @retvalue='Yes'
else    
Begin    
if(@parentId=@UserID)    
 set @retvalue='No'    
else    
  set @retvalue='NoUser'     
End    
 select @retvalue , (Case when @retvalue ='Yes'  then 'Valid subscription' ELSE 'Invalid subscription' end) as  Message;
END





GO

