select @getTotalCount=count(1) from User_Detail(nolock) where ParentID=@userId                
if(@getTotalCount <= cast(@setValue as int))                              
      set @IsInsertRequired=0 --pass                              
   else                              
      set @IsInsertRequired=1 --fail        
    
if @IsInsertRequired =1    
 Begin    
declare @intdur as bigint                        
, @fracdur as bigint       
    
declare @remainingDays as int    
set @remainingDays = DATEDIFF(DAY,GetDAte(),@planEndDate)    
    
select @intdur =Convert(int,@remainingDays/30),                        
 @fracdur= @remainingDays%30                         
if @fracdur >0                        
 set @intdur = @intdur+1     
    
set @price=@price*@intdur    
end    
    
End --end of users                
 else if @optType = 'phonenumber'                
Begin               
set @typeCredit =  8            
set @Remarks='deducted for phonenumber creation'          
set @price=                  
(                  
select Price from Price_Base_PhoneNo_Rate_Exception where OriginCountryId=@OriginCountryID and USERID=@userid                  
union                  
select Price from Price_Base_PhoneNo_Rate where OriginCountryId=@OriginCountryID                  
)                 
End --end of phonenumber            
 -- print @IsInsertRequired              
if @IsInsertRequired =1                
Begin                
  INSERT INTO IntCredit_Details                                                      
                  (ID,          
                   -- Credit_ID -- this column value is auto-generated                                                      
                   M_ID,                                                      
     FromUser_ID,                                                      
                   [User_ID],                                                      
                   Debits,                                                      
                 Credits,                                                      
                 Balance,                                                      
                   Validity,                                                      
                   Default_Credit,                                                      
                   FromDate,                           
                   ToDate,                                                      
                   DateCreated,                                                      
                   DateUpdated,                                                      
               EmpUpdated,                                                      
                   MachineName,                                                      
                   LastModified,                                          
                   typecredit,                    
                   campaignid,          
       Remarks)                                                      
      SELECT top 1 Newid(),                                                      
             Ud.M_ID,                           
             @userId,                                                      
             @userId,                                                      
             isnull(@price,0),                                                      
             0,                                                      
             (SELECT TOP 1 Mcd.Balance                                                      
              FROM   IntCredit_Details AS Mcd                                                      
              WHERE  Mcd.[User_ID] = @userId                                                      
              ORDER  BY Mcd.Credit_ID DESC) -  isnull(@price,0),                                                      
             99999,                            
             '',                                                      
             Getdate(),                                                      
             Getdate(),                                                      
             Getdate(),                                                      
             Getdate(),                                                      
             '',                                                      
             '',                                          
             Getdate(),                                             
             @typeCredit,                    
             0,          
    @Remarks                                                      
      FROM user_detail ud (nolock) where User_ID=@userId                
End      

*/
 end 


GO

