SET QUOTED_IDENTIFIER ON

CREATE   PROC Price_GetPlan --'','ujjwal'        
@type varchar(10),    
@Userlogin varchar(100)        
AS        
Begin        
if (@type='all')        
select * from Price_ServiceMaster        
else    
Begin    
declare @userid as int    
select @userid=ParentID from User_Detail where LOWER(User_Login)=@userlogin and m_id=10043    
if exists(select 1 from User_Detail where LOWER(User_Login)=@userlogin  and m_id=10043)    
 begin    
  
  select *,'ok' as msg from Price_ServiceCategoryLinkUserCopy psu     
   left join Price_CategoryMaster pc on psu.CategoryID=pc.CategoryID where psu.UserId=@userid    
    
 select * from Price_UserSubscriptionDetails where  UserId=@userid and IsNewPlan=1    
 end    
 else    
  select 'Incorrect User login' as msg     
End    
End    




GO

/* ============================================================
   Procedure: [dbo].[Price_GetPlanCategoryDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Price_GetPlanCategoryDetails] --'all',0                     
(@PlanName nvarchar(max)=null,              
@PlanId int = 0 )                    
AS                          
BEGIN                          
if(@PlanName = 'all')                     
begin                
      
create table #tmpPlanData(      
CategoryId nvarchar(500),      
CategoryName nvarchar(500),      
Plan1 nvarchar(500),      
Plan2 nvarchar(100),      
Plan3 nvarchar(100),      
Plan4 nvarchar(100),      
vieworder int      
)      
      
create table #tmpPlanName(      
planid int,      
Planname nvarchar(100),      
showorder int)      
      
insert into #tmpPlanName      
select planid,planname,PlantoShow from [Price_ServiceMaster] where plantoshow <>0 and IsPlanPublish=1      
      
--creating the first row      
insert into #tmpPlanData(CategoryId,CategoryName,Plan1,Plan2,Plan3,Plan4,vieworder)      
select '','',planname,'','','',-3 from [Price_ServiceMaster] where plantoshow=1 and IsPlanPublish=1      
      
insert into #tmpPlanData(CategoryId,CategoryName,Plan1,Plan2,Plan3,Plan4,vieworder)      
select '','',cast(PlanCost as nvarchar(50)) + ' ' + m_country1.ShortName + '/month','','','',-2 from [Price_ServiceMaster]       
left join m_country1 on [Price_ServiceMaster].PlanCurrency=m_country1.Country_ID      
where plantoshow=1 and IsPlanPublish=1      
      
insert into #tmpPlanData(CategoryId,CategoryName,Plan1,Plan2,Plan3,Plan4,vieworder)      
select '','','(billed ' + pd.PlanDuration +')','','','',-1 from [Price_ServiceMaster]      
left join Price_PlanDuration pd on pd.ID=[Price_ServiceMaster].PlanDuration      
 where plantoshow=1 and IsPlanPublish=1      
      
update #tmpPlanData set Plan2=planname       
from [Price_ServiceMaster] where plantoshow=2 and IsPlanPublish=1 and vieworder=-3      
update #tmpPlanData set Plan3=planname      
from [Price_ServiceMaster] where plantoshow=3 and IsPlanPublish=1 and vieworder=-3      
update #tmpPlanData set Plan4=planname      
from [Price_ServiceMaster] where plantoshow=4 and IsPlanPublish=1 and vieworder=-3      
      
update #tmpPlanData set Plan2=cast(PlanCost as nvarchar(50)) + ' ' + m_country1.Shortname + '/month'       
from [Price_ServiceMaster]      
left join m_country1 on [Price_ServiceMaster].PlanCurrency=m_country1.Country_ID      
 where plantoshow=2 and IsPlanPublish=1 and vieworder=-2      
update #tmpPlanData set Plan3=cast(PlanCost as nvarchar(50)) + ' ' + m_country1.Shortname + '/month'      
from [Price_ServiceMaster]       
left join m_country1 on [Price_ServiceMaster].PlanCurrency=m_country1.Country_ID      
where plantoshow=3 and IsPlanPublish=1 and vieworder=-2      
update #tmpPlanData set Plan4=cast(PlanCost as nvarchar(50)) + ' ' + m_country1.Shortname + '/month'      
from [Price_ServiceMaster]       
left join m_country1 on [Price_ServiceMaster].PlanCurrency=m_country1.Country_ID      
where plantoshow=4 and IsPlanPublish=1 and vieworder=-2      
      
      
update #tmpPlanData set Plan2='(billed ' + pd.PlanDuration  +')'    
from [Price_ServiceMaster]      
left join Price_PlanDuration pd on pd.ID=[Price_ServiceMaster].PlanDuration      
 where plantoshow=2 and IsPlanPublish=1 and vieworder=-1      
update #tmpPlanData set Plan3='(billed ' + pd.PlanDuration  +')'    
from [Price_ServiceMaster]       
left join Price_PlanDuration pd on pd.ID=[Price_ServiceMaster].PlanDuration      
where plantoshow=3 and IsPlanPublish=1 and vieworder=-1      
update #tmpPlanData set Plan4='(billed ' + pd.PlanDuration  +')'    
from [Price_ServiceMaster]       
left join Price_PlanDuration pd on pd.ID=[Price_ServiceMaster].PlanDuration      
where plantoshow=4 and IsPlanPublish=1 and vieworder=-1      
      
      
insert into #tmpPlanData(CategoryId,CategoryName,Plan1,Plan2,Plan3,Plan4,vieworder)      
select '','Plan','','','','' ,0      
               
insert into #tmpPlanData(CategoryId,CategoryName,vieworder)      
select CategoryId,CategoryDisplayName,ColumnOrder from[Price_CategoryMaster]       
where ParentCategoryID = 0 and isactive=1 order by columnorder asc      
      
declare @splanID int      
select @splanID=planId from #tmpPlanName where showorder=1       
update #tmpPlanData set Plan1=SC.Value      
  from #tmpPlanData inner join [Price_CategoryMaster] CM on #tmpPlanData.CategoryId=cm.CategoryID      
  left join [dbo].[Price_ServiceCategoryLink] SC on CM.CategoryID=SC.CategoryID      
  where SC.PlanId=@splanID and ParentCategoryID = 0 and cm.columnorder is not null      
       
declare @tempstr nvarchar(500)      
      
           
select @splanID=planId from #tmpPlanName where showorder=2       
update #tmpPlanData set Plan2=SC.Value      
  from #tmpPlanData inner join [Price_CategoryMaster] CM on #tmpPlanData.CategoryId=cm.CategoryID      
 left join [dbo].[Price_ServiceCategoryLink] SC on CM.CategoryID=SC.CategoryID      
 where SC.PlanId=@splanID and ParentCategoryID = 0 and cm.columnorder is not null      
      
      
      
 select @splanID=planId from #tmpPlanName where showorder=3      
 update #tmpPlanData set Plan3=SC.Value      
  from #tmpPlanData inner join [Price_CategoryMaster] CM on #tmpPlanData.CategoryId=cm.CategoryID      
 left join [dbo].[Price_ServiceCategoryLink] SC on CM.CategoryID=SC.CategoryID      
 where SC.PlanId=@splanID and ParentCategoryID = 0 and cm.columnorder is not null      
      
      
select @splanID=planId from #tmpPlanName where showorder=4       
update #tmpPlanData set Plan4=SC.Value      
  from #tmpPlanData inner join [Price_CategoryMaster] CM on #tmpPlanData.CategoryId=cm.CategoryID      
 left join [dbo].[Price_ServiceCategoryLink] SC on CM.CategoryID=SC.CategoryID      
 where SC.PlanId=@splanID and ParentCategoryID = 0 and cm.columnorder is not null      
      
 DECLARE  @ID INT = 6;      
 UPDATE #tmpPlanData SET vieworder = vieworder + 1 WHERE vieworder >= @ID;      
insert into #tmpPlanData(CategoryId,CategoryName,Plan1,Plan2,Plan3,Plan4,vieworder)      
select '','Add-on Services','','','','',@ID       
     
 set @ID  = 11;      
 UPDATE #tmpPlanData SET vieworder = vieworder + 1 WHERE vieworder >= @ID;      
insert into #tmpPlanData(CategoryId,CategoryName,Plan1,Plan2,Plan3,Plan4,vieworder)      
select '','Managed Services','','','','',@ID       
      
 select * from #tmpPlanData order by vieworder asc      
 select * from  Price_ServiceCategoryLink where PlanId in(select planid from #tmpPlanName)      
 select * from #tmpPlanName       
end                
                
else if (@PlanName is null and @PlanId <> 0)              
begin              
   select SM.PlanName,SM.PlanCost,SM.IsPlanPublish,SM.DemoDays,SM.MaxDemoExtension,SM.CountryID, SM.PlanCurrency,SM.PlanDuration,SM.BillingMethod,           
     isnull(SC.value,0) [Value],CM.CategoryDisplayName,CM.CategoryName,CM.ParentCategoryID,CM.ControlType,SC.CategoryID                 
     from Price_ServiceCategoryLink SC                   
             left join Price_CategoryMaster CM on SC.CategoryID=CM.Categoryid                 
    left join Price_ServiceMaster SM on SC.PlanId=SM.PlanID                 
    where CM.ParentCategoryID=0 and SM.PlanID=@PlanId              
                
     select SM.PlanName,SM.PlanCost,SM.IsPlanPublish,SM.DemoDays,SM.MaxDemoExtension, SM.CountryID, SM.PlanCurrency,SM.PlanDuration,  SM.BillingMethod,          
  isnull(SC.value,0) [Value],CM.CategoryDisplayName,CM.CategoryName,CM.ParentCategoryID,CM.ControlType,SC.CategoryID                 
     from Price_ServiceCategoryLink SC                   
             left join Price_CategoryMaster CM on SC.CategoryID=CM.Categoryid                 
    left join Price_ServiceMaster SM on SC.PlanId=SM.PlanID                 
    where CM.ParentCategoryID <> 0 and SM.PlanID=@PlanId                
end              
else              
Begin                  
            select SM.PlanName,SM.PlanCost,SM.IsPlanPublish,SM.DemoDays,SM.MaxDemoExtension,SM.CountryID,SM.PlanCurrency,SM.PlanDuration,SM.BillingMethod  ,          
   isnull(SC.value,0) [Value],CM.CategoryDisplayName,CM.CategoryName,CM.ParentCategoryID,CM.ControlType,SC.CategoryID                 
     from Price_ServiceCategoryLink SC                   
             left join Price_CategoryMaster CM on SC.CategoryID=CM.Categoryid                 
    left join Price_ServiceMaster SM on SC.PlanId=SM.PlanID                 
    where CM.ParentCategoryID=0 and lower(SM.PlanName)=isnull(@PlanName,lower(SM.PlanName))                
                
     select SM.PlanName,SM.PlanCost,SM.IsPlanPublish,SM.DemoDays,SM.MaxDemoExtension,  SM.CountryID,SM.PlanCurrency,SM.PlanDuration,  SM.BillingMethod,       
  isnull(SC.value,0) [Value],CM.CategoryDisplayName,CM.CategoryName,CM.ParentCategoryID,CM.ControlType,SC.CategoryID                 
     from Price_ServiceCategoryLink SC                   
             left join Price_CategoryMaster CM on SC.CategoryID=CM.Categoryid                 
    left join Price_ServiceMaster SM on SC.PlanId=SM.PlanID                 
    where CM.ParentCategoryID <> 0 and lower(SM.PlanName)=isnull(@PlanName,lower(SM.PlanName))                
                
End                
END   


GO

/* ============================================================
   Procedure: [dbo].[Price_GetPlanCategoryDetailsForUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].Price_GetPlanCategoryDetailsForUser --'all',0                       
(                
@UserId int = 0 )                      
AS                            
BEGIN                            
     
	 declare @PlanId as int
	 select @PlanId = planid from Price_UserSubscriptionDetails where UserId=@UserId and isnewPlan=1            
                  
   select SM.PlanName,SM.PlanCost,SM.IsPlanPublish,SM.DemoDays,SM.MaxDemoExtension,SM.CountryID, SM.PlanCurrency,SM.PlanDuration,SM.BillingMethod,             
     isnull(SC.value,0) [Value],CM.CategoryDisplayName,CM.CategoryName,CM.ParentCategoryID,CM.ControlType,SC.CategoryID                   
     from Price_ServiceCategoryLinkUserCopy SC                     
             left join Price_CategoryMaster CM on SC.CategoryID=CM.Categoryid                   
    left join Price_ServiceMaster SM on SC.PlanId=SM.PlanID                   
    where CM.ParentCategoryID=0 and SM.PlanID=@PlanId                
                  
     select SM.PlanName,SM.PlanCost,SM.IsPlanPublish,SM.DemoDays,SM.MaxDemoExtension, SM.CountryID, SM.PlanCurrency,SM.PlanDuration,  SM.BillingMethod,            
  isnull(SC.value,0) [Value],CM.CategoryDisplayName,CM.CategoryName,CM.ParentCategoryID,CM.ControlType,SC.CategoryID                   
     from Price_ServiceCategoryLinkUserCopy SC                     
             left join Price_CategoryMaster CM on SC.CategoryID=CM.Categoryid                   
    left join Price_ServiceMaster SM on SC.PlanId=SM.PlanID                   
    where CM.ParentCategoryID <> 0 and SM.PlanID=@PlanId                  
end


GO

/* ============================================================
   Procedure: [dbo].[Price_GetPlanCategoryDetailsUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

   -- [Price_GetPlanCategoryDetailsUser] 24876              
                  
CREATE   PROCEDURE [dbo].[Price_GetPlanCategoryDetailsUser]                            
(@UserId int      
)                          
AS                                
BEGIN                                
                     
            
create table #tmpPlanData(            
CategoryId nvarchar(10),            
CategoryName nvarchar(100),            
Plan1 nvarchar(150),            
          
vieworder int            
)            
      
            
create table #tmpPlanName(            
planid int,            
Planname nvarchar(100),            
showorder int)            
        
 declare @nPlanid as int
 declare @valfrom as date ,@tofrom as date    
  select @nPlanid=PlanID,@valfrom=PlanStartDate,@tofrom=PlanEndDate from Price_UserSubscriptionDetails where userid=@UserId and IsNewPlan=1       
insert into #tmpPlanName            
select planid,planname,PlantoShow from [Price_ServiceMaster]       
where PlanID = @nPlanid          
            
--creating the first row            
insert into #tmpPlanData(CategoryId,CategoryName,Plan1,vieworder)            
select '','',planname,-3 from [Price_ServiceMaster] where PlanID = @nPlanid              
            
insert into #tmpPlanData(CategoryId,CategoryName,Plan1,vieworder)            
select '','',cast(PlanCost as nvarchar(50)) + ' ' + M_Country1.Shortname + '/month',-2 from [Price_ServiceMaster]             
left join M_Country1 on [Price_ServiceMaster].PlanCurrency=m_country1.Country_ID            
where PlanID = @nPlanid               
            
insert into #tmpPlanData(CategoryId,CategoryName,Plan1,vieworder)            
select '','','(billed ' + pd.PlanDuration +')',-1 from [Price_ServiceMaster]            
left join Price_PlanDuration pd on pd.ID=[Price_ServiceMaster].PlanDuration            
where PlanID = @nPlanid           
            
         
            
      
            
            
insert into #tmpPlanData(CategoryId,CategoryName,Plan1,vieworder)            
select '','Plan','',0            

insert into #tmpPlanData(CategoryId,CategoryName,Plan1,vieworder)            
select '','Validity',CONVERT(VARCHAR(10), @valfrom, 103)  + '  To  ' + CONVERT(VARCHAR(10), @tofrom, 103) ,0 
                     
insert into #tmpPlanData(CategoryId,CategoryName,vieworder)            
select CategoryId,CategoryDisplayName,ColumnOrder from[Price_CategoryMaster]             
where ParentCategoryID = 0 and isactive=1 order by columnorder asc            
            
             
update #tmpPlanData set Plan1=SC.Value            
  from #tmpPlanData inner join [Price_CategoryMaster] CM on #tmpPlanData.CategoryId=cm.CategoryID            
  left join [dbo].[Price_ServiceCategoryLinkUserCopy] SC on CM.CategoryID=SC.CategoryID            
  where SC.PlanId=@nPlanid and ParentCategoryID = 0 and SC.UserId=@UserId and cm.columnorder is not null            
             
declare @tempstr nvarchar(500)            
            
                 
        
            
 DECLARE  @ID INT = 6;            
 UPDATE #tmpPlanData SET vieworder = vieworder + 1 WHERE vieworder >= @ID;            
insert into #tmpPlanData(CategoryId,CategoryName,Plan1,vieworder)            
select '','Add-on Services','',@ID             
           
 set @ID  = 11;            
 UPDATE #tmpPlanData SET vieworder = vieworder + 1 WHERE vieworder >= @ID;            
insert into #tmpPlanData(CategoryId,CategoryName,Plan1,vieworder)            
select '','Managed Services','',@ID             
            
 select * from #tmpPlanData order by vieworder asc            
 select * from  Price_ServiceCategoryLinkUserCopy where PlanId =@nPlanid  and UserId=@UserId          
 select * from #tmpPlanName             
    
  drop table #tmpPlanData
  drop table #tmpPlanName	            
END 

