/* ============================================================
   Procedure: [dbo].[Price_GetPlanDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[Price_GetPlanDetails]              
(@planName nvarchar(max) = '',      
 @planID int =0          
)                
AS                  
BEGIN              
            
if @planName='' and @planID=0                  
select planname ,(CONVERT(VARCHAR(50),plancost) + ' ' + mc.Shortname) plancost,DemoDays,    
       case when IsPlanPublish = 1 then '' else 'No' end IsPlanPublish,        
       Price_ServiceMaster.PlanID,MaxDemoExtension,ps.staticContent     
      from Price_ServiceMaster       
           left join m_country1 mc on Price_ServiceMaster.plancurrency=mc.Country_ID            
     left join Price_PlanStaticContent Ps on ps.planid=Price_ServiceMaster.PlantoShow    
     --where PlantoShow <> 0 
	 order by Price_ServiceMaster.PlantoShow asc    
else if @planName <> ''              
select PlanID from Price_ServiceMaster  where lower(planname)=@planName      
else if @planID <> 0 --- for pricing page      
    select Planname,PlanCost as Price,PlanDescription,mc.Shortname CurrencySymbol,PlanCurrency      
 from Price_ServiceMaster      
 left join m_country1 mc on Price_ServiceMaster.plancurrency=mc.Country_ID       
 where PlanID=@planID             
END       
  


GO

/* ============================================================
   Procedure: [dbo].[Price_GetPlanDetailsCountryWise]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- [Price_GetPlanDetailsCountryWise] '',0,2            
CREATE   PROCEDURE [dbo].[Price_GetPlanDetailsCountryWise]  
(
 @CountryID as varchar(20)          
)                
AS                  
BEGIN              
            
       
select planname ,(CONVERT(VARCHAR(50),plancost) + ' ' + mc.Shortname) plancost,DemoDays,    
       case when IsPlanPublish = 1 then '' else 'No' end IsPlanPublish,        
       Price_ServiceMaster.PlanID,MaxDemoExtension,ps.staticContent     
      from Price_ServiceMaster       
           left join m_country1 mc on Price_ServiceMaster.plancurrency=mc.Country_ID            
     left join Price_PlanStaticContent Ps on ps.planid=Price_ServiceMaster.PlantoShow    
     where IsPlanPublish=1 
	 and (',' + RTRIM(Price_ServiceMaster.CountryID) + ',') LIKE '%,' + @CountryID + ',%'
	 order by Price_ServiceMaster.PlantoShow asc    
         
END 


GO

