CREATE   PROCEDURE [dbo].[Price_InsertServiceMaster]          
 (  
 @PlanName NVARCHAR(max),          
 @PlanCost decimal(18,0),          
-- @CountryCode NVARCHAR(50)= 'In',          
 @DemoDays INT=0,  
 @MaxDemoExtension  INT=0,          
 @IsActive INT=1,          
 @IssystemDefine int =0 ,
 @IsPlanPublish bit
 --,
-- @IsAllowedDiscountCoupen bit
 --@CreatedDate datetime=getdate,          
 --@LastModifiedDate datetime=getdate,          
 --@CreatedBy NVARCHAR(50) =''   
 )        
AS          
BEGIN     
    
 INSERT INTO Price_ServiceMaster  
   (          
     PlanName ,   
  IssystemDefine ,  
  PlanCost  ,  
 -- CountryCode   ,  
  DemoDays     ,  
  MaxDemoExtension,  
  IsActive,
  IsPlanPublish
  --,
 -- AllowedDiscountCoupen
  --CreatedDate   ,  
  --LastModifiedDate ,  
  --CreatedBy  
          
   )          
 VALUES          
   (          
  @PlanName ,  
  @IssystemDefine,  
  @PlanCost,   
 -- @CountryCode,  
  @DemoDays,   
  @MaxDemoExtension,  
  @IsActive ,
  @IsPlanPublish
--  @IsAllowedDiscountCoupen  
   )                    
           
 --SELECT 'Record Saved Successfully'          
         
 SELECT SCOPE_IDENTITY() AS Price_ServiceMaster;          
        
END 



