/* ============================================================
   Procedure: [dbo].[Price_InsertUpdateServiceMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
CREATE   PROCEDURE [dbo].[Price_InsertUpdateServiceMaster]                
 (        
 @PlanID INT=0,      
 @PlanName NVARCHAR(max),                
 @PlanCost decimal(18,0),                
 @CountryId NVARCHAR(50)= 'In',                
 @DemoDays INT=0,        
 @MaxDemoExtension  INT=0,                
 @IsActive INT=1,                
 @IssystemDefine int =0 ,      
 @IsPlanPublish bit,  
 @PlanDuration int,  
 @PlanCurrency nvarchar(100)  ,
 @BillingMethod int
 --@CreatedDate datetime=getdate,                
 --@LastModifiedDate datetime=getdate,                
 --@CreatedBy NVARCHAR(50) =''         
 )              
AS                
BEGIN           
          
if @PlanID=0      
 Begin      
      
 INSERT INTO Price_ServiceMaster        
   (                
     PlanName ,         
  IssystemDefine ,        
  PlanCost  ,        
  CountryId   ,        
  DemoDays     ,        
  MaxDemoExtension,        
  IsActive,      
  IsPlanPublish,  
  PlanDuration,  
  PlanCurrency ,
  BillingMethod 
  --CreatedDate   ,        
  --LastModifiedDate ,        
  --CreatedBy        
                
   )                
 VALUES                
   (                
  @PlanName ,        
  @IssystemDefine,        
  @PlanCost,         
  @CountryId,        
  @DemoDays,         
  @MaxDemoExtension,        
  @IsActive ,      
  @IsPlanPublish,     
  @PlanDuration,  
  @PlanCurrency ,
  @BillingMethod 
   )                          
  End      
 Else      
 Begin      
       
 UPDATE [dbo].[Price_ServiceMaster]      
   SET [PlanName] = @PlanName      
      ,[PlanCost] = @PlanCost      
      ,[IsSystemDefine] = @IssystemDefine      
      ,[CountryId] = @CountryId      
      ,[DemoDays] = @DemoDays      
      ,[IsActive] = @IsActive      
      ,[MaxDemoExtension] = @MaxDemoExtension      
      ,[IsPlanPublish] = @IsPlanPublish      
      ,PlanCurrency=@PlanCurrency  
   ,PlanDuration=@PlanDuration  ,
   BillingMethod=@BillingMethod
 WHERE           
   PlanID=@PlanId      
 End        
                 
 --SELECT 'Record Saved Successfully'                
               
 SELECT SCOPE_IDENTITY() AS Price_ServiceMaster;                
              
END 



GO

/* ============================================================
   Procedure: [dbo].[Price_InsertUserSubscriptionData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Price_InsertUserSubscriptionData] --34594,3,0,1                                      
 @UserID INT ,                                        
 @PlanID INT,                          
 @IsTrailPlan int,                
 @IsKYCRequired bit  =0                                     
 AS                                        
BEGIN   
  
  Declare @ParentID bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @UserID )       
  Declare @MID_P bigint = ( select top 1 isnull(M_ID,0) from User_Detail with(nolock) where User_ID = @ParentID )       
                           
declare @pEndDate as datetime ,                             
        @pDuration as int,                            
  @planCost as decimal(18,4),                      
  @FreeCredit as decimal(18,4),                      
  @preBalance as decimal(18,4) =0,@accounttype nvarchar(50)        
  select @parentid=parentid,@accounttype=userfilter from user_detail(nolock) where user_id=@UserID                      
  select @pDuration=PlanDuration,@planCost=PlanCost from Price_ServiceMaster(nolock) where PlanID=@PlanID                           
   select @FreeCredit=[value] from Price_ServiceCategoryLink(nolock) where PlanId=@PlanID                                    
      and CategoryID=40                       
                      
   SELECT TOP 1 @preBalance= Mcd.Balance                                                                
              FROM   IntCredit_Details(nolock) AS Mcd                                                                
              WHERE  Mcd.[User_ID] = @ParentID                                                                
              ORDER  BY Mcd.Credit_ID DESC                      
  set @pEndDate= dateadd(dd,@pDuration,getdate())                            
  update  [Price_UserSubscriptionDetails] set IsNewPlan=0 where UserID=@ParentID                 
           
  declare @lsd nvarchar(100)='None',@lsp nvarchar(100)='None' ,@lsc decimal(18,2)=0               
  --alter table Price_UserSubscriptionDetails add IsKYCRequired bit               
          
          
  if exists(select 1 from [Price_UserSubscriptionDetails] with (nolock) where userid=@parentid)        
  begin        
  select top 1  @lsd= ltrim(rtrim(cast([PlanStartDate] as nvarchar)))+' to '+ltrim(rtrim(cast(planenddate as nvarchar))),        
  @lsp=ltrim(rtrim(cast(planid as nvarchar))),        
  @lsc=ltrim(rtrim(cast(cost as nvarchar))) from [Price_UserSubscriptionDetails] with (nolock) where userid=@parentid order by id desc        
  end        
                         
 INSERT INTO [dbo].[Price_UserSubscriptionDetails]                            
           ([UserID]                            
           ,[PlanId]                            
           ,[PlanStartDate]                            
           ,[PlanEndDate]                            
           ,[Cost]                          
     ,IsTrailPlan                        
  ,IsNewPlan,IsKYCRequired)                            
     VALUES                            
  (                            
  @ParentID,                            
  @PlanID,                            
  GETDATE(),                            
  @pEndDate,                            
   @planCost,                          
   @IsTrailPlan ,1,@IsKYCRequired                            
  )                        
       declare @iden as int           
    set @iden=Scope_identity()       
      
       
insert into AddCreditDetails(UserID,AccountType,Validity,Amount,Credits,DNDRefundType,FilterMode,Reason,Remarks,      
CreditAgentID,PricePerSMS,PayMode,TransactionID,CreatedDate,IsSMS,IsMail,IntCredit,CreatedBy,tax_amount,ACD_CreatedBy)      
select @parentid,@AccountType,'Unlimited',0,@FreeCredit,'NR',10,'Subscription','Free Credits with subscription',      
335,0,'','',getdate(),0,0,1,335,0,@UserID      

 INSERT INTO IntCredit_Details(ID,M_ID,FromUser_ID,[User_ID],Debits,Credits,Balance,Validity,Default_Credit,FromDate,ToDate,
 DateCreated,DateUpdated,EmpUpdated,MachineName,LastModified,typecredit,campaignid,Remarks , ICD_CreatedBy   )                        
SELECT top 1 Newid(),Ud.M_ID,  @ParentID,  @ParentID,  0,  @FreeCredit,  isnull(@preBalance,0) + @FreeCredit,  99999,  '', 
 Getdate(),  Getdate(),  Getdate(),  Getdate(),  '',  '',  Getdate(),  '',  0,'Free Credits with subscription',@UserID 
 FROM user_detail ud (nolock) where User_ID=@ParentID                      
                 
  insert into [Price_ServiceCategoryLinkUserCopyHistory] ([Value] ,[PlanId]  ,[IsActive]  ,[CategoryID]  ,[CountryId]  ,[UserId], 
 SerrviceCategoryId) 
 (select [Value]  ,[PlanId]  ,[IsActive]  ,[CategoryID]  ,[CountryId]  ,[UserId],  SerrviceCategoryId from Price_ServiceCategoryLinkUserCopy where UserId=@ParentID) 
 
 delete from Price_ServiceCategoryLinkUserCopy where UserId=@ParentID 
 insert into Price_ServiceCategoryLinkUserCopy ([Value]  ,[PlanId]  ,[IsActive]  ,[CategoryID]  ,[CountryId]  ,[UserId],  SerrviceCategoryId) 
 (select [Value] ,[PlanId]  ,[IsActive]  ,[CategoryID]  ,[CountryId]  ,@ParentID,@iden from Price_ServiceCategoryLink where PlanId=@PlanID) 
         
declare @user_login nvarchar(100),@desc nvarchar(1000)          

select @parentid=parentid,@user_login=user_login,@desc='New Subscription added for user '+user_login+' from '+          
cast(cast(getdate() as date) as nvarchar) +' to '+ cast(cast(@pEndDate as date) as nvarchar)          
 from user_detail(nolock) where user_id=@UserID          

if @userid=@parentid          
begin               
exec Usp_InsertUserEventDetails 'New subscription added for user',@userid,@desc,'Price_UserSubscriptionDetails',@iden          
end          
                   
