cast(cast(getdate() as date) as nvarchar) +' to '+ cast(cast(@pEndDate as date) as nvarchar) +') at '        
+cast(@planCost as nvarchar)+' powered by kit19'        
print @smstbs        
exec [usp_sendmessage_WithDLTTemplateID] 335,@smstbs,'7840002738,9910025912','Kitapp',0,1,'1707161918186176263'                  
                                     
  END               
              
              
