/* ============================================================
   Procedure: [dbo].[Price_RemoveUserAssignedPhone]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC Price_RemoveUserAssignedPhone      
@userId int,      
@phoneno varchar(20)      
AS       
Begin      
      
	 if(exists(select 1 from Cloud_User_Phone(nolock) where Parentid = @userId and PhoneNo=@phoneno and ((isnull(Status,'') = '') or ( isnull(Status,'') = 'Rejected') )))
	  Begin

		insert into [Cloud_User_Phone_History] (      
		[Parentid] ,[PhoneNo] , [PurchaseDt] ,      
		 [AppId],[Phonecost] ,[Gst] ,[Totalamount] , [Active] ,InsertDate      
		)      
		select @userId ,[PhoneNo] , [PurchaseDt] ,      
		 [AppId],[Phonecost] ,[Gst] ,[Totalamount] , [Active],GetDate()  from Cloud_User_Phone where parentid=@userid and PhoneNo=@phoneNo      
     
		 update cloud_phone_master set free=1 where PhoneNo=@phoneNo     
		delete from Cloud_User_Phone where parentid=@userid and PhoneNo=@phoneNo      
      
	  End
	 else
	  Begin
	  
	     select 'Sorry this phone no is already engaged in mobile no mapping, please make it free from mapping'   

	  end 
	  

End      
--select [userphid] [bigint],[Parentid] ,[PhoneNo] , [PurchaseDt] ,      
-- [AppId],[Phonecost] ,[Gst] ,[Totalamount] , [Active] 


GO

/* ============================================================
   Procedure: [dbo].[Price_SP_Get_subscription_Admin]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Price_SP_Get_subscription_Admin]                  
(                  
              
--@fmdate datetime,        
--@todate datetime,        
@searchtxt varchar(100)  =''      
                
)                  
as                  
begin                  
        
--select sb.*,um.User_login,pm.*, (select COUNT(*) from User_Detail where Parentid = um.ParentID          
-- and Cloudrole=1) no_user,          
--(select COUNT(*) from dbo.Cloud_User_Phone where Parentid = um.ParentID) no_phone,          
-- dbo.Cloud_Phone_string(um.ParentID) Phone_no into #tmpfl          
-- from Cloud_user_subscription sb                
-- inner join dbo.User_Detail um                
-- on um.User_id = sb.Parentid                
-- inner join dbo.Cloud_plan_master pm                
-- on pm.planid = sb.plan_id           
 --where  Cloudrole=1 and        
 --  CONVERT(date,TransDate) between CONVERT(date,@fmdate) and CONVERT(date,@todate)                  
        
select sb.*,um.User_Login,pm.PlanName into #tmpfl          
 from Price_UserSubscriptionDetails sb                
 inner join dbo.User_Detail um                
 on um.User_id = sb.UserID and sb.IsNewPlan=1 and um.M_ID=10043 --and um.User_ID < 700             
 inner join dbo.Price_ServiceMaster pm                
 on pm.planid = sb.PlanId           
      
 if  @searchtxt =''          
 select * from #tmpfl  order by user_login             
 else          
 select * from #tmpfl            
 where (User_login like '%'+@searchtxt+'%'          
 or PlanName like '%'+@searchtxt+'%'          
)          
  order by user_login     
--or CONVERT(date,valid_to) like '%'+@searchtxt+'%')          
--order by PlanName        
            
drop table #tmpfl             
        
end 


GO

