/* ============================================================
   Procedure: [dbo].[Price_UpdateServicePriceDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
  --select ParentID,* from user_detail where mobile='8871212639'        
  --select * from Price_Base_SMS_Rate_Exception  where origincountryid=110 and pcritical <>0      
 -- select * from [Price_Base_Voice_Rate_Exception]  where origincountryid=110 and pcritical <>0      
CREATE   PROCEDURE [dbo].[Price_UpdateServicePriceDetails]                
(              
@userid int,              
@type nvarchar(20),              
@PTrns decimal(18,4),        
@PPromo decimal(18,4),        
@PCritical decimal(18,4),        
@PTrnsScurb decimal(18,4),        
@destinationCountryId int,              
@isExceptionEntry int,            
@currencyCountryID int,            
@originCountryId int,         
@LocalRTrns  decimal(18,4),        
@STDRTrns  decimal(18,4),        
@ISDRTrns  decimal(18,4),         
@LocalRPromo  decimal(18,4),        
@STDRPromo  decimal(18,4),        
@ISDRPromo  decimal(18,4),        
@LocalRCritical  decimal(18,4),        
@STDRCritical  decimal(18,4),        
@ISDRCritical  decimal(18,4),        
@LocalRTrnsScurb  decimal(18,4),        
@STDRTrnsScurb  decimal(18,4),        
@ISDRTrnsScurb  decimal(18,4)        
        
)                
AS                  
BEGIN                
              
if (@type='sms')              
BEGIN               
if(@isExceptionEntry = 0)               
       update Price_Base_SMS_Rate set        
         PTrns=@PTrns,PPromo=@PPromo,PCritical=@PCritical,PTrnsScurb=@PTrnsScurb    
      where              
         DestinationCountryId=@destinationCountryId         
   and OriginCountryId=@OriginCountryId      
                
else          
Begin      
 if Not Exists(select 1 from Price_Base_SMS_Rate_Exception where UserID=@userid and DestinationCountryId=@destinationCountryId and OriginCountryId=@OriginCountryId )                  
 begin      
 insert into Price_Base_SMS_Rate_Exception (PTrns,PPromo,PCritical,PTrnsScurb,        
      CurrencyCountryId,DestinationCountryId,OriginCountryId, UserID,OriginCountryCode,DestinationCountryCode )      
 select PTrns,PPromo,PCritical,PTrnsScurb,CurrencyCountryId,DestinationCountryId,OriginCountryId,@userid,OriginCountryCode,DestinationCountryCode     
 from Price_Base_SMS_Rate where DestinationCountryId=@destinationCountryId and OriginCountryId=@originCountryId         
end        
 update Price_Base_SMS_Rate_Exception set PTrns=@PTrns,PPromo=@PPromo,PCritical=@PCritical,PTrnsScurb=@PTrnsScurb    
       where OriginCountryId=@originCountryId and              
       DestinationCountryId=@destinationCountryId and UserID=@userid       
END      
        
END-- SMS              
else if (@type='mail')              
BEGIN               
if(@isExceptionEntry = 0)             
BEGIN            
  if Exists(select 1 from [Price_Base_Mail_Rate] where OriginCountryId=@originCountryId)              
       update Price_Base_Mail_Rate set Price=@PTrns,CurrencyCountryId= @currencyCountryID where              
           OriginCountryId=@originCountryId               
  else            
       insert into Price_Base_Mail_Rate (Price,OriginCountryId,CurrencyCountryId)            
     values (@PTrns,@originCountryId,@currencyCountryID)            
END            
ELSE                
  BEGIN            
  if Exists(select 1 from [Price_Base_Mail_Rate_Exception] where UserID=@userid and OriginCountryId=@OriginCountryId)                
      update Price_Base_Mail_Rate_Exception set Price=@PTrns where              
            OriginCountryId=@originCountryId and UserID=@userid                 
  else            
    insert into Price_Base_Mail_Rate_Exception(UserID,Price,OriginCountryId,CurrencyCountryId)            
       values (@userid,@PTrns,@originCountryId,@currencyCountryID)            
  END            
END -- Mail              
              
else if (@type='voice')              
BEGIN               
if(@isExceptionEntry = 0)             
BEGIN            
    update [Price_Base_Voice_Rate] set         
    LocalRTrns=@LocalRTrns,STDRTrns=@STDRTrns,ISDRTrns=@ISDRTrns,        
    LocalRPromo=@LocalRPromo,STDRPromo=@STDRPromo,ISDRPromo=@ISDRPromo,LocalRCritical=@LocalRCritical,STDRCritical=@STDRCritical        
    ,ISDRCritical=@ISDRCritical,LocalRTrnsScurb=@LocalRTrnsScurb,STDRTrnsScurb=@STDRTrnsScurb,ISDRTrnsScurb=@ISDRTrnsScurb        
    where DestinationCountryId=@destinationCountryId  and OriginCountryId=@OriginCountryId               
END            
ELSE                
  BEGIN            
  if Not Exists(select 1 from [Price_Base_Voice_Rate_Exception] where UserID=@userid and DestinationCountryId=@destinationCountryId and OriginCountryId=@OriginCountryId)              
   begin      
        
     insert into [Price_Base_Voice_Rate_Exception] (UserID,LocalRTrns,STDRTrns,ISDRTrns,        
    LocalRPromo,STDRPromo,ISDRPromo,LocalRCritical,STDRCritical        
   ,ISDRCritical,LocalRTrnsScurb,STDRTrnsScurb,ISDRTrnsScurb,OriginCountryId,currencyCountryID,DestinationCountryId)            
     values (@userid,@LocalRTrns,@STDRTrns,@ISDRTrns,        
  @LocalRPromo,@STDRPromo,@ISDRPromo,@LocalRCritical,@STDRCritical,@ISDRCritical,        
  @LocalRTrnsScurb,@STDRTrnsScurb,@ISDRTrnsScurb,@originCountryId,@currencyCountryID,@destinationCountryId)            
    
       
   end      
    update [Price_Base_Voice_Rate_Exception] set           
       LocalRTrns=@LocalRTrns,STDRTrns=@STDRTrns,ISDRTrns=@ISDRTrns,        
       LocalRPromo=@LocalRPromo,STDRPromo=@STDRPromo,ISDRPromo=@ISDRPromo,LocalRCritical=@LocalRCritical,STDRCritical=@STDRCritical        
      ,ISDRCritical=@ISDRCritical,LocalRTrnsScurb=@LocalRTrnsScurb,STDRTrnsScurb=@STDRTrnsScurb,ISDRTrnsScurb=@ISDRTrnsScurb        
                 
       where OriginCountryId=@originCountryId and DestinationCountryId=@destinationCountryId and UserID=@userid               
       
 end          
END -- voice              
          
else if (@type='webform')              
BEGIN               
if(@isExceptionEntry = 0)             
BEGIN            
  if Exists(select 1 from [Price_Base_WebForm_Rate] where UserID=@userid and OriginCountryId=@originCountryId)              
       update [Price_Base_WebForm_Rate] set Price=@PTrns,CurrencyCountryId= @currencyCountryID where              
   OriginCountryId=@originCountryId and UserID=@userid               
  else            
       insert into [Price_Base_WebForm_Rate] (Price,OriginCountryId,CurrencyCountryId)            
     values (@PTrns,@originCountryId,@currencyCountryID)            
END            
ELSE                
  BEGIN            
  if Exists(select 1 from [Price_Base_WebForm_Rate_Exception] where UserID=@userid and OriginCountryId=@OriginCountryId)                
      update [Price_Base_WebForm_Rate_Exception] set Price=@PTrns where              
            OriginCountryId=@originCountryId and UserID=@userid               
  else            
    insert into [Price_Base_WebForm_Rate_Exception](UserID,Price,OriginCountryId,CurrencyCountryId)            
       values (@userid,@PTrns,@originCountryId,@currencyCountryID)            
  END            
END -- Mail           
          
else if (@type='landingpage')              
BEGIN               
if(@isExceptionEntry = 0)             
BEGIN            
  if Exists(select 1 from [Price_Base_LandingPage_Rate] where UserID=@userid and OriginCountryId=@originCountryId)              
       update [Price_Base_LandingPage_Rate] set Price=@PTrns,CurrencyCountryId= @currencyCountryID where              
           OriginCountryId=@originCountryId             
  else            
       insert into [Price_Base_LandingPage_Rate] (UserID,Price,OriginCountryId,CurrencyCountryId)            
     values (@userid,@PTrns,@originCountryId,@currencyCountryID)            
END            
ELSE                
  BEGIN            
  if Exists(select 1 from [Price_Base_LandingPage_Rate_Exception] where UserID=@userid and OriginCountryId=@OriginCountryId)                
      update [Price_Base_LandingPage_Rate_Exception] set Price=@PTrns where              
            OriginCountryId=@originCountryId and UserID=@userid               
  else   
    insert into [Price_Base_LandingPage_Rate_Exception](UserID,Price,OriginCountryId,CurrencyCountryId)            
       values (@userid,@PTrns,@originCountryId,@currencyCountryID)            
  END            
END -- landingpage           
else if (@type='user')              
BEGIN               
if(@isExceptionEntry = 0)             
BEGIN            
  if Exists(select 1 from [Price_Base_Users_Rate] where UserID=@userid and OriginCountryId=@originCountryId)              
       update [Price_Base_Users_Rate] set Price=@PTrns,CurrencyCountryId= @currencyCountryID where              
           OriginCountryId=@originCountryId                
  else            
       insert into [Price_Base_Users_Rate] (Price,OriginCountryId,CurrencyCountryId)            
     values (@PTrns,@originCountryId,@currencyCountryID)            
END            
ELSE                
  BEGIN            
  if Exists(select 1 from [Price_Base_Users_Rate_Exception] where UserID=@userid and OriginCountryId=@originCountryId)                
      update [Price_Base_Users_Rate_Exception] set Price=@PTrns where              
            OriginCountryId=@originCountryId and UserID=@userid               
  else            
    insert into [Price_Base_Users_Rate_Exception](UserID,Price,OriginCountryId,CurrencyCountryId)            
       values (@userid,@PTrns,@originCountryId,@currencyCountryID)            
  END            
END -- user           
else if (@type='phoneno')              
BEGIN               
if(@isExceptionEntry = 0)             
BEGIN            
  if Exists(select 1 from Price_Base_PhoneNo_Rate where UserID=@userid and OriginCountryId=@originCountryId)              
       update Price_Base_PhoneNo_Rate set Price=@PTrns,CurrencyCountryId= @currencyCountryID where              
           OriginCountryId=@originCountryId                
  else            
       insert into Price_Base_PhoneNo_Rate (Price,OriginCountryId,CurrencyCountryId)            
     values (@PTrns,@originCountryId,@currencyCountryID)            
END            
ELSE                
  BEGIN            
  if Exists(select 1 from Price_Base_PhoneNo_Rate_Exception where UserID=@userid and OriginCountryId=@originCountryId)                
      update Price_Base_PhoneNo_Rate_Exception set Price=@PTrns where              
            OriginCountryId=@originCountryId and UserID=@userid               
  else            
    insert into Price_Base_PhoneNo_Rate_Exception(UserID,Price,OriginCountryId,CurrencyCountryId)            
       values (@userid,@PTrns,@originCountryId,@currencyCountryID)            
  END            
END -- phoneno           
 else if (@type='smslink')              
BEGIN               
if(@isExceptionEntry = 0)             
BEGIN            
  if Exists(select 1 from [Price_Base_SMSLink_Rate] where UserID=@userid and OriginCountryId=@originCountryId)              
       update [Price_Base_SMSLink_Rate] set Price=@PTrns,CurrencyCountryId= @currencyCountryID where              
   OriginCountryId=@originCountryId and UserID=@userid               
  else            
       insert into [Price_Base_SMSLink_Rate] (Price,OriginCountryId,CurrencyCountryId)            
     values (@PTrns,@originCountryId,@currencyCountryID)            
END            
ELSE                
  BEGIN            
  if Exists(select 1 from [Price_Base_SMSLink_Rate_Exception] where UserID=@userid and OriginCountryId=@OriginCountryId)                
      update [Price_Base_SMSLink_Rate_Exception] set Price=@PTrns where              
            OriginCountryId=@originCountryId and UserID=@userid               
  else            
    insert into [Price_Base_SMSLink_Rate_Exception](UserID,Price,OriginCountryId,CurrencyCountryId)            
       values (@userid,@PTrns,@originCountryId,@currencyCountryID)            
  END            
END -- smslink            
END     
    
--select * from [Price_Base_Voice_Rate_Exception]    
--select * from Price_Base_Voice_Rate 


