   Procedure: [dbo].[Price_UpdateServicePriceDetailsForPhone]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
  --select ParentID,* from user_detail where mobile='8871212639'        
  --select * from Price_Base_SMS_Rate_Exception  where origincountryid=110 and pcritical <>0      
 -- select * from [Price_Base_Voice_Rate_Exception]  where origincountryid=110 and pcritical <>0      
CREATE   PROCEDURE [dbo].[Price_UpdateServicePriceDetailsForPhone]                
(              
@userid int,              
@isExceptionEntry int,            
@currencyCountryID int,            
@originCountryId int,         
 @NormalNormalOneTime decimal(18,4)
,@NormalLandLineOneTime decimal(18,4)
,@NormalTollFreeOneTime decimal(18,4)
,@VIPNormalOneTime decimal(18,4)
,@VIPLandLineOneTime decimal(18,4)
,@VIPTollFreeOneTime decimal(18,4)
,@VVIPLandLineOneTime decimal(18,4)
,@VVIPTollFreeOneTime decimal(18,4)
,@VVIPNormalOneTime decimal(18,4) 
,@NormalNormalMonth decimal(18,4)
,@NormalLandLineMonth decimal(18,4)
,@NormalTollFreeMonth decimal(18,4)
,@VIPNormalMonth decimal(18,4)
,@VIPLandLineMonth decimal(18,4)
,@VIPTollFreeMonth decimal(18,4)
,@VVIPLandLineMonth decimal(18,4)
,@VVIPTollFreeMonth decimal(18,4)
,@VVIPNormalMonth decimal(18,4)


   
)                
AS                  
BEGIN                
              
        
if(@isExceptionEntry = 0)             
BEGIN  

delete from Price_Base_PhoneNo_Rate where OriginCountryId=@originCountryId           
        
 insert into Price_Base_PhoneNo_Rate ([OriginCountryId]
,[CurrencyCountryId],[NormalNormalOneTime]
,[NormalLandLineOneTime],[NormalTollFreeOneTime]
,[VIPNormalOneTime],[VIPLandLineOneTime],[VIPTollFreeOneTime],[VVIPLandLineMonth],
 [VVIPTollFreeMonth],[VVIPNormalMonth],[VIPNormalMonth],[VIPLandLineMonth],[VIPTollFreeMonth],
 [NormalNormalMonth],[NormalLandLineMonth],[NormalTollFreeMonth],[VVIPLandLineOneTime],
 [VVIPTollFreeOneTime],[VVIPNormalOneTime])            
     values (@originCountryId,
	        @currencyCountryID
	       ,@NormalNormalOneTime
           ,@NormalLandLineOneTime
           ,@NormalTollFreeOneTime
           ,@VIPNormalOneTime
           ,@VIPLandLineOneTime
           ,@VIPTollFreeOneTime
           ,@VVIPLandLineMonth
           ,@VVIPTollFreeMonth
           ,@VVIPNormalMonth
           ,@VIPNormalMonth
           ,@VIPLandLineMonth
           ,@VIPTollFreeMonth
           ,@NormalNormalMonth
           ,@NormalLandLineMonth
           ,@NormalTollFreeMonth
           ,@VVIPLandLineOneTime
           ,@VVIPTollFreeOneTime
           ,@VVIPNormalOneTime
	 )
END            
ELSE                
  BEGIN            
  delete from Price_Base_PhoneNo_Rate_Exception where OriginCountryId=@originCountryId  and userid=@userid         
        
 insert into Price_Base_PhoneNo_Rate_Exception ([OriginCountryId]
,[CurrencyCountryId],[NormalNormalOneTime]
,[NormalLandLineOneTime],[NormalTollFreeOneTime]
,[VIPNormalOneTime],[VIPLandLineOneTime],[VIPTollFreeOneTime],[VVIPLandLineMonth],
 [VVIPTollFreeMonth],[VVIPNormalMonth],[VIPNormalMonth],[VIPLandLineMonth],[VIPTollFreeMonth],
 [NormalNormalMonth],[NormalLandLineMonth],[NormalTollFreeMonth],[VVIPLandLineOneTime],
 [VVIPTollFreeOneTime],[VVIPNormalOneTime],Userid)            
     values (@originCountryId,
	        @currencyCountryID
	       ,@NormalNormalOneTime
           ,@NormalLandLineOneTime
           ,@NormalTollFreeOneTime
           ,@VIPNormalOneTime
           ,@VIPLandLineOneTime
           ,@VIPTollFreeOneTime
           ,@VVIPLandLineMonth
           ,@VVIPTollFreeMonth
           ,@VVIPNormalMonth
           ,@VIPNormalMonth
           ,@VIPLandLineMonth
           ,@VIPTollFreeMonth
           ,@NormalNormalMonth
           ,@NormalLandLineMonth
           ,@NormalTollFreeMonth
           ,@VVIPLandLineOneTime
           ,@VVIPTollFreeOneTime
           ,@VVIPNormalOneTime,@userid
	 )
END -- phoneno           
END
 


GO

/* ============================================================
   Procedure: [dbo].[Price_UpdateUserPlan]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext Price_UpdateUserPlan        
        
CREATE   PROCEDURE [dbo].Price_UpdateUserPlan                         
(                        
@UserID as bigint,        
@ValidTo as datetime,        
@nouser as int,        
@nolandpage as int,        
@nowebform as int,        
@N1 as int,        
@N2 as int,        
@N3 as int,        
@V1 as int,        
@V2 as int,        
@V3 as int,        
@VV1 as int,        
@VV2 as int,        
@VV3 as int,      
@Lead as int,      
@eshop as int                        
)                        
                            
AS                            
BEGIN                        
        
--update Price_History_ChangePlan set isActive=0 where userid=@userid        
Declare @oldvalue as int =0,@categoryid as int,@nvalue as int,@parentid bigint        
select @parentid=parentid from user_detail(nolock) where user_id=@UserID        
set @categoryid=42 --user        
set @nvalue =@nouser         
select @oldvalue=[dbo].fn_price_checkvalue(@categoryid,@parentid)        
if(@oldvalue = -1)        
update Price_History_ChangePlan set oldValue=newvalue,newvalue=@nvalue where userid=@parentid and CategoryID=@categoryid        
else         
insert into Price_History_ChangePlan (oldValue,newvalue,UserID,CategoryID)        
select @oldvalue,@nvalue,@parentid,@categoryid         
update Price_ServiceCategoryLinkUserCopy set value=@nvalue where userid=@parentid and CategoryID=@categoryid        
        
set @categoryid=30 --landing        
set @nvalue =@nolandpage         
select @oldvalue=[dbo].fn_price_checkvalue(@categoryid,@parentid)        
if(@oldvalue = -1)        
update Price_History_ChangePlan set oldValue=newvalue,newvalue=@nvalue where userid=@parentid and CategoryID=@categoryid        
else         
insert into Price_History_ChangePlan (oldValue,newvalue,UserID,CategoryID)        
select @oldvalue,@nvalue,@parentid,@categoryid         
update Price_ServiceCategoryLinkUserCopy set value=@nvalue where userid=@parentid and CategoryID=@categoryid        
        
set @categoryid=29 --webform        
set @nvalue =@nowebform        
select @oldvalue=[dbo].fn_price_checkvalue(@categoryid,@parentid)        
if(@oldvalue = -1)        
update Price_History_ChangePlan set oldValue=newvalue,newvalue=@nvalue where userid=@parentid and CategoryID=@categoryid        
else         
insert into Price_History_ChangePlan (oldValue,newvalue,UserID,CategoryID)        
select @oldvalue,@nvalue,@parentid,@categoryid         
update Price_ServiceCategoryLinkUserCopy set value=@nvalue where userid=@parentid and CategoryID=@categoryid        
        
set @categoryid=43 --normal        
set @nvalue =@N1         
select @oldvalue=[dbo].fn_price_checkvalue(@categoryid,@parentid)        
if(@oldvalue = -1)        
update Price_History_ChangePlan set oldValue=newvalue,newvalue=@nvalue where userid=@parentid and CategoryID=@categoryid        
else         
insert into Price_History_ChangePlan (oldValue,newvalue,UserID,CategoryID)        
select @oldvalue,@nvalue,@parentid,@categoryid         
update Price_ServiceCategoryLinkUserCopy set value=@nvalue where userid=@parentid and CategoryID=@categoryid        
        
        
        
set @categoryid=44 --normal        
set @nvalue =@N2         
select @oldvalue=[dbo].fn_price_checkvalue(@categoryid,@parentid)        
if(@oldvalue = -1)        
update Price_History_ChangePlan set oldValue=newvalue,newvalue=@nvalue where userid=@parentid and CategoryID=@categoryid        
else         
insert into Price_History_ChangePlan (oldValue,newvalue,UserID,CategoryID)        
select @oldvalue,@nvalue,@parentid,@categoryid         
update Price_ServiceCategoryLinkUserCopy set value=@nvalue where userid=@parentid and CategoryID=@categoryid        
        
set @categoryid=45 --normal        
set @nvalue =@N3         
select @oldvalue=[dbo].fn_price_checkvalue(@categoryid,@parentid)        
if(@oldvalue = -1)        
update Price_History_ChangePlan set oldValue=newvalue,newvalue=@nvalue where userid=@parentid and CategoryID=@categoryid        
else        
insert into Price_History_ChangePlan (oldValue,newvalue,UserID,CategoryID)        
select @oldvalue,@nvalue,@parentid,@categoryid         
update Price_ServiceCategoryLinkUserCopy set value=@nvalue where userid=@parentid and CategoryID=@categoryid        
        
set @categoryid=46 --VIP        
set @nvalue =@V1         
select @oldvalue=[dbo].fn_price_checkvalue(@categoryid,@parentid)        
if(@oldvalue = -1)        
update Price_History_ChangePlan set oldValue=newvalue,newvalue=@nvalue where userid=@parentid and CategoryID=@categoryid        
else         
