/* ============================================================
   Procedure: [dbo].[Price_UserPriceForPhoneNo]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
  
CREATE   PROC [dbo].Price_UserPriceForPhoneNo --335    
(    
@userId int    
)      
as     
begin  
declare  @OriginCountryID as int  
 select @OriginCountryID=Country_ID from user_detail(nolock) where USER_ID=@userId                                
 if(@OriginCountryID =110)  
  set @OriginCountryID=101  
  declare @planEndCount as int,@planEndDate as datetime,@enddatediff as int  
  select @planEndDate= PlanEndDate from Price_UserSubscriptionDetails(nolock) where UserID=@userId and IsNewPlan=1  
  set @planEndCount = DATEDIFF(d,GetDate(),@planEndDate)  
  
  set @enddatediff=DATEDIFF(MONTH, GetDate(), @planEndDate)   
  
  if(@planEndCount % @enddatediff <> 0)  
   set @enddatediff =@enddatediff +1  
  
if exists(select 1 from Price_Base_PhoneNo_Rate_Exception(nolock) where USERID = @userid  and OriginCountryid=@OriginCountryID )  
select *,@enddatediff enddateCount from dbo.Price_Base_Phone_Rate_Exception(nolock) where USERID = @userid                                        
      and OriginCountryid=@OriginCountryID                                  
else                              
   select *,@enddatediff enddateCount from Price_Base_PhoneNo_Rate(nolock) where                                      
       OriginCountryid=@OriginCountryID                         
   
   
end   
  


GO

