/* ============================================================
   Procedure: [dbo].[proc_DeleteMailIDRecord]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.proc_DeleteMailIDRecord @mid BIGINT
	,@uid INT
	,-- from bigint        
	@MailID VARCHAR(200)
AS
BEGIN
	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM FromMailIDDetails
			WHERE Mail_ID = @MailID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	DELETE
	FROM FromMailIDDetails
	WHERE m_id = @mid
		AND user_id = @uid
		AND Mail_ID = @MailID

	--added by vinay to delete senderID from Default_SenderID if senderid deleted    
	--created date:- 12-03-2010    
	DELETE
	FROM DefaultMailID
	WHERE Mail_ID = @MailID
		AND M_ID = @mid
		AND User_ID = @uid

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @uid
		,@Activity_type = 'Delt_Mailid'
		,@ActionType = 'D'
		,@RowJson = @rowJson
		,@Table_name = 'FromMailIDDetails'
END



GO

