@mid bigint,                
@uid bigint                
as         
            
   Declare @ParentID bigint = 0      
   Declare @MID_P bigint = 0      
   Select top 1  @ParentID = isnull(ParentID,0) from User_detail with(nolock) where User_ID = @uid and M_ID = @mid       
  Select  @MID_P = isnull(M_ID,0)  from User_detail with(nolock) where User_ID = @ParentID        
            
select top 1 Balance,Validity from credit_details(nolock) where m_id=@MID_P and User_id=@ParentID order by credit_id desc 


