   Procedure: [dbo].[proc_DisplayMailIDDetailsFilter]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


  
CREATE   PROC dbo.proc_DisplayMailIDDetailsFilter --10001,335,'0'                
 @mid BIGINT  
 ,-- from nvarchar(15),                      
 @uid INT  
 ,-- from nvarchar(15),                  
 @status NVARCHAR(50),  
 @mailid nvarchar(max) = null  
AS  
DECLARE @ErrNo INT  
 ,@Query VARCHAR(2000)  
 ,@whereClause VARCHAR(500)  
 ,@operator VARCHAR(10)  
  
SET NOCOUNT OFF  
  
BEGIN TRANSACTION  
  
SET @whereClause = ''  
  
IF @status = 'All'  
BEGIN  
 SET @whereClause = @whereClause + ' 1=1 '  
 SET @ErrNo = @@error  
END  
ELSE  
BEGIN  
 SET @whereClause = @whereClause + ' Status =''' + @status + ''' '  
 SET @ErrNo = @@error  
END  
  
IF @mailid IS NOT NULL  
begin  
 SET @whereClause = @whereClause + ' and Mail_ID LIKE ''%'+@mailid+'%'' '  
end  
--select Sender_Id,m_id,user_id,Sender_Name as SenderName,Type,case Status when 0 then 'Pending' when 1 then 'Approved' end as CurrentStatus from                       
--SenderID_Detail where m_id=@mid and user_id=@uid                    
--set @Query='select Sender_Id,m_id,user_id,Sender_Name as SenderName,Type,case Status when 0 then ''Pending--'' when 1 then ''Approved'' end as CurrentStatus from SenderID_Detail                   
--where m_id='+Convert(varchar,@mid,10)+' and user_id='+convert(varchar,@uid,10)+' and  '+@whereClause+'order by convert(nvarchar,convert(datetime,datecreated,104),112) '              
SET @Query = 'select Mail_ID,m_id,user_id,Type,[key],case Status when 0 then ''Pending'' when 1 then ''Approved'' when 2 then ''Rejected'' when 3 then ''SentForApproval''  end as CurrentStatus ,Case Processed  when 0 then ''No'' when 1 then ''Yes'' end as
  
 Processed , isnull(displayName,'''') + '' &lt; '' + isnull(Mail_ID,'''') + '' &gt; '' as DisplayName   from FromMailIDDetails (nolock)                  
where m_id=' + Convert(VARCHAR, @mid, 10) + ' and user_id=' + convert(VARCHAR, @uid, 10) + ' and  ' + @whereClause + 'order by convert(nvarchar,convert(datetime,datecreated,104),112) desc '  
  
PRINT @Query  
  
EXEC (@Query)  
  
IF @ErrNo = 0  
BEGIN  
 COMMIT TRANSACTION  
  
 SET NOCOUNT ON  
  
 RETURN 0  
END  
ELSE  
BEGIN  
 ROLLBACK TRANSACTION  
  
 SET NOCOUNT ON  
  
 RETURN @ErrNo  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @uid  
  ,@Activity_type = 'View_Mail'  
  ,@ActionType = 'S'  
  ,@RowJson = ''  
  ,@Table_name = 'FromMailIDDetails'  
END  


GO

