/* ============================================================
   Procedure: [dbo].[proc_displaySenderNameOfGSMType_DLT]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.proc_displaySenderNameOfGSMType_DLT --10043, 42716   --10043,21977                  
  @m_id BIGINT    
 ,@user_id BIGINT -- frm big int 19-08-2010              
AS    
DECLARE @ParentId BIGINT = 0;    
DECLARE @IsAdmin BIT = 0;    
DECLARE @RoleType VARCHAR(10);    
DECLARE @TeamCode VARCHAR(20)    
    
SELECT @ParentId = ParentID    
 ,@IsAdmin = IsAdmin    
FROM User_Detail(NOLOCK)    
WHERE User_ID = @user_id;    
  
  
  set @user_id = @ParentId  
  
    
IF object_id('tempdb..#tblUserIds') IS NOT NULL    
BEGIN    
 DROP TABLE #tblUserIds    
END    
    
CREATE TABLE #tblUserIds (UserId BIGINT NOT NULL)    
    
SELECT @TeamCode = tum.TeamCode    
FROM TBL_UA_TeamUserMappingMaster(NOLOCK) tum    
INNER JOIN TBL_UA_TeamMaster(NOLOCK) tm ON tm.TeamCode = tum.TeamCode    
WHERE tum.UserId = @user_id    
    
IF (    
  (@TeamCode IS NULL)    
  AND (    
   @ParentId = @user_id    
   OR @IsAdmin = 1    
   )    
  )    
BEGIN    
 --set @RoleType = 'Global'        
 INSERT INTO #tblUserIds (UserId)    
 SELECT User_Id UserId    
 FROM User_Detail(NOLOCK)    
 WHERE ParentId = @ParentId    
END    
ELSE IF (@TeamCode != NULL)    
BEGIN    
 ---set @RoleType = 'Team'        
 INSERT INTO #tblUserIds (UserId)    
 SELECT UserId    
 FROM TBL_UA_TeamUserMappingMaster(NOLOCK)    
 WHERE TeamCode = @TeamCode    
END    
ELSE    
BEGIN    
 --set @RoleType = 'User'        
 INSERT INTO #tblUserIds (UserId)    
 SELECT  @user_id    
END    
    
IF (    
  EXISTS (    
   SELECT Sender_ID    
    ,Sender_Name    
   FROM SenderID_Detail(NOLOCK)    
   WHERE type = 'GSM'    
    AND STATUS = 1    
    AND m_id = @m_id    
    AND user_id IN (    
     SELECT UserId    
     FROM #tblUserIds    
     )    
   )    
  )    
BEGIN    
 SELECT Sender_ID    
  ,Sender_Name    
 FROM (    
  SELECT DISTINCT ROW_NUMBER() OVER (    
    PARTITION BY Sender_Name ORDER BY Sender_Name    
    ) row_num    
   ,Sender_ID    
   ,Sender_Name    
  FROM SenderID_Detail(NOLOCK)    
  WHERE type = 'GSM'    
   AND STATUS = 1    
   AND m_id = @m_id    
   AND user_id IN (    
    SELECT UserId    
    FROM #tblUserIds    
    )
	
	and  1 =
	        (
			  case when User_ID = 335
	             then 1
		       when  isnull(User_ID,0) <> 335 and Sender_Name = 'TXTSMS' 
			       then 
				        0
              else 
			      1
              end
			 )  


  ) t    
 WHERE row_num = 1    
    
 --select distinct Sender_ID,Sender_Name from SenderID_Detail(nolock) where type='GSM'             
 --and status=1 and m_id=@m_id and user_id in (select UserId From #tblUserIds)        
 ----And Airtel = 1          
END    
  --else          
  -- Begin          
  --      select 1 as Sender_ID  , 'TXTSMS' as Sender_Name          
  -- End 


GO

