SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[proc_ExportPrvMessage] --'1','01/06/2009'  
@uid bigint,  
@datecreated nvarchar(50),  
@senderID varchar(50)  
as  
if(@senderID!='Select')  
begin  
select [From],[To],Message,MsgCount,NoOfPeople,Delivery_Status,Mode,Sender_ID,DateCreated from sentmsgBackUp where user_id=@uid and convert(varchar(50), convert(datetime,datecreated),103)=@datecreated and sender_id=@senderID order by dateCreated  
end  
else  
begin  
select [From],[To],Message,MsgCount,NoOfPeople,Delivery_Status,Mode,Sender_ID,DateCreated from sentmsgBackUp where user_id=@uid and convert(varchar(50), convert(datetime,datecreated),103)=@datecreated order by dateCreated  
end




