/* ============================================================
   Procedure: [dbo].[proc_find_pels]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC proc_find_pels
as
declare @One nvarchar(200),@Two nvarchar(200),@Three nvarchar(200),@Four nvarchar(200),@Five nvarchar(200),@Total nvarchar(200)
select @One=count(MOBILE) from messagedeliverystatustemp(NOLOCK) where len(message)<=160 and account='pels'
select @Two=count(MOBILE) from messagedeliverystatustemp(NOLOCK) where len(message)>160 and len(message)<=306 and account='pels'
select @Three=count(MOBILE) from messagedeliverystatustemp(NOLOCK) where len(message)>306 and len(message)<=459 and account='pels'
select @Four=count(MOBILE) from messagedeliverystatustemp(NOLOCK) where len(message)>459 and len(message)<=612 and account='pels'
select @Five=count(MOBILE) from messagedeliverystatustemp(NOLOCK) where len(message)>612 and len(message)<=765 and account='pels'
select cast(@One as int) as Single
select cast(@Two as int) as 'Double'
select cast(@Three as int) as Triple
select cast(@Four as int) as Four_Time
select cast(@Five as int) as Five_Time
select @Total=cast(@One as int)+cast(@Two as int)*2+cast(@Three as int)*3+cast(@Four as int)*4+cast(@Five as int)*5
select @Total as 'Sent'
select(725295-@Total) as Balance


GO

