SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[proc_findEmail]      
@M_ID bigint,      
@User_ID int, ---bigint,      
@Group_ID bigint      
as 
select * into #Contact_Detail  from Contact_Detail where USER_ID=@User_ID 
select * into #Contact_Group_Detail  from Contact_Group_Detail where USER_ID=@User_ID
select distinct cd.contact_name,cd.contact_mobile,cd.Contact_Email from #Contact_Detail cd left join #Contact_Group_Detail cgd on cd.contact_id=cgd.contact_id and cd.m_id=cgd.m_id and cd.user_id=cgd.user_id where cgd.group_id=@Group_ID      
and cgd.M_ID=@M_ID and cgd.User_ID=@User_ID 




GO

