/* ============================================================
   Procedure: [dbo].[proc_FindTheallRecords]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
  
    
---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
  
    
    
--modified by vinay 15 june 2009        
CREATE   PROC [dbo].[proc_FindTheallRecords] --10001,335,'Select','','',''    
(    
@mid  bigint,-- frm varchar 19-08-2010                  
@uid  int,   -- frm varchar     
@UserName nvarchar(50),          
@fdate nvarchar(50),          
@tdate nvarchar(50),          
@debt_Amount nvarchar(50)    
)               
as                  
declare @ErrNo Int,@Query varchar(2000),@resellerid bigint,@m_id bigint,@u_id int,@rid nvarchar(500),@lowmid bigint,@lowuid bigint,@res_id nvarchar(500),
@whereClause1 varchar(500)--,@whereClause1 varchar(500)                
declare @TopOwner nvarchar(500)          
          
--set @whereClause=''          
set @whereClause1=''          
               
If (@fdate !='' and @tdate !='')                                          
 Begin                                           
  Set @whereClause1 = @whereClause1+ '(convert(nvarchar,convert(datetime,cd.datecreated,104),112) between 
  convert(nvarchar,convert(datetime,'''+@fdate+''',104),112) and convert(nvarchar,convert(datetime ,'''+@tdate +''',104),112)) and '                   
  
Set @ErrNo = @@error                                           
 End                                          
Else                                          
 Begin                                          
  Set @whereClause1 =@whereClause1 +  ' 1=1 and '                                          
  Set @ErrNo = @@error                                          
 End           
          
If (@UserName='Select')                                                                                          
 Begin                                
 Set @whereClause1 =@whereClause1 +  '1=1 and '                                                                                        
  Set @ErrNo = @@error                                                                                      
 End                                                                                          
Else                                                  
Begin                                                                                          
 Set @whereClause1 = @whereClause1+ 'ud.user_login= '''+@UserName+''' and '                                                                                          
  Set @ErrNo = @@error                                                  
 End          
          
If (@debt_Amount='')                                                                                          
 Begin                                
 Set @whereClause1 =@whereClause1 +  '1=1 '                                                                                          
  Set @ErrNo = @@error                                                                                      
 End                                                                                          
Else                                                  
Begin                                                                                          
 Set @whereClause1 = @whereClause1+ 'cd.credits=cast('''+@debt_Amount+''' as int) '                                                                                          
  Set @ErrNo = @@error                                                                            
 End           
                  
          
--set @resellerid=10001--(select rd.reseller_id from reseller_detail rd left join user_detail ud on rd.reseller_id=ud.m_id where ud.m_id=convert(int,@mid) and ud.user_id=convert(int,@uid))                  
--set @m_id=(select m_id from reseller_detail where reseller_id=@resellerid)                  
--set @u_id=(select user_id from reseller_detail where reseller_id=@resellerid)                 
          
set @TopOwner=(select ud.user_login as topowner from user_detail ud left join reseller_detail rd on                  
ud.m_id=rd.m_id and ud.user_id=rd.user_id where rd.m_id=@mid and rd.user_id=@uid)             
set @rid=(select reseller_id from reseller_detail where m_id=@mid and user_id=@uid)                
set @res_id=(select reseller_id from reseller_detail where m_id=convert(int,@mid) and user_id=convert(int,@uid))          
print '1'       
set @Query='Select * from (select convert(nvarchar,datecreated,103) as CreditDate ,'''+@TopOwner+''' as [From],Credits,balance  from credit_details where m_id='+@mid+') and user_id='+@uid+') as D               
