CREATE   PROC [dbo].[proc_GetPageName]  --27828--17626          
@User_ID int           
as       
 declare @MID_Temp bigint = 0  
 declare @ResellerDomain nvarchar(100) = ''  
 select @MID_Temp = M_ID from user_detail where USER_ID = @User_ID  
 declare @type int =(select type from user_detail where USER_ID = @User_ID)
  If(@type<>1 and @MID_Temp = 10043)  
    Begin       
     SELECT [PageName],ShortUrl,SiteVisits,SiteLeads FROM [ClientPageDetail] where USER_ID = @User_ID    
    End 
    else If(@type=1 and @MID_Temp = 10043)  
