    select @ResellerDomain = Domain from reseller_detail where user_ID = @User_ID  
     SELECT replace(PageName,'www.kit19.com',@ResellerDomain) as PageName,ShortUrl,SiteVisits,SiteLeads FROM [ClientPageDetail] where USER_ID = @User_ID    
