     SELECT ID, 'http://' + replace(PageName,'www.kit19.com',@ResellerDomain) as PageName,ShortUrl,SiteVisits,SiteLeads FROM [ClientPageDetail] where USER_ID = @User_ID              
    union  
     select FormId ID, url_script as PageName,'' ShortUrl,0 SiteVisits,0 SiteLeads  FROM [WebFormTbl] where ParentId = @User_ID   
     and isnull(url_script,'') <> ''     
    End           
   Else            
       Begin             
        select  @ResellerDomain = Domain from reseller_detail where Reseller_ID = @MID_Temp            
        SELECT ID, 'http://' + replace(PageName,'www.kit19.com',@ResellerDomain) as PageName,ShortUrl,SiteVisits,SiteLeads         
          FROM [ClientPageDetail] where USER_ID = @User_ID           
       union  
     select FormId ID, url_script as PageName,'' ShortUrl,0 SiteVisits,0 SiteLeads  FROM [WebFormTbl] where ParentId = @User_ID   
     and isnull(url_script,'') <> ''     
       End     
    
    


