/* ============================================================
   Procedure: [dbo].[proc_insert_credit_details_adj]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC proc_insert_credit_details_adj --.02,'anil118771'
@cost decimal(18,2),
@user_login nvarchar(50)
as
declare @UserType nvarchar(10),@uid nvarchar(10)
select @UserType=type,@uid=user_id from user_detail where user_login=@user_login
if @UserType=0
begin
--insert into [MySMS].[dbo].[Credit_Details]([M_ID],[FromUser_ID],[User_ID],[Debits],[Credits],[Balance],[Validity],---[Default_Credit],[FromDate],[ToDate],[typecredit])
SELECT [M_ID],[User_ID],[User_ID],0,0,Balance,cast(round(((Balance*@cost)/(@cost+.05)),0) as int),[Validity],[Default_Credit],[FromDate],[ToDate],'ADJ IC 5P'  FROM [MySMS].[dbo].[Credit_Details]where credit_id in(select max(credit_id) from credit_details where user_id=@uid group by user_id)
end
else
begin
declare @M_ID nvarchar(10),@FromId nvarchar(10)
select @M_ID=reseller_id from [MySMS].[dbo].reseller_detail where user_id=@uid
--insert into [MySMS].[dbo].[Credit_Details]([M_ID],[FromUser_ID],[User_ID],[Debits],[Credits],[Balance],[Validity],---[Default_Credit],[FromDate],[ToDate],[typecredit])
SELECT [M_ID],(select user_id from reseller_detail where reseller_id in(SELECT distinct [M_ID]FROM [MySMS].[dbo].[Credit_Details]where credit_id in(select max(credit_id) from credit_details where M_id=@M_ID group by user_id))),[User_ID],0,0,Balance,cast(round(((Balance*@cost)/(@cost+.05)),0) as int),[Validity],[Default_Credit],[FromDate],[ToDate],'ADJ IC 5P'  FROM [MySMS].[dbo].[Credit_Details]where credit_id in(select max(credit_id) from credit_details where M_id=@M_ID or user_id=@uid group by user_id)
end




GO

