/* ============================================================
   Procedure: [dbo].[proc_InsertMailIDDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.proc_InsertMailIDDetails
  @M_ID BIGINT  
 ,@User_ID INT  
 ,-- frm bigint  19-08-2010      
 @MailID VARCHAR(200) -- frm nvarchar         
 --@Status smallint,          
 --@Type nvarchar(20)
 ,@DisplayName nvarchar(500)          
AS  
IF EXISTS (  
  SELECT *  
  FROM FromMailIDDetails(nolock)  
  WHERE M_ID = @M_ID  
   AND User_ID = @User_ID  
   AND Mail_ID = @MailID  
  )  
BEGIN  
 SELECT 'Mail ID Value already Exists.Try Another Mail Id Value'  
END  
ELSE  
BEGIN  
 INSERT INTO FromMailIDDetails (  
  M_ID  
  ,User_ID  
  ,Mail_ID  
  ,STATUS  
  ,DateCreated  
  ,DisplayName
  )  
 VALUES (  
  @M_ID  
  ,@User_ID  
  ,@MailID  
  ,0  
  ,GETDATE()
  ,@DisplayName  
  )  
  
 SELECT 'Mail ID Added Successfully'  
  
 DECLARE @rowJson NVARCHAR(MAX) = (  
   SELECT *  
   FROM FromMailIDDetails  
   WHERE Mail_ID = @MailID  
   FOR JSON AUTO  
    ,INCLUDE_NULL_VALUES  
   )  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_ID  
  ,@Activity_type = 'Inst_Mail'  
  ,@ActionType = 'I'  
  ,@RowJson = @rowJson  
  ,@Table_name = 'FromMailIDDetails'  
END  
  
