/* ============================================================
   Procedure: [dbo].[Proc_ManageTemplate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Proc_ManageTemplate]  
@UserID int=0,   -- from bigint   
@Template_Id bigint=0,      
@Template_desc nvarchar(500)='',      
@Mode char=''      
    
as    
IF @mode='D'
		DELETE FROM User_Templates WHERE Template_Id=@Template_Id
ELSE IF @Mode='U'
		UPDATE User_Templates SET Template_desc=@Template_desc WHERE Template_Id=@Template_Id
ELSE IF @Mode='I'
		INSERT INTO User_Templates VALUES (@Template_desc,@UserID)
ELSE IF @Mode='S'
		SELECT * FROM User_Templates WHERE User_ID=@UserID ORDER BY template_Id ASC



GO

