/* ============================================================
   Procedure: [dbo].[proc_move_monitor_premium]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC proc_move_monitor_premium  
  @Batchid bigint  
  as 
declare @c int=(select COUNT(1) from [MessageMonitor](nolock) where batchid=@BatchID)

while @c>0
begin
RETRY:                                         
BEGIN TRY                                      
BEGIN TRAN  
create table #temp(messageid bigint)
insert into premiummessage(MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd)  
output inserted.MessageID into #temp
select top 1000 [MessageID],[Mobile],[Message],[SenderID],[SmppID],[MessageInsertDate],[Priority],[U_ID],[IsUniCode],[IsDND],[Operator],[BatchID],[Isallowdnd] FROM  [MySMS].[dbo].[MessageMonitor](nolock) where batchid=@BatchID  order by messageid
--INSERT INTO MESSAGEDELIVERYSTATUSTEMP(MESSAGEID,BATCHID,MOBILE,MESSAGE,SENDERID,SMPPID,U_ID,PRIORITY,ISUNICODE,MESSAGESTATUS,   MESSAGEINSERTDATE,OPERATOR,DATECREATED)
--select m.MessageID,[BatchID],[Mobile],[Message],[SenderID],[SmppID],[U_ID],[Priority],[IsUniCode],'Sent',[MessageInsertDate],[Operator],getdate() FROM  [MySMS].[dbo].[MessageMonitor](nolock) m join #temp t on 
--m.MessageID=t.messageid where batchid=@BatchID  order by m.messageid
delete m from MessageMonitor m join #temp t on t.messageid=m.MessageID and BatchID=@batchid
drop table #temp
set @c=@c-1000
COMMIT                                      
END TRY                                      
BEGIN CATCH  
IF @@TRANCOUNT>0                                      
ROLLBACK                                      
EXECUTE USP_INSERTERRORINFO; 
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number
BEGIN
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms
GOTO RETRY -- Go to Label RETRY
END                                           
END CATCH
update b set filtermode=0,dbtype=7,userfilter='Stopped',batchmonitordate=getdate()  
from batchinfo b where b.batchid=@Batchid  
end



GO

