/* ============================================================
   Procedure: [dbo].[proc_RefundCreditDetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
CREATE   PROC [dbo].[proc_RefundCreditDetail] --10043,1889,2,1                                
(                                  
@M_ID bigint,                                                            
@User_ID int,        
@Message nvarchar(2000),      
@NoOfPeople int,              
@Isunicode int      
)                                
as    
     
 --Declare @ParentID bigint = 0  
 --Declare @MID_P bigint = 0  
 --Select  @ParentID = ParentID from User_detail where User_ID = @User_ID and M_ID = @M_ID   
 --Select  @MID_P = M_ID  from User_detail where User_ID = @ParentID   
    
                                
declare @BalanceMsg bigint,@creditid bigint,@FinalBalance bigint,@UsageMessage int,@default_credit bigint, @rCredit bigint, @rCredit_id bigint ,@creditType varchar(15),@MsgCount int        
      
SELECT @MsgCount=isnull(sum(dbo.fn_GetMessageCount(len(@Message),isnull(@IsUnicode,0))),0)        
                          
set @creditid=(select max(Credit_ID) from Credit_Details where m_id=@M_ID and User_ID=@User_ID)               
                          
select top 1 @rCredit=Debits,@rCredit_id=Credit_ID  from credit_details where m_id=@M_ID and user_id=@User_ID           
order by credit_id  desc                                            
                                                           
select @BalanceMsg=max(Balance) from Credit_Details where m_id=@M_ID and User_ID=@User_ID and Credit_ID=@creditid                            
select @default_credit=max(default_credit) from Credit_Details where m_id=@M_ID and User_ID=@User_ID and Credit_ID=@creditid                            
set @UsageMessage=(@MsgCount*@NoOfPeople)                                                  
              
set @FinalBalance=(@BalanceMsg+@UsageMessage)                       
                      
begin                            
insert into credit_details(FromUser_ID,M_ID,User_ID,Credits,Debits,Balance,Validity,Default_Credit,CreatedBy)                    
values(@User_ID,@M_ID,@User_ID,@UsageMessage,0,@FinalBalance,99999,@default_credit,@User_ID)                    
END 


GO

