 Begin                                                                                        
   Set @whereClause = @whereClause+ ' cd.contact_mobile ='''+@mobile+''' and '                                                                                        
  Set @ErrNo = @@error                                                                                        
 End                         
                        
If @Group = 'Select'                                                                                        
 Begin                                                                                        
  Set @whereClause = @whereClause+' 1=1 and '                                                                                        
  Set @ErrNo = @@error                                                                                        
 End                                                                                        
Else                                                                                        
 Begin          
   Set @whereClause = @whereClause+ ' cgd.Group_ID ='''+@Group+''' and '       
