--where cd.m_id='''+convert(varchar,@mid,10) +''' and cd.user_id='''+convert(varchar,@uid,10) +''' and  '+@whereClause+''                     
  set @Query='select distinct cd.m_id,cd.user_id,cd.contact_id,cd.Contact_Name,cd.Contact_Mobile,                        
cd.Contact_Email,cd.Contact_BG, cd.Contact_DOB,cd.Contact_Anniversary,cd.CompanyName,cd.City,cd.State,cd.Country,cd.Address                        
from contact_detail cd ,Contact_Group_Detail cgd                        
where cd.m_id=cgd.m_id and cd.user_id=cgd.user_id and cd.contact_id=cgd.contact_id                   
                     
and cd.m_id='''+convert(varchar,@mid,10) +''' and cd.user_id='''+convert(varchar,@uid,10) +''' and  '+@whereClause+''               
--start:-by vinay custom paggind                  
declare @TempTable1 table                      
(                      
Id int  identity(1,1),                      
m_id bigint,                      
user_id  int,                      
contact_id varchar(50),                      
Contact_Name varchar(100),                      
Contact_Mobile varchar(50),                      
Contact_Email varchar(50),                      
