)                      
                    
insert into @TempTable1(m_id,user_id,contact_id,Contact_Name,Contact_Mobile,Contact_Email,Contact_BG,Contact_DOB,Contact_Anniversary,CompanyName,City,State,Country,Address) exec(@Query)                     
select count(Id)from @TempTable1                    
                  
                  
declare @TempTable table                      
(                      
Id int  identity(1,1),                      
m_id bigint,                      
user_id  int,                      
contact_id varchar(50),                      
Contact_Name varchar(100),                      
Contact_Mobile varchar(50),                      
Contact_Email varchar(50),                      
Contact_BG varchar(50),                      
Contact_DOB varchar(50) ,                
Contact_Anniversary varchar(50),    
CompanyName varchar(100),    
City   varchar(100),    
State varchar(100),    
Country varchar(100),    
Address varchar(200)      
                      
)                     
                  
                     
insert into @TempTable(m_id,user_id,contact_id,Contact_Name,Contact_Mobile,Contact_Email,Contact_BG,Contact_DOB,Contact_Anniversary,CompanyName,City,State,Country,Address) exec(@Query)                      
select * from (SELECT  *, ROW_NUMBER()   OVER(ORDER BY Id ASC) AS rownum from @TempTable) as TempTable                    
where rownum between (@pageIndex-1)*@PageSize+1 AND @pageIndex*@PageSize                                                                                                
--end 


