DECLARE @ErrNo INT    
 ,@Query VARCHAR(2000)    
 ,@whereClause VARCHAR(500)    
 ,@operator VARCHAR(10)    
    
SET NOCOUNT OFF    
SET @whereClause = ''    
    
IF @name = ''    
BEGIN    
 SET @whereClause = @whereClause + ' 1=1 and '    
 SET @ErrNo = @@error    
END    
ELSE    
BEGIN    
 SET @whereClause = @whereClause + 'cd.contact_name Like ''%' + @name + '%'' and '    
 SET @ErrNo = @@error    
END    
    
IF @mobile = ''    
BEGIN    
