SET @Query = 'SELECT DISTINCT                
                      cd.M_ID, cd.User_ID, cd.Contact_ID, cd.Contact_Name, cd.Contact_Mobile, cd.Contact_Email, cd.Contact_BG, cd.Contact_DOB,                   
                      cd.Contact_Anniversary,cd.CompanyName,cd.City,cd.State,cd.Country,cd.Address                  
