                      Contact_Group_Detail AS cgd ON cd.M_ID = cgd.M_ID AND cd.User_ID = cgd.User_ID AND cd.Contact_ID = cgd.Contact_ID LEFT OUTER JOIN                  
                      Group_Detail AS gd ON cd.M_ID = gd.M_ID AND cd.User_ID = gd.User_ID                     
 where cd.m_id=''' + convert(VARCHAR, @mid, 10) + ''' and cd.user_id=''' + convert(VARCHAR, @uid, 10) + ''' and  ' + @whereClause + '  order by cd.Contact_ID desc'    
    
PRINT (@Query)    
    
--start:-by vinay custom paggind                            
DECLARE @TempTable1 TABLE (    
 Id INT identity(1, 1)    
 ,m_id BIGINT    
 ,-- from varchar(50),                                
 user_id INT    
 ,-- from varchar(50),                                
