 ,Contact_Name    
 ,Contact_Mobile    
 ,Contact_Email    
 ,Contact_BG    
 ,Contact_DOB    
 ,Contact_Anniversary    
 ,CompanyName    
 ,City    
 ,STATE    
 ,Country    
 ,Address    
 )    
EXEC (@Query)    
    
