 SELECT *    
  ,ROW_NUMBER() OVER (    
   ORDER BY Id ASC    
   ) AS rownum    
 FROM @TempTable    
 ) AS TempTable    
WHERE rownum BETWEEN (@pageIndex - 1) * @PageSize + 1    
  AND @pageIndex * @PageSize    
    
