/* ============================================================
   Procedure: [dbo].[proc_search_Credit_detail_userOnly]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
  
--ALTERED BY PRASHANT  
CREATE   PROC [dbo].[proc_search_Credit_detail_userOnly] --10001,3515,'',1      
@m_id bigint , -- from varchar 19-08-2010              
@user_id int,    -- from varchar 19-08-2010   
@credit bigint,  -- from varchar 19-08-2010      
@typeV nvarchar(50)                                                                                       
AS  
SET NOCOUNT ON      
 
    Declare @ParentID bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @user_id )
	Declare @MID_P bigint = ( select top 1 isnull(M_ID,0) from User_Detail with(nolock) where User_ID = @ParentID )

IF(@typeV=1)      
BEGIN       
SELECT cd.LastModified AS Date, cd.credits AS Credit, cd.balance AS Balance, rd.domain AS [From]   
FROM Credit_Details AS cd with(nolock) RIGHT JOIN reseller_detail rd with(nolock)   
ON cd.m_id=rd.reseller_id      
WHERE cd.m_id=@MID_P AND cd.user_id=@ParentID AND cd.credits LIKE '%'+@credit+'%'   
ORDER BY cd.LastModified DESC      
END      
ELSE       
IF(@typeV=2)      
BEGIN      
SELECT cd.creditupdateat AS Date, cd.voiceSmscredits AS Credit, cd.balance AS Balance, rd.domain AS [From]   
FROM tbl_VoiceSmsUsers AS cd with(nolock) RIGHT JOIN reseller_detail rd with(nolock) ON cd.m_id=rd.reseller_id      
WHERE cd.m_id=@m_id AND cd.u_id=@user_id AND cd.voiceSmscredits LIKE '%'+@credit+'%'   
ORDER BY cd.creditupdateat DESC    
END     
ELSE IF(@typeV=3)      
BEGIN         
SELECT cd.LastModified AS Date, cd.credits AS Credit, cd.balance AS Balance, rd.domain AS [From]   
FROM Keyword_Credit_Details AS cd with(nolock) RIGHT JOIN reseller_detail rd with(nolock) ON cd.m_id=rd.reseller_id      
WHERE cd.m_id=@m_id AND cd.user_id=@user_id AND cd.credits LIKE '%'+@credit+'%'   
ORDER BY cd.LastModified DESC         
END  
  
  


GO

/* ============================================================
   Procedure: [dbo].[proc_search_Trefic_details]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[proc_search_Trefic_details]   --10001,335,'elan','2010-09-05','2010-09-10'      
@m_id bigint, -- from nvarchar             
@user_id int, -- from nvarchar                           
@Keyword nvarchar(50),                                                                                         
@Fdate nvarchar(50),                                                                
@Todate nvarchar(50)                  
as       
begin    --alter by vinay remove transaction                                                                                             
Declare @Query varchar(2000),@whereClause varchar(500)                                                                               
set @whereClause=''                           
If @Keyword = 'Select'                                                                                
 Begin                                                                                
  Set @whereClause = @whereClause+' 1=1 and '                                                                                
 End                                                                                
Else                                                                                
 Begin                                                                                
  Set @whereClause =@whereClause+'kd.Keyword= '''+@Keyword+''' and '                                                                                
 End                            
If (@Fdate !='' and @Todate !='')                                                                            
 Begin                                                                             
  Set @whereClause = @whereClause+ '(convert(nvarchar,convert(datetime,md.Incoming_date,104),112) between convert(nvarchar,convert(datetime,'''+@Fdate+''',104),112) and convert(nvarchar ,convert(datetime,'''+@Todate +''',104),112))'                       
  
  
    
 End                                                                            
Else                                    
Begin                                                                            
  Set @whereClause =@whereClause +  '1=1'                                                                            
 End            
set @Query='select kd.Keyword as Keyword,md.SMStext as Message,md.[From] as Mobile, convert(nvarchar,convert(datetime, md.Incoming_date,104),100) as Date               
from MessageStorage_ShortCode md left outer join Shortcode_keyword kd on kd.User_ID=md.User_ID and kd.M_ID=md.M_ID and kd.keyword=md.keyword where md.User_ID='+CONVERT(VARCHAR,@user_id,15) +' and md.M_ID='+CONVERT(VARCHAR,@m_id,15)+' and '+@whereClause+' ORDER BY md.INCOMINGS_ID DESC '                                
  
 -- PRINT (@Query)   
    
exec (@Query)                                                                                          
end  
  




GO

/* ============================================================
   Procedure: [dbo].[PROC_SEARCH_USER_RESELLER_LIST]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [DBO].[PROC_SEARCH_USER_RESELLER_LIST] --10001,335,'USER TYPE','','','','','ALL','OPEN',50,1,'','' --10267                   
@M_ID BIGINT,                                            
@USER_ID INT,		-- FRM VARCHAR 19-08-2010                                            
@TYPE VARCHAR(20),	-- FRM VARCHAR 19-08-2010                                                     
@NAME NVARCHAR(50),                                                                                                                         
@MOBILE NVARCHAR(50),                                                      
@EMAIL NVARCHAR(50),                                                                                                
@LOCATION NVARCHAR(50),                                                    
@STATUS NVARCHAR(50),            
@AC_TYPE VARCHAR(50),            
@PAGEINDEX INT,                              
@PAGESIZE INT=2,
@FRMDATE NVARCHAR(50),
@TODATE NVARCHAR(50)                     
AS                                                                                                                                    
DECLARE @ERRNO INT,@QUERY VARCHAR(MAX),@WHERECLAUSE VARCHAR(1000),@OPERATOR VARCHAR(10)                                                                                                                
SET NOCOUNT OFF                                                                                                                
                             
SET @WHERECLAUSE=''                                               
DECLARE @MID NVARCHAR(50),@RID NVARCHAR(50)             
SET @RID=(SELECT RESELLER_ID FROM RESELLER_DETAIL WHERE M_ID=CONVERT(VARCHAR,@M_ID,10) AND USER_ID=CONVERT(VARCHAR,@USER_ID,10))                                              
IF @TYPE = 'USER TYPE'                                                                                                                
	BEGIN                                                                                                                
	SET @WHERECLAUSE = @WHERECLAUSE+' 1=1 AND  '                                                                                                                
	END                                                                                                                
ELSE                                                                                                                
	BEGIN                                                            
	SET @WHERECLAUSE = @WHERECLAUSE+ ' UD.TYPE ='''+@TYPE+''' AND  '                                                                                                         
	END                                                     
IF @STATUS = 'ALL'                                                                                                                
	BEGIN                                                                                                                
	SET @WHERECLAUSE = @WHERECLAUSE+' 1=1 AND  '                                                                                                                
	END                                                                                                                
ELSE                                                                                                                
	BEGIN                                                            
	SET @WHERECLAUSE = @WHERECLAUSE+ ' UD.STATUS ='''+@STATUS+''' AND  '                                  
	END                 
IF @NAME = ''                                                    
	BEGIN                                                                        
	SET @WHERECLAUSE = @WHERECLAUSE+' 1=1 AND  '                                                                        
	END                                                                           
ELSE                                                                                       
	BEGIN                                                               
	SET @WHERECLAUSE =@WHERECLAUSE+' UD.USER_LOGIN LIKE ''%'+@NAME+'%'' AND  '                                                                          
	END                                   
IF @MOBILE = ''                                                                                
	BEGIN                                             
	SET @WHERECLAUSE = @WHERECLAUSE+' 1=1 AND  '                                                  
	END                                                                                                        
ELSE                                                                                                                
	BEGIN                                                                                          
	SET @WHERECLAUSE = @WHERECLAUSE+ ' UD.MOBILE ='''+@MOBILE+''' AND  '                                                                                                                
	END                                                    
IF @EMAIL=''                                                                                                                
	BEGIN                                                                            
	SET @WHERECLAUSE =@WHERECLAUSE+' 1=1 AND  '                                                            
	END                                                                                                                
ELSE                                                                                              
	BEGIN                                                                                                                
	SET @WHERECLAUSE = @WHERECLAUSE+ ' UD.EMAIL ='''+@EMAIL+''' AND  '                                                          
	END             
IF(@AC_TYPE='')            
	BEGIN            
	SET  @WHERECLAUSE=@WHERECLAUSE +'  1=1 AND '                  
	END            
ELSE            
	BEGIN            
	SET  @WHERECLAUSE=@WHERECLAUSE +'  UD.USERFILTER='''+@AC_TYPE+''' AND  '                  
	END                  
IF (@FRMDATE ='' AND @TODATE !='')                                                                                      
	BEGIN                                                   
	SET @WHERECLAUSE = @WHERECLAUSE+ 'CONVERT(NVARCHAR,CONVERT(DATETIME,UD.DATECREATED,104),112) BETWEEN CONVERT(NVARCHAR,CONVERT(DATETIME,''01/01/1900'',104),112) AND CONVERT(NVARCHAR ,CONVERT(DATETIME,'''+@TODATE +''',104),112) AND '                     
	END                                                                                      
ELSE                                                                                      
	BEGIN                                                                    
	SET @WHERECLAUSE =@WHERECLAUSE +  '1=1 AND '                                                                               
	END                                            
IF (@FRMDATE !='' AND @TODATE !='')                            
	BEGIN                        
	SET @WHERECLAUSE = @WHERECLAUSE+ 'CONVERT(NVARCHAR,CONVERT(DATETIME,UD.DATECREATED,104),112) BETWEEN CONVERT(NVARCHAR,CONVERT(DATETIME,'''+@FRMDATE+''',104),112) AND CONVERT(NVARCHAR,CONVERT(DATETIME,'''+@TODATE +''',104),112) AND '                      
	END                                        
ELSE IF @FRMDATE ='' AND @TODATE =''  
	BEGIN                                                            
	SET @WHERECLAUSE =@WHERECLAUSE +  '1=1 AND '                                                                               
	END                                             
IF @LOCATION=''                                                                                                                
	BEGIN                                                                                 
	SET @WHERECLAUSE =@WHERECLAUSE+' 1=1  '                                                                                                               
	END                       
ELSE                                                                                              
	BEGIN                         
	SET @WHERECLAUSE =@WHERECLAUSE+' UD.CITY LIKE ''%'+@LOCATION+'%'' '                                       
	END                                                  
SET @QUERY='SELECT UD.M_ID,UD.USER_ID,UD.TYPE,UD.STATUS,UD.USER_LOGIN,UD.PWD,UD.MOBILE,UD.EMAIL,UD.CITY,  
(CASE UD.USERFILTER WHEN ''ON'' THEN ''TRANSACTIONAL'' WHEN ''OPEN'' THEN ''OPEN DND''   
WHEN ''FRC'' THEN ''FRC'' WHEN ''TRANS'' THEN ''TRANS'' WHEN ''TR_CURVE'' THEN ''TRANS_CURVE'' WHEN ''MTIX_TR'' THEN ''MTRANSACTIONAL'' WHEN ''MTIX_TRC'' THEN ''MTRC''  
ELSE ''PROMOTIONAL'' END) AS USERFILTER,RD.DOMAIN FROM USER_DETAIL UD                              
LEFT JOIN RESELLER_DETAIL RD ON UD.M_ID=RD.M_ID AND UD.USER_ID=RD.USER_ID                                                   
WHERE UD.M_ID='''+@RID +'''  AND  '+@WHERECLAUSE +' ORDER BY UD.USER_LOGIN  '                       
--START CUSTOM PAGGING   
PRINT @QUERY                         
DECLARE @TEMPTABLE1 TABLE                                
(                                
ID INT  IDENTITY(1,1),                                
M_ID  BIGINT ,                                
USER_ID INT,                                
[TYPE] INT,                                
STATUS VARCHAR(50),                                
USER_LOGIN VARCHAR(50),                                
PWD VARCHAR(50),                                
MOBILE FLOAT,                                
EMAIL VARCHAR(50),                               
CITY VARCHAR(50),            
USERFILTER VARCHAR(50),                                
DOMAIN VARCHAR(50)                                
)                                

INSERT INTO @TEMPTABLE1(M_ID,USER_ID,[TYPE],STATUS,USER_LOGIN,PWD,MOBILE,EMAIL,CITY,USERFILTER,DOMAIN) EXEC(@QUERY)                               
SELECT COUNT(ID)FROM @TEMPTABLE1                              

DECLARE @TEMPTABLE TABLE                                
(                                
ID INT  IDENTITY(1,1),                                
M_ID  BIGINT,                                
USER_ID INT,                                
[TYPE] INT,                        
STATUS VARCHAR(50),                                
USER_LOGIN VARCHAR(50),                                
PWD VARCHAR(50),                                
MOBILE FLOAT,                                
EMAIL VARCHAR(50),                                
CITY VARCHAR(50),            
USERFILTER VARCHAR(50),                                
DOMAIN VARCHAR(50)                      
)                               

INSERT INTO @TEMPTABLE(M_ID,USER_ID,[TYPE],STATUS,USER_LOGIN,PWD,MOBILE,EMAIL,CITY,USERFILTER,DOMAIN) EXEC(@QUERY)                                
SELECT * FROM (SELECT  *, ROW_NUMBER()   OVER(ORDER BY ID ASC) AS ROWNUM FROM @TEMPTABLE) AS TEMPTABLE                              
