 SET @WHERECLAUSE = @WHERECLAUSE+ 'CONVERT(NVARCHAR,CONVERT(DATETIME,UD.DATECREATED,104),112) BETWEEN CONVERT(NVARCHAR,CONVERT(DATETIME,''01/01/1900'',104),112) AND CONVERT(NVARCHAR ,CONVERT(DATETIME,'''+@TODATE +''',104),112) AND '                       
