user_login varchar(50),                              
Pwd varchar(50),                              
mobile float,                              
email varchar(50),                             
city varchar(50),          
 userfilter varchar(50),                              
                             
Domain varchar(50)                              
)                              
                            
insert into @TempTable1(m_id,user_id,[type],Status,user_login,Pwd,mobile,email,city,userfilter,Domain) exec(@Query)                             
select count(id)from @TempTable1                            
                            
declare @TempTable table                              
(                              
Id int  identity(1,1),                              
m_id  bigint,                              
user_id int,                              
[type] int,                      
Status varchar(50),                              
user_login varchar(50),                              
Pwd varchar(50),                              
mobile float,                              
email varchar(50),                              
city varchar(50),          
userfilter varchar(50),                              
                            
Domain varchar(50)                    
                            
)                             
                            
insert into @TempTable(m_id,user_id,[type],Status,user_login,Pwd,mobile,email,city,userfilter,Domain) exec(@Query)                              
 select * from (SELECT  *, ROW_NUMBER()   OVER(ORDER BY Id ASC) AS rownum from @TempTable) as TempTable                            
 where rownum between (@pageIndex-1)*@PageSize+1 AND @pageIndex*@PageSize 


GO

/* ============================================================
   Procedure: [dbo].[proc_select_actype]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[proc_select_actype] --10043,23975             
@M_ID bigint,              
@U_ID bigint              
as              
select (case userfilter when 'MT' then 'MOMT' when 'MTIX_PRO' then 'Promotional' when 'TRANS' then 'Transactional'   
when 'OPEN' then 'OPEN DND' when 'TR_CURVE' then 'SCRUB' when 'MT_TRANS' then 'Transactional' when 'MTIX_TR' then 'Transactional'   
when 'MTIX_TRC' then 'SCRUB' WHEN 'CRITICAL' THEN 'CRITICAL' else 'Promotional' end) as AcType,Type from user_detail where m_id=@M_ID and user_id=@U_ID


GO

