CREATE   PROCEDURE [dbo].[proc_select_actype_support] --10043,23975               
@P_ID bigint               
as                
select top 1 (case userfilter when 'MT' then 'MOMT' when 'MTIX_PRO' then 'Promotional' when 'TRANS' then 'Transactional'     
when 'OPEN' then 'OPEN DND' when 'TR_CURVE' then 'SCRUB' when 'MT_TRANS' then 'Transactional' when 'MTIX_TR' then 'Transactional'     
when 'MTIX_TRC' then 'SCRUB' WHEN 'CRITICAL' THEN 'CRITICAL' else 'Promotional' end) as AcType,Type from user_detail where ParentId=@P_ID  
Order by user_id asc



GO

