   Procedure: [dbo].[proc_select_lodoAndContact_atLogin]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[proc_select_lodoAndContact_atLogin]    
@url nvarchar(50)     
as    
DECLARE @MaxDate DATETIME  
Select @MaxDate = dbo.fn_Max_Update(@url)  
SELECT * FROM dbo.Upload_logo ul JOIN dbo.Reseller_Detail rd ON ul.[User_ID]=rd.[User_ID]  
WHERE Domain =@url-- AND Title IS NOT NULL   
AND ul.DateUpdated=@MaxDate  



GO

/* ============================================================
   Procedure: [dbo].[proc_select_logoAndContactClient_atLogin]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[proc_select_logoAndContactClient_atLogin]        
@url nvarchar(50)         
as        
DECLARE @MaxDate DATETIME   
declare @UserId bigint
declare @ParentId bigint
SELECT @ParentId = parentid
    FROM MYSMSInvoicing_dev.dbo.settings
    WHERE value = @Url;
SELECT TOP 1 @UserId = User_ID
FROM User_Detail WITH (NOLOCK)
WHERE ParentID = @ParentId;
Select @MaxDate = dbo.fn_Max_Update(@url)      
SELECT * FROM dbo.Upload_logo ul      
WHERE User_ID =@UserId-- AND Title IS NOT NULL       
AND ul.DateUpdated=@MaxDate 


GO

