/* ============================================================
   Procedure: [dbo].[proc_SelectListOfSenderIdForOwner]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------


CREATE   PROC [dbo].[proc_SelectListOfSenderIdForOwner] -- 1000,1,4             
@mid bigint,                    
@uid int,    -- frm big int 19-08-2010
@status smallint                    
as                
declare @rid bigint               
set @rid=(select Reseller_ID from Reseller_Detail where m_id=@mid and user_id=@uid)                 
            
if @status=2            
begin            
select distinct (ud.user_login +'--'+sd.sender_Name) as SenderName,sd.Sender_id,sd.m_id,sd.user_id,case sd.status when 0 then 'Pending' when 1 then 'Approve' end as Stat, sd.Type,sd.forward,      
 case sd.airtel when 0 then 'Pending' when 1 then 'Approve' end as Airtel                    
from user_detail ud left join SenderID_Detail sd on ud.m_id=sd.m_id and ud.user_id=sd.user_id              
where sender_id is not null and (Forward is not null ) or sender_id in(select Sender_id from senderID_Detail where m_id=@mid and user_id=@uid) or sender_id in(select Sender_id from senderID_Detail where m_id=@rid)                
end            
    else  if @status=3            
begin            
select distinct (ud.user_login +'--'+sd.sender_Name) as SenderName,sd.Sender_id,sd.m_id,sd.user_id,case sd.status when 0 then 'Pending' when 1 then 'Approve' end as Stat, sd.Type,sd.forward                    
,case sd.airtel when 0 then 'Pending' when 1 then 'Approve' end as Airtel                    
from user_detail ud left join SenderID_Detail sd on ud.m_id=sd.m_id and ud.user_id=sd.user_id             
where sd.Airtel=0 and (sender_id is not null and (Forward is not null )and sender_name not LIKE '%['']%' or sender_id in(select Sender_id from senderID_Detail where m_id=@mid and user_id=@uid) or sender_id in(select Sender_id from senderID_Detail where m_id=@rid))                
end     
    
 else  if @status=4            
begin            
select distinct (ud.user_login +'--'+sd.sender_Name) as SenderName,sd.Sender_id,sd.m_id,sd.user_id,case sd.status when 0 then 'Pending' when 1 then 'Approve' end as Stat, sd.Type,sd.forward                    
,case sd.airtel when 0 then 'Pending' when 1 then 'Approve' end as Airtel                    
from user_detail ud left join SenderID_Detail sd on ud.m_id=sd.m_id and ud.user_id=sd.user_id             
where sd.Airtel=1 and (sender_id is not null and (Forward is not null ) and sender_name not LIKE '%['']%' or sender_id in(select Sender_id from senderID_Detail where m_id=@mid and user_id=@uid) or sender_id in(select Sender_id from senderID_Detail where m_id=@rid))                
end     
    
else            
begin            
select distinct (ud.user_login +'--'+sd.sender_Name) as SenderName,sd.Sender_id,sd.m_id,sd.user_id,case sd.status when 0 then 'Pending' when 1 then 'Approve' end as Stat, sd.Type,sd.forward                    
,case sd.airtel when 0 then 'Pending' when 1 then 'Approve' end as Airtel                    
from user_detail ud left join SenderID_Detail sd on ud.m_id=sd.m_id and ud.user_id=sd.user_id             
where sd.status=@status and (sender_id is not null and (Forward is not null ) or sender_id in(select Sender_id from senderID_Detail where m_id=@mid and user_id=@uid) or sender_id in(select Sender_id from senderID_Detail where m_id=@rid))                
end  







