where sd.Airtel=0 and (sender_id is not null and (Forward is not null )and sender_name not LIKE '%['']%' or sender_id in(select Sender_id from senderID_Detail where m_id=@mid and user_id=@uid) or sender_id in(select Sender_id from senderID_Detail where m_id=@rid))                  
