CREATE   PROC [dbo].[proc_SelectListOfSenderIdForOwner3] -- 1000,1,4                     
@mid bigint,                            
@uid int,    -- frm big int 19-08-2010        
@status varchar(10),       
@senderName varchar(50),                            
@senderid varchar(10),                          
@userlogin varchar(30),                
@fdate nvarchar(100),                                                        
@tdate nvarchar(100)                         
as          
declare @rid varchar(25)                          
declare @select varchar(1000),@where varchar(500),@whereClause varchar(500)                            
              
set @whereClause=''                   
                      
                      
                    
if @status=2                    
begin                    
set @select= 'select distinct ud.user_login as username,sd.sender_Name as SenderName,sd.Sender_id,sd.m_id,sd.user_id,case sd.status when 0 then ''Pending'' when 1 then ''Approve'' end as Stat, sd.Type,sd.forward,              
 case sd.airtel when 0 then ''Pending'' when 1 then ''Approved'' when 3 then ''Rejected'' end as Airtel,convert(varchar,sd.DateCreated,103) as DateCreated , convert(varchar,sd.DateUpdated,103) as DateUpdated,convert(varchar
,sd.DateCreated,112) as DateCreatedSD , convert(varchar,sd.DateUpdated,112) as DateUpdatedSD                                                       
from user_detail ud left join SenderID_Detail sd on ud.m_id=sd.m_id and ud.user_id=sd.user_id '                     
                       
end                    
    else  if @status=3                    
begin                    
set @select= 'select distinct ud.user_login as username, sd.sender_Name as SenderName,sd.Sender_id,sd.m_id,sd.user_id,case sd.status when 0 then ''Pending'' when 1 then ''Approve'' end as Stat, sd.Type,sd.forward                            
,case sd.airtel when 0 then ''Pending'' when 1 then ''Approved'' when 3 then ''Rejected'' end as Airtel ,convert(varchar,sd.DateCreated,103) as DateCreated , convert(varchar,sd.DateUpdated,103) as DateUpdated,convert(varchar
,sd.DateCreated,112) as DateCreatedSD , convert(varchar,sd.DateUpdated,112) as DateUpdatedSD                                                      
from user_detail ud left join SenderID_Detail sd on ud.m_id=sd.m_id and ud.user_id=sd.user_id '                    
                       
end             
            
 else  if @status=4                    
begin                    
set @select='select distinct ud.user_login as username, sd.sender_Name as SenderName,sd.Sender_id,sd.m_id,sd.user_id,case sd.status when 0 then ''Pending'' when 1 then ''Approve'' end as Stat, sd.Type,sd.forward                            
,case sd.airtel when 0 then ''Pending'' when 1 then ''Approved'' when 3 then ''Rejected'' end as Airtel ,convert(varchar,sd.DateCreated,103) as DateCreated , convert(varchar,sd.DateUpdated,103) as DateUpdated,convert(varchar
,sd.DateCreated,112) as DateCreatedSD , convert(varchar,sd.DateUpdated,112) as DateUpdatedSD                                                      
from user_detail ud left join SenderID_Detail sd on ud.m_id=sd.m_id and ud.user_id=sd.user_id '                    
                      
end             
            
else                    
begin                    
set @select='select distinct ud.user_login as username, sd.sender_Name as SenderName,sd.Sender_id,sd.m_id,sd.user_id,case sd.status when 0 then ''Pending'' when 1 then ''Approve'' end as Stat, sd.Type,sd.forward                            
,case sd.airtel when 0 then ''Pending'' when 1 then ''Approved'' when 3 then ''Rejected'' end as Airtel,convert(varchar,sd.DateCreated,103) as DateCreated , convert(varchar,sd.DateUpdated,103) as DateUpdated,convert(varchar
,sd.DateCreated,112) as DateCreatedSD , convert(varchar,sd.DateUpdated,112) as DateUpdatedSD                                                       
from user_detail ud left join SenderID_Detail sd on ud.m_id=sd.m_id and ud.user_id=sd.user_id '     
      
end          
    
set @rid=(select reseller_id from reseller_detail where m_id=@mid and user_id=@uid)                                                   
              
--set @where=' where sd.m_id='''+@mid+''' and sd.user_id='''+@uid+''' '                            
set @where=' where 1=1  and (sd.sender_Name IS NOT NULL OR sd.sender_Name !='''+''+''')'                        
if (@mid!=10000)                            
begin                        
set @where=@where+ ' and sd.m_id='''+@rid+''''                            
end                      
if (@status!=2)                            
begin                            
set @where=@where+ ' and sd.status='''+@status+''''                                     
end                             
if(@senderName!='')                            
begin                         
set @where=@where+ ' and sd.sender_Name like '''+'%'+@senderName+'%'+''''                                     
end                            
if(@userlogin!='')                            
begin                            
set @where=@where+ ' and ud.user_login like '''+'%'+@userlogin+'%'+''''                                     
end                        
if(@uid=1 and @mid=10000)                        
begin                        
set  @where=@where+ 'and (sd.m_id=10001 or sd.m_id=10000 or sd.forward='''+'FTO'+''')'                        
end           
        
If (@fdate !='' and @tdate !='')                                                    
Begin                              
  Set @where = @where+ 'and convert(nvarchar, convert(datetime, sd.DateCreated),10) between convert(datetime,'''+@fdate+''',104) and convert(datetime,'''+@tdate+''',104)' 
End                                                            

Set @where = @where+ 'order by sd.DateCreated'              
              
set @select=@select+@where                            
print  @select                            
exec  (@select)     
        



