CREATE   PROC [dbo].[proc_showcontactdetailslistNew]          
(    
@OffsetValue int = 0,          
@PagingSize int = 20,          
@m_id bigint,          
@user_id bigint    
)    
as          
Begin    
   SELECT count(Contact_ID) over() as TotalRow, * FROM (  
select Contact_Name as Name,contact_mobile as contact ,Contact_ID from Contact_Detail where m_id=@m_id and user_id=@user_id and contact_mobile<>''       
)t
 order by t.Name           
 OFFSET  @OffsetValue Rows FETCH NEXT @PagingSize ROWS ONLY    
SET ANSI_NULLS ON        
End        
  


GO

