CREATE   PROC [dbo].[proc_ShowContactListAcToGroupWise] --8,2,3          
@gid  bigint, -- from varchar(5) by abhishek            
@pageIndex int,                  
@PageSize int=2              
as        
declare @Query nvarchar(MAX)         
set @Query='select cd.contact_id,cd.m_id,cgd.group_id,cd.user_id,cd.contact_name,cd.contact_mobile,cd.contact_email,cd.Contact_BG,cd.Contact_DOB,cd.Contact_Anniversary from contact_detail cd          
left join contact_group_detail cgd on cd.contact_id=cgd.contact_id and cd.m_id=cgd.m_id and cd.user_id= cgd.user_id          
left join group_detail gd on cgd.m_id=gd.m_id and cgd.user_id=gd.user_id and cgd.group_id=gd.group_id          
where cgd.group_id='''+convert(varchar,@gid,12)+''' order by cgd.group_id'       
  
print (@Query)      
        
--start:-by vinay custom paggind                            
declare @TempTable1 table                                
(                                
Id int  identity(1,1),                                
contact_id varchar(50),                                
M_ID  varchar(50),                                
group_id varchar(50),                                
user_id varchar(50),                                
contact_name varchar(100),                                
contact_mobile varchar(50),                                
contact_email varchar(50),                                
Contact_BG varchar(50),                          
Contact_DOB varchar(50),                  
Contact_Anniversary VARCHAR(50)                                  
)                              
                  
insert into @TempTable1(contact_id,M_ID,group_id,user_id,contact_name,contact_mobile,contact_email,Contact_BG,Contact_DOB,Contact_Anniversary) exec(@Query)                  
select count(Id)from @TempTable1                  
                  
declare @TempTable table                                
(                                
Id int  identity(1,1),                                
contact_id varchar(50),                                
M_ID  varchar(50),                                
group_id varchar(50),                                
user_id varchar(50),                                
contact_name varchar(100),                                
contact_mobile varchar(50),                                
contact_email varchar(50),                                
Contact_BG varchar(50),                          
Contact_DOB varchar(50),                  
Contact_Anniversary VARCHAR(50)       
)          
insert into @TempTable(contact_id,M_ID,group_id,user_id,contact_name,contact_mobile,contact_email,Contact_BG,Contact_DOB,Contact_Anniversary) exec(@Query)                                
select * from (SELECT  *, ROW_NUMBER()   OVER(ORDER BY Id ASC) AS rownum from @TempTable) as TempTable                         
where rownum between (@pageIndex-1)*@PageSize+1 AND @pageIndex*@PageSize 


GO

