/* ============================================================
   Procedure: [dbo].[proc_showgroupDetailslist]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
  
CREATE   PROC [dbo].[proc_showgroupDetailslist]      
   
@m_id BIGINT,            
  
@user_id INT -- frm big int 19-08-2010           
  
AS         
  
BEGIN  
 SELECT gd.group_id,  
        gd.group_name  AS groupName,  
        (  
            SELECT COUNT(1)  
            FROM    Contact_Group_Detail AS cgd  
                          
            WHERE  cgd.Group_ID = gd.Group_ID  
        )              AS countGroup  
 FROM   group_detail      gd  
 WHERE  gd.m_id = @M_id  
        AND gd.USER_ID = @user_id  
 ORDER BY  
        gd.group_name  
END     
  
    



GO

/* ============================================================
   Procedure: [dbo].[proc_showgroupDetailslist_FRomMailID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
  
  
  
CREATE   PROC [dbo].[proc_showgroupDetailslist_FRomMailID] --10043,26150         
       
@m_id BIGINT,                
      
@user_id bigINT -- frm big int 19-08-2010               
      
AS             
      
BEGIN     
select * into #Contact_Detail  from Contact_Group_Detail(nolock) cgd --inner join Contact_Detail(nolock) cd 
--on cgd.Contact_ID = cd.Contact_ID 
 where cgd.User_ID=@User_ID   
select * into #group_detail  from group_detail(nolock) where USER_ID=@User_ID   
     
     select * from (  select  gd.group_id,      
       gd.group_name  AS groupName,    
        (    
          select ISNULL(Count(Group_ID),0) from #Contact_Detail     
         where Group_ID in (select Group_ID from #group_detail where m_id = @m_id      
          AND USER_ID = @user_id ) 
          
             
         and  user_ID in  ( select USER_ID From Contact_Detail(nolock) where USER_ID = @user_id and Contact_Email <> '')    
        
        
         and  Group_ID = gd.Group_ID    
         group by Group_ID    
              
        )    
            
        AS countGroup    
       
   from #group_detail  gd    
        
   where gd.m_id = @M_id      
       AND gd.USER_ID = @user_id     
       ) as tbl    
           
       where isnull(tbl.countGroup,'')<>''     
      
     
 --SELECT gd.group_id,      
 --       gd.group_name  AS groupName,      
 --       (      
 --           SELECT COUNT(1)      
 --           FROM    Contact_Group_Detail AS cgd      
                              
 --           WHERE  cgd.Group_ID = gd.Group_ID      
