/* ============================================================
   Procedure: [dbo].[proc_showgroupDetailslistNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[proc_showgroupDetailslistNew]            
(    
@OffsetValue int = 0,          
@PagingSize int = 20,          
@m_id BIGINT,                  
@user_id INT -- frm big int 19-08-2010                 
)        
AS               
        
BEGIN        
   SELECT count(group_id) over() as TotalRow, * FROM (    
   SELECT gd.group_id,        
        gd.group_name  AS groupName,        
        (        
            SELECT COUNT(1)        
            FROM    Contact_Group_Detail AS cgd        
                                
            WHERE  cgd.Group_ID = gd.Group_ID        
        )              AS countGroup        
 FROM   group_detail      gd        
 WHERE  gd.m_id = @M_id        
        AND gd.USER_ID = @user_id        
		)t
 ORDER BY        
        t.groupName        
 OFFSET  @OffsetValue Rows FETCH NEXT @PagingSize ROWS ONLY    
END           
  


GO

