CREATE   PROC [dbo].[proc_SiteVisits]                    
@CompnayName varchar(200)                       
as       
  
declare @PageName varchar(200), @SelectMaxSiteVists bigint,@SelectMaxSiteVistsNew bigint     
set @PageName='www.kit19.com/'+@CompnayName   
  
set @SelectMaxSiteVists = (select MAX(SiteVisits) from ClientPageDetail where PageName=@PageName)  
 if(@SelectMaxSiteVists is NULL)        
  begin        
