/* ============================================================
   Procedure: [dbo].[proc_SiteVisits2]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
              
CREATE   PROC [dbo].[proc_SiteVisits2]               
              
@CompnayName varchar(200),          
@Source varchar(20)              
as              
        
              
declare @PageName varchar(200), @SelectMaxVisits bigint,@SelectMaxVisitsNew bigint                   
set @PageName='www.kit19.com/'+@CompnayName                 
        
declare @ClientPageID bigint          
set @ClientPageID = (select Id from ClientPageDetail where PageName=@PageName)        
        
if(@Source<>'')        
begin        
              
  set @SelectMaxVisits = (select MAX(SiteVisits) from ClientSiteUrl where ClientPageiD=@ClientPageID and Ptype= @Source)                
  if(@SelectMaxVisits is NULL)                      
   begin                      
  set @SelectMaxVisitsNew = 1                      
   end                       
   else                      
   begin                      
  set @SelectMaxVisitsNew = @SelectMaxVisits +1                      
   end                        
   update ClientSiteUrl set SiteVisits = @SelectMaxVisitsNew where ClientPageiD=@ClientPageID and Ptype= @Source                
 end        
 else        
 begin        
          
 if exists(select * from [ClientSiteUrl] where ClientPageiD=@ClientPageID and Ptype = '0')                                                            
 begin                                                            
   set @SelectMaxVisits = (select MAX(SiteVisits) from ClientSiteUrl where ClientPageiD=@ClientPageID and Ptype= '0')                
   if(@SelectMaxVisits is NULL)                      
    begin                      
   set @SelectMaxVisitsNew = 1                      
    end                       
    else                      
    begin                      
   set @SelectMaxVisitsNew = @SelectMaxVisits +1                      
    end                        
    update ClientSiteUrl set SiteVisits = @SelectMaxVisitsNew where ClientPageiD=@ClientPageID and Ptype= '0'                
 end               
 else          
 begin       
  if(@ClientPageID is not NULL)   
   begin                            
 INSERT INTO [ClientSiteUrl]            
      ([ClientPageiD],[Ptype],SiteVisits)            
   VALUES            
      (@ClientPageID ,'0',1)  
   end          
 end         
         
 end                             
select @SelectMaxVisitsNew   


GO

