/* ============================================================
   Procedure: [dbo].[proc_UpdateCreditDetail_app]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

          
                  
CREATE   PROC [dbo].[proc_UpdateCreditDetail_app] --10043,1889,2,1                                    
(                                      
@User_ID int,  -- from bigint                                                              
@isunicode int,            
@Message nvarchar(2000),           
@NoOfPeople int                  
)                                    
as            
          
   Declare @ParentID bigint = 0    
   Declare @MID_P bigint = 0    
   Select top 1  @ParentID = isnull(ParentID,0) from User_detail with(nolock) where User_ID = @User_ID       
   Select top 1  @MID_P = isnull(M_ID,0)  from User_detail with(nolock) where User_ID = @ParentID       
      
                                  
declare @BalanceMsg bigint,@creditid bigint,@FinalBalance bigint,@UsageMessage int,@default_credit bigint, @rCredit bigint, @rCredit_id bigint ,@creditType varchar(15) ,@M_ID int ,@MsgCount int            
          
SELECT @MsgCount=isnull(sum(dbo.fn_GetMessageCount(len(@Message),isnull(@IsUnicode,0))),0)          
                     
set  @M_ID=(select isnull(M_ID,0) from user_Detail with(nolock) where User_ID=@User_ID)                               
set @creditid=(select max(Credit_ID) from Credit_Details with(nolock) where User_ID=@ParentID)                   
set @creditType =(select top (1) typecredit from Credit_Details with(nolock) where User_ID=@ParentID  order by credit_id desc )                                                              
                              
select top 1 @rCredit=Debits,@rCredit_id=Credit_ID  from credit_details with(nolock) where user_id=@ParentID and typecredit=@creditType order by credit_id  desc                                                
                                                               
                                                               
select @BalanceMsg=max(Balance) from Credit_Details with(nolock) where User_ID=@ParentID and Credit_ID=@creditid                                
select @default_credit=max(default_credit) from Credit_Details with(nolock) where User_ID=@ParentID and Credit_ID=@creditid                                
set @UsageMessage=(@MsgCount*@NoOfPeople)                                                      
            
                  
set @FinalBalance=(@BalanceMsg-@UsageMessage)                           
                          
if((select convert(nvarchar,getdate(),10))=(select top 1 convert(nvarchar,dateupdated,10) from credit_details with(nolock) where user_id=@ParentID and typecredit=@creditType order by credit_id desc))                                
begin                                
   update Credit_Details set Balance=(@FinalBalance),CreatedBy = @User_ID  where User_ID=@ParentID and Credit_ID=@creditid                          
   update Credit_Details set Debits=(@rCredit+@UsageMessage),CreatedBy = @User_ID where User_ID=@ParentID and convert(nvarchar,LastModified,10)=convert(nvarchar,GETDATE(),10)  and typecredit=@creditType                                
                        
  end                                
else                                
begin                                
   insert into credit_details(FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,Validity,Default_Credit,typecredit,CreatedBy, CD_CreatedBy)                        
values(@ParentID,@MID_P,@ParentID,@UsageMessage,0,@FinalBalance,99999,@default_credit,@creditType,@User_ID , @User_ID)                        
                                
END   


GO

/* ============================================================
   Procedure: [dbo].[proc_UpdateCreditDetail_onScheduleCan]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[proc_UpdateCreditDetail_onScheduleCan]        
(        
@M_ID bigint,                                  
@User_ID int,  --frm big int 19-08-2010    
@MsgSent int,    
@MsgLen int
--@unicode int    
)      
as    
Declare @totalCredit int 
--if @unicode=0    
--Begin    
--set @totalCredit= (((@MsgLen-1)/160)+1)* @MsgSent     
--End    
--Else    
--Begin    
--set @totalCredit= (((@MsgLen-1)/70)+1)* @MsgSent     
--End      
set @totalCredit= (((@MsgLen-1)/160)+1)* @MsgSent    
declare @BalanceMsg bigint,@creditid bigint,@FinalBalance bigint,@UsageMessage int,@debit bigint ,@finaldebit bigint                                 
set @creditid=(select max(Credit_ID) from Credit_Details where m_id=@M_ID and User_ID=@User_ID)                                  
set @BalanceMsg=(select max(Balance) from Credit_Details where m_id=@M_ID and User_ID=@User_ID and Credit_ID=@creditid)    
set @debit=(select max(Debits) from Credit_Details where m_id=@M_ID and User_ID=@User_ID and Credit_ID=@creditid)                                                                
--set @UsageMessage=(@MsgCount*@NoOfPeople)                        
--set @FinalBalance=(@BalanceMsg-@MsgCount)                                  
set @FinalBalance=(@BalanceMsg+@totalCredit)  
set @finaldebit=(@debit-@totalCredit)                        
update Credit_Details set Balance=@FinalBalance,Debits=@finaldebit where m_id=@M_ID and User_ID=@User_ID and Credit_ID=@creditid    
---------------------------------------------------


GO

/* ============================================================
   Procedure: [dbo].[proc_UpdateCreditDetail_onScheduleCan_NEW]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[proc_UpdateCreditDetail_onScheduleCan_NEW]                    
(                    
@M_ID bigint,                                              
@User_ID int,  --frm big int 19-08-2010                
@MsgSent int,                
@MsgLen int,              
@unicode int,              
@batchid bigint                
)                  
as       
      
   Declare @ParentID bigint = 0    
   Declare @MID_P bigint = 0    
   Select top 1 @ParentID = isnull(ParentID,0) from User_detail with(nolock) where User_ID = @User_ID   and M_ID =  @M_ID    
   Select top 1 @MID_P = isnull(M_ID,0)  from User_detail with(nolock) where User_ID = @ParentID     
               
Declare @totalCredit int                
if @unicode=0              
Begin              
set @totalCredit= (((@MsgLen-1)/160)+1)* @MsgSent               
End              
Else              
Begin              
set @totalCredit= (((@MsgLen-1)/70)+1)* @MsgSent               
End               
declare @BalanceMsg bigint,@creditid bigint,@FinalBalance bigint,@UsageMessage int,@debit bigint ,@finaldebit bigint                                             
set @creditid=(select max(Credit_ID) from Credit_Details with(nolock) where m_id=@MID_P and User_ID=@ParentID)                                              
set @BalanceMsg=(select max(Balance) from Credit_Details with(nolock) where m_id=@MID_P and User_ID=@ParentID and Credit_ID=@creditid)                
set @debit=(select max(Debits) from Credit_Details with(nolock) where m_id=@MID_P and User_ID=@ParentID and Credit_ID=@creditid)                                                                            
--set @UsageMessage=(@MsgCount*@NoOfPeople)                                    
--set @FinalBalance=(@BalanceMsg-@MsgCount)                                              
set @FinalBalance=(@BalanceMsg+@totalCredit)              
set @finaldebit=(@debit-@totalCredit)                                    
update Credit_Details set Balance=@FinalBalance,Debits=@finaldebit,batchid=@batchid ,CreatedBy = @User_ID where m_id=@MID_P  
 and User_ID=@ParentID and Credit_ID=@creditid                
delete from batchinfo where userid=@User_ID and batchid=@batchid


GO

/* ============================================================
   Procedure: [dbo].[proc_UpdateCreditDetailMail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
         
    
    
CREATE   PROCEDURE [dbo].[proc_UpdateCreditDetailMail] --10043,1889,2,1    
 @M_ID BIGINT,    
 @User_ID INT,    
 @MsgCount INT,    
 @NoOfPeople INT    
AS    
BEGIN    
  
 --Declare @ParentID bigint = 0  
 --Declare @MID_P bigint = 0  
 --Select  @ParentID = ParentID from User_detail where User_ID = @User_ID and M_ID =  @M_ID  
 --Select  @MID_P = M_ID  from User_detail where User_ID = @ParentID   
  
  
 DECLARE @BalanceMsg         BIGINT,    
         @creditid           BIGINT,    
         @FinalBalance       BIGINT,    
         @UsageMessage       INT,    
         @default_credit     BIGINT,    
         @rCredit            BIGINT,    
         @rCredit_id         BIGINT,    
         @creditType         VARCHAR(15) --,@priorty tinyint                
     
     
     
 SET @creditid = (    
         SELECT MAX(Credit_ID)    
         FROM   Credit_Details    
         WHERE  m_id            = @M_ID    
                AND USER_ID     = @User_ID    
     )     
     
     
     
 SELECT TOP 1 @rCredit = mcd.Debits,    
        @rCredit_id = mcd.Credit_ID    
 FROM   MailCreditDetails AS mcd    
 WHERE  mcd.m_id = @M_ID    
        AND mcd.USER_ID = @User_ID    
 ORDER BY    
        mcd.credit_id DESC                                        
     
     
     
 SELECT @BalanceMsg = MAX(Balance)    
 FROM   MailCreditDetails    
 WHERE  m_id              = @M_ID    
        AND USER_ID       = @User_ID    
        AND Credit_ID     = @creditid                        
     
 SELECT @default_credit = MAX(default_credit)    
 FROM   MailCreditDetails    
 WHERE  m_id              = @M_ID    
        AND USER_ID       = @User_ID    
        AND Credit_ID     = @creditid                        
     
 SET @UsageMessage = (@MsgCount * @NoOfPeople)                                              
     
     
 BEGIN    
  INSERT INTO MailCreditDetails    
    (    
      FromUser_ID,    
      M_ID,    
      USER_ID,    
      Debits,    
      Credits,    
      Balance,    
      Validity,    
      Default_Credit,  
   CreatedBy    
    )    
  VALUES    
    (    
      @User_ID,    
      @M_ID,    
      @User_ID,    
      @UsageMessage,    
      0,    
      @FinalBalance,    
      99999,    
      @default_credit,  
   @User_ID  
    )    
 END    
END 


GO

/* ============================================================
   Procedure: [dbo].[proc_UpdateCreditDetailThroughCSV]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
  
CREATE   PROC [dbo].[proc_UpdateCreditDetailThroughCSV]            
(            
@M_ID bigint,                                      
@User_ID int, -- frm big int 19-08-2010                                     
@MsgCount int          
)          
as 
    Declare @ParentID bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @User_ID)
	Declare @MID_P bigint = ( select top 1 isnull(M_ID,0) from User_Detail with(nolock) where User_ID = @ParentID)
     
Declare @NoOfPeople int                       
declare @BalanceMsg bigint,@creditid bigint,@FinalBalance bigint,@UsageMessage int,@default_credit bigint, @rCredit bigint, @rCredit_id bigint              
set @NoOfPeople=1                  
set @creditid=(select max(Credit_ID) from Credit_Details with(nolock) where m_id=@MID_P and User_ID=@ParentID)                   
select top 1 @rCredit=Debits,@rCredit_id=Credit_ID  from credit_details with(nolock) where m_id=@MID_P and user_id=@ParentID and typecredit='SMS'  order by credit_id  desc                                    
                                                   
                                                   
select @BalanceMsg=max(Balance) from Credit_Details with(nolock) where m_id=@MID_P and User_ID=@ParentID and Credit_ID=@creditid                    
select @default_credit=max(default_credit) from Credit_Details with(nolock) where m_id=@MID_P and User_ID=@ParentID and Credit_ID=@creditid                    
set @UsageMessage=(@MsgCount*@NoOfPeople)                                          
--set @FinalBalance=(@BalanceMsg-@MsgCount)                                                    
set @FinalBalance=(@BalanceMsg-@UsageMessage)               
              
if((select convert(nvarchar,getdate(),10))=(select top 1 convert(nvarchar,dateupdated,10) from credit_details with(nolock) where m_id=@MID_P and user_id=@ParentID and typecredit='SMS' order by credit_id desc))                    
begin                    
   update Credit_Details set Balance=(@FinalBalance) where m_id=@MID_P and User_ID=@ParentID and Credit_ID=@creditid              
   update Credit_Details set Debits=(@rCredit+@UsageMessage) where m_id=@MID_P and User_ID=@ParentID and convert(nvarchar,LastModified,10)=convert(nvarchar,GETDATE(),10)  and typecredit='SMS'                    
            
  end                    
else                    
begin                    
--insert into credit_details (m_id,user_id,credits,balance,validity,default_credit,FromDate,ToDate,typecredit)                    
-- values(@M_ID,@User_ID,@UsageMessage,@FinalBalance,99999,@default_credit,getdate(),getdate(),'SMS')                       
   insert into credit_details(FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,Validity,Default_Credit,typecredit,CD_CreatedBy)            
   values(@MID_P,@MID_P,@ParentID,@UsageMessage,0,@FinalBalance,99999,@default_credit,'SMS',@User_ID)            
                    
END   
  
  
  
  


GO

