CREATE   PROC [dbo].[proc_UpdateCreditDetailVirtualLess] --10043,1889,2,1                                      
(                                        
@M_ID bigint,                                                                  
@User_ID bigint,  -- from bigint                                                                
@MsgCount int,                                      
@NoOfPeople int ,            
@BATCHID bigint,          
@deductcredits int =null                  
)                                      
as              
set @deductcredits = coalesce(@deductcredits,1)                                  
declare @BalanceMsg bigint,            
@creditid bigint,            
@FinalBalance bigint,            
@UsageMessage bigint,            
@default_credit bigint,             
@rCredit bigint,             
@rCredit_id bigint ,            
@creditType varchar(15),            
@VirtualBalanceMsg bigint,            
@Virtualcreditid bigint,            
@VirtualFinalBalance bigint,            
@VirtualUsageMessage bigint,            
@Virtualdefault_credit bigint,             
@VirtualrCredit bigint,             
@VirtualrCredit_id bigint ,            
@VirtualcreditType varchar(15),            
@parentsuperresellerid bigint,            
@SuperresellerM_id bigint            
            
    Declare @ParentID bigint = 0      
    Declare @MID_P bigint = 0      
    Select  @ParentID = ParentID from User_detail(nolock) where User_ID = @User_ID and M_ID =  @M_ID      
    Select  @MID_P = M_ID  from User_detail(nolock) where User_ID = @ParentID       
      
      
      
select @parentsuperresellerid= parentsuperresellerid from user_detail (nolock) where user_id=@user_id and HasVirtualCredits=1 select @SuperresellerM_id = m_id from user_detail where USER_ID=@parentsuperresellerid            
                              
set @creditid=(select max(Credit_ID) from Credit_Details(nolock) where m_id=@MID_P and User_ID=@ParentID)                     
select top 1 @rCredit=Debits,@rCredit_id=Credit_ID  from credit_details(nolock) where m_id=@MID_P and user_id=@ParentID                 
order by credit_id  desc                                                  
select @BalanceMsg=max(Balance) from Credit_Details(nolock) where m_id=@MID_P and User_ID=@ParentID and Credit_ID=@creditid             
select @default_credit=max(default_credit) from Credit_Details(nolock) where m_id=@MID_P and User_ID=@ParentID and Credit_ID=@creditid 
    
         
select @UsageMessage=(@MsgCount*@NoOfPeople),@FinalBalance=(@BalanceMsg-@UsageMessage)            
insert into credit_details(FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,Validity,Default_Credit,batchid,CreatedBy,CD_CreatedBy)                          
values(@User_ID,@MID_P,@ParentID,@UsageMessage,0,@FinalBalance,99999,@default_credit,@batchid,@User_ID,@User_ID)                          
          
if @parentsuperresellerid<>335 and @parentsuperresellerid is not null and @deductcredits=1           
begin            
set @virtualcreditid=(select max(Credit_ID) from SuperResellerCredit_Details where m_id=@SuperresellerM_id and User_ID=@parentsuperresellerid)           
select top 1 @virtualrCredit=Debits,@virtualrCredit_id=Credit_ID  from SuperResellerCredit_Details where user_id=@parentsuperresellerid order by credit_id  desc                                                  
select @VirtualBalanceMsg=max(Balance) from SuperResellerCredit_Details where User_ID=@parentsuperresellerid and Credit_ID=@virtualcreditid              
select @virtualdefault_credit=max(default_credit) from SuperResellerCredit_Details where User_ID=@parentsuperresellerid and Credit_ID=@virtualcreditid              
select  @VirtualUsageMessage=(@MsgCount*@NoOfPeople),            
@virtualFinalBalance=(@virtualBalanceMsg-@virtualUsageMessage)            
if (@virtualFinalBalance>=0)            
begin            
update CloneMessageDeliveryStatusless set HasSufficientvirtualcredits=1 where BatchID=@BATCHID            
insert into SuperResellerCredit_Details(FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,Validity,Default_Credit,batchid)                        
values(@parentsuperresellerid,@SuperresellerM_id,@parentsuperresellerid,@virtualUsageMessage,0,@virtualFinalBalance,99999,@virtualdefault_credit,@batchid)                          
end            
else            
begin            
update CloneMessageDeliveryStatusless set HasSufficientvirtualcredits=0 where BatchID=@BATCHID            
end            
end 


GO

