insert into IntCredit_Details(FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,Validity)                
     values(@User_ID,@M_ID,@User_ID,@Price,0,@FinalBalance,99999)                              
              
 declare @intCreditId bigint = scope_identity()
