    @deductcredits int = NULL,    
    @TotalCostForCreditDetails DECIMAL(18, 4) = NULL    
)    
AS    
    
BEGIN    
    SET NOCOUNT ON;    
    
    BEGIN TRY    
        SET @deductcredits = COALESCE(@deductcredits, 1);    
    
        DECLARE @BalanceMsg decimal(18,4),    
                @creditid bigint,    
                @FinalBalance decimal(18,4),    
                @UsageMessage decimal(18,4),    
                @default_credit decimal(18,4),    
                @rCredit bigint,    
                @rCredit_id bigint,    
                @creditType varchar(15),    
                @VirtualBalanceMsg bigint,    
                @Virtualcreditid bigint,    
                @VirtualFinalBalance bigint,    
                @VirtualUsageMessage bigint,    
                @Virtualdefault_credit bigint,    
                @VirtualrCredit bigint,    
                @VirtualrCredit_id bigint,    
                @VirtualcreditType varchar(15),    
                @parentsuperresellerid bigint,    
                @SuperresellerM_id bigint,    
                @ParentID bigint,    
    @servicetype varchar(100),    
                @M_ID_P bigint,@credittypeid int,@realbal numeric(18,4);    
    
        SELECT TOP 1 @ParentID = ParentID     
        FROM User_Detail WITH (NOLOCK)     
        WHERE User_ID = @User_ID;    
    
        SELECT TOP 1 @M_ID_P = M_ID     
        FROM User_Detail WITH (NOLOCK)     
        WHERE User_ID = @ParentID;    
    
        SET @creditid = (SELECT MAX(Credit_ID) FROM IntCredit_Details WITH (NOLOCK) WHERE User_ID = @ParentID);    
    
        SELECT TOP 1 @rCredit = Debits,@rCredit_id = Credit_ID,@realbal=balance      
        FROM IntCredit_Details WITH (NOLOCK) WHERE User_ID = @ParentID  ORDER BY Credit_ID DESC;    
    
        --SELECT @BalanceMsg = MAX(Balance)FROM IntCredit_Details WITH (NOLOCK)  WHERE User_ID = @ParentID AND Credit_ID = @creditid;    
  set @servicetype='DomesticSMS';    
  select @credittypeid=credittypeid from Price_Master_TypeCredit(nolock) where creditname=@servicetype    
        SELECT @BalanceMsg = dbo.GetAvailableBalanceForService(@ParentID,@credittypeid);    
      
        SELECT @default_credit = MAX(default_credit) FROM IntCredit_Details WITH (NOLOCK) WHERE User_ID = @ParentID AND Credit_ID = @creditid;    
    
  PRINT concat('@TotalCostForCreditDetails :', @TotalCostForCreditDetails)    
  PRINT concat('@@NoOfPeople :', @NoOfPeople)    
    
        SELECT @UsageMessage = (ISNULL(@TotalCostForCreditDetails, 0) )--* ISNULL(@NoOfPeople, 1))    
  select @FinalBalance = (@realbal - @UsageMessage);    
  PRINT concat('@@UsageMessage :', @UsageMessage)    
  PRINT concat('@@@FinalBalance :', @FinalBalance)    
        INSERT INTO IntCredit_Details    
        (    
            FromUser_ID, M_ID, User_ID, Debits, Credits, Balance,Validity, Default_Credit, BatchID, ICD_CreatedBy,typecredit,remarks    
        )    
        VALUES    
        (    
            @User_ID, @M_ID_P, @ParentID, @UsageMessage, 0, @FinalBalance, 99999, @default_credit, @BATCHID, @User_ID,21,'Credit deducted for SMS sent through batchid '+cast(@batchid as nvarchar)  
        );    
    
    
  DECLARE @InsertedCreditID bigINT;    
  SET @InsertedCreditID = SCOPE_IDENTITY();    
    
  exec usp_rf_UpdateReserveFundTransaction @InsertedCreditID    
      
      
  select @parentsuperresellerid= parentsuperresellerid from user_detail (nolock) where user_id=@user_id and HasVirtualCredits=1 select @SuperresellerM_id = m_id from user_detail where USER_ID=@parentsuperresellerid              
       /*    
    IF @parentsuperresellerid <> 335  AND @parentsuperresellerid IS NOT NULL   AND @deductcredits = 1    
        BEGIN    
            SET @virtualcreditid = (SELECT MAX(Credit_ID)  FROM SuperResellerCredit_Details WITH (NOLOCK) WHERE M_ID = @SuperresellerM_id AND User_ID = @parentsuperresellerid);    
    
            SELECT TOP 1 @VirtualrCredit = Debits,@VirtualrCredit_id = Credit_ID  FROM SuperResellerCredit_Details WITH (NOLOCK)     
  WHERE User_ID = @parentsuperresellerid ORDER BY Credit_ID DESC;    
    
            SELECT @VirtualBalanceMsg = MAX(Balance) FROM SuperResellerCredit_Details WITH (NOLOCK) WHERE User_ID = @parentsuperresellerid AND Credit_ID = @virtualcreditid;    
    
            SELECT @virtualdefault_credit = MAX(default_credit) FROM SuperResellerCredit_Details WITH (NOLOCK) WHERE User_ID = @parentsuperresellerid AND Credit_ID = @virtualcreditid;    
    
            SELECT @VirtualUsageMessage = (@MsgCount * @NoOfPeople), @VirtualFinalBalance = (@VirtualBalanceMsg - @VirtualUsageMessage);    
    
            IF (@VirtualFinalBalance >= 0)    
            BEGIN    
                UPDATE CloneMessageDeliveryStatus  SET HasSufficientvirtualcredits = 1  WHERE BatchID = @BATCHID;    
    
                INSERT INTO SuperResellerCredit_Details    
                (    
                    FromUser_ID, M_ID, User_ID, Debits, Credits, Balance, Validity, Default_Credit, BatchID    
                )    
                VALUES    
                (    
                    @parentsuperresellerid, @SuperresellerM_id, @parentsuperresellerid,  @VirtualUsageMessage, 0, @VirtualFinalBalance, 99999, @virtualdefault_credit, @BATCHID    
                );    
            END    
            ELSE    
            BEGIN    
                UPDATE CloneMessageDeliveryStatus SET HasSufficientvirtualcredits = 0   WHERE BatchID = @BATCHID;    
            END    
        END    
        ELSE IF @deductcredits = 1    
        BEGIN    
  --select top 2 * from CloneMessageDeliveryStatus (nolock) order by 1 desc    
            UPDATE CloneMessageDeliveryStatus  SET HasSufficientvirtualcredits = 1  WHERE BatchID = @BATCHID;    
        END    
  */    
    
  EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_ID          
  ,@Activity_type = 'Wallet balance update'          
  ,@ActionType = 'U'          
  ,@RowJson = ''          
  ,@Table_name = 'IntCredit_Details'      
    END TRY    
    BEGIN CATCH    
        exec usp_InsertErrorInfo            
    END CATCH    
END;    
    
    


