   Procedure: [dbo].[proc_updateUserDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[proc_updateUserDetails]            
@M_ID BIGINT,                 
    -- change all datatypes belos by gaurav on 18-08-2010 according to table                     
@User_ID INT,                
--@Pwd varchar(20),                          
@FName VARCHAR(50),                          
@LName VARCHAR(50),                          
@EMail VARCHAR(50),                          
@Mobile VARCHAR(20),                          
@City VARCHAR(50),                          
@State VARCHAR(50),                          
@Country VARCHAR(50),          
@URL     VARCHAR(200),      
@CompanyName VARCHAR(200),    
@IsAdmin bit=null,    
@IsInternalUser bit=null                        
AS  
set @IsInternalUser =coalesce(@isinternaluser,0)
set @IsAdmin=coalesce(@isadmin,0)  
if @IsInternalUser=0
begin
set @IsAdmin=1
end                    
  
UPDATE user_detail      
SET    FName = @FName,      
       LName = @LName,      
       EMail = @EMail,      
       Mobile = @Mobile,      
       City = @City,      
       STATE = @State, --Pwd=@Pwd,                        
       Country = @Country,      
       CompnayName = @CompanyName,    
       IsAdmin =@IsAdmin,    
       IsInternalUser = @IsInternalUser     
WHERE  M_ID = @M_ID      
       AND USER_ID = @User_ID      
          
IF (@URL <> '')      
BEGIN      
    UPDATE reseller_detail      
    SET    Domain      = @URL      
    WHERE  USER_ID     = @User_ID      
END   

if @IsInternalUser=0
begin
if @IsAdmin=1
begin
update user_detail set ParentID=@User_ID where USER_ID=@user_id
end
exec usp_InsertPredefinedValues @User_ID
end     
                        
SELECT 'User Updated Successfully' 


GO

