/* ============================================================
   Procedure: [dbo].[proc_updateUserDetailsProfile_support]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.proc_updateUserDetailsProfile_support @M_ID BIGINT
	,
	-- change all datatypes belos by gaurav on 18-08-2010 according to table                             
	@User_ID INT
	,@Pwd VARCHAR(20)
	,@FName VARCHAR(50)
	,@LName VARCHAR(50)
	,@EMail VARCHAR(50)
	,@Mobile VARCHAR(20)
	,@City VARCHAR(50)
	,@State VARCHAR(50)
	,@Country VARCHAR(50)
	,@NewoficeName VARCHAR(50)
	,@CompanyName VARCHAR(200)
	,@Image NVARCHAR(200)
	,@MobileCountryCode VARCHAR(50)
AS
BEGIN
	UPDATE user_detail
	SET FName = @FName
		,LName = @LName
		,EMail = @EMail
		,Mobile = @Mobile
		,City = @City
		,STATE = @State
		,--Pwd=@Pwd,                                
		Country = @Country
		,Office_Name = @NewoficeName
		,CompnayName = @CompanyName
		,IMAGE = @Image
		,MobileCountryCode = @MobileCountryCode
	WHERE M_ID = @M_ID
		AND USER_ID = @User_ID

	IF EXISTS (
			SELECT 1
			FROM Referrer_Details
			WHERE kit19userid = @User_ID
			)
	BEGIN
		UPDATE Referrer_Details
		SET Name = isnull(@FName, '') + ' ' + ISNULL(@LName, '')
			,EMail = @EMail
			,Mobile = @Mobile
			,City = @City
			,STATE = @State
			,--Pwd=@Pwd,                                
			Country = @Country
		WHERE kit19userID = @User_ID
	END

	SELECT 'User Updated Successfully'

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM user_detail WITH (NOLOCK)
			WHERE M_ID = @M_ID
		AND USER_ID = @User_ID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_ID
		,@Activity_type = 'Updt_Profle'
		,@ActionType = 'U'
		,@RowJson = @rowJson
		,@Table_name = 'user_detail'
END



GO

