/* ============================================================
   Procedure: [dbo].[proc_UrlLeadsViews]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROC [dbo].[proc_UrlLeadsViews]          
@User_ID int      
as          
      
declare @ClientPageID bigint      
      
set @ClientPageID =(select TOP 1 Id from ClientPageDetail where USER_ID=@User_ID)      
      
select ms.Marketing_Source as Marketing_Source,cs.ClientPageiD,cs.Ptype,cs.ShortUrl,cs.SiteLeads,cs.SiteVisits      
from ClientSiteUrl cs inner join MarketingSource ms       
on cs.Ptype=ms.Id where cs.ClientPageiD=@ClientPageID      
      
union      
       
Select 'Others' as Marketing_Source,ClientPageiD,Ptype,ShortUrl, SiteLeads,SiteVisits      
from ClientSiteUrl where Ptype='0' and ClientPageiD IN(SELECT Id from ClientPageDetail where USER_ID=@User_ID)
      
      
      


GO

