@Sender_Name nvarchar(100)      
 -- frm big int 19-08-2010        
as       
      
  select @user_id = ParentID  from User_Detail with(nolock) where User_ID =  @user_id 
  select @m_id = m_id  from User_Detail with(nolock) where User_ID =  @user_id 
  
declare @userfilter as varchar(10) =''      
if exists (select 1 from user_detail ud(nolock)       
where user_id=@user_id and userfilter = 'MTIX_PRO')      
select 1,1      
else      
select Sender_ID,Sender_Name from SenderID_Detail where type='GSM' and status=1       
and m_id=@m_id and user_id=@user_id  and Sender_Name= @Sender_Name 


