/* ============================================================
   Procedure: [dbo].[ReceiveDeadlock]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[ReceiveDeadlock]
/******************************************************************************
* Name     : dbo.ReceiveDeadlock
* Purpose  : Handles deadlock events (activated by QUEUE queDeadlockNotification)
* Inputs   : None
* Outputs  : None
* Returns  : Nothing
******************************************************************************
* Change History
*      06/26/2017    DMason Created
******************************************************************************/
AS
BEGIN
 SET NOCOUNT ON
 DECLARE @MsgBody XML
 
 WHILE (1 = 1)
 BEGIN
  BEGIN TRANSACTION
 
  -- Receive the next available message FROM the queue
  WAITFOR (
   RECEIVE TOP(1) -- just handle one message at a time
   @MsgBody = CAST(message_body AS XML)
   FROM queDeadlockNotification
  ), TIMEOUT 1000  -- if the queue is empty for one second, give UPDATE and go away
  -- If we didn't get anything, bail out
  IF (@@ROWCOUNT = 0)
  BEGIN
   ROLLBACK TRANSACTION
   BREAK
  END
  ELSE
  BEGIN
   --Do stuff here.
   DECLARE @Login SYSNAME = @MsgBody.value('(/EVENT_INSTANCE/LoginName)[1]', 'VARCHAR(128)' );
   DECLARE @IsSystem INT = @MsgBody.value('(/EVENT_INSTANCE/IsSystem)[1]', 'VARCHAR(8)' );
   DECLARE @StartTime VARCHAR(128) = @MsgBody.value('(/EVENT_INSTANCE/StartTime)[1]', 'VARCHAR(128)' );
   DECLARE @Start DATETIME = @StartTime
   DECLARE @FileName NVARCHAR(255)= 'Deadlock Graph ' +
    REPLACE(CONVERT(VARCHAR, @Start, 121), ':', '.') + '.xdl';
 
   DECLARE @MailBody NVARCHAR(MAX);
   DECLARE @Subject NVARCHAR(255);
   DECLARE @Qry NVARCHAR(MAX);
 
   SET @Qry = CAST(@MsgBody.query('/EVENT_INSTANCE/TextData/deadlock-list') AS NVARCHAR(MAX));
   SET @Qry = REPLACE(@Qry, CHAR(39), CHAR(39) + CHAR(39));
   SET @Qry = 'SET NOCOUNT ON; ' + CHAR(13) + CHAR(10) +
    'SELECT ' + CHAR(39) + @Qry + CHAR(39);
                    
   SET @Subject = @@SERVERNAME + ' -- ' + @MsgBody.value('(/EVENT_INSTANCE/EventType)[1]', 'VARCHAR(128)' )   
   SET @MailBody =
    '<table border="1">' +
    '<tr><td>Server Name</td><td>' + @MsgBody.value('(/EVENT_INSTANCE/ServerName)[1]', 'VARCHAR(128)' ) + '</td></tr>' +
    '<tr><td>Start Time</td><td>' + @StartTime + '</td></tr>' + 
    '<tr><td>Login Name</td><td>' + @Login + '</td></tr>' +
    '<tr><td>Session Login Name</td><td>' + @MsgBody.value('(/EVENT_INSTANCE/SessionLoginName)[1]', 'VARCHAR(128)' ) + '</td></tr>' +
    '<tr><td>Is System</td><td>' + @MsgBody.value('(/EVENT_INSTANCE/IsSystem)[1]', 'VARCHAR(128)' ) + '</td></tr>' +
    '</table><br/>';
 
   EXEC usp_enqueueemail
    @profile_name='Alerts',
    @recipients = 'karuna@pelsoftlabs.in;chakravarthy.9866@gmail.com',
    @subject = @Subject,
    @body = @MailBody,
    @body_format = 'HTML',
    @query = @Qry,
    @attach_query_result_as_file = 1,
    @query_attachment_filename = @FileName,
    @query_no_truncate = 1,
    @query_result_width = 32767,                                                  
    @exclude_query_output = 1

   /*
    Commit the transaction.  At any point before this, we
    could roll back -- the received message would be back
    on the queue AND the response wouldn't be sent.
   */

   COMMIT TRANSACTION
  END
 END
END



GO

/* ============================================================
   Procedure: [dbo].[SAVEEmailWebAPI_sp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

   
CREATE   PROCEDURE [dbo].[SAVEEmailWebAPI_sp] 
(
    @UserId         BIGINT,
    @TVP            EmailSendTableTypeWebApi READONLY,
    --@EmailDataXML VARCHAR(MAX),      
    @Error_msg      VARCHAR(100) OUTPUT,
    @StatusCode     INT OUTPUT
)
AS
BEGIN
	--***************************************
	--CREATED BY : VISHAL  KUMAR SRIVASTAVA
	--CREATED ON : 8 Sep 2017
	-- SAVEEmailWebAPI_sp 335 ,'<ROOT><ROW Email = ''vishal.srivastava917@gmail.com'' Subjects = ''Testing DAta'' Content = ''p'' ReplyTo = ''vishal.srivastava917@gmail.com''></ROW></ROOT>','',0
	--***************************************      
	BEGIN TRY
		BEGIN TRANSACTION 
		--DECLARE @handle  INT      
		DECLARE @TempData_tbl TABLE 
		        (
		            Email VARCHAR(50),
		            Subjects VARCHAR(MAX),
		            CONTENT NVARCHAR(MAX),
		            ReplyTo VARCHAR(50)
		        ) 
		--EXEC sp_xml_preparedocument @handle OUTPUT, @EmailDataXML
		--INSERT INTO @TempData_tbl(Email,Subjects,Content,ReplyTo)
		--SELECT  tblU.Email,tblU.Subjects,tblU.Content,tblU.ReplyTo
		--FROM OPENXML (@handle, 'ROOT/ROW', 1) WITH (Email VARCHAR(50),Subjects VARCHAR(MAX),Content NVARCHAR(MAX),ReplyTo VARCHAR(50)) tblU
		--EXEC sp_xml_removedocument @handle
		--SELECT * FROM @TempData_tbl      
		
		INSERT INTO @TempData_tbl
		  (
		    Email,
		    Subjects,
		    CONTENT,
		    ReplyTo
		  )
		SELECT Email,
		       Subjects,
		       CONTENT,
		       ReplyTo
		FROM   @TVP  
		
		DECLARE @MailCount     BIGINT,
		        @IsMonitor     BIT = 1
		
		SELECT @MailCount = COUNT(*)
		FROM   @TempData_tbl          
		
		DECLARE @Status         BIGINT = 0,
		        @CountLimit     BIGINT = 0
		
		SELECT @Status = STATUS,
		       @CountLimit = Plimit
		FROM   ProcessMailLimit
		
		IF (@Status = 1)
		BEGIN
		    IF (@MailCount > @CountLimit)
		    BEGIN
		        SET @IsMonitor = 0
		    END
		END 
		
		----------------For Balance Check--------------------         
		DECLARE @CurrentBalance BIGINT = (
		            SELECT TOP 1 mcd.Balance
		            FROM   MailCreditDetails AS mcd
		            WHERE  mcd.[User_ID] = @UserId
		            ORDER BY
		                   mcd.Credit_ID DESC
		        )
		
		DECLARE @Balance BIGINT = @CurrentBalance - @MailCount 
		--------------------------------------------------------    
		
		IF @Balance > 0
		BEGIN
		    DECLARE @m_id BIGINT = (
		                SELECT TOP 1 ud.M_ID
		                FROM   User_Detail AS ud
		                WHERE  ud.[User_ID] = @UserId
		            )
		    
		    INSERT INTO GetBatchRecord
		      (
		        [User_id],
		        RandNum
		      )
		    VALUES
		      (
		        @UserId,
		        @UserId
		      )                
		    DECLARE @BatchID BIGINT = (
		                SELECT MAX(gbr.BatchID)
		                FROM   GetBatchRecord(NOLOCK) AS gbr
		                WHERE  gbr.[User_id] = @UserId
		            )
		    
		    DELETE 
		    FROM   GetBatchRecord
		    WHERE  [User_id] = @UserId             
		    
		    DECLARE @Mail_FromEmail VARCHAR(500) = ''            
		    SELECT @Mail_FromEmail = ud.EMail
		    FROM   User_Detail          AS ud
		           LEFT JOIN User_Type  AS ut(NOLOCK)
		                ON  ud.UserType = ut.ID
		    WHERE  ud.[User_ID] = @UserId         
		    
		    DECLARE @SenderName VARCHAR(100) = ''       
		    SELECT @SenderName = ud.FName + ISNULL(ud.LName, '')
		    FROM   User_Detail          AS ud
		           LEFT JOIN User_Type  AS ut(NOLOCK)
		                ON  ud.UserType = ut.ID
		           INNER JOIN User_Filter UF(NOLOCK)
		                ON  ud.userfilter = Uf.Code
		    WHERE  ud.[User_ID] = @UserId    
		    
		    
		    CREATE TABLE #tempTable
		    (
		    	EmailID         VARCHAR(100),
		    	AccountID       VARCHAR(100),
		    	SenderName      VARCHAR(100),
		    	MailContent     VARCHAR(MAX),
		    	MailSubject     VARCHAR(MAX),
		    	ReplyTo         VARCHAR(100)
		    )      
		    INSERT INTO #tempTable
		      (
		        EmailID,
		        AccountID,
		        SenderName,
		        MailContent,
		        MailSubject,
		        ReplyTo
		      )
		    SELECT Email,
		           @UserId,
		           @SenderName,
		           CONTENT,
		           Subjects,
		           ReplyTo
		    FROM   @TempData_tbl 
		    ----------SELECT * FROM #tempTable
		    --------------------Mail Information Entry--------------------------    
		    
		    INSERT INTO BatchEmail_Infos
		      (
		        -- ID -- this column value is auto-generated          
		        BatchID,
		        UserID,
		        SenderName,
		        MESSAGE,
		        TotalRecords,
		        TotalProcessed,
		        ProcessTable,
		        IsProcess,
		        Priority_Level,
		        BatchInsertTime,
		        BatchProcessTime,
		        ScheduledDate,
		        ScheduledTime,
		        TemplateID,
		        [Route],
		        PageName,
		        IsScheduled,
		        Email_Subject,
		        ReplyTo,
		        Amount,
		        Currency
		      )
		    SELECT @BatchID,
		           A.AccountID,
		           A.SenderName,
		           A.MailContent,
		           COUNT(*),
		           0,
		           0,
		           0,
		           0,
		           GETDATE(),
		           NULL,
		           NULL,
		           NULL,
		           NULL,
		           NULL,
		           NULL,
		           0,
		           A.MailSubject,
		           A.ReplyTo,
		           COUNT(*),
		           'INR'
		    FROM   #tempTable A
		    GROUP BY
		           A.AccountID,
		           A.SenderName,
		           A.MailContent,
		           A.MailSubject,
		           A.ReplyTo           
		    
		    INSERT INTO ClientEmails
		      (
		        -- Id -- this column value is auto-generated          
		        GUID,
		        Email_Id,
		        SentDateTime,
		        UserId,
		        ReplyTo,
		        [Status],
		        BatchID,
		        MESSAGE
		      )
		    SELECT NEWID(),
		           A.EmailID,
		           GETDATE(),
		           A.AccountID,
		           A.ReplyTo,
		           '',
		           @BatchID,
		           A.MailContent
		    FROM   #tempTable A          
		    
		    INSERT INTO EmailsFilter
		      (
		        Mail_GUID,
		        -- Mail_ID -- this column value is auto-generated          
		        Mail_FromEmail,
		        Mail_ToEmail,
		        Mail_Subject,
		        Mail_TempleteName,
		        Messages,
		        Mail_InsertedDate,
		        Mail_UserID,
		        ReplyTo,
		        Mail_BatchID,
		        Mail_Priority,
		        Mail_ScheduleDate,
		        Mail_Attechement,
		        Mail_TempleteBody,
		        IsMonitor
		      )
		    SELECT NEWID(),
		           @Mail_FromEmail,
		           A.EmailID,
		           A.MailSubject,
		           '',
		           A.MailContent,
		           GETDATE(),
		           A.AccountID,
		           A.ReplyTo,
		           @BatchID,
		           0,
		           NULL,
		           0,
		           A.MailContent,
		           @IsMonitor
		    FROM   #tempTable A 
		    -------------------------For Debit entry -------------------------    
		    
		    INSERT INTO MailCreditDetails
		      (
		        FromUser_ID,
		        M_ID,
		        USER_ID,
		        Debits,
		        Credits,
		        Balance,
		        Validity
		      )
		    VALUES
		      (
		        @UserId,
		        @m_id,
		        @UserId,
		        @MailCount,
		        0,
		        @Balance,
		        99999
		      ) 
		    ---------------------------------------------------                                 
		    DROP TABLE #tempTable    
		    SET @Error_msg = 'Success'    
		    SET @StatusCode = 1
		END
		ELSE
		BEGIN
		    SET @Error_msg = 'Insufficient Balance'     
		    SET @StatusCode = 0
		END 
		COMMIT TRANSACTION
	END TRY      
	BEGIN CATCH
		IF @@ERROR <> 0
		BEGIN
		    ROLLBACK TRANSACTION
		END
		
		SET @Error_msg = ERROR_MESSAGE()
	END CATCH
END 


GO

/* ============================================================
   Procedure: [dbo].[SAVESMSWebAPI_sp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

       
CREATE   PROCEDURE  [dbo].[SAVESMSWebAPI_sp]             
(           
 @UserId BIGINT,      
 @IsUniCode INT,        
 @SenderName VARCHAR(100),        
 @SMSDataXML VARCHAR(MAX),            
 @Error_msg VARCHAR(100) OUTPUT            
)            
AS            
BEGIN       
    
    Declare @ParentID bigint = ( select top 1 ParentID from User_Detail with(nolock) where User_ID = @UserId) 
    
         
--***************************************                        
 --CREATED BY : VISHAL  KUMAR SRIVASTAVA                        
 --CREATED ON : 11 Sep 2017               
 -- SAVESMSWebAPI_sp 335 ,1,'PELSOFT','<ROOT><ROW MobileNo=''9811827632'' Message=''Hi'' Messagelen=''10''/><ROW MobileNo=''9811827632'' Message=''Hi''  Messagelen=''10''/></ROOT>',''               
--***************************************            
BEGIN TRY                
 BEGIN TRANSACTION    
     
    --Declare @ParentID bigint = 0    
    --Select  @ParentID = ParentID from User_detail where User_ID =  @UserId    
             
   --DECLARE @SMSDataXML1 VARCHAR(MAX)            
   --SET @SMSDataXML1 ='<ROOT><ROW MobileNo=''9811827632'' Message=''Hi'' Messagelen=''10''/><ROW MobileNo=''9811827632'' Message=''Hi''  Messagelen=''10''/></ROOT>'       
   DECLARE @handle  INT            
   DECLARE @TempData_tbl  TABLE            
   (            
    MobileNo VARCHAR(50),            
    Messages VARCHAR(MAX),      
    Messagelen BIGINT          
   )            
   EXEC sp_xml_preparedocument @handle OUTPUT, @SMSDataXML            
   INSERT INTO @TempData_tbl(MobileNo,Messages,Messagelen)            
   SELECT  tblU.MobileNo,tblU.Message,tblU.Messagelen            
   FROM OPENXML (@handle, 'ROOT/ROW', 1) WITH (MobileNo VARCHAR(50),Message VARCHAR(MAX),Messagelen BIGINT) tblU             
   EXEC sp_xml_removedocument @handle             
        
   -- SELECT * FROM @TempData_tbl            
   ----------------For Balance Check--------------------        
   DECLARE @MailCount BIGINT ;             
   SELECT @MailCount = COUNT(1) FROM   @TempData_tbl              
   DECLARE @CurrentBalance BIGINT = (              
             SELECT TOP 1 ISNULL(mcd.Balance,0)              
             FROM   Credit_Details AS mcd              
             WHERE  mcd.[User_ID] = @ParentID              
             ORDER BY            
                    mcd.Credit_ID DESC              
         )              
 DECLARE @Balance BIGINT = @CurrentBalance - @MailCount           
         
 --PRINT   @Balance       
 --------------------------------------------------------       
 IF(@Balance>0)      
  BEGIN        
  INSERT INTO GetBatchRecord                
  (                
  [User_id],                
  RandNum                
  )                
  VALUES                
  (                
  @UserId,                
  @UserId                
  )                      
      
  DECLARE @BatchID BIGINT = (                
   SELECT MAX(gbr.BatchID)                
   FROM  GetBatchRecord (nolock)AS gbr                
   WHERE  gbr.[User_id] = @UserId                
   )                    
  DELETE                 
   FROM   GetBatchRecord                
   WHERE  [User_id] = @UserId        
              
      
    CREATE TABLE #tempTable          
   (       
   BatchID BIGINT,      
   UserId BIGINT,          
   Mobile VARCHAR(100),        
   IsUniCode BIT,        
   Messagelen  BIGINT,          
   Message VARCHAR(MAX),           
   SenderName  VARCHAR(100)        
   )         
         
   INSERT INTO #tempTable(BatchID,UserId,Mobile,IsUniCode,Messagelen,Message,SenderName)          
   SELECT @BatchID,@UserId,MobileNo,@IsUniCode,Messagelen,Messages,@SenderName FROM @TempData_tbl          
      
   -- SELECT * FROM #tempTable          
      
   SELECT B.UserID,        
   CASE         
     WHEN B.Balance > B.Credits THEN 1        
     ELSE 0        
   END  AS ValidEntries        
           
   INTO #tempMobile        
    FROM   (        
    SELECT A.UserID,        
        SUM(        
         CAST(A.Credits AS BIGINT) + CASE (A.Credits % 1)        
               WHEN 0 THEN 0        
               ELSE 1        
                END       
        )  AS Credits,        
        A.Balance        
    FROM   (        
         SELECT tt.UserID,        
          (        
           CAST(tt.Messagelen AS DECIMAL(18, 2)) / CASE         
                       WHEN         
                      tt.IsUniCode         
                                                                                       
                      =        
                                                                                       
                      0 THEN         
                      160        
                       ELSE         
                      70        
                     END        
          ) * 1  AS Credits,        
          tt.Mobile,        
          tt.BatchID,        
          (        
           SELECT TOP 1 Balance        
           FROM   credit_details        
           WHERE  USER_ID = tt.UserID        
           ORDER BY        
            Credit_ID DESC        
          )      AS Balance        
         FROM   #tempTable tt        
        )     A        
    GROUP BY        
        A.UserID,        
        A.Balance        
   )       B        
      
  --  SELECT * FROM #tempMobile       
      
  -----------------------------------Entry in CloneMessageDeliveryStatus         
   INSERT INTO CloneMessageDeliveryStatus            
   (            
   -- MessageID -- this column value is auto-generated                  
   BatchID,            
   Mobile,            
   [Message],            
   MessageStatus,            
   SenderID,            
   MessageInsertDate,            
   ScheduledDate,            
   ScheduledTime,            
   SmppID,            
   U_ID,            
   IsUniCode,            
   IsDnd,            
   IsAirtel,            
   MobileSubSet,            
   ValidNo,            
   IsPrority,            
   IsAllowDND,            
   DBType,
   CMDS_CreatedBy            
   )         
   SELECT tt.BatchID  ,           
   tt.Mobile,        
   tt.Message,            
   NULL        AS MessageStatus,            
   tt.SenderName ,            
   GETDATE()   AS MessageInsertDate,            
   GETDATE()    AS ScheduledDate,            
   GETDATE()   AS ScheduledTime,            
   (            
   SELECT TOP 1 ud.SmppID            
   FROM   User_Detail AS ud            
   WHERE  ud.[User_ID] = @UserId            
   )           AS SmppID,            
   tt.UserId    AS U_ID,            
   tt.IsUniCode  AS IsUnicode,            
   0           AS IsDnd,            
   0           AS IsAirtel,            
   0           AS MobileSubSet,            
   1           AS ValidNo,            
   1           AS IsPrority,            
   0           AS IsAllowDND,            
   0           AS DBType,
   @UserId  as CMDS_CreatedBy                                
   FROM #tempTable tt       
   INNER JOIN #tempMobile tm        
     ON  tm.userID = tt.userID        
     AND ValidEntries = 1        
 SET @Error_msg ='Success'          
  END      
  ELSE      
   BEGIN      
    SET @Error_msg = 'Insufficient Balance'         
   END      
    DROP TABLE #tempTable          
    DROP TABLE #tempMobile      
        
  ----------------------------------------        
                     
 COMMIT TRANSACTION            
END TRY            
BEGIN CATCH            
 IF @@ERROR<>0             
 BEGIN            
  ROLLBACK TRANSACTION            
 END               
 SET @Error_msg = ERROR_MESSAGE()                     
END CATCH             
END   


GO

