)
as
Begin

   insert into Serv_Notification_Agent(ParentID,Activity_id,N_Sub,N_Body)
     (select ParentID,Activity_id,[subject],[Messagebody] from Serv_Activity_Mast where (Access = 0 or Access = 2) and ParentID = @ParentID and Activity_id not in ( select Activity_id from Serv_Notification_Agent where ParentID = @ParentID 
