/* ============================================================
   Procedure: [dbo].[Serv_AddAgentDetailsNotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_AddAgentDetailsNotification]  
(  
 @NotificationID bigint,  
 @EmailID nvarchar(200),  
 @LoginID nvarchar(200)  
)  
as  
Begin  
  Declare @VarLoginID  nvarchar(max) = '',@VarEmailID nvarchar(max) = ''
  select @VarLoginID = isnull(Login_ID,''),@VarEmailID = ISNULL(Email_ID,'')  From  Serv_Notification_Agent where Notification_ID = @NotificationID
   if(@VarLoginID <> '')
      Begin
        set @LoginID = @VarLoginID + ',' + @LoginID 
      End
      
   if(@VarEmailID <> '')
      Begin
        set @EmailID = @VarEmailID + ',' + @EmailID 
      End
   
 update Serv_Notification_Agent set Email_ID = @EmailID,Login_ID = @LoginID where  Notification_ID = @NotificationID;  
  select 'Agent Saved'         


End


GO

