        set @MobileNo = @VarMobileNo + ',' + @MobileNo     
      End    
       
   update Serv_SMS_Notification_Agent set Mobile_No = @MobileNo,Login_ID = @LoginID where  SMS_Notification_ID = @SMS_NotificationID;      
     select 'SMS Agent Saved'             
      
End


