CREATE   PROCEDURE [dbo].[Serv_AgentMastBinding] --335  
  (  
    @UserID int,  
    @groupid as int,  
    @opt as varchar(1)  
  )  
  as  
  Begin  
    if @groupid = 0 
    select 0 User_id,'ALL Agent' Login_id 
    union
  Select ud.User_id, ud.Login_id  from Serv_User_Detail ud  
  inner join Serv_Agent_Mast am  
  on am.Userid =ud.User_ID and   
  am.ParentId = ud.ParentID  
  where ud.ParentId = @UserID  order by User_id 
    
  if @groupid > 0 and @opt = '0' 
  select 0 User_id,'ALL Agent' Login_id 
    union 
 Select ud.User_id, ud.Login_id  from Serv_User_Detail ud  
  inner join Serv_Agent_Mast am  
  on am.Userid =ud.User_ID and   
  am.ParentId = ud.ParentID  
  where am.Group_id =  @groupid    order by User_id 
  
if @groupid > 0 and @opt = '1'  
 Select ud.User_id, ud.Login_id  from Serv_User_Detail ud  
  inner join Serv_Agent_Mast am  
  on am.Userid =ud.User_ID and   
  am.ParentId = ud.ParentID  
  where am.Userid =  @UserID  
  
    
  End


