/* ============================================================
   Procedure: [dbo].[Serv_Aoto_Dispatcher]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_Aoto_Dispatcher]   --1, 1, 841 , 0       
(          
@TResp_Rule_Id bigint,          
@Rule_Match_type int,          
@ticketid bigint ,          
@result int  output          
)          
          
AS          
BEGIN          
          
          
--declare @TResp_Rule_Id bigint= 1,          
--@Rule_Match_type int =1,          
--@ticketid bigint =5          
          
DECLARE @LoopCounter INT , @MaxId INT,           
        @fld_Name NVARCHAR(100), @Filter_Value NVARCHAR(100),          
        @Filter_Cond NVARCHAR(100)='',          
        @sqlstr as nvarchar(max)='' --, @result as int           
cReate table #tmp (rno int,ticketid bigint)          
declare @rcno as int        
if exists(select 1 FROM Serv_Ticket_Dispatch_Filter           
  where TResp_Rule_Id = @TResp_Rule_Id )          
 begin      
  SELECT @LoopCounter = min(tkt_filter_ID) , @MaxId = max(tkt_filter_ID)           
  FROM Serv_Ticket_Dispatch_Filter           
  where TResp_Rule_Id = @TResp_Rule_Id          
      
           
  declare @cond varchar(max)=''          
            
  WHILE(@LoopCounter IS NOT NULL          
     AND @LoopCounter <= @MaxId)          
  BEGIN          
     SELECT @fld_Name = ct.fldnm,@Filter_Cond = Filter_Cond, @Filter_Value = Filter_Value          
     FROM Serv_Ticket_Dispatch_Filter td          
     inner join Serv_Cond_TypeMaster ct          
     on ct.Description = td.Filter_Field          
     WHERE tkt_filter_ID = @LoopCounter           
     and TResp_Rule_Id = @TResp_Rule_Id          
            
            
            
   set @cond = ''+@Filter_Cond +'''' +@Filter_Value+''''          
   if @Filter_Cond = 'like'          
    set @cond = ' like '''+'%' +@Filter_Value+'%'''          
   if @Filter_Cond = 'Start with'          
    set @cond = ' like '''+'%' +@Filter_Value+''''          
    if @Filter_Cond = 'End with'          
    set @cond = ' like ''' +@Filter_Value+'%'''          
            
   declare @orcnd as varchar(Max) = ''          
   set @orcnd = @fld_Name +@cond          
   if @fld_Name = 'Company'          
   begin          
    set @orcnd = ' tm.'+@fld_Name +@cond          
   end          
            
   if @fld_Name = 'Subject or Desc'          
   begin          
    set @orcnd = ' ( Subject ' +@cond          
   +' or Description '+@cond+' )'          
   end          
           
            
             
  if (@Rule_Match_type = 0)          
  begin          
  if (@sqlstr ='')          
    set @sqlstr = ' and '+ @orcnd          
   else          
    set @sqlstr = @sqlstr+' and '+ @orcnd           
  end          
  else          
  begin          
  if (@sqlstr ='')          
   set @sqlstr =  ' and ('+ @orcnd          
  else          
    set @sqlstr = @sqlstr+' or '+ @orcnd          
  end          
           
            
    SET @LoopCounter  = @LoopCounter  + 1                  
 END          
           
 if (@Rule_Match_type = 1)          
  set @sqlstr = @sqlstr +')'          
           
            
 set @sqlstr = 'Select ROW_NUMBER() OVER(ORDER BY ticketid ASC) rno, tm.ticketid  from '          
  +'Serv_TicketMaster tm inner join Serv_User_Detail ud '+          
    ' on ud.User_id = tm.User_id '+          
    ' where tm.ticketid = '+ cast(@ticketid as varchar(20)) + @sqlstr          
           
           
        
 --select  ticketid into #tmp from serv_TicketMaster where 1=2          
           
           
 insert into #tmp EXECUTE (@sqlstr)          
         
       
end      
else      
begin      
insert into #tmp (rno ,ticketid )      
Select ROW_NUMBER() OVER(ORDER BY ticketid ASC) rno, tm.ticketid  from       
 Serv_TicketMaster tm inner join Serv_User_Detail ud       
 on ud.User_id = tm.User_id where ticketid = @ticketid      
      
end      
select @rcno= COUNT(*) from #tmp          
 set @result = 0      
       
if @rcno > 0          
           
Begin          
set @result = 1          
 DECLARE @Maxrow INT = 0 ,           
   @EmployeeName NVARCHAR(100);          
                   
          
 select *, ROW_NUMBER() OVER(ORDER BY ord_no ASC) rno into #tmpaction           
  from Serv_Ticket_Dispatch_Action          
   where TResp_Rule_Id = @TResp_Rule_Id          
            
 select  @LoopCounter = MIN(rno), @Maxrow= max(rno)          
 from #tmpaction            
            
  WHILE(@LoopCounter <= @Maxrow)          
  BEGIN         
   declare @actn as varchar(20), @act_val as varchar(20)          
   select @actn = Action,@act_val = Act_Value from #tmpaction           
   where rno = @LoopCounter          
            
   declare @Agent_id as bigint =0        
  declare @grpid as bigint =0, @ParentID as bigint =0,@user_id as bigint        
   select @user_id = user_id, @ParentID= ParentID from Serv_TicketMaster with(nolock) where TicketID = @ticketid           
             
          
             
             
   if @actn= 'Add Tag'          
   begin          
    update dbo.Serv_TicketMaster set Status=1, tkt_tag = @act_val          
    where TicketID = @ticketid          
   end          
            
   if @actn= 'Set Type as'          
   begin          
    update dbo.Serv_TicketMaster set Status=1, Ticket_type =           
    (select Type_ID  FROM Serv_TicketType_Mast where Type_Desc = @act_val)          
    where TicketID = @ticketid          
   end          
   if @actn= 'Assign to Agent'          
   begin          
         
  select @Agent_id=User_id, @ParentID= ParentID FROM Serv_User_Detail where Login_id = @act_val        
   update Serv_TicketHistory set TransferredTo =            
    (select User_id FROM Serv_User_Detail where Login_id = @act_val)          
    where TicketID = @ticketid          
              
    update dbo.Serv_TicketMaster set Status=1, AssignTo =           
    (select User_id FROM Serv_User_Detail where Login_id = @act_val)          
    where TicketID = @ticketid          
         exec serv_Raise_emailNotification_support @ticketid,@ParentID,0 , @Agent_id,@Agent_id,'Ticket Assigned to Agent','Agent'          
        -- exec serv_Raise_emailNotification @ticketid,@ParentID,@grpid , @user_id,@user_id,'Ticket Assigned to Group','Requester'          
   end          
   if @actn= 'Assign to Group'          
   begin          
      select @grpid =Groupid FROM Serv_Group_Mast with(nolock) where Group_Name = @act_val        
            
            
    update Serv_TicketHistory set Assign_Group = @grpid           
     where TicketID = @ticketid          
               
     update dbo.Serv_TicketMaster set Status=1, Assign_Group =           
     (select Groupid FROM dbo.Serv_Group_Mast where Group_Name = @act_val)          
     where TicketID = @ticketid         
             
         exec serv_Raise_emailNotification_support @ticketid,@ParentID,@grpid , @user_id,@user_id,'Ticket Assigned to Group','Agent'          
         exec serv_Raise_emailNotification_support @ticketid,@ParentID,@grpid , @user_id,@user_id,'Ticket Assigned to Group','Requester'          
   end          
   if @actn= 'Assign Product'          
   begin          
     update dbo.Serv_TicketMaster set Status=1, Product = @act_val          
     where TicketID = @ticketid          
   end          
   if @actn= 'Skip New Ticket email Notification'          
   begin          
     update dbo.Serv_TicketMaster set Status=1, skip_nticketmail = 1          
     where TicketID = @ticketid          
   end          
   if @actn = 'Set Priority As'          
   begin          
    update dbo.Serv_TicketMaster set Status=1, Priority =          
     (select Priority_ID FROM Serv_Priority_Mast where Priority_Desc = @act_val)          
     where TicketID = @ticketid          
             
    update Serv_TicketHistory set Status = @act_val           
    where TicketID = @ticketid          
   end          
   if @actn = 'Delete the Ticket'          
   begin          
    update dbo.Serv_TicketMaster set deleted = 1, Remarks = @act_val          
    where TicketID = @ticketid          
   end          
   if @actn = 'Set Ticket Status as'          
   begin          
    update Serv_TicketHistory set Status = @act_val           
     where TicketID in (select TicketID From #tmp)          
          
    update dbo.Serv_TicketMaster set Status =           
     (select Stat_ID FROM Serv_Ticket_Stat_Mast where Stat_Desc = @act_val)          
     where TicketID = @ticketid          
          
   if @act_val=4         
 exec serv_Raise_emailNotification_support @TicketID,@ParentID,0 , @User_ID,@User_ID,'Agent Solves the Ticket','Requester'        
        
 if @act_val=2         
 exec serv_Raise_emailNotification_support @TicketID,@ParentID,0 , @User_ID,@User_ID,'Agent Closes the Ticket','Requester'        
        
        
          
   end          
   if @actn = 'Mark as Spam'          
   begin          
    update dbo.Serv_TicketMaster set spam = 1, Remarks = @act_val          
     where TicketID = @ticketid          
   end          
   set @LoopCounter = @LoopCounter+1          
            
  end          
            
  --select * from #tmpaction          
  drop table #tmpaction          
 end          
       
drop table #tmp          
--select @result as rsult          
return @result          
end


GO

/* ============================================================
   Procedure: [dbo].[Serv_Aoto_Dispatcher_Support]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_Aoto_Dispatcher_Support]  
(                      
@TResp_Rule_Id bigint,                      
@Rule_Match_type int,                      
@ticketid bigint ,                      
@result int  output                      
)                      
AS                      
BEGIN                      
                      
DECLARE @LoopCounter INT , @MaxId INT,                       
        @fld_Name NVARCHAR(100), @Filter_Value NVARCHAR(100),                      
        @Filter_Cond NVARCHAR(100)='',                      
        @sqlstr as nvarchar(max)='' --, @result as int                       
cReate table #tmp (rno int,ticketid bigint)                      
declare @rcno as int                    
-- select * FROM Serv_Ticket_Dispatch_Filter where ParentID = 37540  
if exists(select 1 FROM Serv_Ticket_Dispatch_Filter where TResp_Rule_Id = @TResp_Rule_Id )  
 begin                  
  SELECT @LoopCounter = min(tkt_filter_ID) , @MaxId = max(tkt_filter_ID)                       
  FROM Serv_Ticket_Dispatch_Filter                       
  where TResp_Rule_Id = @TResp_Rule_Id                      
                       
  declare @cond varchar(max)=''                      
                        
  WHILE(@LoopCounter IS NOT NULL AND @LoopCounter <= @MaxId)                      
  BEGIN                      
	SELECT @fld_Name = ct.fldnm,@Filter_Cond = Filter_Cond, @Filter_Value = ltrim(rtrim(Filter_Value))
	FROM Serv_Ticket_Dispatch_Filter td inner join Serv_Cond_TypeMaster ct
	on ct.Description = td.Filter_Field and td.Filter_FldType = ct.opt
	WHERE tkt_filter_ID = @LoopCounter and TResp_Rule_Id = @TResp_Rule_Id
            
   set @cond = ''+@Filter_Cond +'''' +@Filter_Value+''''                      
   if @Filter_Cond = 'like'                      
    set @cond = ' like '''+'%' +@Filter_Value+'%'''                      
   if @Filter_Cond = 'End with'                      
    set @cond = ' like '''+'%' +@Filter_Value+''''                      
    if @Filter_Cond = 'Start with'                      
    set @cond = ' like ''' +@Filter_Value+'%'''                      
                        
   declare @orcnd as varchar(Max) = ''                      
   set @orcnd = @fld_Name +@cond                      
   if @fld_Name = 'Company'                      
   begin                      
    set @orcnd = ' tm.'+@fld_Name +@cond                      
   end                      
                        
   if @fld_Name = 'Subject or Desc'                      
   begin                      
    set @orcnd = ' ( Subject ' +@cond                      
   +' or Description '+@cond+' )'                      
   end                      
                         
 if @fld_Name = 'Priority'    
 begin      
  set @orcnd = ' ( Priority = ' + cast(isnull((select Priority_ID from Serv_Priority_Mast where Priority_Desc=@Filter_Value),0) as varchar) +' )'    
 end    
    
  if (@Rule_Match_type = 2)                      
  begin                      
  if (@sqlstr ='')                      
    set @sqlstr = ' and ('+ @orcnd                      
   else                      
    set @sqlstr = @sqlstr+' and '+ @orcnd                       
  end                      
  else                      
  begin                      
  if (@sqlstr ='')                      
   set @sqlstr =  ' and ('+ @orcnd                      
  else                      
    set @sqlstr = @sqlstr+' or '+ @orcnd                      
  end                      
                        
    SET @LoopCounter  = @LoopCounter  + 1                              
 END                      
                       
 --if (@Rule_Match_type = 1)                      
  set @sqlstr = @sqlstr +')'                      
                        
 set @sqlstr = 'Select top 1 ROW_NUMBER() OVER(ORDER BY ticketid ASC) rno, tm.ticketid  from '                      
  +'Serv_TicketMaster tm inner join Serv_User_Detail ud '+                      
    ' on ud.ser_user_id = tm.User_id '+                      
    ' where tm.ticketid = '+ cast(@ticketid as varchar(20)) + @sqlstr                      
      
 print @sqlstr      
  --set @sqlstr = 'Select ROW_NUMBER() OVER(ORDER BY ticketid ASC) rno, tm.ticketid  from '                      
  --+'Serv_TicketMaster tm '+                      
  --  ' where tm.ticketid = '+ cast(@ticketid as varchar(20)) + @sqlstr                      
      
                       
 insert into #tmp EXECUTE (@sqlstr)                      
                   
end                  
else                  
begin                  
insert into #tmp (rno ,ticketid )                  
Select ROW_NUMBER() OVER(ORDER BY ticketid ASC) rno, tm.ticketid  from                   
 Serv_TicketMaster tm inner join Serv_User_Detail ud                   
 on ud.ser_user_id = tm.User_id where ticketid = @ticketid                  
                  
end                  
  
select @rcno= COUNT(*) from #tmp                      
 set @result = 0                  
                   
if @rcno > 0                      
Begin                      
set @result = 1                      
 DECLARE @Maxrow INT = 0 , @EmployeeName NVARCHAR(100);                      
                               
                      
 select *, ROW_NUMBER() OVER(ORDER BY ord_no ASC) rno into #tmpaction                       
  from Serv_Ticket_Dispatch_Action  
   where TResp_Rule_Id = @TResp_Rule_Id                      
  
-- select * from Serv_Ticket_Dispatch_Action where parentid=37540  
 select  @LoopCounter = MIN(rno), @Maxrow= max(rno) from #tmpaction  
                        
  WHILE(@LoopCounter <= @Maxrow)                      
  BEGIN                     
   declare @actn as varchar(20), @act_val as varchar(20)                      
   select @actn = Action,@act_val = Act_Value from #tmpaction                       
   where rno = @LoopCounter                      
                        
   declare @Agent_id as bigint =0, @AssignTo bigint=0, @AssignGroup bigint=0
  declare @grpid as bigint =0, @ParentID as bigint =0,@user_id as bigint                    
   select @user_id = user_id, @ParentID= ParentID, @AssignTo=isnull(AssignTo,0), @AssignGroup=isnull(Assign_Group,0)
   from Serv_TicketMaster with(nolock) 
   where TicketID = @ticketid
   --------------------------------------------------------------------------------------
   if @actn= 'Add Tag'                      
   begin                      
    update dbo.Serv_TicketMaster set Status=1, tkt_tag = @act_val                      
    where TicketID = @ticketid                      
   end                      
   if @actn= 'Set Type as'                      
   begin                      
    update dbo.Serv_TicketMaster set Status=1, Ticket_type =                       
    (select Type_ID  FROM Serv_TicketType_Mast where Type_Desc = @act_val)                      
    where TicketID = @ticketid                      
   end                      

   If(@AssignTo=0 and @AssignGroup=0)
   Begin
	   if @actn= 'Assign to Agent'
	   begin
		select @Agent_id=ser_user_id, @ParentID= ParentID FROM Serv_User_Detail where Login_id = @act_val

		update Serv_TicketHistory set TransferredTo = @Agent_id
		--(select ser_user_id FROM Serv_User_Detail where Login_id = @act_val)
		where TicketID = @ticketid

		update dbo.Serv_TicketMaster set Status=1, AssignTo = @Agent_id
		--(select ser_user_id FROM Serv_User_Detail where Login_id = @act_val)
		where TicketID = @ticketid

		exec serv_Raise_emailNotification_support1 @ticketid,@ParentID,0 , @user_id,@Agent_id,'Ticket Assigned to Agent','Agent'
		--exec serv_Raise_emailNotification @ticketid,@ParentID,@grpid , @user_id,@user_id,'Ticket Assigned to Group','Requester'
		--exec serv_Raise_emailNotification_support1 @ticketid,@ParentID,0 , @user_id,@Agent_id,'New Ticket Created','Requester'
	   end                      
	   
	   if @actn= 'Assign to Group'
	   begin                      
			select @grpid =Groupid FROM Serv_Group_Mast with(nolock) where Group_Name = @act_val and Parentid=@ParentID   
                        
			update Serv_TicketHistory set Assign_Group = @grpid where TicketID = @ticketid                      
                   
			update dbo.Serv_TicketMaster set Status=1, Assign_Group = @grpid  
			--(select Groupid FROM dbo.Serv_Group_Mast where Group_Name = @act_val)                      
			where TicketID = @ticketid                     
  
			select top 1 @Agent_id=UserId from Serv_Agent_Mast where parentid=@ParentID and Group_id=@grpid and Access_Level='All Group'  
                         
			exec serv_Raise_emailNotification_support1 @ticketid,@ParentID,@grpid , @user_id,@Agent_id,'Ticket Assigned to Group','Agent'  
                      
			--exec serv_Raise_emailNotification_support1 @ticketid,@ParentID,@grpid , @user_id,@Agent_id,'New Ticket Created','Requester'  
	   end                      
   End

   if @actn= 'Assign Product'                      
   begin                      
     update dbo.Serv_TicketMaster set Status=1, Product = @act_val                      
     where TicketID = @ticketid                      
   end                      
   if @actn= 'Skip New Ticket email Notification'                      
   begin                      
     update dbo.Serv_TicketMaster set Status=1, skip_nticketmail = 1                      
     where TicketID = @ticketid                      
   end                      
   if @actn = 'Set Priority As'                      
   begin                      
    update dbo.Serv_TicketMaster set Status=1, Priority =                      
     (select Priority_ID FROM Serv_Priority_Mast where Priority_Desc = @act_val)                      
     where TicketID = @ticketid                      
                         
    update Serv_TicketHistory set Status = 1, Priority =                      
     (select Priority_ID FROM Serv_Priority_Mast where Priority_Desc = @act_val)                       
    where TicketID = @ticketid                      
   end                      
   if @actn = 'Delete the Ticket'                      
   begin                      
    update dbo.Serv_TicketMaster set deleted = 1, Remarks = @act_val                      
    where TicketID = @ticketid                      
   end                      
   if @actn = 'Set Ticket Status as'                      
  begin                      
    update Serv_TicketHistory set Status = (select Stat_ID FROM Serv_Ticket_Stat_Mast where Stat_Desc = @act_val)  
     where TicketID in (select TicketID From #tmp)                      
                      
    update dbo.Serv_TicketMaster set Status =                       
     (select Stat_ID FROM Serv_Ticket_Stat_Mast where Stat_Desc = @act_val)                      
     where TicketID = @ticketid                      
                      
 if @act_val=4                     
  exec serv_Raise_emailNotification_support1 @TicketID,@ParentID,0 , @User_ID,@User_ID,'Agent Solves the Ticket','Requester'                    
                    
 if @act_val=2                     
  exec serv_Raise_emailNotification_support1 @TicketID,@ParentID,0 , @User_ID,@User_ID,'Agent Closes the Ticket','Requester'                    
   end                      
   if @actn = 'Mark as Spam'                      
   begin                      
    update dbo.Serv_TicketMaster set spam = 1, Remarks = @act_val                      
     where TicketID = @ticketid                      
   end                      
   set @LoopCounter = @LoopCounter+1                      
                        
  end                      
                        
  --select * from #tmpaction                      
  --drop table #tmpaction                      
if object_id('tempdb..#tmpaction') is not null begin drop table #tmpaction end      
 end                      
                   
--drop table #tmp                      
if object_id('tempdb..#tmp') is not null begin drop table #tmp end      
--select @result as rsult                      
return @result                      
end         



GO

/* ============================================================
   Procedure: [dbo].[Serv_Aoto_Ticket_Dispatch]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_Aoto_Ticket_Dispatch]
(
@TResp_Rule_Id bigint,
@Rule_Match_type int,
@ParentID bigint,
@ticketid bigint
)

AS
BEGIN


DECLARE @LoopCounter INT , @MaxId INT, 
        @fld_Name NVARCHAR(100), @Filter_Value NVARCHAR(100),
        @Filter_Cond NVARCHAR(100),
        @sqlstr as nvarchar(max) 

SELECT @LoopCounter = min(tkt_filter_ID) , @MaxId = max(tkt_filter_ID) 
FROM Serv_Ticket_Dispatch_Filter 
where TResp_Rule_Id = @TResp_Rule_Id
select @sqlstr= ''

WHILE(@LoopCounter IS NOT NULL
      AND @LoopCounter <= @MaxId)
BEGIN
   SELECT @fld_Name = ct.fldnm,@Filter_Cond = Filter_Cond, @Filter_Value = Filter_Value
   FROM Serv_Ticket_Dispatch_Filter td
   inner join Serv_Cond_TypeMaster ct
   on ct.Description = td.Filter_Field
   WHERE tkt_filter_ID = @LoopCounter 
   and TResp_Rule_Id = @TResp_Rule_Id

	declare @cond varchar(max)=''

	set @cond = ''+@Filter_Cond +'''' +@Filter_Value+''''
	if @Filter_Cond = 'like'
		set @cond = ' like '''+'%' +@Filter_Value+'''%'
	if @Filter_Cond = 'Start with'
		set @cond = ' like '''+'%' +@Filter_Value+''''
	 if @Filter_Cond = 'End with'
		set @cond = ' like '''+'%' +@Filter_Value+'''%'

	declare @orcnd as varchar(Max) = ''
	set @orcnd = @fld_Name +@cond
	if @fld_Name = 'Company'
	begin
		set @orcnd = ' tm.'+@fld_Name +@cond
	end

	if @fld_Name = 'Subject or Desc'
	begin
		set @orcnd = ' ( Subject ' +@cond
				+' or Description '+@cond+' )'
	end

	
	 
	if (@Rule_Match_type = 0)
	begin
	if (@sqlstr ='')
			set @sqlstr = ' and '+ @orcnd
		else
			set @sqlstr = @sqlstr+' and '+ @orcnd	
	end
	else
	begin
	if (@sqlstr ='')
		set @sqlstr = ' and ('+ @orcnd
	else
			set @sqlstr = @sqlstr+' or '+ @orcnd
	end

	
   SET @LoopCounter  = @LoopCounter  + 1        
END
if (@Rule_Match_type = 1)
	set @sqlstr = @sqlstr +')'
	
set @sqlstr = 'Select ROW_NUMBER() OVER(ORDER BY ticketid ASC) rno, tm.ticketid  from Serv_TicketMaster tm inner join Serv_User_Detail ud '+
			' on ud.User_id = tm.User_id '+
			--' where   isnull(tm.spam,0) =0 and isnull(tm.deleted,0) =0 ' --+ @sqlstr
			' where tm.ParentID = '+ cast(@ParentID as varchar(20)) + ' and ' +
			' isnull(tm.Status,0) = 0 and isnull(tm.spam,0) =0 and isnull(tm.deleted,0) =0 ' 
			--+ @sqlstr
 cReate table #tmp (rno int,ticketid bigint)
--select  ticketid into #tmp from serv_TicketMaster where 1=2


insert into #tmp EXECUTE (@sqlstr)
select * from #tmp
declare @rcno as int
select @rcno= COUNT(*) from #tmp
if @rcno > 0
Begin


DECLARE @Maxrow INT = 0 , 
        @EmployeeName NVARCHAR(100);
        
with cte_action 
as
(
select *, ROW_NUMBER() OVER(ORDER BY ord_no ASC) rno from Serv_Ticket_Dispatch_Action
where TResp_Rule_Id = @TResp_Rule_Id
) 
select * into #tmpaction from cte_action;

 
select  @LoopCounter = MIN(rno), @Maxrow= max(rno)
from #tmpaction  
	WHILE(@LoopCounter <= @Maxrow)
	BEGIN
	declare @actn as varchar(20), @act_val as varchar(20)
	select @actn = Action,@act_val = Act_Value from #tmpaction 
	where rno = @LoopCounter
	
	select @actn,@act_val
	if @actn= 'Add Tag'
	begin
		update dbo.Serv_TicketMaster set Status=1, tkt_tag = @act_val
		where TicketID in (select TicketID From #tmp)
	end
	
	if @actn= 'Set Type as'
	begin
		update dbo.Serv_TicketMaster set Status=1, Ticket_type = 
		(select Type_ID  FROM Serv_TicketType_Mast where Type_Desc = @act_val)
		where TicketID in (select TicketID From #tmp)
	end
	if @actn= 'Assign to Agent'
	begin
	update Serv_TicketHistory set TransferredTo =  
		(select User_id FROM Serv_User_Detail where Login_id = @act_val)
		where TicketID in (select TicketID From #tmp)
		
	 update dbo.Serv_TicketMaster set Status=1, AssignTo = 
		(select User_id FROM Serv_User_Detail where Login_id = @act_val)
		where TicketID in (select TicketID From #tmp)
	end
	if @actn= 'Assign to Group'
	begin
	
	update Serv_TicketHistory set Assign_Group = 
	(select Groupid FROM dbo.Serv_Group_Mast where Group_Name = @act_val) 
		where TicketID in (select TicketID From #tmp)
		
	 update dbo.Serv_TicketMaster set Status=1, Assign_Group = 
		(select Groupid FROM dbo.Serv_Group_Mast where Group_Name = @act_val)
		where TicketID in (select TicketID From #tmp)
	end
	if @actn= 'Assign Product'
	begin
	
	 update dbo.Serv_TicketMaster set Status=1, Product = @act_val
		where TicketID in (select TicketID From #tmp)
	end
	if @actn= 'Skip New Ticket email Notification'
	begin
	
	 update dbo.Serv_TicketMaster set Status=1, skip_nticketmail = 1
		where TicketID in (select TicketID From #tmp)
	end
	if @actn = 'Set Priority As'
	begin
	
	update dbo.Serv_TicketMaster set Status=1, Priority =
	(select Priority_ID FROM Serv_Priority_Mast where Priority_Desc = @act_val)
		where TicketID in (select TicketID From #tmp)
	
		update Serv_TicketHistory set Status = @act_val 
		where TicketID in (select TicketID From #tmp)
	end
	if @actn = 'Delete the Ticket'
	begin
	
	update dbo.Serv_TicketMaster set deleted = 1, Remarks = @act_val
	where TicketID in (select TicketID From #tmp)
	end
	if @actn = 'Set Ticket Status as'
	begin
	update Serv_TicketHistory set Status = @act_val 
		where TicketID in (select TicketID From #tmp)
	update dbo.Serv_TicketMaster set Status = 
	(select Stat_ID FROM Serv_Ticket_Stat_Mast where Stat_Desc = @act_val)
		where TicketID in (select TicketID From #tmp)
	end
	if @actn = 'Mark as Spam'
	begin
	
	update dbo.Serv_TicketMaster set spam = 1, Remarks = @act_val
		where TicketID in (select TicketID From #tmp)
	end


	
	set @LoopCounter = @LoopCounter+1
	
	end
	--select * from #tmpaction
	drop table #tmpaction
end
--select * from #tmp
select @sqlstr
drop table #tmp
END


GO

/* ============================================================
   Procedure: [dbo].[Serv_apply_slarule]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_apply_slarule] --8,7,0  
(      
 @TicketID bigint,     
 @SLAId bigint,    
 @result int output    
      
)      
as      
Begin      
--drop table #tmprule    
--drop table #tkttmp    
--declare @TicketID bigint,     
-- @SLAId bigint    
     
 --set @TicketID = 8    
 --set @SLAId =7    
select *,ROW_NUMBER() over (Order by appl_id) rno into #tmprule from  Serv_SLA_ApplyRule    
where SLAId = @SLAId    
    
declare @stno as int, @enno as int    
    
declare @sqlstr as varchar(max), @condstr as varchar(max)    
set @condstr =''    
    
set @sqlstr = 'Select * from dbo.Serv_TicketMaster where ticketid = '     
+ cast(@TicketID as varchar(20))    
 +' and ('    
    
    
    
    
--select @sqlstr     
select @stno =MIN(rno) , @enno = MAX(rno) from #tmprule    
while @stno <= @enno    
begin    
 declare @Apply_to varchar(100), @Apply_val varchar(100)    
 select @Apply_to =Apply_to, @Apply_val=Apply_val     
  from #tmprule where rno = @stno    
     
     
     
 if @Apply_to = 'Company'    
  if @condstr = ''    
   set @condstr =  ' Company like '''+'%' +@Apply_val+'%'''    
  else    
   set @condstr = @condstr + ' or Company like '''+'%' +@Apply_val+'%'''    
 if @Apply_to = 'Source'    
  if @condstr = ''    
   set @condstr =  ' Source like '''+'%' +@Apply_val+'%'''    
  else    
   set @condstr = @condstr + ' or Source like '''+'%' +@Apply_val+'%'''    
 if @Apply_to = 'Product'    
  if @condstr = ''    
   set @condstr =  ' Product like '''+'%' +@Apply_val+'%'''    
  else    
   set @condstr = @condstr + ' or Product like '''+'%' +@Apply_val+'%'''    
       
 if @Apply_to = 'Type'    
  if @condstr = ''    
   set @condstr =  ' Ticket_type ='    
   +'(select Type_ID  FROM Serv_TicketType_Mast where Type_Desc =''' +@Apply_val +''')'     
  else    
   set @condstr = @condstr + ' or Ticket_type ='+    
   '(select Type_ID  FROM Serv_TicketType_Mast where Type_Desc =''' +@Apply_val +''')'     
 if @Apply_to = 'Group'    
     
  if @condstr = ''    
   set @condstr =  ' Assign_Group ='    
   +'(select Groupid FROM dbo.Serv_Group_Mast where Group_Name =''' +@Apply_val +''')'     
  else    
   set @condstr = @condstr + ' or Assign_Group ='+    
   '(select Groupid FROM dbo.Serv_Group_Mast where Group_Name =''' +@Apply_val +''')'     
    
set @stno = @stno+1    
end     
    
    
set @sqlstr =  @sqlstr+ @condstr+' )'    

--select @sqlstr 
    
set @result = 0    
 create table #tkttmp     
 (    
 [TicketID] [bigint] NULL,    
 [User_id] [bigint] NULL,    
 [ParentID] [bigint] NOT NULL,    
 [TicketNo] [nvarchar](16) NULL,    
 [Requester] [nvarchar](100) NULL,    
 [Subject] [nvarchar](250) NULL,    
 [Description] [nvarchar](max) NULL,    
 [Status] [tinyint] NULL,    
 [Remarks] [nvarchar](max) NULL,    
 [Note] [nvarchar](max) NULL,    
 [Date_Created] [datetime] NULL,    
 [Priority] [tinyint] NULL,    
 [AssignTo] [bigint] NULL,    
 [Assign_Group] [bigint] NULL,    
 [UserResponse] [nvarchar](max) NULL,    
 [Active] [tinyint] NULL,    
 [Ticket_type] [int] NULL,    
 [ARemindRSPNSSent] [bit] NULL,    
 [ARemindResolveSent] [bit] NULL,    
 [ARSPSent] [bit] NULL,    
 [A1RSLSent] [bit] NULL,    
 [A2RSLSent] [bit] NULL,    
 [A3RSLSent] [bit] NULL,    
 [A4RSLSent] [bit] NULL,    
 [Source] [nvarchar](200) NULL,    
 [Product] [nvarchar](200) NULL,    
 [Company] [nvarchar](200) NULL,    
 [EmailId] [nvarchar](200) NULL,    
 [domain] [nvarchar](200) NULL,    
 [spam] [bit] NULL,    
 [deleted] [bit] NULL,    
 [skip_nticketmail] [bit] NULL, 
 [tkt_tag] nvarchar(250) null
 )     
 insert into #tkttmp exec (@sqlstr)    
 --select * from #tkttmp    
 set @result = 0
 if exists( select * from #tkttmp)
 begin   
	  
	  /* Start Creation of batchid */
	    DECLARE @Random INT;
		DECLARE @Upper INT;
		DECLARE @Lower INT
		Declare @User_ID bigint 
		Declare @BatchID bigint
		
		
		---- This will create a random number between 1 and 999
		SET @Lower = 1 ---- The lowest random number
		SET @Upper = 10000 ---- The highest random number
		SELECT @Random = ROUND(((@Upper - @Lower -1) * RAND() + @Lower), 0)
		--SELECT @Random
	    
	    select @User_ID = USER_ID   from #tkttmp   
	    insert into GetBatchRecord (User_id,RandNum)        
        values(@User_ID,@Random)        
    select @BatchID = max(BatchID)  from GetBatchRecord With (Nolock) where User_id=@User_ID and RandNum=@Random        
        delete from GetBatchRecord  where User_id=@User_ID and RandNum=@Random 
	    
	  /* End Creation of batchid */
	
	
	
	 declare @ARemindRSPNSSent bit, @ARSPSent bit, @ARemindResolveSent bit,    
	 @A1RSLSent bit,@A2RSLSent bit, @A3RSLSent bit, @A4RSLSent as bit,  
	 @Date_Created datetime ,@ParentID Bigint,@Priority tinyint ,@Subject nvarchar(100);
	     
	     
	      
	     
	 select @ARemindRSPNSSent=ARemindRSPNSSent, @ARSPSent = ARSPSent ,    
	 @ARemindResolveSent = ARemindResolveSent,@A1RSLSent = A1RSLSent ,    
	 @A2RSLSent=A2RSLSent, @A3RSLSent=A3RSLSent, @A3RSLSent=A3RSLSent ,@Date_Created = Date_Created  
	 ,@ParentID = ParentID,@Priority = Priority ,@Subject = Subject   
	 from #tkttmp      
	  
	  Declare @ToEmailID nvarchar(200) = '',@FromMailID nvarchar(200) = '' 
	     
	 if  exists(select 1 from dbo.Serv_SLA_Response rs    
	 inner join #tkttmp tm on tm.Priority = rs.Priority_ID    
	 where  SLAId = @SLAId and Escalation_email = 1)    
	 begin   
	     
	 	  
		 if not exists(select 1 from dbo.Serv_TicketHistory     
			  where TicketID = @TicketID and Ticket_Response = 1)    
		begin    
		 
		     
		 
		 if @ARemindRSPNSSent = 0  
			Begin 
	   /* Start Remind rspns sent */
		
		 --select ''
			   
   Declare @resp_assigned int,@RespondSecond int, @resp_Remind_Freq nvarchar(200)='',@RespRemindSeconds int = 0;
	              		    
   select @resp_Remind_Freq = resp_remind_freq,@RespondSecond =Respond_Sec , @resp_assigned = resp_assignd  from Serv_SLA_Response(nolock)
			  where SLAID = @SLAId and ParentID = @ParentID and Priority_ID = @Priority     
     
			    
			    select @RespRemindSeconds = val_sec from Serv_SLA_Freq where Freq_Desc = @resp_Remind_Freq
			     
      if(DATEDIFF(second, DATEADD(SECOND,@RespRemindSeconds,GETDATE()),@Date_Created) < @RespondSecond)  
				  Begin  
		     	--Process to send mail 
			     select @FromMailID = isnull(Email,'')  From User_Detail where USER_ID = @resp_assigned  
				 select @ToEmailID = isnull(Email,'')  From User_Detail where USER_ID = @User_ID  	
					
			  
					
	           insert into CloneEmailsFilter(
	             Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName
                 ,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID
                 ,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime
                 ,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source
	               
	              )
	              values( @FromMailID,@ToEmailID,@Subject,'','Under Your before respond time , plz give response', GETDATE(),@resp_assigned,@ParentID,'noreply@kit19.com',@BatchID,2,'','','','Under Your before respond time ,plz give response',1,0,1,'TicketManagement'
	              
	              ) 									
					   
				   insert into Serv_ProcessedTicketDetails(TicketID,SLAID,Subject,ActionPerformed)   
				   values(@TicketID,@SLAId,@Subject,'Before Remind Respond')  
				   update Serv_TicketMaster set ARemindRSPNSSent =1 where TicketID = @TicketID  
					set @result = 1
				  end     
			        
				 end
			   
			   
			   /* End Remind rspns sent */  
			
			End 
		 if @result = 1
		   begin
			return @result;
		   end	
			    
		  if @ARSPSent = 0    
			 Begin
		 	 
		   --Process to send mail    
			   Declare @Assign_Agent int,@resp_Freq nvarchar(200)='',@RespSeconds int = 0;
	              		    
             select @resp_Freq = resp_Freq,@Assign_Agent = Assign_Agent  from Serv_SLA_Response(nolock)
			  where SLAID = @SLAId and ParentID = @ParentID and Priority_ID = @Priority     
     
			    
			    select @RespSeconds = val_sec from Serv_SLA_Freq where Freq_Desc = @resp_Freq
			    
			     
			     
			   if(DATEADD(SECOND,@RespSeconds,@Date_Created) < GETDATE())  
				  Begin  
				  
				  
				  
		     	--Process to send mail 
			     select @FromMailID = isnull(Email,'')  From User_Detail where USER_ID = @Assign_Agent  
				 select @ToEmailID = isnull(Email,'')  From User_Detail where USER_ID = @User_ID  	
					
			   --select @Assign_Agent, @BatchID		
					
	           insert into CloneEmailsFilter(
	             Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName
                 ,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID
                 ,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime
                 ,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source
	               
	              )
	              values( @FromMailID,@ToEmailID,@Subject,'','Your after respond time has been over, plz give response', GETDATE(),@Assign_Agent,@ParentID,'noreply@kit19.com',@BatchID,2,'','','','Your after respond time has been over,plz give response',1,0,1,'TicketManagement'
	              
	              ) 									
					   
				   insert into Serv_ProcessedTicketDetails(TicketID,SLAID,Subject,ActionPerformed)   
				   values(@TicketID,@SLAId,@Subject,'After Respond')  
				   update Serv_TicketMaster set ARSPSent =1 where TicketID = @TicketID  
					set @result = 1
				  end     
			        
				 end
		end
		if  @result = 1
			return @result;
		if @ARemindResolveSent =0  
				  Begin
			         /* start before remind resolve */
				       
    Declare @resolution_assignd int,@resolve_Sec int, @resolution_Remind_Freq nvarchar(200)='',@ResolutionRemindSeconds int = 0;
	              		    
   select @resolution_Remind_Freq = resolution_remind_freq,@resolve_Sec =resolve_Sec , @resolution_assignd = resolution_assignd  from Serv_SLA_Response(nolock)
			  where SLAID = @SLAId and ParentID = @ParentID and Priority_ID = @Priority     
     
			    
			    select @ResolutionRemindSeconds = val_sec from Serv_SLA_Freq where Freq_Desc = @resolution_Remind_Freq
			     
      if(DATEDIFF(second, DATEADD(SECOND,@ResolutionRemindSeconds,GETDATE()),@Date_Created) < @resolve_Sec)  
				  Begin  
		     	--Process to send mail 
			     select @FromMailID = isnull(Email,'')  From User_Detail where USER_ID = @resolution_assignd  
				 select @ToEmailID = isnull(Email,'')  From User_Detail where USER_ID = @User_ID  	
					
			   -- select @resolution_assignd, @BatchID		
					
	           insert into CloneEmailsFilter(
	             Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName
                 ,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID
                 ,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime
                 ,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source
	               
	              )
	              values( @FromMailID,@ToEmailID,@Subject,'','Under Your before resolve time , plz give response', GETDATE(),@resolution_assignd,@ParentID,'noreply@kit19.com',@BatchID,2,'','','','Under Your before resolve time ,plz give response',1,0,1,'TicketManagement'
	              
	              ) 									
					   
				   insert into Serv_ProcessedTicketDetails(TicketID,SLAID,Subject,ActionPerformed)   
				   values(@TicketID,@SLAId,@Subject,'Before Remind Resolve')  
				   update Serv_TicketMaster set ARemindResolveSent =1 where TicketID = @TicketID  
					set @result = 1
				  end     
			        
				
				       
				     /* stop before remind resolve */
				  end
		if  @result = 1
			return @result;
		
		
	declare @MailMSG nvarchar(500) = ''	
	declare @TicketProcessMSG nvarchar(200) = ''	
			
  if @A1RSLSent = 0
    Begin   
        /* Start Escalation resolve1  sent */
        	        
     set @MailMSG  = ' Ticket ID : '+CAST(@TicketID as varchar)+' Your escalation resolve time is over please give response';
     set @TicketProcessMSG  = 'Escalation Resolved action1'; 	  
        	        
	    exec Serv_EscalationRuleAction  @User_ID,@ParentID,@SLAId,'1',@BatchID,@Date_Created,
        @Subject,@MailMsg,@TicketID,@TicketProcessMSG,'A1RSLSent',@result output		        
        
        /* End Escalation resolve1  sent */
    End 
       
  else if @A2RSLSent =0
    Begin    
        /* Start Escalation resolve2  sent */
        	        
     set @MailMSG  = ' Ticket ID : '+CAST(@TicketID as varchar)+' Your escalation resolve time is over please give response';
     set @TicketProcessMSG  = 'Escalation Resolved action2'; 	  
        	        
	    exec Serv_EscalationRuleAction  @User_ID,@ParentID,@SLAId,'2',@BatchID,@Date_Created,
        @Subject,@MailMsg,@TicketID,@TicketProcessMSG,'A2RSLSent',@result output		        
        
        /* End Escalation resolve2  sent */
    End    
  else if @A3RSLSent =0
   Begin    
      
      /* Start Escalation resolve3  sent */
         	        
     set @MailMSG  = ' Ticket ID : '+CAST(@TicketID as varchar)+' Your escalation resolve time is over please give response';
     set @TicketProcessMSG  = 'Escalation Resolved action3'; 	  
        	        
	    exec Serv_EscalationRuleAction  @User_ID,@ParentID,@SLAId,'3',@BatchID,@Date_Created,
        @Subject,@MailMsg,@TicketID,@TicketProcessMSG,'A3RSLSent',@result output		        
        
        /* Start Escalation resolve3  sent */
        
  
   End    
  else if @A4RSLSent =0    
   Begin
   /* Start Escalation resolve4  sent */
         	        
  set @MailMSG  = ' Ticket ID : '+CAST(@TicketID as varchar)+' Your escalation resolve time is over please      give response';
     set @TicketProcessMSG  = 'Escalation Resolved action4'; 	  
        	        
	    exec Serv_EscalationRuleAction  @User_ID,@ParentID,@SLAId,'4',@BatchID,@Date_Created,
        @Subject,@MailMsg,@TicketID,@TicketProcessMSG,'A4RSLSent',@result output		        
        
        /* Start Escalation resolve4  sent */
     End
      
   if  @result = 1
    return @result;
   
   end 
  end    
 --end     
     
    
--select * from dbo.Serv_TicketHistory     
--  where TicketID = @TicketID    
     
                                
--End 
--end
--End


GO

