CREATE   PROCEDURE [dbo].[Serv_apply_slarule_FurtherUse] --8,7,0                  
(                      
@TicketID bigint,  
@SLAId bigint,  
@result int output  
)                      
as                      
Begin           
-- declare @TicketID bigint=41815,@SLAId bigint=767,@result int drop table #tmprule drop table #tkttmp  
  
Declare @TimelyDateID Bigint  = 0,@Parent_ID bigint=0  
  
select @Parent_ID=ParentID from serv_Ticketmaster(nolock) where ticketid=@TicketID  
  
select *,ROW_NUMBER() over (Order by appl_id) rno into #tmprule from  Serv_SLA_ApplyRule                    
where SLAId = @SLAId                    
            
-- select * from Serv_SLA_ApplyRule where parent_id=32222  
                    
declare @stno as int, @enno as int                    
                    
declare @sqlstr as varchar(max), @condstr as varchar(max)                    
set @condstr =''                    
                    
set @sqlstr = 'Select TicketID,User_id,ParentID,TicketNo,Requester,Subject,Description,Status,Remarks,Note,Date_Created,Priority,    AssignTo,Assign_Group,UserResponse,Active,Ticket_type,ARemindRSPNSSent,ARemindResolveSent,ARSPSent,A1RSLSent,A2RSLSent,   
   A3RSLSent,A4RSLSent,agrp_unassigned,Source,Product,Company,EmailId,domain,spam,deleted,skip_nticketmail,tkt_tag,resolved_dt,   Assignedby,AssignedDateTime from dbo.Serv_TicketMaster where ticketid = '        
    + cast(@TicketID as varchar(20)) +' and ('                    
                    
                   
                    
--select @sqlstr                     
select @stno =MIN(rno) , @enno = MAX(rno) from #tmprule                    
while @stno <= @enno                    
begin                    
 declare @Apply_to varchar(100), @Apply_val varchar(100)                    
 select @Apply_to =Apply_to, @Apply_val=Apply_val                     
  from #tmprule where rno = @stno                    
                     
                     
                     
 if @Apply_to = 'Company'                    
  if @condstr = ''                    
   set @condstr =  ' Company like '''+'%' +@Apply_val+'%'''                    
  else                    
   set @condstr = @condstr + ' or Company like '''+'%' +@Apply_val+'%'''                    
 if @Apply_to = 'Source'                    
  if @condstr = ''                    
   set @condstr =  ' Source like '''+'%' +@Apply_val+'%'''                    
  else                    
   set @condstr = @condstr + ' or Source like '''+'%' +@Apply_val+'%'''                    
 if @Apply_to = 'Product'                    
  if @condstr = ''                    
   set @condstr =  ' Product like '''+'%' +@Apply_val+'%'''                    
  else                    
   set @condstr = @condstr + ' or Product like '''+'%' +@Apply_val+'%'''                    
  
 if @Apply_to = 'Type'                    
  if @condstr = ''                    
   set @condstr =  ' Ticket_type ='                    
   +'(select Type_ID  FROM Serv_TicketType_Mast where Type_Desc =''' +@Apply_val +''')'                     
  else                    
   set @condstr = @condstr + ' or Ticket_type ='+                    
   '(select Type_ID  FROM Serv_TicketType_Mast where Type_Desc =''' +@Apply_val +''')'                     
  
 if @Apply_to = 'Group'                    
  if @condstr = ''                    
   set @condstr =  ' Assign_Group ='                    
   +'(select top 1 Groupid FROM dbo.Serv_Group_Mast where ParentId='+cast(@Parent_ID as varchar)+' and Group_Name =''' +@Apply_val +''')'                     
  else                    
   set @condstr = @condstr + ' or Assign_Group ='+                    
   '(select top 1 Groupid FROM dbo.Serv_Group_Mast where ParentId='+cast(@Parent_ID as varchar)+' and Group_Name =''' +@Apply_val +''')'                     
                    
set @stno = @stno+1                    
end                     
                    
                    
set @sqlstr =  @sqlstr + case when @condstr= '' then '1=1' else @condstr end + ' )'                    
                
               
                   
set @result = 0             
          
--Select * into #tkttmp  from dbo.Serv_TicketMaster where 1=2                
 create table #tkttmp                     
 (                    
 [TicketID] [bigint] NULL,                    
 [User_id] [bigint] NULL,                    
 [ParentID] [bigint] NOT NULL,                    
 [TicketNo] [nvarchar](16) NULL,                    
 [Requester] [nvarchar](100) NULL,                    
 [Subject] [nvarchar](250) NULL,                    
 [Description] [nvarchar](max) NULL,                    
 [Status] [tinyint] NULL,                    
 [Remarks] [nvarchar](max) NULL,                    
 [Note] [nvarchar](max) NULL,                   
 [Date_Created] [datetime] NULL,                    
 [Priority] [tinyint] NULL,                    
 [AssignTo] [bigint] NULL,                    
 [Assign_Group] [bigint] NULL,                    
 [UserResponse] [nvarchar](max) NULL,                    
 [Active] [tinyint] NULL,                    
 [Ticket_type] [int] NULL,                    
 [ARemindRSPNSSent] [bit] NULL,                    
 [ARemindResolveSent] [bit] NULL,                    
 [ARSPSent] [bit] NULL,                    
 [A1RSLSent] [bit] NULL,                    
 [A2RSLSent] [bit] NULL,                    
 [A3RSLSent] [bit] NULL,                    
 [A4RSLSent] [bit] NULL,          
  agrp_unassigned  bit null,                 
 [Source] [nvarchar](200) NULL,                    
 [Product] [nvarchar](200) NULL,                    
 [Company] [nvarchar](200) NULL,                    
 [EmailId] [nvarchar](200) NULL,                    
 [domain] [nvarchar](200) NULL,                    
 [spam] [bit] NULL,                    
 [deleted] [bit] NULL,                    
 [skip_nticketmail] [bit] NULL,                 
 [tkt_tag] nvarchar(250) null,  resolved_dt  datetime null  ,          
 Assignedby bigint null, AssignedDateTime datetime null,      
           
 )              
 ----select @sqlstr            
 --drop table #tkttmp            
--select Serv_TicketMaster.* into #tkttmp from dbo.Serv_TicketMaster  where 1=2               
 --select * from #tkttmp             
          
 print @sqlstr       
 print '@condstr: '+@condstr  
 insert into #tkttmp exec (@sqlstr)                  
                   
 set @result = 0                
 if exists( select * from #tkttmp)                
 begin                   
                 
                 
  declare @ARemindRSPNSSent bit, @ARSPSent bit, @ARemindResolveSent bit,                    
  @A1RSLSent bit,@A2RSLSent bit, @A3RSLSent bit, @A4RSLSent as bit,                  
  @Date_Created datetime ,@ParentID Bigint,@Priority tinyint ,@Subject nvarchar(100);                
                      
                      
              
                      
  select @ARemindRSPNSSent=ARemindRSPNSSent, @ARSPSent = ARSPSent ,                    
  @ARemindResolveSent = ARemindResolveSent,@A1RSLSent = A1RSLSent ,                    
  @A2RSLSent=A2RSLSent, @A3RSLSent=A3RSLSent, @A3RSLSent=A3RSLSent ,@Date_Created = Date_Created                  
  ,@ParentID = ParentID,@Priority = Priority ,@Subject = Subject                   
  from #tkttmp                      
                   
   Declare @ToEmailID nvarchar(200) = '',@FromMailID nvarchar(200) = ''                 
                          
                      
   Declare @resp_assigned int,@RespondSecond int, @resp_Remind_Freq nvarchar(200)='',@RespRemindSeconds int = 0;                
                                     
  select @resp_Remind_Freq = resp_remind_freq,@RespondSecond =Respond_Sec , @resp_assigned = resp_assignd  from Serv_SLA_Response(nolock)                
     where SLAID = @SLAId and ParentID = @ParentID and Priority_ID = @Priority                     
                     
                       
   select @RespRemindSeconds = val_sec from Serv_SLA_Freq where Freq_Desc = @resp_Remind_Freq                
                      
    if(not exists(select 'x' from Serv_TicketTimelyPRM where TicketID = @TicketID))                  
          Begin            
                          
              insert into Serv_TicketTimelyPRM(TicketID,SLAID,RSPWithinDate)            
              values(@TicketID,@SLAId,DATEADD(SECOND,@RespondSecond,@Date_Created))             
                            
          End            
     else            
      Begin            
       update Serv_TicketTimelyPRM set SLAID = @SLAId , RSPWithinDate = DATEADD(SECOND,@RespondSecond,@Date_Created)  where TicketID = @TicketID             
       End                  
                         
          -- select * from Serv_TicketTimelyPRM              
         if(not exists(select 'x' from Serv_TicketTimelyPRM where TicketID = @TicketID))                  
          Begin            
                          
              insert into Serv_TicketTimelyPRM(TicketID,SLAID,BeforeRSPNSDate)            
              values(@TicketID,@SLAId,DATEADD(SECOND,@RespRemindSeconds,@Date_Created))             
                            
          End            
     else            
      Begin            
       update Serv_TicketTimelyPRM set SLAID = @SLAId , BeforeRSPNSDate = DATEADD(SECOND,@RespRemindSeconds,@Date_Created)  where TicketID = @TicketID             
       End                        
                         
                         
                         
                           
   --end                
               
    /* Start  RSLV_Within_Date */              
                
                   
   Declare @rslv_assigned int,@RSLVSecond int, @rslv_Remind_Freq nvarchar(200)='',@RSLVRemindSeconds int = 0;                
                                     
  select @rslv_Remind_Freq = resolution_remind_freq,@RSLVSecond = resolve_Sec, @rslv_assigned = resolution_assignd  from Serv_SLA_Response(nolock)                
     where SLAID = @SLAId and ParentID = @ParentID and Priority_ID = @Priority                     
                     
                       
   select @RSLVRemindSeconds = val_sec from Serv_SLA_Freq where Freq_Desc = @rslv_Remind_Freq                
                      
    if(not exists(select 'x' from Serv_TicketTimelyPRM where TicketID = @TicketID))                  
          Begin            
                          
              insert into Serv_TicketTimelyPRM(TicketID,SLAID,RSLVWithinDate)            
              values(@TicketID,@SLAId,DATEADD(SECOND,@RSLVSecond,@Date_Created))             
                            
          End            
     else            
      Begin            
       update Serv_TicketTimelyPRM set SLAID = @SLAId , RSLVWithinDate = DATEADD(SECOND,@RSLVSecond,@Date_Created)  where TicketID = @TicketID             
       End            
                
  
                
              
    /* End RSLV_Within_Date */            
              
              
                           
                       
   -- if @ARSPSent = 0                    
   -- Begin                
                     
     --Process to send mail                    
      Declare @Assign_Agent int,@resp_Freq nvarchar(200)='',@RespSeconds int = 0;                
                                     
             select @resp_Freq = resp_Freq,@Assign_Agent = Assign_Agent  from Serv_SLA_Response(nolock)                
     where SLAID = @SLAId and ParentID = @ParentID and Priority_ID = @Priority                     
                     
                       
       select @RespSeconds = val_sec from Serv_SLA_Freq where Freq_Desc = @resp_Freq                
                       
                    
     if(not exists(select 'x' from Serv_TicketTimelyPRM where TicketID = @TicketID))                  
          Begin            
                          
              insert into Serv_TicketTimelyPRM(TicketID,SLAID,AfterARSPNSDate)            
              values(@TicketID,@SLAId,DATEADD(SECOND,@RespSeconds,@Date_Created))             
                            
          End            
     else            
      Begin            
       update Serv_TicketTimelyPRM set SLAID = @SLAId ,AfterARSPNSDate  = DATEADD(SECOND,@RespSeconds,@Date_Created)  where TicketID = @TicketID             
       End                  
                
 -- if @ARemindResolveSent =0                  
 --     Begin                
            /* start before remind resolve */                
                           
    Declare @resolution_assignd int,@resolve_Sec int, @resolution_Remind_Freq nvarchar(200)='',@ResolutionRemindSeconds int = 0;                
                                     
   select @resolution_Remind_Freq = resolution_remind_freq,@resolve_Sec =resolve_Sec , @resolution_assignd = resolution_assignd  from Serv_SLA_Response(nolock)                
     where SLAID = @SLAId and ParentID = @ParentID and Priority_ID = @Priority                     
                     
                       
       select @ResolutionRemindSeconds = val_sec from Serv_SLA_Freq where Freq_Desc = @resolution_Remind_Freq                
                       
                    
    if(not exists(select 'x' from Serv_TicketTimelyPRM where TicketID = @TicketID))                  
          Begin            
                          
          insert into Serv_TicketTimelyPRM(TicketID,SLAID,BeforeRSLVDate)            
              values(@TicketID,@SLAId,DATEADD(SECOND,@ResolutionRemindSeconds,@Date_Created))             
                            
          End            
     else            
      Begin            
       update Serv_TicketTimelyPRM set SLAID = @SLAId ,BeforeRSLVDate  = DATEADD(SECOND,@ResolutionRemindSeconds,@Date_Created)  where TicketID = @TicketID             
       End                  
                  
 --declare @MailMSG nvarchar(500) = ''                 
 --declare @TicketProcessMSG nvarchar(200) = ''                 
                   
 Declare @Assigned_to int,@Interval_Seconds bigint = 0               
                                   
                   
                   
 -- if @A1RSLSent = 0              
                
  if(exists ( select 'x'  from Serv_SLA_escalation_rule(nolock)              
     where SLAID = @SLAId and ParentID = @ParentID and Responselevel = 1 ))              
    Begin                   
           select @Assigned_to = Assigned_to,@Interval_Seconds = Interval_Sec  from Serv_SLA_escalation_rule(nolock)              
     where SLAID = @SLAId and ParentID = @ParentID and Responselevel = 1                   
                   
      --if(DATEADD(SECOND,@Interval_Seconds,@Date_Created) < GETDATE())                
             
       if(not exists(select 'x' from Serv_TicketTimelyPRM where TicketID = @TicketID))                  
          Begin            
                          
              insert into Serv_TicketTimelyPRM(TicketID,SLAID,AfterA1RSLVDate)            
              values(@TicketID,@SLAId,DATEADD(SECOND,@Interval_Seconds,@Date_Created))             
                            
          End            
     else            
      Begin            
       update Serv_TicketTimelyPRM set SLAID = @SLAId ,AfterA1RSLVDate  = DATEADD(SECOND,@Interval_Seconds,@Date_Created)  where TicketID = @TicketID             
       End                  
             
             
    End                 
                       
 -- else if @A2RSLSent =0                
            
   if(exists ( select 'x'  from Serv_SLA_escalation_rule(nolock)              
     where SLAID = @SLAId and ParentID = @ParentID and Responselevel = 2 ))             
    Begin                    
      select @Assigned_to = Assigned_to,@Interval_Seconds = Interval_Sec  from Serv_SLA_escalation_rule(nolock)              
     where SLAID = @SLAId and ParentID = @ParentID and Responselevel = 2                   
                          
      --if(DATEADD(SECOND,@Interval_Seconds,@Date_Created) < GETDATE())                
             
       if(not exists(select 'x' from Serv_TicketTimelyPRM where TicketID = @TicketID))                  
          Begin            
                          
              insert into Serv_TicketTimelyPRM(TicketID,SLAID,AfterA2RSLVDate)            
              values(@TicketID,@SLAId,DATEADD(SECOND,@Interval_Seconds,@Date_Created))             
                            
          End            
     else            
      Begin            
       update Serv_TicketTimelyPRM set SLAID = @SLAId ,AfterA2RSLVDate = DATEADD(SECOND,@Interval_Seconds,@Date_Created)  where TicketID = @TicketID             
       End                  
    End                    
 -- else if @A3RSLSent =0                
               
  if(exists ( select 'x'  from Serv_SLA_escalation_rule(nolock)              
     where SLAID = @SLAId and ParentID = @ParentID and Responselevel = 3 ))             
   Begin                    
                      
    select @Assigned_to = Assigned_to,@Interval_Seconds = Interval_Sec  from Serv_SLA_escalation_rule(nolock)              
     where SLAID = @SLAId and ParentID = @ParentID and Responselevel = 3                   
                          
      --if(DATEADD(SECOND,@Interval_Seconds,@Date_Created) < GETDATE())                
             
       if(not exists(select 'x' from Serv_TicketTimelyPRM where TicketID = @TicketID))                  
          Begin            
                          
              insert into Serv_TicketTimelyPRM(TicketID,SLAID,AfterA3RSLVDate)            
              values(@TicketID,@SLAId,DATEADD(SECOND,@Interval_Seconds,@Date_Created))             
                            
          End            
     else            
      Begin            
       update Serv_TicketTimelyPRM set SLAID = @SLAId ,AfterA3RSLVDate = DATEADD(SECOND,@Interval_Seconds,@Date_Created)  where TicketID = @TicketID             
       End                  
                      
                  
   End                    
 -- else if @A4RSLSent =0                    
             
 if(exists ( select 'x'  from Serv_SLA_escalation_rule(nolock)              
     where SLAID = @SLAId and ParentID = @ParentID and Responselevel = 4 ))             
  Begin                
                   
  select @Assigned_to = Assigned_to,@Interval_Seconds = Interval_Sec  from Serv_SLA_escalation_rule(nolock)              
     where SLAID = @SLAId and ParentID = @ParentID and Responselevel = 4                   
                          
      --if(DATEADD(SECOND,@Interval_Seconds,@Date_Created) < GETDATE())                
             
       if(not exists(select 'x' from Serv_TicketTimelyPRM where TicketID = @TicketID))                  
          Begin            
                          
              insert into Serv_TicketTimelyPRM(TicketID,SLAID,AfterA4RSLVDate)            
              values(@TicketID,@SLAId,DATEADD(SECOND,@Interval_Seconds,@Date_Created))             
                            
          End            
     else            
      Begin            
  update Serv_TicketTimelyPRM set SLAID = @SLAId ,AfterA4RSLVDate = DATEADD(SECOND,@Interval_Seconds,@Date_Created)  where TicketID = @TicketID             
       End                  
                         
   end                 
             
  end     
      
  /* Start Lead activity Leads ticket reaches SLA */    
    
  Begin try    
    
   Declare @TicketID_LDACTV bigint = @TicketID     
   Declare @SLAID_LDACTV bigint =  @SLAId    
   Declare @AssignedTo_LDACTV bigint = 0    
   Declare @AssignedToName_LDACTV nvarchar(500) = 0    
       
   Declare @Priority_LDACTV int  = 0      
    
   Declare @UserID_LDACTV bigint = 1    
   Declare @ParentID_LDACTV bigint = 0    
       
   Declare @kit19UserID bigint = 0     
       
   Declare @TicketTitle_LDACTV nvarchar(500) = ''    
       
      
   select top 1 @UserID_LDACTV = isnull(USER_ID,0),@ParentID_LDACTV = isnull(ParentID,0),@TicketTitle_LDACTV = isnull(Subject,'')    
        ,@Priority_LDACTV = isnull(Priority,0)  from Serv_TicketMaster where TicketID =  ISNULL(@TicketID_LDACTV,0)     
      
    select top 1 @AssignedTo_LDACTV = isnull(Assign_Agent,0)  from Serv_SLA_Response(nolock)                
    where SLAID = @SLAID_LDACTV and ParentID = @ParentID_LDACTV and Priority_ID = @Priority_LDACTV      
    
 select top 1 @AssignedToName_LDACTV = isnull(User_Login,'') from user_detail where User_ID = isnull(@AssignedTo_LDACTV,0)    
    
    
    
    
    
  Declare @LeadID_LDACTV bigint = 0    
      
  Select top 1 @LeadID_LDACTV = isnull(LeadID,0)  from Serv_User_Detail where ser_user_id = @UserID_LDACTV    
     
   if(exists(select 1 from Serv_User_Master where Service_id = @UserID_LDACTV and kit19_User = 1))    
       Begin    
        select @kit19UserID = isnull(kit19_id,0)  from Serv_User_Master where Service_id = @UserID_LDACTV    
    End    
 else    
    Begin    
       set  @kit19UserID = @ParentID_LDACTV     
    End    
        
    
  create table #tblEventDescrb    
   (    
     EVNT_Description nvarchar(max)     
   )    
    
  if( isnull(@LeadID_LDACTV,0) > 0)    
   Begin    
        
   insert into #tblEventDescrb    
      exec  Usp_EventTemplate_DynamicVarReplacement 'Leads ticket reaches SLA',@kit19UserID,'','',@LeadID_LDACTV,'',null    
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,@TicketTitle_LDACTV,null    
   ,null,null,null,@AssignedToName_LDACTV,null,null,null,null,    
   0,0,0,null,null,null,null,null,null,null,0,null,null    
         
   declare @evntMessage nvarchar(max) = ''     
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb    
     
   if(@evntMessage <> '')    
   Begin    
   exec UspSaveLeadActivity_withid @LeadID_LDACTV,@kit19UserID,@ParentID_LDACTV,@evntMessage,    'Leads ticket reaches SLA','serv_Ticketmaster',@TicketID    
   end    
    
    
   End      
    
   end try     
   Begin catch    
    
     exec usp_insertErrorInfo    
    
   end catch    
    
   IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence      
   Begin      
        DROP TABLE #tblEventDescrb      
   End      
      
    
     /* End Lead activity Leads ticket reaches SLA */    
    
    
    
                     
 end                     


GO

/* ============================================================
   Procedure: [dbo].[Serv_BindInternalUsers]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_BindInternalUsers]  --335
(
@ParentID int
)
as  
Begin  
 select USERID as User_ID ,(select top 1 User_Login from user_detail where USER_ID = USERID) as User_Login  from Serv_Agent_Mast where ParentId = @ParentID order by Date_Created desc  
End


GO

/* ============================================================
   Procedure: [dbo].[Serv_BindInternalUsers_support]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_BindInternalUsers_support]  --335    
(    
@ParentID int    
)    
as      
Begin      

	 select SAM.USERID as User_ID ,SUD.Login_id as User_Login  
	 from	Serv_Agent_Mast(nolock) SAM inner join Serv_User_Detail(nolock) SUD
	 on		SAM.UserId=SUD.ser_user_ID
	 where  SAM.ParentId = @ParentID 
	 order by SAM.Date_Created desc      

End   



GO

