CREATE   PROCEDURE dbo.Serv_ChangePassword      
(      
  @UserID int,      
  @PWD nvarchar(25)       
)      
as      
Begin      
   update Serv_User_Detail set Pwd = @PWD ,resetguid = '',resetrequested = null,resetexpired = null where USER_ID = @UserID      
   select 'Record Updated'      
End


GO

/* ============================================================
   Procedure: [dbo].[Serv_ChangeRoleStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_ChangeRoleStatus]    
(    
  @RoleID bigint,    
  @Status bit     
)    
as    
Begin
 if EXISTS( SELECT * FROM Serv_Role_mast where RoleId = @RoleID and dummy_rec=1)
	begin
	SELECT 'Can not Perform Active/Deactive Action on Default Record' msg,0 row  
	end
else
	begin	
	if (@Status=1)  
		begin  
		 update Serv_Role_mast set Active = @Status where RoleId = @RoleID    
		   select 'Status Changed'  msg,1 row    
		end  
		else  
		 begin  
		 if EXISTS( SELECT * FROM dbo.Serv_Agent_Mast where RoleId = @RoleID)   
		  SELECT 'Can not Deactive Agent is assigned with this role' msg,0 row  
		 else  
		 begin  
		   update Serv_Role_mast set Active = @Status where RoleId = @RoleID    
		   select 'Status Changed'  msg,1 row    
		   end    
		End  
	end
end


GO

