/* ============================================================
   Procedure: [dbo].[Serv_ChangeStatusGroupMast]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Serv_ChangeStatusGroupMast         
(        
  @GroupID bigint,         
  @Status bit    
)        
as        
Begin        
 if(@Status = 1)    
   Begin    
       Update  Serv_Group_Mast set Active = 1  where GroupID = @GroupID        
       select 'Activated'       
   End     
 else if(@Status = 0)    
      Begin    
           if not exists (select 'x' from Serv_Agent_Mast where Group_id = @GroupID)    
            Begin   
            if exists ( select 'x' from Serv_Agent_Mast where Group_id = @GroupID and Dummy_Rec = 1)   
            Begin  
               select 'Group admin can not be deactivted'  
            End   
         else  
            Begin  
             
            Update  Serv_Group_Mast set Active = 0  where GroupID = @GroupID        
                   select 'DeActivated'    
            End  
             
            End    
           else    
            Begin    
            select 'Group has already been assigned to some agent(s) so it could not be deactivated'         
            End     
      End    
      
End


GO

/* ============================================================
   Procedure: [dbo].[Serv_ChangeTicketCategoryStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Serv_ChangeTicketCategoryStatus]      
(      
  @TicketCategoryId bigint,      
  @IsActive bit       
)      
as      
Begin  
 if EXISTS( SELECT * FROM Serv_TicketCategory_Mast where TicketCategoryId = @TicketCategoryId and @TicketCategoryId < 6)
 begin  
 SELECT 'Can not Perform Active/Deactive Action on Default Record' msg,0 row    
 end  
else  
 begin   
 if (@IsActive = 1) 
  begin    
   update Serv_TicketCategory_Mast set IsActive = @IsActive where TicketCategoryId = @TicketCategoryId      
     select 'Status Changed'  msg,1 row      
  end    
  else    
   begin    
   if EXISTS( SELECT * FROM dbo.Serv_TicketMaster where TicketCategoryId = @TicketCategoryId)     
    SELECT 'Can not Deactive Category is assigned with this category ' msg,0 row    
   else    
   begin    
     update Serv_TicketCategory_Mast set IsActive = @IsActive where TicketCategoryId = @TicketCategoryId      
     select 'Status Changed'  msg,1 row      
     end      
  End    
 end  
end  




GO

