/* ============================================================
   Procedure: [dbo].[Serv_CheckSingle_User]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_CheckSingle_User]            
(            
  @ParentID bigint,            
  @Email nvarchar(100),             
   @domainNm nvarchar(100)            
)            
--ser_user_id, , Status, Date_Created            
--dbo.Serv_User_Detail            
as            
Begin            
declare             
@user_id bigint,            
@Company nvarchar(100),             
  @Country nvarchar(100),             
  @City nvarchar(100),             
  @State nvarchar(100),             
  @Address nvarchar(Max)='',             
  @Zip int,             
  @kit19_id bigint ,            
  @Service_id nvarchar(100),            
  @Crm_ID bigint,            
  @Pwd nvarchar(100),             
  @Name nvarchar(100),             
  @Mobile nvarchar(20),            
  @Login_id nvarchar(100),            
  @ser_user_id bigint,          
  @CountryCode  varchar(10)           
             
              
 if (exists(select 'x' from Serv_User_Master where ParentID = @ParentID and Email_id = @Email))            
 begin            
 select @kit19_id= kit19_id,@Service_id=Service_id,@Crm_ID = Crm_ID               
 from Serv_User_Master where ParentID = @ParentID and Email_id = @Email            
             
 if @kit19_id >0            
  select 'You are already Signup with ' +@domainNm +            
  ' Please use the same Credential in Service Module' respmsg            
 else if @Crm_ID >0            
  select 'You are already Signup with Pelcti Please use the same Credential in Service Module'             
  respmsg            
 else if @Service_id >0            
  select 'You are already Signup with Service Module' respmsg            
             
 end            
else            
begin            
 if (exists(select 'x' from user_detail where ParentID=@ParentID and EMail = @Email))            
 begin            
               
   select @Name=FName,@user_id=user_id,@Login_id = User_Login,             
   @Pwd = Pwd,@Mobile = str(mobile,20,0),@CountryCode=CountryCode, @City = City,@State= State ,            
   @Country = Country, @Company=CompnayName, @Zip=Pincode, @Address = Address            
   from user_detail where ParentID=@ParentID and EMail = @Email            
        
if (not exists(select 'x' from Serv_User_Detail where ParentID = @ParentID and user_id_old = @user_id))
 begin        
   insert into Serv_User_Detail(ParentId, User_id, Login_id, Pwd, Name, Mobile,            
   Email, Company, Country, City, State, Address, Zip, Country_Code,user_id_old)             
    values(@ParentId, @user_id, @Login_id, @Pwd, @Name, @Mobile,            
   @Email, @Company, @Country, @City, @State, @Address, @Zip,@CountryCode,@user_id)            
   select @ser_user_id = SCOPE_IDENTITY()            
   update Serv_User_Detail set user_id=@ser_user_id      
  where ser_user_id = @ser_user_id           
             
  if(not exists (select 'x' from Serv_User_Master where ParentID = @ParentID and Email_id = @Email ))            
   insert into Serv_User_Master (ParentID,Email_id,Service_User,Service_id, kit19_id, kit19_User)            
   Values (@ParentID, @Email, 1, @ser_user_id ,@user_id, 1)            
  else            
   update Serv_User_Master set Service_User = 1, Service_id=@ser_user_id,            
   kit19_id= @user_id, kit19_User =1            
   where ParentID=@ParentID and Email_id =@email            
 end            
  select 'You are already Signup with ' +@domainNm +            
  ' Please use the same Credential in Service Module' respmsg               
   end             
   else            
    select 'Valid email' respmsg            
               
               
  End             
end 



GO

/* ============================================================
   Procedure: [dbo].[Serv_CheckSLAMatrix]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_CheckSLAMatrix]      
(  
@ticketid bigint,  
@ParentID bigint,  
@User_ID bigint,  
@opt varchar(10)  
)  
as      
Begin      
declare @Date datetime, @slaid bigint,  @Assign_Agent  bigint,   
 @resp_assignd  bigint, @resolution_assignd  bigint, @Subject varchar(100)  
 

if @opt = 'Agrp'
begin
 select   
  @Date =BeforeRSPNSDate, @slaid = tm.slaid, @Assign_Agent = resp_assignd  
  from Serv_TicketTimelyPRM tm inner join   
   Serv_SLA_Response sm on sm.SLAID = tm.SLAID where TicketID= @ticketid  
  set @Subject= 'Ticket Unattended in Group & Response Time expired' 
 if @Date <= GETDATE()
 	BEGIN 
 	
  exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @Assign_Agent,@Assign_Agent,'Ticket Unattended in Group','Agent' 
  update Serv_TicketMaster set agrp_unassigned = 1 where TicketID =@TicketID  
  END 
end
 if @opt ='bresp'  
  begin
  select   
  @Date =BeforeRSPNSDate, @slaid = tm.slaid, @Assign_Agent = resp_assignd  
  from Serv_TicketTimelyPRM tm inner join   
   Serv_SLA_Response sm on sm.SLAID = tm.SLAID where TicketID= @ticketid  
  set @Subject= 'Response Time is going to expire' 
 if @Date <= GETDATE() 
 BEGIN

  exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @Assign_Agent,@Assign_Agent,'First Response SLA Reminder','Agent' 
 		  update Serv_TicketMaster set ARemindRSPNSSent = 1 where TicketID =@TicketID 
 END  
 end
 if @opt ='brslv' 
 begin 
  select   
  @Date =BeforeRSLVDate , @slaid = tm.slaid ,@Assign_Agent = resolution_assignd  
  from Serv_TicketTimelyPRM tm inner join   
   Serv_SLA_Response sm on sm.SLAID = tm.SLAID  where TicketID= @ticketid  
    set @Subject= 'Resolution Time is going to expire'  
  if @Date<= GETDATE() 
  BEGIN


  exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @Assign_Agent,@Assign_Agent,'Resolution Time SLA Reminder','Agent'  
  	  update Serv_TicketMaster set ARemindResolveSent = 1 where TicketID =@TicketID  
END 
 end 
if @opt ='Aresp'
begin 
  select   
  @Date = AfterARSPNSDate, @slaid = tm.slaid ,@Assign_Agent = Assign_Agent   
  from Serv_TicketTimelyPRM tm inner join   
   Serv_SLA_Response sm on sm.SLAID = tm.SLAID  where TicketID= @ticketid  
   set @Subject= 'Response Time expired'  
  if @Date <= GETDATE() 
	begin
	 	
	 exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @Assign_Agent,@Assign_Agent,'First Response SLA Violation','Agent' 
	 update Serv_TicketMaster set ARSPSent = 1 where TicketID =@TicketID
	end  
end
 if @opt ='sla1' 
 begin 
  select   
  @Date =AfterA1RSLVDate , @slaid = tm.slaid, @Assign_Agent = Assigned_to  
  from Serv_TicketTimelyPRM tm inner join   
   Serv_SLA_escalation_rule sm on sm.SLAID = tm.SLAID and Responselevel=1 where TicketID= @ticketid  
   set @Subject= 'SLA1 Voilated' 
  if @Date <= GETDATE() 
  BEGIN

     exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @Assign_Agent,@Assign_Agent,'Resolution Time SLA Violation','Agent' 
     update Serv_TicketMaster set A1RSLSent = 1 where TicketID =@TicketID 
     END  
end  
if @opt ='sla2'  
 begin
  select   
  @Date =AfterA2RSLVDate , @slaid = tm.slaid , @Assign_Agent = Assigned_to  
  from Serv_TicketTimelyPRM  tm inner join   
   Serv_SLA_escalation_rule sm on sm.SLAID = tm.SLAID and Responselevel=2 where TicketID= @ticketid  
 set @Subject= 'SLA2 Voilated'  

  if @Date <= GETDATE() 
  BEGIN

 exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @Assign_Agent,@Assign_Agent,'Resolution Time SLA Violation','Agent'   
 update Serv_TicketMaster set A2RSLSent = 1 where TicketID =@TicketID 
 END
end
if @opt ='sla3'  
begin
  select   
  @Date =AfterA3RSLVDate , @slaid = tm.slaid , @Assign_Agent = Assigned_to  
  from Serv_TicketTimelyPRM  tm inner join   
   Serv_SLA_escalation_rule sm on sm.SLAID = tm.SLAID and Responselevel=3   where TicketID= @ticketid  
  set @Subject= 'SLA3 Voilated'  

   if @Date <= GETDATE() 
   BEGIN
    	
	 exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @Assign_Agent,@Assign_Agent,'Resolution Time SLA Violation','Agent' 
	  update Serv_TicketMaster set A3RSLSent = 1 where TicketID =@TicketID 
	END 
end 
if @opt ='sla4'
begin
  select   
  @Date =AfterA4RSLVDate , @slaid = tm.slaid  , @Assign_Agent = Assigned_to  
  from Serv_TicketTimelyPRM  tm inner join   
   Serv_SLA_escalation_rule sm on sm.SLAID = tm.SLAID and Responselevel=4  where TicketID= @ticketid    
 set @Subject= 'SLA4 Voilated' 

  if @Date <= GETDATE() 
  BEGIN

 exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @Assign_Agent,@Assign_Agent,'Resolution Time SLA Violation','Agent' 
 update Serv_TicketMaster set A4RSLSent = 1 where TicketID =@TicketID  
 END 
end   
  

if @Date <= GETDATE() 

begin  

/* Start Creation of batchid */  
     DECLARE @Random INT;  
  DECLARE @Upper INT;  
  DECLARE @Lower INT  
  Declare @BatchID bigint  
    
    
  ---- This will create a random number between 1 and 999  
  SET @Lower = 1 ---- The lowest random number  
  SET @Upper = 10000 ---- The highest random number  
  SELECT @Random = ROUND(((@Upper - @Lower -1) * RAND() + @Lower), 0)  
  --SELECT @Random  
       
          
     insert into GetBatchRecord (User_id,RandNum)          
        values(@User_ID,@Random)          
    select @BatchID = max(BatchID)  from GetBatchRecord With (Nolock) where User_id=@User_ID  and RandNum=@Random          
        delete from GetBatchRecord  where User_id=@User_ID and RandNum=@Random   
       
   /* End Creation of batchid */  
     Declare @ToEmailID nvarchar(200) = '',@FromMailID nvarchar(200) = ''                
   select @FromMailID =virtual_mail from serv_user_domain where ParentID=@ParentID    
    
           --Process to send mail   
          
     select @ToEmailID = isnull(Email,'')  From User_Detail   
     where USER_ID = @Assign_Agent   
       
            insert into CloneEmailsFilter(  
              Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName  
                 ,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID  
                 ,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime  
                 ,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source  
               )  
               values( @FromMailID,@ToEmailID,@Subject,'','Under Your before respond time , plz give response', GETDATE(),@Assign_Agent,  
               @ParentID,'noreply@kit19.com',@BatchID,2,'','','','Under Your before respond time ,plz give response',1,0,1,'TicketManagement'  
                 
               )      
  
end  
 end


GO

/* ============================================================
   Procedure: [dbo].[Serv_CheckUserDomain]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_CheckUserDomain]                
  (                        
    @ParentID int,                    
    @domain varchar(100)                        
  )                        
  as                        
  Begin                 
             
                  
  if  @ParentID > 0                      
       select  top 1 ud.*,dm.VDomain_Name,dm.virtual_domain,dm.VEmailID_Name,dm.virtual_mail,dm.link_Account from serv_user_domain dm inner join Serv_User_Detail ud                       
       on ud.ParentId = dm.ParentId  INNER JOIN User_Detail u(nolock) on ud.ParentId = u.ParentID and u.ParentId = dm.ParentId and ud.Login_id = u.User_Login where dm.ParentId = @ParentID and u.User_ID = @ParentID   order by ud.ser_user_id              
                      
 -- if @ParentID = 0                     
 --select top 1 ud.*,dm.VDomain_Name,dm.virtual_domain,dm.VEmailID_Name,dm.virtual_mail,dm.link_Account  from serv_user_domain dm inner join Serv_User_Detail ud                       
 --      on ud.ParentId = dm.ParentId where replace(replace(replace(dm.virtual_domain,'https://',''),'http://',''),'www.','') = replace(replace(replace(@domain,'https://',''),'http://',''),'www.','')    
  End 


GO

/* ============================================================
   Procedure: [dbo].[Serv_CheckUserDomain_signin]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
  
  
  
CREATE   PROCEDURE [dbo].[Serv_CheckUserDomain_signin]            
  (            
    @ParentID int,        
    @domain varchar(100)            
  )            
  as            
  Begin     
 SET NOCOUNT OFF      
  if  @ParentID > 0          
       select ud.*,dm.VDomain_Name,dm.virtual_domain,dm.VEmailID_Name,dm.virtual_mail,dm.link_Account from serv_user_domain dm inner join Serv_User_Detail ud           
       on ud.ParentId = dm.ParentId where dm.ParentId = @ParentID        
          
  if @ParentID = 0         
 select top 1 ud.*,dm.VDomain_Name,dm.virtual_domain,dm.VEmailID_Name,dm.virtual_mail,dm.link_Account  
 from VW_serv_user_domain dm inner join Serv_User_Detail ud           
       on ud.ParentId = dm.ParentId 
	   where replace(replace(replace(dm.virtual_domain,'https://',''),'http://',''),'www.','') = replace(replace(replace(@domain,'https://',''),'http://',''),'www.','')           
	   
  End    
    
    


GO

