/* ============================================================
   Procedure: [dbo].[Serv_CheckUserType]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec Serv_CheckUserType @userID=32222
-- exec Serv_CheckUserType @userID=36967
CREATE   PROCEDURE [dbo].[Serv_CheckUserType]          
(          
  @userID int      
 --@ser_user_id bigint    
)       
as          
Begin      
    
	update Serv_User_Detail  
	set Last_Login_date = getdate()  
	where User_id = @userID   
     
	 -- if else added to handle corrupt data in userid & ser_user_id
	If exists(select 1	from Serv_User_Detail ud inner join Serv_Agent_Mast ag on ag.Userid =ud.User_id where ud.User_id = @userID)
	Begin
		select ud.* 
		from Serv_User_Detail ud inner join Serv_Agent_Mast ag
		on ag.Userid =ud.User_id      
		where ud.User_id = @userID      
		--ud.ser_user_id = @ser_user_id      
	End
	Else
	Begin
		select ud.* 
		from Serv_User_Detail ud inner join Serv_Agent_Mast ag
		on ag.Userid =ud.ser_user_id
		where ud.User_id = @userID      
	End

End      



GO

