/* ============================================================
   Procedure: [dbo].[Serv_DefaultEntry_FirstTimeCreation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_DefaultEntry_FirstTimeCreation]          
(          
 @ParentID int,          
 @UserID  int,          
 @CompanyName nvarchar(200)          
)          
as          
Begin          
           
     declare @GroupID bigint = 0           
     
     if(not exists(select 'x' from Serv_Group_Mast where ParentId = @ParentID  and  Group_Name = 'Admin' and Dummy_Rec = 1 ))    
     Begin  
   insert into Serv_Group_Mast(ParentId,Group_Name,Group_Desc,Dummy_Rec)values(@ParentID,'Admin','Admin',1)          
   select @GroupID = SCOPE_IDENTITY()       
     End  
     else  
     Begin  
        -- Not required to update just get Groupid  
       select @GroupID = ISNULL(Groupid,0) from Serv_Group_Mast where ParentId = @ParentID  and  Group_Name = 'Admin' and Dummy_Rec = 1     
     End   
      
      
      /*          
       SELECT TOP 1000 [RoleId]          
      ,[ParentId]          
      ,[RoleDesc]          
      ,[Active]          
      ,[Date_Created]          
      ,[dummy_rec]          
  FROM [MYSMSLatest].[dbo].[Serv_Role_mast]          
            
     */          
               
     declare @RoleID bigint = 0  
       
     if(not exists(select 'x' from Serv_Role_mast where ParentId = @ParentID and RoleDesc = 'Admin' and Dummy_Rec = 1))  
      Begin          
   insert into Serv_Role_mast(ParentId,RoleDesc,Dummy_Rec)values(@ParentID,'Admin',1)          
   select @RoleID = SCOPE_IDENTITY()          
      End         
    else  
     Begin  
        select @RoleID = isnull(RoleId,0) from Serv_Role_mast where ParentId = @ParentID and RoleDesc = 'Admin' and Dummy_Rec = 1  
     End  
      
      
      /*          
      SELECT TOP 1000 [Agent_Id]          
      ,[ParentId]          
      ,[Userid]          
      ,[RoleId]          
      ,[Active]          
      ,[Group_id]          
      ,[Date_Created]          
      ,[Internal]          
      ,[Access_level]          
      ,[Dummy_Rec]          
  FROM [MYSMSLatest].[dbo].[Serv_Agent_Mast]          
             
   */          
             
  declare @Agent_Id bigint = 0            
    
  if(not exists (select 'x' from Serv_Agent_Mast where ParentId = @ParentID and USERID = @UserID and Access_level = 'All Group' and  Dummy_Rec = 1))   Begin  
   insert into Serv_Agent_Mast([ParentId]          
      ,[Userid]          
      ,[RoleId]          
      ,[Group_id]          
      ,[Internal]          
      ,[Access_level]          
      ,[Dummy_Rec])          
      values          
      (@ParentID,@UserID,@RoleID,@GroupID,1,'All Group',1)          
     select @Agent_Id = SCOPE_IDENTITY()          
   End        
   else  
    Begin  
    -- get AgentID   
  select @Agent_Id = isnull(Agent_Id,0)from Serv_Agent_Mast where ParentId = @ParentID and USERID = @UserID and Access_level = 'All Group' and  Dummy_Rec = 1  
          
    End  
      
     /*          
     SELECT TOP 1000 [TResp_Rule_Id]          
      ,[ParentID]          
      ,[Rule_Name]          
      ,[Rule_Match_type]          
      ,[Rule_Desc]          
      ,[Respons_Order]          
      ,[DateCreated]          
      ,[ord_no]          
      ,[Dummy_Rec]          
  FROM [MYSMSLatest].[dbo].[Serv_Ticket_Dispatch]          
             
   */          
      
             
  declare @TResp_Rule_Id bigint = 0   
    
  if(not exists (select 'x' from Serv_Ticket_Dispatch where ParentID = @ParentID and Rule_Name = 'Admin' and Dummy_Rec = 1))  
    Begin  
   insert into Serv_Ticket_Dispatch          
    (          
     [ParentID]          
    ,[Rule_Name]          
    ,[Rule_Match_type]          
    ,[Rule_Desc]          
    ,[Respons_Order]          
    ,[ord_no]          
    ,[Dummy_Rec]          
    )          
    values          
    (@ParentID          
    ,'Admin'          
    ,1          
    ,'The Dispatch’r lets you bring your business rules into your support'          
    ,1          
    ,1          
    ,1)          
    select @TResp_Rule_Id = SCOPE_IDENTITY()          
    End         
    else  
     Begin  
    select @TResp_Rule_Id = ISNULL(TResp_Rule_Id,0) from Serv_Ticket_Dispatch where ParentID = @ParentID and Rule_Name = 'Admin' and Dummy_Rec = 1        End  
      
    /*          
      SELECT TOP 1000 [tkt_filter_ID]          
      ,[TResp_Rule_Id]          
      ,[ParentID]          
      ,[Filter_Field]          
      ,[Filter_Cond]          
      ,[Filter_Value]          
      ,[Filter_FldType]          
      ,[ord_no]          
      ,[Dummy_Rec]          
  FROM [MYSMSLatest].[dbo].[Serv_Ticket_Dispatch_Filter]          
             
   */          
             
             
  declare @tkt_filter_ID bigint = 0            
    
  if (not exists (select 'x' from Serv_Ticket_Dispatch_Filter where ParentID = @ParentID and Dummy_Rec = 1 ))  
  Begin  
    
  insert into Serv_Ticket_Dispatch_Filter          
      (          
                
      [TResp_Rule_Id]          
      ,[ParentID]          
      ,[Filter_Field]          
      ,[Filter_Cond]          
      ,[Filter_Value]          
      ,[Filter_FldType]          
      ,[ord_no]          
      ,[Dummy_Rec]          
                
      )          
      values          
      (          
                
      @TResp_Rule_Id          
      ,@ParentID          
      ,'Company Name'          
      ,'='          
      ,@CompanyName          
      ,1          
      ,1          
      ,1          
                
      
        )          
     select @tkt_filter_ID = SCOPE_IDENTITY()          
       
    End  
    else  
     Begin  
       select @tkt_filter_ID = isnull(tkt_filter_ID,0) from Serv_Ticket_Dispatch_Filter where ParentID = @ParentID and Dummy_Rec = 1   
     End  
      
        
      /*                 
     SELECT TOP 1000 [Tkt_ActionID]          
      ,[TResp_Rule_Id]          
      ,[Parentid]          
      ,[Action]          
      ,[Act_Value]          
      ,[ord_no]          
      ,[Dummy_Rec]          
  FROM [MYSMSLatest].[dbo].[Serv_Ticket_Dispatch_Action]          
             
   */          
             
   declare @Tkt_ActionID bigint = 0     
     
  if(not exists (select 'x' from Serv_Ticket_Dispatch_Action where Parentid = @ParentID and Dummy_Rec = 1))  
  Begin         
    
  insert into Serv_Ticket_Dispatch_Action          
      (          
                
  [TResp_Rule_Id]          
      ,[Parentid]          
      ,[Action]          
      ,[Act_Value]          
      ,[ord_no]          
      ,[Dummy_Rec]          
                
      )          
      values          
      (          
                
       @TResp_Rule_Id          
      ,@ParentID          
      ,'Assign to Group'          
      ,'Incident'          
      ,1          
      ,1          
      )          
      select @Tkt_ActionID = SCOPE_IDENTITY()          
     
    
   End          
   else  
    Begin  
       select @Tkt_ActionID = ISNULL(Tkt_ActionID,0)  from Serv_Ticket_Dispatch_Action where Parentid = @ParentID and Dummy_Rec = 1  
    End  
        
        
       /*          
       SELECT TOP 1000 [SLAId]          
      ,[ParentID]          
      ,[SLA_Name]          
      ,[SLA_Desc]          
      ,[DateCreated]          
      ,[Active]          
      ,[ord_no]          
      ,[Dummy_Rec]          
  FROM [MYSMSLatest].[dbo].[Serv_SLA_Setting]          
            
    */          
                
   declare @SLAId bigint = 0            
   
 if(not exists(select 'x' from Serv_SLA_Setting  where ParentID = @ParentID and Dummy_Rec = 1))  
    Begin  
    insert into Serv_SLA_Setting          
      (          
                
       [ParentID]          
      ,[SLA_Name]          
      ,[SLA_Desc]          
      ,[ord_no]          
      ,[Dummy_Rec]          
                
      )          
      values          
      (          
                
       @ParentID          
      ,'Dummy'          
      ,'Dummy'          
      ,1           
      ,1          
                
      )          
      select @SLAId = SCOPE_IDENTITY()          
   End  
  else  
   Begin  
     select @SLAId = isnull(SLAId,0)  from Serv_SLA_Setting  where ParentID = @ParentID and Dummy_Rec = 1      
   End  
     
    /*          
     SELECT TOP 1000 [appl_id]          
      ,[Parent_id]          
      ,[SLAID]          
      ,[Apply_to]          
      ,[Apply_val]          
      ,[Dummy_Rec]          
  FROM [MYSMSLatest].[dbo].[Serv_SLA_ApplyRule]          
             
   */          
                
    declare @appl_id bigint = 0   
      
   if( not exists (select 'x' from Serv_SLA_ApplyRule where Parent_id = @ParentID and Dummy_Rec = 1))           
  Begin  
  insert into Serv_SLA_ApplyRule          
      (          
                
       [Parent_id]          
      ,[SLAID]          
      ,[Apply_to]          
      ,[Apply_val]          
      ,[Dummy_Rec]          
                
      )          
      values          
      (          
       @Parentid          
      ,@SLAId          
      ,'Company'          
      ,@CompanyName          
      ,1          
      )          
      select @appl_id = SCOPE_IDENTITY()         
     
   End  
   else  
     Begin  
        select @appl_id = ISNULL(appl_id,0)  from Serv_SLA_ApplyRule where Parent_id = @ParentID and Dummy_Rec = 1  
     End  
        
        
         /*          
      SELECT TOP 1000 [SLA_escalationID]          
      ,[SLAID]          
      ,[ParentID]         
      ,[Interval_val]          
      ,[Interval_Unit]          
      ,[Interval_Sec]          
      ,[Assigned_to]          
      ,[Responselevel]          
      ,[Dummy_Rec]          
  FROM [MYSMSLatest].[dbo].[Serv_SLA_escalation_rule]          
      
   */             
             
  declare @SLA_escalationID bigint = 0  
    
  if(not exists (select 'x' from Serv_SLA_escalation_rule where ParentID = @ParentID and Dummy_Rec = 1))  
  Begin            
  insert into Serv_SLA_escalation_rule          
      (          
                
       [SLAID]          
      ,[ParentID]          
      ,[Interval_val]          
      ,[Interval_Unit]          
      ,[Interval_Sec]          
      ,[Assigned_to]          
      ,[Responselevel]          
      ,[Dummy_Rec]          
                
      )          
      values          
      (          
       @SLAId          
      ,@ParentID          
      ,0          
      ,'Immediately'          
      ,0          
      ,@UserID          
      ,1          
      ,1          
      )          
      select @SLA_escalationID = SCOPE_IDENTITY()    
        
   end  
   else  
     Begin  
       select @SLA_escalationID = SLA_escalationID from Serv_SLA_escalation_rule where ParentID = @ParentID and Dummy_Rec = 1   
     End  
     
     
     
        /* Rule Auth mast Default entry   */          
     -- Select           
     --   [RoleId]          
     --  ,[ParentId]          
     --  ,[Menu]          
     --  ,[Activity]          
     --  ,[Permission]          
     --  ,[Access_Level]          
     --  ,[Dummy_Rec]          
     --   into #tmptbl          
     --FROM  [Serv_Role_Auth_Mast] where RoleId = 2 and ParentId = 335           
     -- update #tmptbl set RoleId = @RoleID ,ParentId = @ParentID          
                      
     -- select * From #tmptbl          
                      
                      
    if(not exists (select 'x' from Serv_Role_Auth_Mast where ParentId = @ParentID and Dummy_Rec = 1))  
    Begin                  
      insert into Serv_Role_Auth_Mast          
      ([RoleId]          
      ,[ParentId]          
      ,[Menu]          
      ,[Activity]          
      ,[Permission]          
      ,[Access_Level]          
      ,[Dummy_Rec]          
      )           
 select @RoleID          
      ,@ParentID          
      ,[Menu]          
      ,[Activity]          
      ,1          
      ,[Access_Level]          
       ,1 from Serv_Auth_Mast       
   end  
     
   if(not exists (select 'x' from Serv_Notification_Requester where ParentID = @ParentID) )  
     Begin     
    insert into Serv_Notification_Requester       
    (ParentID, Activity_Id, Email_ID, Login_ID, N_Sub, N_Body)      
    select @ParentID, Activity_Id, '', '', [subject], [Messagebody]      
    from [Serv_Activity_Mast]  where ParentId = @ParentID and [Access]=1     
    End    
   else  
     Begin  
        update SNR   
        set SNR.N_Sub = SAM.subject,SNR.N_Body = SAM.Messagebody  
        from Serv_Notification_Requester SNR   
        inner join Serv_Activity_Mast SAM  
        on  SNR.Activity_Id = SAM.Activity_id   
        where SAM.ParentID = @ParentID and SNR.ParentID  = @ParentID and SAM.Access =1  
           
      
     End    
       
       
       
       
   if(not exists (select 'x' from Serv_Notification_Agent where ParentID = @ParentID) )  
    Begin     
    insert into Serv_Notification_Agent        
    (ParentID, Activity_Id, Email_ID, Login_ID, N_Sub, N_Body)         
   select @ParentID, Activity_Id, '', '', [subject], [Messagebody]      
    from [Serv_Activity_Mast]  where ParentId = @ParentID   and [Access]=0    
    End  
    else  
     Begin  
       
        update SNA   
        set SNA.N_Sub = SAM.subject,SNA.N_Body = SAM.Messagebody  
        from Serv_Notification_Agent SNA   
        inner join Serv_Activity_Mast SAM  
        on  SNA.Activity_Id = SAM.Activity_id   
        where SNA.ParentID = @ParentID and SAM.ParentID  = @ParentID  and Access = 0  
       
       
     End  
      
                  
   if(not exists (select 'x' from Serv_SMS_Notification_Requester where ParentID = @ParentID) )  
    Begin     
    insert into Serv_SMS_Notification_Requester       
    (ParentID, Activity_Id,  Login_ID, N_MSG_Body  )      
    select @ParentID, Activity_Id,  '', [smsbody]      
    from [Serv_Activity_Mast]  where ParentId = @ParentID and [Access]=1     
    End  
    else  
      Begin  
        
        update SSNR   
        set SSNR.N_MSG_Body = SAM.smsbody  
        from Serv_SMS_Notification_Requester SSNR   
        inner join Serv_Activity_Mast SAM  
        on  SSNR.Activity_Id = SAM.Activity_id   
        where SSNR.ParentID = @ParentID and SAM.ParentID  = @ParentID and SAM.Access =1  
        
     End   
     
     
     
     
   if(not exists (select 'x' from Serv_SMS_Notification_Agent where ParentID = @ParentID) )  
    Begin     
    insert into Serv_SMS_Notification_Agent        
    (ParentID, Activity_Id,  Login_ID, N_MSG_Body)         
   select @ParentID, Activity_Id, '', [smsbody]     
    from [Serv_Activity_Mast]  where ParentId = @ParentID   and [Access]=0            
 End    
 else  
  Begin  
    
     update SSNA   
        set SSNA.N_MSG_Body = SAM.smsbody  
        from Serv_SMS_Notification_Agent SSNA   
        inner join Serv_Activity_Mast SAM  
        on  SSNA.Activity_Id = SAM.Activity_id   
        where SSNA.ParentID = @ParentID and SAM.ParentID  = @ParentID and SAM.Access =0  
      
    
  End  
    
End 


GO

/* ============================================================
   Procedure: [dbo].[Serv_DefaultEntryCreation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_DefaultEntryCreation]      
(      
 @ParentID int,      
 @UserID  int,      
 @CompanyName nvarchar(200)      
)      
as      
Begin      
      /*      
       SELECT TOP 1000 [Groupid]      
      ,[ParentId]      
      ,[Group_Name]      
      ,[Group_Desc]      
      ,[Created_Date]      
      ,[Active]      
      ,[Dummy_Rec]      
       FROM [MYSMSLatest].[dbo].[Serv_Group_Mast]      
            
      */      
            
            
     declare @GroupID bigint = 0       
     insert into Serv_Group_Mast(ParentId,Group_Name,Group_Desc,Dummy_Rec)values(@ParentID,'Admin','Admin',1)      
     select @GroupID = SCOPE_IDENTITY()      
           
           
     /*      
       SELECT TOP 1000 [RoleId]      
      ,[ParentId]      
      ,[RoleDesc]      
      ,[Active]      
      ,[Date_Created]      
      ,[dummy_rec]      
  FROM [MYSMSLatest].[dbo].[Serv_Role_mast]      
        
     */      
           
     declare @RoleID bigint = 0       
     insert into Serv_Role_mast(ParentId,RoleDesc,Dummy_Rec)values(@ParentID,'Admin',1)      
     select @RoleID = SCOPE_IDENTITY()      
           
     /*      
       SELECT TOP 1000 [AutId]      
      ,[RoleId]      
      ,[ParentId]      
      ,[Menu]      
      ,[Activity]      
      ,[Permission]      
      ,[Access_Level]      
      ,[Date_Created]      
      ,[Dummy_Rec]      
       FROM [MYSMSLatest].[dbo].[Serv_Role_Auth_Mast]      
           
     */      
           
     
         
   
         
   /*      
      SELECT TOP 1000 [Agent_Id]      
      ,[ParentId]      
      ,[Userid]      
      ,[RoleId]      
      ,[Active]      
      ,[Group_id]      
      ,[Date_Created]      
      ,[Internal]      
      ,[Access_level]      
      ,[Dummy_Rec]      
  FROM [MYSMSLatest].[dbo].[Serv_Agent_Mast]      
         
   */      
         
  declare @Agent_Id bigint = 0        
  insert into Serv_Agent_Mast([ParentId]      
      ,[Userid]      
      ,[RoleId]      
      ,[Group_id]      
      ,[Internal]      
      ,[Access_level]      
      ,[Dummy_Rec])      
      values      
      (@ParentID,@UserID,@RoleID,@GroupID,1,'All Group',1)      
     select @Agent_Id = SCOPE_IDENTITY()      
       
   /*      
     SELECT TOP 1000 [TResp_Rule_Id]      
      ,[ParentID]      
      ,[Rule_Name]      
      ,[Rule_Match_type]      
      ,[Rule_Desc]      
      ,[Respons_Order]      
      ,[DateCreated]      
      ,[ord_no]      
      ,[Dummy_Rec]      
  FROM [MYSMSLatest].[dbo].[Serv_Ticket_Dispatch]      
         
   */      
     
  
         
  declare @TResp_Rule_Id bigint = 0        
  insert into Serv_Ticket_Dispatch      
      (      
       [ParentID]      
      ,[Rule_Name]      
      ,[Rule_Match_type]      
      ,[Rule_Desc]      
      ,[Respons_Order]      
      ,[ord_no]      
      ,[Dummy_Rec]      
      )      
      values      
      (@ParentID      
      ,'Admin'      
      ,1      
      ,'The Dispatch’r lets you bring your business rules into your support'      
      ,1      
      ,1      
      ,1)      
      select @TResp_Rule_Id = SCOPE_IDENTITY()      
         
         
   /*      
      SELECT TOP 1000 [tkt_filter_ID]      
      ,[TResp_Rule_Id]      
      ,[ParentID]      
      ,[Filter_Field]      
      ,[Filter_Cond]      
      ,[Filter_Value]      
      ,[Filter_FldType]      
      ,[ord_no]      
      ,[Dummy_Rec]      
  FROM [MYSMSLatest].[dbo].[Serv_Ticket_Dispatch_Filter]      
         
   */      
         
         
  declare @tkt_filter_ID bigint = 0        
  insert into Serv_Ticket_Dispatch_Filter      
      (      
            
      [TResp_Rule_Id]      
      ,[ParentID]      
      ,[Filter_Field]      
      ,[Filter_Cond]      
      ,[Filter_Value]      
      ,[Filter_FldType]      
      ,[ord_no]      
      ,[Dummy_Rec]      
            
      )      
      values      
      (      
            
      @TResp_Rule_Id      
      ,@ParentID      
      ,'Company Name'      
      ,'='      
      ,@CompanyName      
      ,1      
      ,1      
      ,1      
            
            
        )      
      select @tkt_filter_ID = SCOPE_IDENTITY()      
       
         
   /*             
     SELECT TOP 1000 [Tkt_ActionID]      
      ,[TResp_Rule_Id]      
      ,[Parentid]      
      ,[Action]      
      ,[Act_Value]      
      ,[ord_no]      
      ,[Dummy_Rec]      
  FROM [MYSMSLatest].[dbo].[Serv_Ticket_Dispatch_Action]      
         
   */      
         
     declare @Tkt_ActionID bigint = 0        
  insert into Serv_Ticket_Dispatch_Action      
      (      
            
  [TResp_Rule_Id]      
      ,[Parentid]      
      ,[Action]      
      ,[Act_Value]      
      ,[ord_no]      
      ,[Dummy_Rec]      
            
      )      
      values      
      (      
            
       @TResp_Rule_Id      
      ,@ParentID      
      ,'Assign to Group'      
      ,'Incident'      
      ,1      
      ,1      
      )      
      select @Tkt_ActionID = SCOPE_IDENTITY()      
         
    /*      
       SELECT TOP 1000 [SLAId]      
      ,[ParentID]      
      ,[SLA_Name]      
      ,[SLA_Desc]      
      ,[DateCreated]      
      ,[Active]      
      ,[ord_no]      
      ,[Dummy_Rec]      
  FROM [MYSMSLatest].[dbo].[Serv_SLA_Setting]      
        
    */      
            
   declare @SLAId bigint = 0        
  insert into Serv_SLA_Setting      
      (      
            
       [ParentID]      
      ,[SLA_Name]      
      ,[SLA_Desc]      
      ,[ord_no]      
      ,[Dummy_Rec]      
            
      )      
      values      
      (      
            
       @ParentID      
      ,'Dummy'      
      ,'Dummy'      
      ,1       
      ,1      
            
      )      
      select @SLAId = SCOPE_IDENTITY()      
         
         
   /*      
     SELECT TOP 1000 [appl_id]      
      ,[Parent_id]      
      ,[SLAID]      
      ,[Apply_to]      
      ,[Apply_val]      
      ,[Dummy_Rec]      
  FROM [MYSMSLatest].[dbo].[Serv_SLA_ApplyRule]      
         
   */      
            
    declare @appl_id bigint = 0        
  insert into Serv_SLA_ApplyRule      
      (      
            
       [Parent_id]      
      ,[SLAID]      
      ,[Apply_to]      
      ,[Apply_val]      
      ,[Dummy_Rec]      
            
      )      
      values      
      (      
       @Parentid      
      ,@SLAId      
      ,'Company'      
      ,@CompanyName      
      ,1      
      )      
      select @appl_id = SCOPE_IDENTITY()      
        
   /*      
      SELECT TOP 1000 [SLA_escalationID]      
      ,[SLAID]      
      ,[ParentID]     
      ,[Interval_val]      
      ,[Interval_Unit]      
      ,[Interval_Sec]      
      ,[Assigned_to]      
      ,[Responselevel]      
      ,[Dummy_Rec]      
  FROM [MYSMSLatest].[dbo].[Serv_SLA_escalation_rule]      
  
   */         
         
    declare @SLA_escalationID bigint = 0        
  insert into Serv_SLA_escalation_rule      
      (      
            
       [SLAID]      
      ,[ParentID]      
      ,[Interval_val]      
      ,[Interval_Unit]      
      ,[Interval_Sec]      
      ,[Assigned_to]      
      ,[Responselevel]      
      ,[Dummy_Rec]      
            
      )      
      values      
      (      
       @SLAId      
      ,@ParentID      
      ,0      
      ,'Immediately'      
      ,0      
      ,@UserID      
      ,1      
      ,1      
      )      
      select @SLA_escalationID = SCOPE_IDENTITY()      
        
         
       /* Rule Auth mast Default entry   */      
      Select       
        [RoleId]      
       ,[ParentId]      
       ,[Menu]      
       ,[Activity]      
       ,[Permission]      
       ,[Access_Level]      
       ,[Dummy_Rec]      
        into #tmptbl      
     FROM  [Serv_Role_Auth_Mast] where RoleId = 33 and ParentId = 29172       
      update #tmptbl set RoleId = @RoleID ,ParentId = @ParentID      
                  
     -- select * From #tmptbl      
                  
      insert into Serv_Role_Auth_Mast      
      ([RoleId]      
      ,[ParentId]      
      ,[Menu]      
      ,[Activity]      
      ,[Permission]      
      ,[Access_Level]      
      ,[Dummy_Rec]      
      )       
             
      select [RoleId]      
      ,[ParentId]      
      ,[Menu]      
      ,[Activity]      
      ,1      
      ,[Access_Level]      
       ,1 from #tmptbl       
            
      drop table #tmptbl      
       
      insert into Serv_Notification_Requester   
   (ParentID, Activity_Id, Email_ID, Login_ID, N_Sub, N_Body)  
   select @ParentID, Activity_Id, '', '', N_Sub, N_Body  
   from Serv_Notification_Requester  where ParentId = 335  
   
   insert into Serv_Notification_Agent    
   (ParentID, Activity_Id, Email_ID, Login_ID, N_Sub, N_Body)     
     select @ParentID, Activity_Id, '', '', N_Sub, N_Body  
     from Serv_Notification_Agent  where ParentId = 335   
           
             
End


GO

/* ============================================================
   Procedure: [dbo].[Serv_DefaultEntryCreation_support]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_DefaultEntryCreation_support]        
(        
 @ParentID int,        
 @Ser_User_ID  int,        
 @CompanyName nvarchar(200)        
)        
as        
Begin        
      /*        
       SELECT TOP 1000 [Groupid]        
      ,[ParentId]        
      ,[Group_Name]        
      ,[Group_Desc]        
      ,[Created_Date]        
      ,[Active]        
      ,[Dummy_Rec]        
       FROM [MYSMSLatest].[dbo].[Serv_Group_Mast]        
              
      */        
              
              
     declare @GroupID bigint = 0   
  IF NOT EXISTS(SELECT * FROM Serv_Group_Mast WHERE ParentId =   @ParentID)  
  BEGIN  
     insert into Serv_Group_Mast(ParentId,Group_Name,Group_Desc,Dummy_Rec)values(@ParentID,'Admin','Admin',1)    
  END      
     select @GroupID = SCOPE_IDENTITY()        
             
             
     /*        
       SELECT TOP 1000 [RoleId]        
      ,[ParentId]        
      ,[RoleDesc]        
      ,[Active]        
      ,[Date_Created]        
      ,[dummy_rec]        
  FROM [MYSMSLatest].[dbo].[Serv_Role_mast]        
          
     */        
             
     declare @RoleID bigint = 0    
  IF NOT EXISTS(SELECT * FROM Serv_Role_mast WHERE ParentId =   @ParentID)  
  BEGIN       
     insert into Serv_Role_mast(ParentId,RoleDesc,Dummy_Rec)values(@ParentID,'Admin',1)    
  END      
     select @RoleID = SCOPE_IDENTITY()        
             
     /*        
       SELECT TOP 1000 [AutId]        
      ,[RoleId]        
      ,[ParentId]        
      ,[Menu]        
      ,[Activity]        
      ,[Permission]        
      ,[Access_Level]        
      ,[Date_Created]        
      ,[Dummy_Rec]        
       FROM [MYSMSLatest].[dbo].[Serv_Role_Auth_Mast]        
             
     */        
             
       
           
     
           
   /*        
      SELECT TOP 1000 [Agent_Id]        
      ,[ParentId]        
      ,[Userid]        
      ,[RoleId]        
      ,[Active]        
      ,[Group_id]        
      ,[Date_Created]        
      ,[Internal]        
      ,[Access_level]        
      ,[Dummy_Rec]        
  FROM [MYSMSLatest].[dbo].[Serv_Agent_Mast]        
           
   */        
           
  declare @Agent_Id bigint = 0       
  IF NOT EXISTS(SELECT * FROM Serv_Agent_Mast WHERE ParentId =   @ParentID AND Userid = @Ser_User_ID)  
  BEGIN      
  insert into Serv_Agent_Mast([ParentId]        
      ,[Userid]        
      ,[RoleId]        
      ,[Group_id]        
      ,[Internal]        
      ,[Access_level]        
      ,[Dummy_Rec])        
      values        
      (@ParentID,@Ser_User_ID,@RoleID,@GroupID,1,'All Group',1)    
   END      
     select @Agent_Id = SCOPE_IDENTITY()        
         
   /*        
     SELECT TOP 1000 [TResp_Rule_Id]        
      ,[ParentID]        
      ,[Rule_Name]        
      ,[Rule_Match_type]        
      ,[Rule_Desc]        
      ,[Respons_Order]        
      ,[DateCreated]        
      ,[ord_no]        
      ,[Dummy_Rec]        
  FROM [MYSMSLatest].[dbo].[Serv_Ticket_Dispatch]        
           
   */        
       
    
           
  declare @TResp_Rule_Id bigint = 0    
  IF NOT EXISTS(SELECT * FROM Serv_Ticket_Dispatch WHERE ParentId =   @ParentID )  
  BEGIN        
  insert into Serv_Ticket_Dispatch        
      (        
       [ParentID]        
      ,[Rule_Name]        
      ,[Rule_Match_type]        
      ,[Rule_Desc]        
      ,[Respons_Order]        
      ,[ord_no]        
      ,[Dummy_Rec]        
      )        
      values        
      (@ParentID        
      ,'Admin'        
      ,1        
      ,'The Dispatch’r lets you bring your business rules into your support'        
      ,1        
      ,1        
      ,1)        
   END  
      select @TResp_Rule_Id = SCOPE_IDENTITY()        
           
           
   /*        
      SELECT TOP 1000 [tkt_filter_ID]        
      ,[TResp_Rule_Id]        
      ,[ParentID]        
      ,[Filter_Field]        
      ,[Filter_Cond]        
      ,[Filter_Value]        
      ,[Filter_FldType]        
      ,[ord_no]        
      ,[Dummy_Rec]        
  FROM [MYSMSLatest].[dbo].[Serv_Ticket_Dispatch_Filter]        
           
   */        
           
           
  declare @tkt_filter_ID bigint = 0    
    IF NOT EXISTS(SELECT * FROM Serv_Ticket_Dispatch_Filter WHERE ParentId =   @ParentID )  
  BEGIN        
  insert into Serv_Ticket_Dispatch_Filter        
      (        
              
      [TResp_Rule_Id]        
      ,[ParentID]        
      ,[Filter_Field]        
      ,[Filter_Cond]        
      ,[Filter_Value]        
      ,[Filter_FldType]        
      ,[ord_no]        
      ,[Dummy_Rec]        
              
      )        
      values        
      (        
              
      @TResp_Rule_Id        
      ,@ParentID        
      ,'Company Name'        
      ,'='        
      ,@CompanyName        
      ,1        
      ,1        
      ,1        
        
              
        )      
  END    
      select @tkt_filter_ID = SCOPE_IDENTITY()        
         
           
   /*               
     SELECT TOP 1000 [Tkt_ActionID]        
      ,[TResp_Rule_Id]        
      ,[Parentid]        
      ,[Action]        
      ,[Act_Value]        
      ,[ord_no]        
      ,[Dummy_Rec]        
  FROM [MYSMSLatest].[dbo].[Serv_Ticket_Dispatch_Action]        
           
   */        
           
     declare @Tkt_ActionID bigint = 0          
   IF NOT EXISTS(SELECT * FROM Serv_Ticket_Dispatch_Action WHERE ParentId =   @ParentID )  
  BEGIN  
  insert into Serv_Ticket_Dispatch_Action        
      (        
              
  [TResp_Rule_Id]        
      ,[Parentid]        
      ,[Action]        
      ,[Act_Value]        
      ,[ord_no]        
      ,[Dummy_Rec]        
              
      )        
      values        
      (        
              
       @TResp_Rule_Id        
      ,@ParentID        
      ,'Assign to Group'        
      ,'Incident'        
      ,1        
      ,1        
      )        
   END  
      select @Tkt_ActionID = SCOPE_IDENTITY()        
           
    /*        
       SELECT TOP 1000 [SLAId]        
      ,[ParentID]        
      ,[SLA_Name]        
      ,[SLA_Desc]        
      ,[DateCreated]        
      ,[Active]        
      ,[ord_no]        
      ,[Dummy_Rec]        
  FROM [MYSMSLatest].[dbo].[Serv_SLA_Setting]        
          
    */        
              
   declare @SLAId bigint = 0    
   IF NOT EXISTS(SELECT * FROM Serv_SLA_Setting WHERE ParentId =   @ParentID )  
  BEGIN        
  insert into Serv_SLA_Setting        
      (        
              
       [ParentID]        
      ,[SLA_Name]        
      ,[SLA_Desc]        
      ,[ord_no]        
      ,[Dummy_Rec]        
              
      )        
      values        
      (        
              
       @ParentID        
      ,'Dummy'        
      ,'Dummy'        
      ,1         
      ,1        
              
      )        
   END  
      select @SLAId = SCOPE_IDENTITY()        
           
           
   /*        
     SELECT TOP 1000 [appl_id]        
      ,[Parent_id]        
      ,[SLAID]        
      ,[Apply_to]        
      ,[Apply_val]        
      ,[Dummy_Rec]        
  FROM [MYSMSLatest].[dbo].[Serv_SLA_ApplyRule]        
           
   */        
              
    declare @appl_id bigint = 0    
  IF NOT EXISTS(SELECT * FROM Serv_SLA_ApplyRule WHERE Parent_Id =   @ParentID )  
  BEGIN        
  insert into Serv_SLA_ApplyRule        
      (        
              
       [Parent_id]        
      ,[SLAID]        
      ,[Apply_to]        
      ,[Apply_val]        
      ,[Dummy_Rec]        
              
      )        
      values        
      (        
       @Parentid        
      ,@SLAId        
      ,'Company'        
      ,@CompanyName        
      ,1        
      )        
   END  
      select @appl_id = SCOPE_IDENTITY()        
          
   /*        
      SELECT TOP 1000 [SLA_escalationID]        
      ,[SLAID]        
      ,[ParentID]       
      ,[Interval_val]        
      ,[Interval_Unit]        
      ,[Interval_Sec]        
      ,[Assigned_to]        
      ,[Responselevel]        
      ,[Dummy_Rec]        
  FROM [MYSMSLatest].[dbo].[Serv_SLA_escalation_rule]        
    
   */           
           
    declare @SLA_escalationID bigint = 0     
 IF NOT EXISTS(SELECT * FROM Serv_SLA_escalation_rule WHERE ParentId =   @ParentID )  
  BEGIN         
  insert into Serv_SLA_escalation_rule        
      (        
              
       [SLAID]        
      ,[ParentID]        
      ,[Interval_val]        
      ,[Interval_Unit]        
      ,[Interval_Sec]        
      ,[Assigned_to]        
      ,[Responselevel]        
      ,[Dummy_Rec]        
              
      )        
      values        
      (        
       @SLAId        
      ,@ParentID        
      ,0        
      ,'Immediately'        
      ,0        
      ,@Ser_User_ID        
      ,1        
      ,1        
      )       
   END   
      select @SLA_escalationID = SCOPE_IDENTITY()        
          
            
       /* Rule Auth mast Default entry   */        
      Select         
        [RoleId]        
       ,[ParentId]        
       ,[Menu]        
       ,[Activity]        
       ,[Permission]        
       ,[Access_Level]        
       ,[Dummy_Rec]        
        into #tmptbl        
     FROM  [Serv_Role_Auth_Mast] where RoleId = 2 and ParentId = 335         
      update #tmptbl set RoleId = @RoleID ,ParentId = @ParentID        
                    
     -- select * From #tmptbl        
                    
      insert into Serv_Role_Auth_Mast        
      ([RoleId]        
      ,[ParentId]        
      ,[Menu]        
      ,[Activity]        
      ,[Permission]        
      ,[Access_Level]        
      ,[Dummy_Rec]        
      )      
               
      select [RoleId]        
      ,[ParentId]        
      ,[Menu]        
      ,[Activity]        
      ,1        
      ,[Access_Level]        
       ,1 from #tmptbl         
              
      drop table #tmptbl
	  
   IF NOT EXISTS(SELECT * FROM Serv_Activity_Mast WHERE ParentId =   @ParentID )  
  BEGIN   
     
   insert into Serv_Activity_Mast      
   (ParentID,Activity_Desc,Access,subject,Messagebody,help_text,smsbody)      
     select @ParentID,Activity_Desc,Access,subject,Messagebody,help_text,smsbody
   from Serv_Activity_Mast  where ParentId = 335     
  END    
        
         
    IF NOT EXISTS(SELECT * FROM Serv_Notification_Requester WHERE ParentId =   @ParentID )  
  BEGIN   
      insert into Serv_Notification_Requester     
   (ParentID, Activity_Id, Email_ID, Login_ID, N_Sub, N_Body, DateCreated, Active)    
   select ParentID, Activity_Id, NULL, NULL, subject, Messagebody, getdate(), 1    
   from Serv_Activity_Mast  where ParentId = @ParentID and Access = 1 
   END  
   IF NOT EXISTS(SELECT * FROM Serv_Notification_Agent WHERE ParentId =   @ParentID )  
  BEGIN   
     
   insert into Serv_Notification_Agent      
   (ParentID, Activity_Id, Email_ID, Login_ID, N_Sub, N_Body, DateCreated, Active)    
   select ParentID, Activity_Id, NULL, NULL, subject, Messagebody, getdate(), 1    
   from Serv_Activity_Mast  where ParentId = @ParentID and Access = 0     
  END  

      IF NOT EXISTS(SELECT * FROM Serv_SMS_Notification_Requester WHERE ParentId =   @ParentID )  
  BEGIN   
      insert into Serv_SMS_Notification_Requester     
   (ParentID, Activity_Id, Mobile_No, Login_ID, SenderID, N_MSG_Body, IsSMSActive, DateCreated)    
   select ParentID, Activity_Id, NULL, NULL,  
   ISNULL((select top 1 sender_name from default_senderid where USER_ID= @ParentID AND sender_id<>0),'TXTSMS') AS SenderID, 
   smsbody, 1, getdate()    
   from Serv_Activity_Mast  where ParentId = @ParentID and Access = 1   
   END  
   IF NOT EXISTS(SELECT * FROM Serv_SMS_Notification_Agent WHERE ParentId =   @ParentID )  
  BEGIN   
     
   insert into Serv_SMS_Notification_Agent      
   (ParentID, Activity_Id, Mobile_No, Login_ID, SenderID, N_MSG_Body, IsSMSActive, DateCreated)    
   select ParentID, Activity_Id, NULL, NULL,  
   ISNULL((select top 1 sender_name from default_senderid where USER_ID= @ParentID AND sender_id<>0),'TXTSMS') AS SenderID, 
   smsbody, 1, getdate()    
   from Serv_Activity_Mast  where ParentId = @ParentID and Access = 0    
  END 

  
             
               
End   


