/* ============================================================
   Procedure: [dbo].[serv_delete_default_data]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[serv_delete_default_data]      
     
as      
Begin      
     
   
     delete From Serv_Group_Mast where ParentID not in (Select ParentID from Serv_User_Detail)
            
 delete from Serv_Role_mast where ParentID  not in (Select ParentID from Serv_User_Detail)
   delete from Serv_Agent_Mast  where ParentID  not in (Select ParentID from Serv_User_Detail)
       
  delete From Serv_Ticket_Dispatch  where ParentID  not in (Select ParentID from Serv_User_Detail)
  delete From Serv_Ticket_Dispatch_Filter  where ParentID  not in (Select ParentID from Serv_User_Detail)
  delete From Serv_Ticket_Dispatch_Action  where ParentID  not in (Select ParentID from Serv_User_Detail)     
  delete From Serv_SLA_Setting       where ParentID  not in (Select ParentID from Serv_User_Detail)
  delete From Serv_SLA_ApplyRule       where Parent_ID  not in (Select ParentID from Serv_User_Detail)
  delete From Serv_SLA_escalation_rule       where ParentID  not in (Select ParentID from Serv_User_Detail)
  delete From  [Serv_Role_Auth_Mast] where   ParentID  not in (Select ParentID from Serv_User_Detail)
      delete From Serv_Notification_Requester    where ParentID  not in (Select ParentID from Serv_User_Detail)
   delete From Serv_Notification_Agent     where ParentID  not in (Select ParentID from Serv_User_Detail)
      
End


