/* ============================================================
   Procedure: [dbo].[Serv_EscalationRuleAction]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_EscalationRuleAction]
(
@UserID bigint,
@ParentID bigint,
@SLAId bigint,
@Responselevel tinyint,
@BatchID bigint,
@Date_Created datetime,
@Subject nvarchar(200),
@MailMsg nvarchar(500),
@TicketID bigint,
@TicketProcessMSG nvarchar(200),
@ARSLSent nvarchar(50),
@Result int output 
)
as
Begin

 Declare @Assigned_to int,@Interval_Seconds bigint = 0 
 Declare @FromMailID nvarchar(200), @ToEmailID  nvarchar(200)    
 set @Result = 0;
	              
	              		    
 select @Assigned_to = Assigned_to,@Interval_Seconds = Interval_Sec  from Serv_SLA_escalation_rule(nolock)
			  where SLAID = @SLAId and ParentID = @ParentID and Responselevel = @Responselevel     
     		     
			   if(DATEADD(SECOND,@Interval_Seconds,@Date_Created) < GETDATE())  
				  Begin  
		         select @FromMailID = isnull(Email,'')  From User_Detail where USER_ID = @Assigned_to  
				 select @ToEmailID = isnull(Email,'')  From User_Detail where USER_ID = @UserID  	
					
			   		
	    insert into CloneEmailsFilter(
	            Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName
                ,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID
                ,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime
                ,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source
	               
	              )
	   values( @FromMailID,@ToEmailID,@Subject,'',@MailMsg, GETDATE(),@Assigned_to,@ParentID,'noreply@kit19.com',@BatchID,2,'','','',@MailMsg,1,0,1,'TicketManagement'
	              
	              ) 									
					   
	  insert into Serv_ProcessedTicketDetails(TicketID,SLAID,Subject,ActionPerformed)   
	  values(@TicketID,@SLAId,@Subject,@TicketProcessMSG)  
	
	  declare @sqlStr nvarchar(500)= '' 
	  --declare @ARSLSent1 nvarchar(50) = 'A1RSLSent'
	  --declare @TicketID1 int = 5;
	  set @sqlStr = 'update Serv_TicketMaster set '+@ARSLSent+' = 1 where TicketID = '+ CAST(@TicketID as varchar)+''  
	  --select @sqlStr 		       
		exec (@sqlStr)	       
	    set @Result = 1
	       
	    
	  end     


End


GO

/* ============================================================
   Procedure: [dbo].[Serv_executeSLARule]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_executeSLARule]      
as      
Begin      
 Declare @TicketCount int = 0        
 Declare @i int = 1      
 Declare @TicketID bigint,@ParentID bigint;       
     
    
       
select ROW_NUMBER() OVER (ORDER BY TicketID DESC) AS RowID,* into #TicketCollections   
 from Serv_TicketMaster where Status not in (2,4,5) and isnull(spam,0) = 0 and deleted = 0      
      
 select @TicketCount = Count(*) from #TicketCollections      
       
       
 while( @i <= @TicketCount)      
	 Begin      
	   declare @ARemindRSPNSSent bit,  @ARemindResolveSent bit, @ARSPSent bit,   
	   @A1RSLSent bit, @A2RSLSent bit, @A3RSLSent bit, @A4RSLSent bit , @User_ID bigint,
	   @agrp_unassigned bit      
	  select @TicketID = TicketID,@ParentID = ParentID, @User_ID = USER_ID,  
	  @ARemindRSPNSSent=ARemindRSPNSSent,  @ARemindResolveSent=ARemindResolveSent,  
	  @ARSPSent= ARSPSent, @A1RSLSent=A1RSLSent, @A2RSLSent=A2RSLSent,  
		@A3RSLSent=A3RSLSent, @A4RSLSent=A4RSLSent ,@agrp_unassigned = agrp_unassigned 
		from #TicketCollections   
	  where RowID = @i  
	if @agrp_unassigned =0
	 begin
	 declare @ctl int
	select @ctl = Count(*) from  dbo.Serv_TicketMaster
	where TicketID= @ticketid and ISNULL(Assign_Group,0)> 0 
	and isnull(AssignTo,0) = 0
	if @ctl > 0
	begin
		 exec Serv_CheckSLAMatrix @TicketID,@ParentID,@User_ID, 'Agrp'
		  
	end
	end
	 if @ARemindRSPNSSent=0  
	  begin
	  if not exists(select 1 from dbo.Serv_TicketHistory     
				  where TicketID = @TicketID and Ticket_Response = 1)
	  begin
		  exec Serv_CheckSLAMatrix @TicketID,@ParentID,@User_ID, 'bresp'
	  end
	  end
	 if @ARemindResolveSent=0
	 begin 
	  exec Serv_CheckSLAMatrix @TicketID,@ParentID,@User_ID, 'brslv'  
	  end
	 if @ARSPSent=0
	 begin
	  if not exists(select 1 from dbo.Serv_TicketHistory     
				  where TicketID = @TicketID and Ticket_Response = 1)
	  begin  
	  exec Serv_CheckSLAMatrix @TicketID,@ParentID,@User_ID, 'Aresp'  
	  
	  end 

	 end
	 if @A1RSLSent=0  
	  begin
	  exec Serv_CheckSLAMatrix @TicketID,@ParentID,@User_ID, 'sla1'  
	  
	 end
	 if @A2RSLSent=0 
	 begin 
	  exec Serv_CheckSLAMatrix @TicketID,@ParentID,@User_ID, 'sla2'  
	  
	 end 
	 if @A3RSLSent=0
	 begin
	  exec Serv_CheckSLAMatrix @TicketID,@ParentID,@User_ID, 'sla3'  
	 
	 end 
	 if @A4RSLSent=0
	 begin
	  exec Serv_CheckSLAMatrix @TicketID,@ParentID,@User_ID, 'sla4'  
	  
	 end 
	 set @i = @i +1;  
	  
	--select @i
  
 End       
      
      
drop table #TicketCollections   
   
End


GO

