/* ============================================================
   Procedure: [dbo].[serv_get_Resolver_Name]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec serv_get_Resolver_Name @exp=N'335_0039222_69126_51Q'
--exec serv_get_Resolver_Name @exp=N'37540_038_44844_5ZP6'
CREATE   PROC serv_get_Resolver_Name -- '32222_028_2173_O64'      
(        
	@exp nvarchar(50)        
)        
as        
begin     
  
--select a.Name, b.subject from    Serv_User_Detail a inner join Serv_TicketMaster b   
--on a.ser_user_id = b.update_by  
--where convert(nvarchar(30),TicketNo) = SUBSTRING(@exp,0,(((LEN(@exp))-CHARINDEX('_', REVERSE(@exp)))-CHARINDEX('_',REVERSE(@exp))))  

-- declare @exp nvarchar(50)='37540_038_44844_5ZP6' 
print SUBSTRING(@exp,0,CHARINDEX('_', @exp,CHARINDEX('_',@exp)+1))
select top 1 SUD.Name, STM.Subject
from Serv_TicketMaster STM inner join Serv_TicketHistory STH
on	STM.TicketID=STH.TicketID inner join  Serv_User_Detail SUD
on	STH.RaisedBy=SUD.ser_user_id
where convert(nvarchar(30),STM.TicketNo) = SUBSTRING(@exp,0,CHARINDEX('_', @exp,CHARINDEX('_',@exp)+1))
  
end 



