CREATE   PROCEDURE [dbo].[Serv_get_Ticket_Dispatch]
(        
 @TResp_Rule_Id bigint ,         
 @Parentid bigint,         
 @flOpt varchar(10)='Get'           
)        
AS        
begin        
if @flopt='Get'      
begin       
if @TResp_Rule_Id = 0        
select   
       [TResp_Rule_Id]  
      ,[ParentID]  
      ,[Rule_Name]  
      ,[Rule_Match_type]  
      ,[Rule_Desc]  
      ,[Respons_Order]  
      --,[DateCreated]  
      ,dbo.[fn_getusertimefromindiantime](@ParentID,[DateCreated] ) as DateCreated   
      ,[ord_no]=isnull([ord_no],[TResp_Rule_Id])  
      ,[Dummy_Rec]  
   from Serv_Ticket_Dispatch        
   where Parentid =@Parentid  order by ord_no      
else         
 select   
       [TResp_Rule_Id]  
      ,[ParentID]  
      ,[Rule_Name]  
      ,[Rule_Match_type]  
      ,[Rule_Desc]  
      ,[Respons_Order]  
      --,[DateCreated]  
       ,dbo.[fn_getusertimefromindiantime](@ParentID,[DateCreated] ) as DateCreated   
      ,[ord_no]  
      ,[Dummy_Rec]  
  from Serv_Ticket_Dispatch        
      where Parentid =@Parentid        
 and TResp_Rule_Id=@TResp_Rule_Id  order by ord_no      
end       
if @flopt='Delete'      
delete from Serv_Ticket_Dispatch_Action where Parentid =@Parentid        
 and TResp_Rule_Id=@TResp_Rule_Id       
       
 -- Select 'Deleted' resp           
end  



GO

