/* ============================================================
   Procedure: [dbo].[Serv_get_TicketHistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 -- [Serv_get_TicketHistory]     49,335                
CREATE   PROCEDURE [dbo].[Serv_get_TicketHistory]             
(                  
@TicketID bigint,                   
@User_id bigint                   
                  
)                  
AS                  
                  
begin                  
                  
--select sud.Login_id, hst.*,isnull(stm.Stat_Desc,'New') Stat_Desc, tm.Subject,                  
--tm.Description, tm.User_id                  
-- from Serv_TicketMaster tm left outer join  Serv_TicketHistory hst                   
--on hst.TicketID = tm.TicketID                  
-- left outer join Serv_Ticket_Stat_Mast stm                  
-- on stm.Stat_ID = hst.Status               
-- inner join Serv_User_Detail sud   on sud.User_id = tm.User_id                
--where tm.User_id = @User_id and tm.TicketID= @TicketID order by HistoryDate desc                  
          
            
 select sud.Login_id,  hst.TicketHistoryID, hst.TicketID, hst.user_id, hst.ParentID,
   
   --hst.ResponseTime,           
   dbo.[fn_getusertimefromindiantime](hst.ParentID,hst.ResponseTime) as  ResponseTime,
   
   --hst.SubmittedDate,
   
   dbo.[fn_getusertimefromindiantime](hst.ParentID,hst.SubmittedDate) as  SubmittedDate,
   
   SUBSTRING(hst.Remarks,0,100) as shrtRemarks, SUBSTRING(hst.Note,0,100) as shrtNote,          
   hst.Note, hst.Status,
    
  -- hst.HistoryDate,
   dbo.[fn_getusertimefromindiantime](hst.ParentID,hst.HistoryDate) as  HistoryDate,
   
   hst.TransferredTo, hst.Remarks, hst.Priority, hst.Transfered_from,          
   hst.Activity_lavel, hst.Assign_Group, hst.Ticket_Response,    
    isnull(updb.Login_id,'')+ ' '+'('+isnull(updb.Email,'')+')' raisedby ,    
    isnull(stm.Stat_Desc,'New') Stat_Desc, (case when isnull(aud.Login_id,'') !='' then 'Agent : '+ aud.Login_id+'('+aud.Email+')'       
    else  case when isnull(gm.Group_Name,'')!='' then 'Group : '+ gm.Group_Name else '' end  end) as agent,       
    tm.Subject,  tm.Description, tm.User_id 
                     
 from Serv_TicketMaster tm left outer join  Serv_TicketHistory hst                   
on hst.TicketID = tm.TicketID                  
 left outer join Serv_Ticket_Stat_Mast stm                  
 on stm.Stat_ID = hst.Status               
 inner join Serv_User_Detail sud   on sud.User_id = tm.User_id          
 left join Serv_User_Detail aud   on aud.User_id = hst.TransferredTo     
  left join Serv_User_Detail updb   on updb.User_id = hst.raisedby      
 left outer join  Serv_Group_Mast gm on gm.Groupid = hst.Assign_Group              
where tm.TicketID= @TicketID order by HistoryDate desc                      
                  
                  
end



GO

