    isnull(updb.Login_id,'')+ ' '+'('+isnull(updb.Email,'')+')' raisedby ,                    
    isnull(stm.Stat_Desc,'New') Stat_Desc, (case when isnull(aud.Login_id,'') !='' then 'Agent : '+ aud.Login_id+'('+aud.Email+')'                       
    else  case when isnull(gm.Group_Name,'')!='' then 'Group : '+ gm.Group_Name else '' end  end) as agent,                       
    tm.Subject,  tm.Description, tm.User_id, isnull(ta.filename,'') as attachfile, isnull(ta.path,'') as filepath,      
 isnull((select a.Rating from serv_ticket_feedback_tbl a where a.TicketHistoryID = hst.TicketHistoryID),'') as Rating,      
 isnull((select a.Comments from serv_ticket_feedback_tbl a where a.TicketHistoryID = hst.TicketHistoryID),'') as Cust_Comments, 
 isnull((Select srv.TicketCategoryName from Serv_TicketCategory_Mast srv where srv.TicketCategoryId = tm.TicketCategoryId),'') as TicketCategoryName, tm.TicketCategoryId 
 from Serv_TicketMaster tm left outer join  Serv_TicketHistory hst                                   
 on hst.TicketID = tm.TicketID                                  
 left outer join Serv_Ticket_Stat_Mast stm                                  
 on stm.Stat_ID = hst.Status                               
 inner join Serv_User_Detail sud   on sud.ser_user_id = tm.User_id                          
 left join Serv_User_Detail aud   on aud.ser_user_id = hst.TransferredTo              
 left join Serv_User_Detail updb   on updb.ser_user_id = convert(BigInt,hst.raisedby)          
 left outer join  Serv_Group_Mast gm on gm.Groupid = hst.Assign_Group            
 LEFT OUTER JOIN spt_tkt_attach ta on tm.TicketID = ta.ticketid and hst.TicketHistoryID = ta.tickethistoryid        
where tm.TicketID= @TicketID order by HistoryDate desc                                      

end   





