/* ============================================================
   Procedure: [dbo].[Serv_get_TicketMaster_support]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

                                       
CREATE   PROCEDURE [dbo].[Serv_get_TicketMaster_support]-- 0,26956,515,'All Group','01JUN2019','30JUN2019','01JUN2019','30JUN2019'        
(                                                  
@TicketID bigint,                                               
@ParentID bigint,                                            
--@User_id bigint,                     
@ser_user_id bigint,                                              
@access_level varchar(20),                        
@TicketCreatedDateFrom date,                      
@TicketCreatedDateTo date,                       
@TicketUpdatedDateFrom date,                      
@TicketUpdatedDateTo date,                       
@vwstatus int = null,                      
@status int=null,                        
@AssignTo bigint=null,                        
@Assign_Group bigint=null,                        
@ticketno nvarchar(35)='',                                  
@Subject nvarchar(500)='',                                
@Description nvarchar(500)='',                             
@Requester nvarchar(400)=''                        
)                                                  
AS                                                  
                                                  
begin                            
                       
 if @vwstatus=0                       
 begin                      
  set @vwstatus=null                      
 end                    
                     
 if @status=0                       
 begin                      
  set @status=null                      
 end 
 if @AssignTo=0                       
 begin                      
  set @AssignTo=null                      
 end 
 if @Assign_Group=0                       
 begin                      
  set @Assign_Group=null                      
 end                     
                                                 
if @TicketID > 0                                                  
 select                                  
  dbo.[fn_getusertimefromindiantime](@ParentID,tm.AssignedDateTime) as AssignedDateTime,                                  
  dbo.[fn_getusertimefromindiantime](@ParentID,tm.resolved_dt) as resolved_dt,                                
  tm.*,isnull(stm.Stat_Desc,'New') Stat_Desc,                                  
 CONVERT( date,dbo.[fn_getusertimefromindiantime](@ParentID,tm.Date_Created)) as Date_Creat,                                  
  GM.Group_Name, ud.Login_id , SUBSTRING(tm.Description,0,100) as shrtdesc,                                        
  ud.Name req_name, ud.Login_id,                                          
  (case when isnull(ag.Login_id,'') !='' then 'Agent : '+ ag.Login_id+'('+ag.Email+')'                                       
   else  (case when isnull(gm.Group_Name,'')!='' then 'Group : '+ gm.Group_Name else 'Not Assigned' end)  end) as Agent_name,                                        
  ( select dbo.[fn_getusertimefromindiantime](@ParentID,SubmittedDate) as SubmittedDate           
    From Serv_TicketHistory                                         
    where TicketID =tm.TicketID AND TicketHistoryID = (SELECT MAX(TICKETHISTORYID) FROM Serv_TicketHistory B where TicketID =tm.TicketID )
	AND ParentID =   @ParentID                                
  ) ldate,      
  isnull((select top 1 [filename] from spt_tkt_attach where ticketid = tm.TicketID order by id desc),'') as attachfile,      
 isnull((select top 1 [path] from spt_tkt_attach where ticketid = tm.TicketID order by id desc),'') as filepath,    
 isnull((select top 1 a.Rating from serv_ticket_feedback_tbl a , Serv_TicketHistory b where a.TicketHistoryID = b.TicketHistoryID    
 and b.TicketID = tm.TicketID order by id desc ),'') as Rating,    
 isnull((select top 1 a.Comments from serv_ticket_feedback_tbl a , Serv_TicketHistory b where a.TicketHistoryID = b.TicketHistoryID    
 and b.TicketID = tm.TicketID  order by id desc),'') as Cust_Comments                            
  from VW_Serv_TicketMaster tm                                                  
  left outer join VW_Serv_Ticket_Stat_Mast stm                                                 
  on stm.Stat_ID = tm.Status                                                  
  left join Serv_Group_Mast GM                                                
  on GM.Groupid = tm.Assign_Group                           
  left outer join dbo.Serv_User_Detail ud                                                
  --on ud.User_id = tm.User_id                                         
  on ud.ser_user_id = tm.User_id                                         
  left outer join dbo.Serv_User_Detail ag                                             
  on ag.User_id = tm.AssignTo                                                
  where  TicketID= @TicketID          
  and   convert(date,dbo.[fn_getISTtimefromusertime](@ParentId,tm.Date_Created)) between                           
      CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@TicketCreatedDateFrom))                          
      and                              
      CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@TicketCreatedDateTo))                       
and    convert(date,dbo.[fn_getISTtimefromusertime](@ParentId,tm.update_date))      between                           
      CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@TicketUpdatedDateFrom))                    
      and                              
      CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@TicketUpdatedDateTo))                   
 and tm.Status=isnull(@Status,tm.Status)                             
