begin                   
                       
if @TicketID > 0                        
Begin            
          
        
select            
  convert(date, dbo.[fn_getusertimefromindiantime](@ParentID,tm.AssignedDateTime)) AssignedDateTime,              
  tm.*,            
  isnull(stm.Stat_Desc,'New') Stat_Desc,             
             
  convert(date, dbo.[fn_getusertimefromindiantime](@ParentID,tm.Date_Created)) Date_Creat,                      
             
 GM.Group_Name, ud.Login_id , SUBSTRING(tm.Description,0,100) as shrtdesc,  isnull(AssignTo,0) Assign ,  isnull(Assign_Group,0)   agrp,                  
             
 (select Name from  dbo.Serv_User_Detail  where ser_user_id = tm.User_id) req_name,                
 (select Email from  dbo.Serv_User_Detail  where ser_user_id = tm.User_id) req_Email,       
 isnull((select Name from  dbo.Serv_User_Detail  where ser_user_id = tm.AssignTo),'Not Assigned') Agent_name,      
 isnull((COALESCE(NULLIF (LeadImage, '') , '~/UserProfile/defaultimage.png')),'~/UserProfile/defaultimage.png') as LeadImage,
 isnull((select top 1 [filename] from spt_tkt_attach where ticketid = tm.TicketID order by id desc),'') as attachfile,
 isnull((select top 1 [path] from spt_tkt_attach where ticketid = tm.TicketID order by id desc),'') as filepath                             
from Serv_TicketMaster tm                        
 left outer join Serv_Ticket_Stat_Mast stm                       
 on stm.Stat_ID = tm.Status                        
 left join Serv_Group_Mast GM                      
 on GM.Groupid = tm.Assign_Group                      
 left join dbo.Serv_User_Detail ud                      
