AS                        
                 
begin                   
                       
if @TicketID > 0                        
Begin            
          
        
select            
  convert(date, dbo.[fn_getusertimefromindiantime](@ParentID,tm.AssignedDateTime)) AssignedDateTime,              
  tm.*,            
  isnull(stm.Stat_Desc,'New') Stat_Desc,             
             
  convert(date, dbo.[fn_getusertimefromindiantime](@ParentID,tm.Date_Created)) Date_Creat,                      
             
 GM.Group_Name, ud.Login_id , SUBSTRING(tm.Description,0,100) as shrtdesc,  isnull(AssignTo,0) Assign ,  isnull(Assign_Group,0)   agrp,                  
             
 (select Name from  dbo.Serv_User_Detail  where ser_user_id = tm.User_id) req_name,                
 isnull((select Name from  dbo.Serv_User_Detail  where ser_user_id = tm.AssignTo),'Not Assigned') Agent_name , 
 isnull(ul.LeadImage,'../../../UserProfile/defaultimage.png') as LeadImage               
