/* ============================================================
   Procedure: [dbo].[Serv_get_TicketMaster1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_get_TicketMaster1]      
(      
@TicketID bigint,   
@User_id bigint,      
@ParentID bigint       
      
)      
AS      
      
begin      
if @TicketID > 0      
select tm.*,isnull(stm.Stat_Desc,'New') Stat_Desc, convert(date,tm.Date_Created) Date_Creat,    
 GM.Group_Name, ud.Login_id    
from Serv_TicketMaster tm      
 left outer join Serv_Ticket_Stat_Mast stm     
 on stm.Stat_ID = tm.Status      
 left join Serv_Group_Mast GM    
 on GM.Groupid = tm.Assign_Group    
 left join dbo.Serv_User_Detail ud    
 on ud.User_id = tm.User_id    
where  TicketID= @TicketID order by tm.Date_Created desc      
      
else   
if @ParentID = 0    
select tm.*,isnull(stm.Stat_Desc,'New') Stat_Desc, convert(date,tm.Date_Created) Date_Creat,    
 GM.Group_Name, ud.Login_id    
from Serv_TicketMaster tm      
 left outer join Serv_Ticket_Stat_Mast stm     
 on stm.Stat_ID = tm.Status      
 left join Serv_Group_Mast GM    
 on GM.Groupid = tm.Assign_Group    
 left join dbo.Serv_User_Detail ud    
 on ud.User_id = tm.User_id      
where tm.User_id = @User_id  order by tm.Date_Created desc     
if @ParentID > 0    
select tm.*,isnull(stm.Stat_Desc,'New') Stat_Desc, convert(date,tm.Date_Created) Date_Creat,    
 GM.Group_Name, ud.Login_id    
from Serv_TicketMaster tm      
 left outer join Serv_Ticket_Stat_Mast stm     
 on stm.Stat_ID = tm.Status      
 left join Serv_Group_Mast GM    
 on GM.Groupid = tm.Assign_Group    
 left join dbo.Serv_User_Detail ud    
 on ud.User_id = tm.User_id      
where tm.ParentID = @ParentID  order by tm.Date_Created desc      
     
end


