/* ============================================================
   Procedure: [dbo].[Serv_get_TicketMasterData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
CREATE   PROCEDURE [dbo].[Serv_get_TicketMasterData]                  
(                  
@TicketID bigint,               
@ParentID bigint           
               
)                  
AS                  
                  
begin             
                 
                
 select  
    
  dbo.[fn_getusertimefromindiantime](@ParentID,tm.AssignedDateTime) as AssignedDateTime  
   ,  
  dbo.[fn_getusertimefromindiantime](@ParentID,tm.resolved_dt) as resolved_dt  
   ,  
    
  tm.*,isnull(stm.Stat_Desc,'New') Stat_Desc,  
    
 -- convert(date,tm.Date_Created) Date_Creat,  
 CONVERT( date,dbo.[fn_getusertimefromindiantime](@ParentID,tm.Date_Created)) as Date_Creat,  
    
  GM.Group_Name, ud.Login_id , SUBSTRING(tm.Description,0,100) as shrtdesc,        
  ud.Name req_name, ud.Login_id,          
  (case when isnull(ag.Login_id,'') !='' then 'Agent : '+ ag.Login_id+'('+ag.Email+')'       
   else  (case when isnull(gm.Group_Name,'')!='' then 'Group : '+ gm.Group_Name else 'Not Assigned' end)  end) as Agent_name,        
  (  
    select top 1   
      
     -- SubmittedDate   
     dbo.[fn_getusertimefromindiantime](@ParentID,SubmittedDate) as SubmittedDate  
      
    From Serv_TicketHistory         
    where TicketID =tm.TicketID order by SubmittedDate Desc  
  ) ldate          
  from Serv_TicketMaster tm                  
  left outer join Serv_Ticket_Stat_Mast stm                 
  on stm.Stat_ID = tm.Status                  
  left join Serv_Group_Mast GM                
  on GM.Groupid = tm.Assign_Group                
  left outer join dbo.Serv_User_Detail ud                
  on ud.User_id = tm.User_id         
  left outer join dbo.Serv_User_Detail ag                
  on ag.User_id = tm.AssignTo                
  where  TicketID= @TicketID order by tm.Date_Created desc                  

end          
            





GO

