   and    convert(date,tm.Date_Created)      between       
      CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@TicketCreatedDateFrom))      
      and          
      CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@TicketCreatedDateTo))   
  
   and    convert(date,tm.update_date)      between       
      CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@TicketUpdatedDateFrom))      
      and          
      CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@TicketUpdatedDateTo))   
      
 and tm.Status=isnull(@Status,tm.Status)         
 and stm.VW_Stat_ID=isnull(@vwstatus,stm.VW_Stat_ID)       
 and tm.TicketNo like isnull('%'+@ticketno + '%',tm.TicketNo)              
 and tm.Subject like isnull('%'+@Subject + '%',tm.Subject)              
 and tm.Description like isnull('%'+@Description + '%',tm.Description)              
and tm.Requester like isnull('%'+Requester + '%',tm.Requester)          
             
  and (tm.AssignTo=isnull(@AssignTo,tm.AssignTo)  or  
   tm.Assign_Group=isnull(@Assign_Group,tm.Assign_Group)   )        
           
  order by tm.Date_Created desc                         
 end                             
end                             
end   
  



GO

