  left outer join dbo.Serv_User_Detail ud                        
  on ud.ser_user_id = tm.User_id                 
  left outer join dbo.Serv_User_Detail ag                        
  on ag.ser_user_id = tm.AssignTo                        
  where (tm.AssignTo = @ser_user_id or tm.User_id = @ser_user_id)      
   order by tm.Date_Created desc                      
end                         
if @access_level = 'Within Group'                     
 begin                    
                  
 select sm1.Group_id,Userid into #tmp from Serv_Agent_Mast sm1 where sm1.Userid = @ser_user_id                   
                
 select          
  dbo.[fn_getusertimefromindiantime](@ParentID,tm.AssignedDateTime) as AssignedDateTime,          
  dbo.[fn_getusertimefromindiantime](@ParentID,tm.resolved_dt) as resolved_dt,          
  tm.*,isnull(stm.Stat_Desc,'New') Stat_Desc,          
  CONVERT( date,dbo.[fn_getusertimefromindiantime](@ParentID,tm.Date_Created)) as Date_Creat,          
  GM.Group_Name, ud.Login_id , SUBSTRING(tm.Description,0,100) as shrtdesc,                
  ud.Name req_name, ud.Login_id,                  
  (case when isnull(ag.Login_id,'') !='' then 'Agent : '+ ag.Login_id+'('+ag.Email+')'               
  else  (case when isnull(gm.Group_Name,'')!='' then 'Group : '+ gm.Group_Name else 'Not Assigned' end)  end) as Agent_name,                
  (  select top 1  dbo.[fn_getusertimefromindiantime](@ParentID,SubmittedDate) as SubmittedDate  From Serv_TicketHistory                 
  where TicketID =tm.TicketID order by SubmittedDate Desc) ldate,    
 isnull((select top 1 [filename] from spt_tkt_attach where ticketid = tm.TicketID order by id desc),'') as attachfile,    
  isnull((select top 1 [path] from spt_tkt_attach where ticketid = tm.TicketID order by id desc),'') as filepath ,  
 isnull((select top 1 a.Rating from serv_ticket_feedback_tbl a , Serv_TicketHistory b where a.TicketHistoryID = b.TicketHistoryID  
 and b.TicketID = tm.TicketID order by id desc ),'') as Rating,  
 isnull((select top 1 a.Comments from serv_ticket_feedback_tbl a , Serv_TicketHistory b where a.TicketHistoryID = b.TicketHistoryID  
 and b.TicketID = tm.TicketID  order by id desc),'') as Cust_Comments         
  from Serv_TicketMaster tm                          
  left outer join Serv_Ticket_Stat_Mast stm                         
  on stm.Stat_ID = tm.Status                          
  left join Serv_Group_Mast GM                        
  on GM.Groupid = tm.Assign_Group                        
  left outer join dbo.Serv_User_Detail ud                        
  on ud.ser_user_id = tm.User_id                 
  left outer join dbo.Serv_User_Detail ag                        
  on ag.ser_user_id = tm.AssignTo                        
  where tm.AssignTo in (select Userid from #tmp)                    
  union          
 select           
    dbo.[fn_getusertimefromindiantime](@ParentID,tm.AssignedDateTime) as AssignedDateTime,          
    dbo.[fn_getusertimefromindiantime](@ParentID,tm.resolved_dt) as resolved_dt,        
    tm.*,isnull(stm.Stat_Desc,'New') Stat_Desc,          
    CONVERT( date,dbo.[fn_getusertimefromindiantime](@ParentID,tm.Date_Created)) as Date_Creat,          
    GM.Group_Name,          
 ud.Login_id , SUBSTRING(tm.Description,0,100) as shrtdesc,                
 ud.Name req_name, ud.Login_id,                  
 (case when isnull(ag.Login_id,'') !='' then 'Agent : '+ ag.Login_id+'('+ag.Email+')'               
    else  (case when isnull(gm.Group_Name,'')!='' then 'Group : '+ gm.Group_Name else 'Not Assigned' end)  end) as Agent_name,                
    ( select top 1 dbo.[fn_getusertimefromindiantime](@ParentID,SubmittedDate) as SubmittedDate From Serv_TicketHistory                 
 where TicketID =tm.TicketID order by SubmittedDate Desc ) ldate,    
 isnull((select top 1 [filename] from spt_tkt_attach where ticketid = tm.TicketID order by id desc),'') as attachfile ,    
  isnull((select top 1 [path] from spt_tkt_attach where ticketid = tm.TicketID order by id desc),'') as filepath ,  
 isnull((select top 1 a.Rating from serv_ticket_feedback_tbl a , Serv_TicketHistory b where a.TicketHistoryID = b.TicketHistoryID  
 and b.TicketID = tm.TicketID order by id desc ),'') as Rating,  
 isnull((select top 1 a.Comments from serv_ticket_feedback_tbl a , Serv_TicketHistory b where a.TicketHistoryID = b.TicketHistoryID  
 and b.TicketID = tm.TicketID  order by id desc),'') as Cust_Comments                 
  from Serv_TicketMaster tm                          
  left outer join Serv_Ticket_Stat_Mast stm       
  on stm.Stat_ID = tm.Status                          
  left join Serv_Group_Mast GM                        
  on GM.Groupid = tm.Assign_Group                        
  left outer join dbo.Serv_User_Detail ud                        
  on ud.ser_user_id = tm.User_id                 
  left outer join dbo.Serv_User_Detail ag                
  on ag.ser_user_id = tm.AssignTo                        
  where tm.Assign_Group in (select Group_id from #tmp) and tm.AssignTo =0                    
   order by tm.Date_Created desc                     
                
   drop table #tmp                     
 end                    
 if @access_level = 'All Group'                     
  begin                    
SELECT        [dbo].[fn_getusertimefromindiantime](@ParentID, [tm].
[AssignedDateTime]) AS [AssignedDateTime],
			  [dbo].[fn_getusertimefromindiantime](@ParentID, [tm].
			  [resolved_dt]) AS [resolved_dt],
			  [tm].*,
			  ISNULL([stm].[Stat_Desc], 'New') AS [Stat_Desc],
			  CONVERT(DATE, [dbo].[fn_getusertimefromindiantime](@ParentID,
			  [tm].[Date_Created])) AS [Date_Creat],
			  [GM].[Group_Name],
			  [ud].[Login_id],
			  SUBSTRING([tm].[Description], 0, 100) AS [shrtdesc],
			  [ud].[Name] AS [req_name],
			  [ud].[Login_id],
			  ( CASE
				WHEN ISNULL([ag].[Login_id], '') != ''
					THEN 'Agent : ' + [ag].[Login_id] + '(' + [ag].[Email]
					+ ')'
				ELSE( CASE
					  WHEN ISNULL([gm].[Group_Name], '') != ''
						  THEN 'Group : ' + [gm].[Group_Name]
					  ELSE 'Not Assigned'
					  END )
				END ) AS [Agent_name],
			  (SELECT TOP 1 [dbo].[fn_getusertimefromindiantime](@ParentID,
			  [SubmittedDate]) AS [SubmittedDate]
			   FROM          [Serv_TicketHistory]
			   WHERE        [TicketID] = [tm].[TicketID]
			   ORDER BY [SubmittedDate] DESC) AS [ldate],
			  ISNULL((SELECT TOP 1 [filename]
					  FROM         [spt_tkt_attach]
					  WHERE        [ticketid] = [tm].[TicketID]
					  ORDER BY [id] DESC), '') AS [attachfile],
			  ISNULL((SELECT TOP 1 [path]
					  FROM         [spt_tkt_attach]
					  WHERE        [ticketid] = [tm].[TicketID]
					  ORDER BY [id] DESC), '') AS [filepath],
			  ISNULL((SELECT TOP 1 [a].[Rating]
					  FROM         [serv_ticket_feedback_tbl] AS [a],
					  [Serv_TicketHistory] AS [b]
					  WHERE        [a].[TicketHistoryID] = [b].
					  [TicketHistoryID]
								   AND [b].[TicketID] = [tm].[TicketID]
					  ORDER BY [id] DESC), '') AS [Rating],
			  ISNULL((SELECT TOP 1 [a].[Comments]
					  FROM         [serv_ticket_feedback_tbl] AS [a],
					  [Serv_TicketHistory] AS [b]
					  WHERE        [a].[TicketHistoryID] = [b].
					  [TicketHistoryID]
								   AND [b].[TicketID] = [tm].[TicketID]
					  ORDER BY [id] DESC), '') AS [Cust_Comments]
FROM Serv_TicketMaster AS tm LEFT OUTER JOIN Serv_Ticket_Stat_Mast AS stm
ON stm.Stat_ID = tm.STATUS LEFT JOIN Serv_Group_Mast AS GM
ON GM.Groupid = tm.Assign_Group LEFT OUTER JOIN dbo.Serv_User_Detail AS ud
ON ud.ser_user_id = tm.User_id LEFT OUTER JOIN dbo.Serv_User_Detail AS ag
ON ag.ser_user_id = tm.AssignTo
WHERE [tm].[ParentID] = @ParentID
ORDER BY [tm].[Date_Created] DESC;                     
 end                         
end                         
end 



GO

