CREATE   PROCEDURE [dbo].[Serv_GetAgentDisplay] --335          
(          
  @ParentID bigint          
)          
as          
Begin          
    
              
      select          
       SAM.[Agent_Id]          
      ,SAM.[ParentId]          
      ,SAM.[Userid]          
      ,SAM.[RoleId]          
      ,SAM.[Active]          
      ,SAM.[Group_id]          
      ,( select Group_Name From Serv_Group_Mast where Groupid = SAM.Group_id ) as Group_Name          
        
        
      , dbo.[fn_getusertimefromindiantime](@ParentID,SAM.[Date_Created]) as   Date_Created         
        
        
      ,SUD.Login_id         
      ,SUD.Email          
      ,SUD.Mobile,        
      Access_level,        
      isnull(rm.RoleDesc,'') RoleDesc        
       from Serv_Agent_Mast(Nolock)  SAM inner join       
       dbo.Serv_Role_mast rm on rm.RoleId = sam.RoleId       
       inner join Serv_User_Detail SUD      
       on sud.ser_user_id = sam.Userid and sud.ParentId = sam.ParentId      
         where SAM.ParentId = @ParentID        
End  




