SET QUOTED_IDENTIFIER ON

-- exec Serv_GetAgentDisplay_support 32222
CREATE   PROCEDURE [dbo].[Serv_GetAgentDisplay_support]
(          
  @ParentID bigint
)          
as          
Begin
	-- declare @ParentID bigint=32222

	SELECT SAM.[Agent_Id], 
		   SAM.[ParentId], 
		   SAM.[Userid], 
		   SAM.[RoleId], 
		   SAM.[Active], 
		   SAM.[Group_id], 
		   (SELECT Group_Name FROM Serv_Group_Mast WHERE Groupid = SAM.Group_id) AS Group_Name, 
		   dbo.[fn_getusertimefromindiantime](@ParentID, SAM.[Date_Created]) AS Date_Created, 
		   Login_id=SUD.Login_id + ' (' + SUD.Name + ')', 
		   SUD.Email, 
		   SUD.Mobile, 
		   Access_level, 
		   ISNULL(rm.RoleDesc, '') RoleDesc
	FROM Serv_Agent_Mast(NOLOCK) SAM INNER JOIN dbo.Serv_Role_mast rm 
	ON	 rm.RoleId = sam.RoleId INNER JOIN Serv_User_Detail SUD 
	ON	 sud.ser_user_id = sam.Userid AND sud.ParentId = sam.ParentId
	WHERE SAM.ParentId = @ParentID;

End  



