/* ============================================================
   Procedure: [dbo].[Serv_GetAgentTicketStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_GetAgentTicketStatus] --1,'2018-01-01','2018-05-10'         
(        
  @UserID bigint,        
  @fmdate date,        
  @todate date         
)        
as        
Begin        
        
 --declare @UserID int = 0;        
 --select @UserID = Userid from Serv_Agent_Mast where Agent_Id = @AgentID         
  Declare @new int = 0, @total int = 0 , @open int = 0, @close int = 0,@Resolve int = 0,        
  @pending int = 0, @wait int = 0, @intime int = 0, @extime int = 0 ,@UnResolved int =0       
            
         
  select @total =COUNT(*) from Serv_TicketMaster where  AssignTo = @UserID        
 and convert(date,Date_Created)
 
     between 
     
  convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) 
    and 
  convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))      
 
 
  select @New =COUNT(*)  from Serv_TicketMaster where Status = 0 and AssignTo = @UserID         
     and convert(date,Date_Created) 
     
     between 
     
   convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) 
     and 
   convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))      
 
     
              
  select @Open =COUNT(*)  from Serv_TicketMaster where Status = 1 and AssignTo = @UserID         
     and convert(date,Date_Created)
     
      between
       
    convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) 
      and 
    convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))      
 
            
  select @close =COUNT(*)  from Serv_TicketMaster where Status = 2 and AssignTo = @UserID         
   and convert(date,Date_Created) 
   
   between 
   
   convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) 
      and 
   convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))      
        
        
  select @pending = COUNT(*)  from Serv_TicketMaster where Status = 3 and AssignTo = @UserID         
   and convert(date,Date_Created) 
   
   between 
   
   convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) 
      and 
   convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))      
         
        
  select @Resolve = COUNT(*)  from Serv_TicketMaster where Status = 4 and AssignTo = @UserID         
   and convert(date,Date_Created) 
   between 
   
  convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) 
     and 
  convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))      
         
          
  select @intime = Count(*) from Serv_TicketMaster(nolock) STM inner join Serv_TicketTimelyPRM (nolock)        
       STTP on stm.TicketID = STTP.TicketID where CONVERT(date,STTP.RSLVWithinDate) >= CONVERT(date,STM.resolved_dt)        
           
  select @extime = Count(*) from Serv_TicketMaster(nolock) STM inner join Serv_TicketTimelyPRM (nolock)        
       STTP on stm.TicketID = STTP.TicketID where CONVERT(date,STTP.RSLVWithinDate) < CONVERT(date,STM.resolved_dt)     
   select @UnResolved =Count(*) from Serv_TicketMaster where Status <> 2 and     
   convert(date,Date_Created) 
   between 
   
  convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) 
    and 
  convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))      
 
   
   and AssignTo = @UserID             
          
          
select am.Group_id,@UserID as AgentID,@total as Total ,@New as New ,      
@Open as [Open],@close as [Closed],@pending as Pending,@Resolve as Resolved, @UnResolved as UnResolved,@intime as InTime,      
@extime as ExTime,Group_Name, Login_id Agent_name      
from Serv_Agent_Mast am inner join dbo.Serv_User_Detail ud      
on ud.User_id = am.Userid inner join dbo.Serv_Group_Mast gm      
on gm.Groupid = am.Group_id where Userid = @UserID        
        
          
               
end         
        
 --select * from Serv_TicketMaster          
 -- select COUNT(*) as 'New' from Serv_TicketMaster where Status =1 and AssignTo = 335 group by AssignTo



GO

/* ============================================================
   Procedure: [dbo].[Serv_GetAgentTicketStatus_INTDateTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_GetAgentTicketStatus_INTDateTime] --1,'2018-01-01','2018-05-10'         
(        
  @UserID bigint,        
  @fmdate date,        
  @todate date         
)        
as        
Begin        
        
 --declare @UserID int = 0;        
 --select @UserID = Userid from Serv_Agent_Mast where Agent_Id = @AgentID         
  Declare @new int = 0, @total int = 0 , @open int = 0, @close int = 0,@Resolve int = 0,        
  @pending int = 0, @wait int = 0, @intime int = 0, @extime int = 0 ,@UnResolved int =0       
            
         
  select @total =COUNT(*) from Serv_TicketMaster where  AssignTo = @UserID        
 and convert(date,Date_Created)
 
     between 
     
  convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) 
    and 
  convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))      
 
 
  select @New =COUNT(*)  from Serv_TicketMaster where Status = 0 and AssignTo = @UserID         
     and convert(date,Date_Created) 
     
     between 
     
   convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) 
     and 
   convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))      
 
     
              
  select @Open =COUNT(*)  from Serv_TicketMaster where Status = 1 and AssignTo = @UserID         
     and convert(date,Date_Created)
     
      between
       
    convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) 
      and 
    convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))      
 
            
  select @close =COUNT(*)  from Serv_TicketMaster where Status = 2 and AssignTo = @UserID         
   and convert(date,Date_Created) 
   
   between 
   
   convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) 
      and 
   convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))      
        
        
  select @pending = COUNT(*)  from Serv_TicketMaster where Status = 3 and AssignTo = @UserID         
   and convert(date,Date_Created) 
   
   between 
   
   convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) 
      and 
   convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))      
         
        
  select @Resolve = COUNT(*)  from Serv_TicketMaster where Status = 4 and AssignTo = @UserID         
   and convert(date,Date_Created) 
   between 
   
  convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) 
     and 
  convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))      
         
          
  select @intime = Count(*) from Serv_TicketMaster(nolock) STM inner join Serv_TicketTimelyPRM (nolock)        
       STTP on stm.TicketID = STTP.TicketID where CONVERT(date,STTP.RSLVWithinDate) >= CONVERT(date,STM.resolved_dt)        
           
  select @extime = Count(*) from Serv_TicketMaster(nolock) STM inner join Serv_TicketTimelyPRM (nolock)        
       STTP on stm.TicketID = STTP.TicketID where CONVERT(date,STTP.RSLVWithinDate) < CONVERT(date,STM.resolved_dt)     
   select @UnResolved =Count(*) from Serv_TicketMaster where Status <> 2 and     
   convert(date,Date_Created) 
   between 
   
  convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) 
    and 
  convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))      
 
   
   and AssignTo = @UserID             
          
          
select am.Group_id,@UserID as AgentID,@total as Total ,@New as New ,      
@Open as [Open],@close as [Closed],@pending as Pending,@Resolve as Resolved, @UnResolved as UnResolved,@intime as InTime,      
@extime as ExTime,Group_Name, Login_id Agent_name      
from Serv_Agent_Mast am inner join dbo.Serv_User_Detail ud      
on ud.User_id = am.Userid inner join dbo.Serv_Group_Mast gm      
on gm.Groupid = am.Group_id where Userid = @UserID        
        
          
               
end         
        
 --select * from Serv_TicketMaster          
 -- select COUNT(*) as 'New' from Serv_TicketMaster where Status =1 and AssignTo = 335 group by AssignTo


GO

/* ============================================================
   Procedure: [dbo].[Serv_GetAgentTicketStatus_support]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec Serv_GetAgentTicketStatus_support @UserID=5510,@fmdate='2022-12-01',@todate='2022-12-31'
CREATE   PROCEDURE [dbo].[Serv_GetAgentTicketStatus_support]
(            
  @UserID bigint,            
  @fmdate date,            
  @todate date             
)            
as            
Begin            
            
 --declare @UserID bigint=5510,@fmdate date='2022-12-01',@todate date='2022-12-31'
 --select @UserID = Userid from Serv_Agent_Mast where Agent_Id = @AgentID             
  Declare @new int = 0, @total int = 0 , @open int = 0, @close int = 0,@Resolve int = 0,            
  @pending int = 0, @WaitCustomer int=0, @WaitParty int=0, @intime int = 0, @extime int = 0 ,@UnResolved int =0           
                
             
  select @total =COUNT(*) 
  from Serv_TicketMaster(nolock)
  where  AssignTo = @UserID and convert(date,Date_Created) between convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) and convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))          
     
     
  select @New =COUNT(*)  
  from Serv_TicketMaster(nolock) 
  where Status = 0 and AssignTo = @UserID and convert(date,Date_Created) between convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) and convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))          
                  
  select @Open =COUNT(*) 
  from Serv_TicketMaster(nolock) 
  where Status = 1 and AssignTo = @UserID and convert(date,Date_Created) between convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) and convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))          
     
                
  select @close =COUNT(*)
  from Serv_TicketMaster(nolock) 
  where Status = 2 and AssignTo = @UserID and convert(date,Date_Created) between convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) and convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))          
            
            
  select @pending = COUNT(*)  
  from Serv_TicketMaster(nolock)
  where Status = 3 and AssignTo = @UserID and convert(date,Date_Created) between convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) and convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))          
             
            
  select @Resolve = COUNT(*) 
  from Serv_TicketMaster(nolock) 
  where Status = 4 and AssignTo = @UserID and convert(date,Date_Created) between convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) and convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))          
             
  select @WaitCustomer = COUNT(*) 
  from Serv_TicketMaster(nolock) 
  where Status = 5 and AssignTo = @UserID and convert(date,Date_Created) between convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) and convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))          
             
  select @WaitParty = COUNT(*) 
  from Serv_TicketMaster(nolock) 
  where Status = 8 and AssignTo = @UserID and convert(date,Date_Created) between convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) and convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate))          
             
              
  select @intime = Count(*) 
  from Serv_TicketMaster(nolock) STM inner join Serv_TicketTimelyPRM (nolock) STTP 
  on stm.TicketID = STTP.TicketID 
  where CONVERT(date,STTP.RSLVWithinDate) >= CONVERT(date,STM.resolved_dt)            
               
  select @extime = Count(*) 
  from Serv_TicketMaster(nolock) STM inner join Serv_TicketTimelyPRM (nolock) STTP 
  on stm.TicketID = STTP.TicketID where CONVERT(date,STTP.RSLVWithinDate) < CONVERT(date,STM.resolved_dt)
  
  select @UnResolved =Count(*) 
  from Serv_TicketMaster(nolock) 
  where Status <> 2 and convert(date,Date_Created) between convert(date,dbo.[fn_getISTtimefromusertime](ParentID,@fmdate)) and convert(date, dbo.[fn_getISTtimefromusertime](ParentID,@todate)) and AssignTo = @UserID                 
              
              
	select	am.Group_id, @UserID as AgentID, @total as Total, @New as New, @Open as [Open], 
			@close as [Closed], @pending as Pending, @Resolve as Resolved, @WaitCustomer as WaitCustomer,
			@WaitParty as WaitThirdParty, @UnResolved as UnResolved, @intime as InTime, 
			@extime as ExTime,Group_Name, Login_id Agent_name          
	from Serv_Agent_Mast(nolock) am inner join dbo.Serv_User_Detail(nolock) ud
	on ud.ser_user_id = am.Userid inner join dbo.Serv_Group_Mast gm
	on gm.Groupid = am.Group_id where Userid = @UserID
            
              
                   
end             



GO

