/* ============================================================
   Procedure: [dbo].[Serv_getauth_check]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Serv_getauth_check]     
(    
@user_id bigint,    
@opt int =0,    
@menu_desc nvarchar(100) ='',    
@desc nvarchar(100) =''    
)    
as     
begin    
if @opt = 0    
select am.Access_level ,ud.User_id,ud.ParentId,ud.Login_id, Menu,    
rm.RoleId,rm.RoleDesc,rm.Active,au.AutId,    
au.Activity,au.Permission from serv_user_detail ud inner join    
Serv_Agent_Mast am on am.Userid = ud.User_id    
inner join Serv_Role_mast rm on rm.RoleId = am.RoleId    
inner join Serv_Role_Auth_Mast au    
on au.RoleId = am.RoleId where user_id = @user_id     
    
if @opt = 1    
select am.Access_level ,ud.User_id,ud.ParentId,ud.Login_id, Menu,    
rm.RoleId,rm.RoleDesc,rm.Active,au.AutId,    
au.Activity,au.Permission from serv_user_detail ud inner join    
Serv_Agent_Mast am on am.Userid = ud.User_id    
inner join Serv_Role_mast rm on rm.RoleId = am.RoleId    
inner join Serv_Role_Auth_Mast au    
on au.RoleId = am.RoleId where user_id = @user_id and    
 Menu = @menu_desc    
     
if @opt = 2    
select am.Access_level ,ud.User_id,ud.ParentId,ud.Login_id, Menu,    
rm.RoleId,rm.RoleDesc,rm.Active,au.AutId,    
au.Activity,au.Permission from serv_user_detail ud inner join    
Serv_Agent_Mast am on am.Userid = ud.User_id    
inner join Serv_Role_mast rm on rm.RoleId = am.RoleId    
inner join Serv_Role_Auth_Mast au    
on au.RoleId = am.RoleId where user_id = @user_id and    
 Activity not in( 'Menu') and Menu = @desc    
    
    
     
if @opt = 3    
select am.Access_level ,ud.User_id,ud.ParentId,ud.Login_id, Menu,    
rm.RoleId,rm.RoleDesc,rm.Active,au.AutId,    
au.Activity,au.Permission from serv_user_detail ud inner join    
Serv_Agent_Mast am on am.Userid = ud.User_id    
inner join Serv_Role_mast rm on rm.RoleId = am.RoleId    
inner join Serv_Role_Auth_Mast au    
on au.RoleId = am.RoleId where user_id = @user_id and    
 Activity = @menu_desc and Menu = @desc    
     
end


GO

