/* ============================================================
   Procedure: [dbo].[Serv_GetRoleAuthMastDisplay]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
    
CREATE   PROCEDURE [dbo].[Serv_GetRoleAuthMastDisplay] --1, 29159               
(                    
 @RoleID bigint = 0,                    
 @ParentID  bigint                    
)                    
 As                    
 Begin                    
    Declare @Count int = 0;                      
    if(@RoleID = 0)                    
       Begin                    
         select @Count = Count(*) From Serv_Role_Auth_Mast where ParentId = @ParentID                    
       End                      
    else                     
       Begin                    
         select @Count = Count(*) From Serv_Role_Auth_Mast where ParentId = @ParentID and RoleId = @RoleID       End                        
                       
 if(@Count > 0)                    
   Begin                    
   if(@RoleID = 0)                   
      Begin                  
   SELECT RoleId, ParentId,act_menu, isnull([menu],'') [menu],            
 isnull([Add],'') [Add],  isnull([Modify],'') [Modify], isnull([delete],'') [delete],            
  isnull([view],'') [view],              
   isnull([Activate or DeActivate],'') Activate, isnull([History View],'') History,              
  isnull(Assign,'') Assign,isnull(Status,'') Status,isnull(Priority,'') Priority,             
  isnull(Reorder,'') Reorder,            
   isnull([History Reply],'')[HistoryReply],isnull([Merge],'') [Merge],isnull([Split],'') [Split]            
     FROM                 
    (SELECT RoleId,ParentId,[menu] act_menu, Activity , CAST(Permission as varchar(1))               
    Permission FROM dbo.Serv_Role_Auth_Mast               
    where parentid = @ParentID and roleid=@RoleID and menu !='Manage Ticket') Tab1                
    PIVOT                
    (                
    max(Permission)  FOR Activity IN ([menu],[Add],[Modify],[delete],[view],[Activate or DeActivate]    ,  [History View]              
    ,Assign,Status,Priority, Reorder, [History Reply],[Merge],[Split] )) AS Tab2                
  ORDER BY Tab2.menu                
            
SELECT RoleId, ParentId,act_menu, isnull([menu],'') [menu],            
 isnull([Add],'') [Add],  isnull([Modify],'') [Modify], isnull([delete],'') [delete],            
  isnull([view],'') [view],              
   isnull([Activate or DeActivate],'') Activate, isnull([History View],'') History,              
  isnull(Assign,'') Assign,isnull(Status,'') Status,isnull(Priority,'') Priority,             
  isnull(Reorder,'') Reorder,            
   isnull([History Reply],'')[HistoryReply],isnull([Merge],'') [Merge],isnull([Split],'') [Split]            
     FROM                 
    (SELECT RoleId,ParentId,[menu] act_menu, Activity , CAST(Permission as varchar(1))               
    Permission FROM dbo.Serv_Role_Auth_Mast               
