/* ============================================================
   Procedure: [dbo].[Serv_GetSourceValue]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_GetSourceValue]    
(    
  -- @SourceName Nvarchar(200)    
 @ParentID Bigint    
    
)    
as    
Begin    
      
  declare @SourceID bigint  = 0    
 -- select isnull(SourceID,0) from UserSourceSettings where Name = @SourceName   
 if not exists(select 1 from usersourcesettings(nolock) where userid=@parentid
 and name='ServiceTicketSignup'
 ) 
  begin     
    INSERT INTO UserSourceSettings                    
     (NAME, UserID, IsEditable,IsActive,CreatedDate,ModifiedDate,ModifiedBy )                    
   VALUES                    
     (                    
    'ServiceTicketSignup',                    
    @ParentID,                    
    0,                    
    1,                    
    GETDATE(),                    
    GETDATE(),                    
    335                    
     )       
    select @SourceID = SCOPE_IDENTITY()    
    end
    else
    begin
    select top 1 @SourceID=sourceid from usersourcesettings(nolock) where userid=@parentid and name='ServiceTicketSignup'
    end
    select @SourceID as SourceID      
            
End


GO

/* ============================================================
   Procedure: [dbo].[Serv_getStatusofticket]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec Serv_getStatusofticket @ParentId=31871,@Groupid=0,@UserID=0,@fmdate='2022-10-01',@todate='2022-10-31'
-- exec Serv_getStatusofticket @ParentId=335,@Groupid=0,@UserID=0,@fmdate='2022-12-01',@todate='2022-12-31'
CREATE   PROCEDURE [dbo].[Serv_getStatusofticket] --335,40,335,'01-01-2017','01-01-2019'              
(              
 @ParentId bigint,            
 @Groupid bigint,              
 @UserID bigint,            
 @fmdate date,                
 @todate date                 
)              
as              
Begin
	--declare @ParentId bigint=335,@Groupid bigint=0,@UserID bigint=0,@fmdate date='2022-12-01',@todate date='2022-12-31'

 drop table if exists #tmpuser  
 select USERID, Group_id into #tmpuser from Serv_Agent_Mast where 1=2  
              
 if @UserID > 0              
 begin              
  insert into #tmpuser (USERID,Group_id) select USERID,0 from Serv_Agent_Mast where USERID =@UserID          
 end              
 if @Groupid > 0 and @UserID =0              
 begin              
  insert into #tmpuser (USERID,Group_id) select USERID,Group_id  from Serv_Agent_Mast where Group_id =@Groupid              
 end              
 if @Groupid = 0 and @UserID =0              
 begin              
  insert into #tmpuser (USERID,Group_id) select USERID,Group_id from Serv_Agent_Mast(nolock) where ParentId = @ParentId              
 end              
              
 declare @total int =0,@New int=0,@Open int=0,@close int=0, @pending int=0,@Resolve int=0,@intime int=0, @OverDue int=0, @UnResolved int=0,@unassigned int =0,@DueToday int = 0,@WaitCustomer int=0,@WaitParty int=0

 --select * from Serv_TicketMaster(nolock) Where parentid=335 and Assign_Group not in (select Group_id From #tmpuser)   
  --select * from Serv_Agent_Mast where  Group_id = 1385 
              
 select @total =COUNT(distinct TicketID)   
 from Serv_TicketMaster(nolock)   
 where (AssignTo in (select USERID From #tmpuser) OR Assign_Group IN (SELECT  Group_id FROM #tmpuser) OR AssignTo = 0 AND Assign_Group = 0) AND ParentId = @ParentId and convert(date,Date_Created) between CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate)) and CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))          
    --group by AssignTo          
                    
  select @New =COUNT(distinct TicketID)    
  from Serv_TicketMaster 
  where ParentId = @ParentId and Status = 0 and (AssignTo in (select USERID From #tmpuser) OR Assign_Group IN (SELECT  Group_id FROM #tmpuser)) and convert(date,Date_Created) between CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate)) and CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))          
      --group by AssignTo          
               
                        
  select @Open =COUNT(distinct TicketID)    
  from Serv_TicketMaster   
  where ParentId = @ParentId and Status = 1 and (AssignTo in (select USERID From #tmpuser) OR   
  Assign_Group IN (SELECT  Group_id FROM #tmpuser)) and convert(date,Date_Created) between CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate)) and CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))          
     --group by AssignTo                   
           
           
  select @close =COUNT(distinct TicketID)    
  from Serv_TicketMaster 
  where ParentId = @ParentId and Status = 2 and (AssignTo in (select USERID From #tmpuser) OR Assign_Group IN (SELECT  Group_id FROM #tmpuser)) and convert(date,Date_Created) between CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate)) and CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))
     --group by AssignTo                   
                  
           
  select @pending = COUNT(distinct TicketID)    
  from Serv_TicketMaster   
  where ParentId = @ParentId and Status = 3 and (AssignTo in (select USERID From #tmpuser) OR Assign_Group IN (SELECT  Group_id FROM #tmpuser)) and convert(date,Date_Created) between CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate)) and CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))
    --group by AssignTo                   
                  
           
  select @Resolve = COUNT(distinct TicketID)    
  from Serv_TicketMaster   
  where ParentId = @ParentId and Status = 4 and (AssignTo in (select USERID From #tmpuser) OR   
  Assign_Group IN (SELECT  Group_id FROM #tmpuser)) and convert(date,Date_Created) between CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate)) and CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))          
       --group by AssignTo                   
                    
   select @WaitCustomer = COUNT(distinct TicketID)    
  from Serv_TicketMaster   
  where ParentId = @ParentId and Status = 5 and (AssignTo in (select USERID From #tmpuser) OR   
  Assign_Group IN (SELECT  Group_id FROM #tmpuser)) and convert(date,Date_Created) between CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate)) and CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))          
       --group by AssignTo                   
 
 select @WaitParty = COUNT(distinct TicketID)    
  from Serv_TicketMaster   
  where ParentId = @ParentId and Status = 8 and (AssignTo in (select USERID From #tmpuser) OR   
  Assign_Group IN (SELECT  Group_id FROM #tmpuser)) and convert(date,Date_Created) between CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate)) and CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))          
       --group by AssignTo                   
           
 select @intime = COUNT(distinct STM.TicketID)   
 from Serv_TicketMaster(nolock) STM inner join Serv_TicketTimelyPRM (nolock) STTP   
 on stm.TicketID = STTP.TicketID   
 where STM.ParentId = @ParentId and convert(date,Date_Created) between CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate)) and CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate)) and CONVERT(date,STTP.RSLVWithinDate) >= CONVERT(date,STM.resolved_dt) and (AssignTo in (select USERID From #tmpuser) OR Assign_Group IN (SELECT  Group_id FROM #tmpuser))                
                     
           
 select @OverDue = COUNT(distinct STM.TicketID)   
 from Serv_TicketMaster(nolock) STM inner join Serv_TicketTimelyPRM (nolock) STTP   
 on stm.TicketID = STTP.TicketID   
 where stm.ParentId = @ParentId and convert(date,Date_Created) between CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate)) and CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate)) and CONVERT(date,STTP.RSLVWithinDate) < CONVERT(date,STM.resolved_dt) and (AssignTo in (select USERID From #tmpuser) OR Assign_Group IN (SELECT  Group_id FROM #tmpuser))                     
              
          
 SELECT @DueToday = COUNT(distinct TM.TicketID)   
 FROM [Serv_TicketMaster](nolock) TM inner join  Serv_TicketTimelyPRM (nolock) TTP   
 on TM.TicketID = TTP.[TicketID]    
 where  TM.ParentId = @ParentId and CONVERT(date,TTP.RSLVWithinDate) = CONVERT(date,GETDATE()) and (AssignTo in (select USERID From #tmpuser) OR Assign_Group IN (SELECT  Group_id FROM #tmpuser))    
              
                   
   select @UnResolved =COUNT(distinct TicketID) from Serv_TicketMaster where ParentId = @ParentId and Status <> 2 and convert(date,Date_Created) between @fmdate and @todate and (AssignTo in (select USERID From #tmpuser) OR Assign_Group IN (SELECT  Group_id FROM #tmpuser))
            
                 
   select @unassigned = COUNT(distinct TicketID)  
   from Serv_TicketMaster(NOLOCK) 
   where ParentID = @ParentID and isnull(AssignTo,0) = 0 and  ISNULL(Assign_Group,0) = 0 AND STATUS NOT IN (2, 4) AND   
   convert(date,Date_Created) between CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate))  
   and CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))  

               
 SELECT @total AS [total], @New AS [New], @Open AS [Open], @close AS [close], @pending AS [pending], @Resolve  
 AS [Resolve], @WaitCustomer as WaitCustomer, @WaitParty as WaitThirdParty, @intime AS [intime], @OverDue AS [OverDue], @UnResolved AS [UnResolved], @unassigned AS  
 [unassigned], @DueToday AS [DueToday];              
  
 end   



GO

/* ============================================================
   Procedure: [dbo].[Serv_getStatusofticket_INTDateTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_getStatusofticket_INTDateTime] --335,40,335,'01-01-2017','01-01-2019'      
(      
 @ParentId int,    
 @Groupid int,      
 @UserID int,    
 @fmdate date,        
 @todate date         
)      
as      
Begin      
select USERID into #tmpuser from Serv_Agent_Mast where 1=2    
    
if @UserID > 0    
begin    
insert into #tmpuser (USERID) select USERID from Serv_Agent_Mast where USERID =@UserID    
end    
if @Groupid > 0 and @UserID =0    
begin    
insert into #tmpuser (USERID) select USERID from Serv_Agent_Mast where Group_id =@Groupid    
end    
if @Groupid = 0 and @UserID =0    
begin    
insert into #tmpuser (USERID) select USERID from Serv_Agent_Mast where ParentId = @ParentId    
end    
    
declare @total int =0,@New int=0,@Open int=0,@close int=0, @pending int=0,@Resolve int=0,@intime int=0,    
 @OverDue int=0, @UnResolved int=0,@unassigned int =0,@DueToday int = 0    
    
 select @total =COUNT(*) from Serv_TicketMaster where  AssignTo in (select USERID From #tmpuser)        
 and 
    convert(date,Date_Created) 
  
    between 
  
   CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate))
     and
   CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))
  
    --group by AssignTo
          
  select @New =COUNT(*)  from Serv_TicketMaster where Status = 0 and AssignTo in (select USERID From #tmpuser)         
     and
      convert(date,Date_Created) 
      between 
     
      CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate))
     
      and
       
      CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))
      
      --group by AssignTo
     
              
  select @Open =COUNT(*)  from Serv_TicketMaster where Status = 1 and AssignTo in (select USERID From #tmpuser)          
     and 
     convert(date,Date_Created) 
     between 
     
     CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate))
     and 
     CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))
     
     --group by AssignTo         
 
 
  select @close =COUNT(*)  from Serv_TicketMaster where Status = 2 and AssignTo in (select USERID From #tmpuser)        
   and 
   convert(date,Date_Created)
    between 
    
    CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate))
    
    and 
    
    CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))
    
     --group by AssignTo         
        
 
  select @pending = COUNT(*)  from Serv_TicketMaster where Status = 3 and AssignTo in (select USERID From #tmpuser)          
   and 
   convert(date,Date_Created)
    between 
    
    CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate)) 
    
    and
    
    CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))
    
    --group by AssignTo         
        
 
  select @Resolve = COUNT(*)  from Serv_TicketMaster where Status = 4 and AssignTo in (select USERID From #tmpuser)         
   and
    convert(date,Date_Created)
     between
     
      CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate)) 
     
       and 
     
      CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))
      
       --group by AssignTo         
          
 
  select @intime = Count(*) from Serv_TicketMaster(nolock) STM inner join Serv_TicketTimelyPRM (nolock)        
       STTP on stm.TicketID = STTP.TicketID where
       convert(date,Date_Created)
        between 
        
        CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate)) 
        
        and 
        
        CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))
        
        and     
       CONVERT(date,STTP.RSLVWithinDate) >= CONVERT(date,STM.resolved_dt) and AssignTo in (select USERID From #tmpuser)         
           
 
  select @OverDue = Count(*) from Serv_TicketMaster(nolock) STM inner join Serv_TicketTimelyPRM (nolock)        
       STTP on stm.TicketID = STTP.TicketID where
        convert(date,Date_Created)
         between 
         
         CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate))  
         
         and
         
         CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))
         
         and 
            
       CONVERT(date,STTP.RSLVWithinDate) < CONVERT(date,STM.resolved_dt) and AssignTo in (select USERID From #tmpuser)           
    

SELECT @DueToday = Count(*) FROM [Serv_TicketMaster](nolock) TM inner join  Serv_TicketTimelyPRM (nolock) TTP on TM.TicketID = TTP.[TicketID]  where  CONVERT(date,TTP.RSLVWithinDate) = CONVERT(date,GETDATE())  and AssignTo in (select USERID From #tmpuser)
       
    
         
   select @UnResolved =Count(*) from Serv_TicketMaster where Status <> 2 and     
   convert(date,Date_Created) 
   between 
   @fmdate 
   and 
   @todate 
   and AssignTo in (select USERID From #tmpuser)     
  
       
   select @unassigned = Count(*) from Serv_TicketMaster where     
   ParentID = @ParentID  and isnull(AssignTo,0) = 0 and     
   convert(date,Date_Created)
    between
    
     CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentId,@fmdate))  
    
      and 
    
     CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentId,@todate))
  
     
select @total total ,@New New,@Open [Open], @close [close], @pending pending,@Resolve Resolve,@intime intime,    
 @OverDue OverDue, @UnResolved UnResolved, @unassigned unassigned,@DueToday DueToday    
    
 end


GO

/* ============================================================
   Procedure: [dbo].[Serv_getStatusofticket_Support]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec Serv_getStatusofticket_Support @ParentId=31871,@Groupid=0,@UserID=3871,@fmdate='2010-01-01',@todate='2022-10-31'
--exec Serv_getStatusofticket_Support @ParentId=335,@Groupid=0,@UserID=5510,@fmdate='2010-01-01',@todate='2022-12-31'
CREATE   PROCEDURE [dbo].[Serv_getStatusofticket_Support] --335,40,335,'01-01-2017','01-01-2019'
(
	@ParentId INT,
	@Groupid  INT,
	@UserID   INT,
	@fmdate   DATE,
	@todate   DATE
)
AS
BEGIN
	
	--declare @ParentId INT=335,@Groupid INT=0,@UserID INT=5510,@fmdate DATE='2022-12-01',@todate DATE='2022-12-31'

	drop table if exists #tmpuser
	DECLARE @Access_Level VARCHAR(100);

	SELECT @Access_Level=[Access_Level]
	FROM Serv_Agent_Mast(NOLOCK)
	WHERE [Userid] = @UserID AND [ParentId] = @ParentId;

	SELECT [USERID], [Group_id]
	INTO [#tmpuser] FROM Serv_Agent_Mast(NOLOCK) WHERE 1 = 2;

	DECLARE @total INT=0, @New INT=0, @Open INT=0, @close INT=0, @pending INT=0, @Resolve INT=0, @intime INT=
	0, @OverDue INT=0, @UnResolved INT=0, @unassigned INT=0, @DueToday INT=0,@WaitCustomer int=0,@WaitParty int=0;
	
	print @Access_Level

	IF @Access_Level = 'All Group'
	BEGIN

		SELECT @total=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE [ParentID] = @ParentID
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                  
		SELECT @New=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 0
			  AND [ParentID] = @ParentID
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                  
		SELECT @Open=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 1
			  AND [ParentID] = @ParentID
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                           
		SELECT @close=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 2
			  AND [ParentID] = @ParentID
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                           
		SELECT @pending=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 3
			  AND [ParentID] = @ParentID
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                           
		SELECT @Resolve=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 4
			  AND [ParentID] = @ParentID
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		SELECT @WaitCustomer=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 5
			  AND [ParentID] = @ParentID
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		SELECT @WaitParty=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 8
			  AND [ParentID] = @ParentID
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                           
		SELECT @intime=COUNT(DISTINCT [stm].[TicketId])
		FROM Serv_TicketMaster(NOLOCK) AS STM INNER JOIN Serv_TicketTimelyPRM(NOLOCK) AS STTP
		ON stm.TicketID = STTP.TicketID
		WHERE CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId,
		@fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate))
			  AND CONVERT(DATE, [STTP].[RSLVWithinDate]) >= CONVERT(DATE, [STM].[resolved_dt])
			  AND [ParentID] = @ParentID;

		SELECT @OverDue=COUNT(DISTINCT [stm].[TicketId])
		FROM Serv_TicketMaster(NOLOCK) AS STM INNER JOIN Serv_TicketTimelyPRM(NOLOCK) AS STTP
		ON stm.TicketID = STTP.TicketID
		WHERE CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId,
		@fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate))
			  AND CONVERT(DATE, [STTP].[RSLVWithinDate]) < CONVERT(DATE, [STM].[resolved_dt])
			  AND [ParentID] = @ParentID;

		SELECT @DueToday=COUNT(DISTINCT [tm].[TicketId])
		FROM [Serv_TicketMaster](NOLOCK) AS TM INNER JOIN Serv_TicketTimelyPRM(NOLOCK) AS TTP
		ON TM.TicketID = TTP.[TicketID]
		WHERE CONVERT(DATE, [TTP].[RSLVWithinDate]) = CONVERT(DATE, GETDATE())
			  AND [tm].STATUS NOT IN (2, 4)
			  AND [ParentID] = @ParentID;

		SELECT @UnResolved=COUNT(*)
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS NOT IN (2, 4)
			  AND CONVERT(DATE, [Date_Created]) BETWEEN @fmdate AND @todate
			  AND [ParentID] = @ParentID;

		SELECT @unassigned=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE [ParentID] = @ParentID
			  AND ISNULL([AssignTo], 0) = 0
			  AND ISNULL([Assign_Group], 0) = 0
			  AND STATUS NOT IN (2, 4)
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));
	END;

	IF @access_level = 'Within Group'
	BEGIN
		INSERT INTO #tmpuser
		SELECT [Userid], [Group_id] FROM serv_agent_mast WHERE [Userid] = @UserID;

		SELECT @total=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE( [AssignTo] IN(SELECT [Userid] FROM [#tmpuser])
			   OR [Assign_Group] IN(SELECT [Group_id] FROM [#tmpuser])
			   OR [User_id] = @UserID )
			 AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			 @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                  
		SELECT @New=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 0
			  AND ( [AssignTo] IN(SELECT [Userid] FROM [#tmpuser])
					OR [Assign_Group] IN(SELECT [Group_id] FROM [#tmpuser])
					OR [User_id] = @UserID )
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                  
		SELECT @Open=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 1
			  AND ( [AssignTo] IN(SELECT [Userid] FROM [#tmpuser])
					OR [Assign_Group] IN(SELECT [Group_id] FROM [#tmpuser])
					OR [User_id] = @UserID )
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                           
		SELECT @close=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 2
			  AND ( [AssignTo] IN(SELECT [Userid] FROM [#tmpuser])
					OR [Assign_Group] IN(SELECT [Group_id] FROM [#tmpuser])
					OR [User_id] = @UserID )
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                           
		SELECT @pending=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 3
			  AND ( [AssignTo] IN(SELECT [Userid] FROM [#tmpuser])
					OR [Assign_Group] IN(SELECT [Group_id] FROM [#tmpuser])
					OR [User_id] = @UserID )
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                           
		SELECT @Resolve=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 4
			  AND ( [AssignTo] IN(SELECT [Userid] FROM [#tmpuser])
					OR [Assign_Group] IN(SELECT [Group_id] FROM [#tmpuser])
					OR [User_id] = @UserID )
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		SELECT @WaitCustomer=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 5
			  AND ( [AssignTo] IN(SELECT [Userid] FROM [#tmpuser])
					OR [Assign_Group] IN(SELECT [Group_id] FROM [#tmpuser])
					OR [User_id] = @UserID )
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		SELECT @WaitParty=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 8
			  AND ( [AssignTo] IN(SELECT [Userid] FROM [#tmpuser])
					OR [Assign_Group] IN(SELECT [Group_id] FROM [#tmpuser])
					OR [User_id] = @UserID )
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                           
		SELECT @intime=COUNT(DISTINCT [stm].[TicketId])
		FROM Serv_TicketMaster(NOLOCK) AS STM INNER JOIN Serv_TicketTimelyPRM(NOLOCK) AS STTP
		ON stm.TicketID = STTP.TicketID
		WHERE CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId,
		@fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate))
			  AND CONVERT(DATE, [STTP].[RSLVWithinDate]) >= CONVERT(DATE, [STM].[resolved_dt])
			  AND ( [AssignTo] IN(SELECT [Userid] FROM [#tmpuser])
					OR [Assign_Group] IN(SELECT [Group_id] FROM [#tmpuser])
					OR [User_id] = @UserID );

		SELECT @OverDue=COUNT(DISTINCT [stm].[TicketId])
		FROM Serv_TicketMaster(NOLOCK) AS STM INNER JOIN Serv_TicketTimelyPRM(NOLOCK) AS STTP
		ON stm.TicketID = STTP.TicketID
		WHERE CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId,
		@fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate))
			  AND CONVERT(DATE, [STTP].[RSLVWithinDate]) < CONVERT(DATE, [STM].[resolved_dt])
			  AND ( [AssignTo] IN(SELECT [Userid] FROM [#tmpuser])
					OR [Assign_Group] IN(SELECT [Group_id] FROM [#tmpuser])
					OR [User_id] = @UserID );

		SELECT @DueToday=COUNT(DISTINCT [tm].[TicketId])
		FROM [Serv_TicketMaster](NOLOCK) AS TM INNER JOIN Serv_TicketTimelyPRM(NOLOCK) AS TTP
		ON TM.TicketID = TTP.[TicketID]
		WHERE CONVERT(DATE, [TTP].[RSLVWithinDate]) = CONVERT(DATE, GETDATE())
			  AND [tm].STATUS NOT IN (2, 4)
			  AND ( [AssignTo] IN(SELECT [Userid] FROM [#tmpuser])
					OR [Assign_Group] IN(SELECT [Group_id] FROM [#tmpuser])
					OR [User_id] = @UserID );

		SELECT @UnResolved=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS NOT IN (2, 4)
			  AND CONVERT(DATE, [Date_Created]) BETWEEN @fmdate AND @todate
			  AND ( [AssignTo] IN(SELECT [Userid] FROM [#tmpuser])
					OR [Assign_Group] IN(SELECT [Group_id] FROM [#tmpuser])
					OR [User_id] = @UserID );

		SELECT @unassigned=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE( [AssignTo] IN(SELECT [Userid] FROM [#tmpuser])
			   OR [Assign_Group] IN(SELECT [Group_id] FROM [#tmpuser])
			   OR [User_id] = @UserID )
			 AND STATUS NOT IN (2, 4)
			 AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			 @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

	END;
	IF @access_level = 'self'
	BEGIN

		SELECT @total=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE( [AssignTo] = @UserID
			   OR [User_id] = @UserID )
			 AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			 @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                  
		SELECT @New=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 0
			  AND ( [AssignTo] = @UserID
					OR [User_id] = @UserID )
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                  
		SELECT @Open=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 1
			  AND ( [AssignTo] = @UserID
					OR [User_id] = @UserID )
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                       
		SELECT @close=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 2
			  AND ( [AssignTo] = @UserID
					OR [User_id] = @UserID )
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                           
		SELECT @pending=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 3
			  AND ( [AssignTo] = @UserID
					OR [User_id] = @UserID )
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                           
		SELECT @Resolve=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 4
			  AND ( [AssignTo] = @UserID
					OR [User_id] = @UserID )
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		SELECT @WaitCustomer=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 5
			  AND ( [AssignTo] = @UserID
					OR [User_id] = @UserID )
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		SELECT @WaitParty=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS = 8
			  AND ( [AssignTo] = @UserID
					OR [User_id] = @UserID )
			  AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			  @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate));

		--group by AssignTo                           
		SELECT @intime=COUNT(DISTINCT [stm].[TicketId])
		FROM Serv_TicketMaster(NOLOCK) AS STM INNER JOIN Serv_TicketTimelyPRM(NOLOCK) AS STTP
		ON stm.TicketID = STTP.TicketID
		WHERE CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId,
		@fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate))
			  AND CONVERT(DATE, [STTP].[RSLVWithinDate]) >= CONVERT(DATE, [STM].[resolved_dt])
			  AND ( [AssignTo] = @UserID
					OR [User_id] = @UserID );

		SELECT @OverDue=COUNT(DISTINCT [stm].[TicketId])
		FROM Serv_TicketMaster(NOLOCK) AS STM INNER JOIN Serv_TicketTimelyPRM(NOLOCK) AS STTP
		ON stm.TicketID = STTP.TicketID
		WHERE CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId,
		@fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate))
			  AND CONVERT(DATE, [STTP].[RSLVWithinDate]) < CONVERT(DATE, [STM].[resolved_dt])
			  AND ( [AssignTo] = @UserID
					OR [User_id] = @UserID );

		SELECT @DueToday=COUNT(DISTINCT [tm].[TicketId])
		FROM [Serv_TicketMaster](NOLOCK) AS TM INNER JOIN Serv_TicketTimelyPRM(NOLOCK) AS TTP
		ON TM.TicketID = TTP.[TicketID]
		WHERE CONVERT(DATE, [TTP].[RSLVWithinDate]) = CONVERT(DATE, GETDATE())
			  AND ( [AssignTo] = @UserID
					OR [User_id] = @UserID )
			  AND [tm].STATUS NOT IN (2, 4);

		SELECT @UnResolved=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE STATUS NOT IN (2, 4)
			  AND CONVERT(DATE, [Date_Created]) BETWEEN @fmdate AND @todate
			  AND ( [AssignTo] = @UserID
					OR [User_id] = @UserID );

		SELECT @unassigned=COUNT(DISTINCT [TicketId])
		FROM Serv_TicketMaster(NOLOCK)
		WHERE( [AssignTo] = @UserID
			   OR [User_id] = @UserID )
			 AND ISNULL([AssignTo], 0) = 0
			 AND CONVERT(DATE, [Date_Created]) BETWEEN CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](
			 @ParentId, @fmdate)) AND CONVERT(DATE, [dbo].[fn_getISTtimefromusertime](@ParentId, @todate))
			 AND STATUS NOT IN (2, 4);

	END;

	SELECT @total AS [total], @New AS [New], @Open AS [Open], @close AS [close], @pending AS [pending],
	@Resolve AS [Resolve], @WaitCustomer as WaitCustomer, @WaitParty as WaitThirdParty, @intime AS [intime], @OverDue AS [OverDue], @UnResolved AS [UnResolved],
	@unassigned AS [unassigned], @DueToday AS [DueToday];

END;



GO

/* ============================================================
   Procedure: [dbo].[Serv_GettGroupTicketStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_GettGroupTicketStatus] --'2018-01-01','2018-06-01'            
 (            
  @parentid bigint,      
  @groupid bigint,          
  @fmdate date,            
  @todate date,       
  @Agentid bigint,        
  @opt varchar(20)            
 )            
 as            
 Begin            
             
 Declare @Min int = 0 , @Max int = 0             
  Declare @AMin int = 0 , @AMax int = 0        
   
 create table #tmptblg  
 ( Groupid bigint, RowNum int  
 )     
   
       
 if @groupid =0              
  insert into #tmptblg (Groupid, RowNum)      
  select Groupid,ROW_NUMBER() OVER(ORDER BY Groupid ASC) AS RowNum          
  from  dbo.Serv_Group_Mast where ParentId =@parentid            
       
  if @groupid > 0              
  insert into #tmptblg (Groupid, RowNum)      
  select Groupid,ROW_NUMBER() OVER(ORDER BY Groupid ASC) AS RowNum          
  from  dbo.Serv_Group_Mast where ParentId =@parentid       
  and Groupid = @Groupid      
      
        
             
 select @Min =(MIN(RowNum)),@Max = (MAX(RowNum)) from #tmptblg            
           
            
 --create table #tmpMaintbl1            
 --(            
 -- Group_id int,            
 --Total int, New int,[Open] int,Closed int, Pending int ,Resolved int,           
 --InTime int, ExTime int,  group_name varchar(max)      
 --)            
create table #tmpMaintbl1          
 (          
  Group_id int,          
  AgentID int,Total int, New int,[Open] int,Closed int, Pending int ,Resolved int, UnResolved int,         
  InTime int, ExTime int,  group_name varchar(max), Agent_name varchar(max)         
 )        
       
if @Agentid > 0      
begin      
 insert into #tmpMaintbl1  exec Serv_GetAgentTicketStatus @Agentid,@fmdate,@todate       
      
end      
else      
begin            
 while((@Min <= @Max) and @Min>0 and @Max > 0)            
    Begin            
  select @Groupid = Groupid From #tmptblg where RowNum = @Min           
                    
    insert into #tmpMaintbl1 (Group_id ,            
 Total, New ,[Open] ,Closed , Pending ,Resolved ,UnResolved,           
 InTime, ExTime,  group_name)  exec Serv_GroupTotalStatus @Groupid,@fmdate,@todate            
          
                 
  set @Min = @Min + 1            
 End      
end      
            
 if @opt= 'All'            
 select * From #tmpMaintbl1         
if @opt = 'Open'           
 select [Open] fldnm, Group_id , group_name,group_name From #tmpMaintbl1         
        
if @opt = 'Total'           
 select Total fldnm, Group_id , group_name,group_name From #tmpMaintbl1         
        
if @opt = 'Pending'           
 select Pending fldnm, Group_id , group_name,group_name From #tmpMaintbl1         
        
if @opt = 'Resolved'           
 select Resolved fldnm, Group_id , group_name,group_name From #tmpMaintbl1         
        
if @opt = 'InTime'           
 select InTime fldnm, Group_id , group_name,group_name From #tmpMaintbl1         
        
if @opt = 'ExTime'           
 select ExTime fldnm, Group_id , group_name,group_name From #tmpMaintbl1         
          
        
 drop table #tmptblg            
 drop table #tmpMaintbl1             
 End



GO

