/* ============================================================
   Procedure: [dbo].[Serv_GetTicketDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_GetTicketDetails] --335    
 (    
 @ParentID bigint    
)      
As    
Begin    
    
 SELECT     
       [TicketID]    
      ,[User_id]    
      ,[ParentID]    
      ,[TicketNo]    
      ,[Requester]    
      ,[Subject]    
      ,[Description]    
      ,(select Stat_Desc From Serv_Ticket_Stat_Mast  where  Stat_ID = [Status]) as Status  
      ,[Remarks]    
      ,[Note]    
      ,[Date_Created]    
      ,[Active]    
          
 FROM  Serv_TicketMaster where ParentID = @ParentID  order by Date_Created desc  
     
 End


