SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_GetTicketDetailsAgentWise] --335          
(          
 @UserID bigint,  
 @fmdate date,   
 @todate date         
)            
As          
Begin          
          
 SELECT           
       [TicketID]          
      ,[User_id]          
      ,[ParentID]          
      ,[TicketNo]          
      ,[Requester]          
      ,[Subject]          
      ,[Description]          
      ,(select Stat_Desc From Serv_Ticket_Stat_Mast  where  Stat_ID = [Status]) as Status        
      ,[Remarks]          
      ,[Note]          
      --,[Date_Created]          
      ,dbo.[fn_getusertimefromindiantime](ParentID,Date_Created) as Date_Created
      ,[Active]          
                
 FROM  Serv_TicketMaster where AssignTo = @UserID   
 and CONVERT(date, Date_Created) 
  between
  
 CONVERT(date, dbo.fn_getISTtimefromusertime(ParentID,@fmdate)) 
  and 
 CONVERT(date, dbo.fn_getISTtimefromusertime(ParentID,@todate)) 
  
  
    
  order by Date_Created desc        
           
 End



