CREATE   PROCEDURE [dbo].[Serv_GetTicketHistory] --3    
(    
  @TicketID bigint     
)    
as    
Begin    
 SELECT    
      -- [TicketHistoryID]    
         [TicketID]    
      --,[user_id]    
      --,[ParentID]    
      --,[ResponseTime]    
      --,[SubmittedDate]    
      --,[Note]    
      ,(select Stat_Desc From Serv_Ticket_Stat_Mast  where  Stat_ID = [Status]) as Status   
      ,[HistoryDate]    
      ,(select isnull(User_Login,'') from User_Detail where User_ID = [TransferredTo]) as  [TransferredTo]   
      ,[Remarks]    
      ,[Priority]    
      ,(select isnull(User_Login,'') from User_Detail where User_ID = Transfered_from)as[Transfered_from]    
      ,[Activity_lavel]    
      --,[Assign_Group]    
      --,[Ticket_Response]    
     
 FROM [Serv_TicketHistory] where TicketID = @TicketID  order by HistoryDate desc   
     
 End


