/* ============================================================
   Procedure: [dbo].[Serv_GetTotalAgentTicketStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 CREATE   PROCEDURE [dbo].[Serv_GetTotalAgentTicketStatus] --'2018-01-01','2018-06-01'          
 (          
  @ParentId bigint,  
  @groupid bigint,      
  @UserID bigint,        
  @fmdate date,          
  @todate date           
 )          
 as          
 Begin          
          
 Declare @Min int = 0 , @Max int = 0           
     
  create table #tmptbl1    
 ( Userid bigint, RowNum int    
 )       
   
  
  if @UserID  = 0  and @groupid =0    
 insert into #tmptbl1(Userid, RowNum)       
  select Userid,ROW_NUMBER() OVER(ORDER BY Agent_id ASC) AS RowNum        
  from Serv_Agent_Mast  where ParentId=@ParentId      
        
 if @UserID  = 0  and @groupid >0    
 insert into #tmptbl1(Userid, RowNum)       
  select Userid,ROW_NUMBER() OVER(ORDER BY Agent_id ASC) AS RowNum        
  from Serv_Agent_Mast  where Group_id =@groupid          
   
 if @UserID  > 0  and @groupid >0    
   insert into #tmptbl1(Userid, RowNum)       
   select Userid,ROW_NUMBER() OVER(ORDER BY Userid ASC) AS RowNum        
  from Serv_Agent_Mast  where Group_id =@groupid and Userid = @UserID       
  
if @UserID  > 0  and @groupid = 0    
   insert into #tmptbl1(Userid, RowNum)       
   select Userid,ROW_NUMBER() OVER(ORDER BY Userid ASC) AS RowNum        
  from Serv_Agent_Mast  where  Userid = @UserID                 
 select @Min =(MIN(RowNum)),@Max = (MAX(RowNum)) from #tmptbl1          
  
            
           
 create table #tmpMaintbl1          
 (          
  Group_id int,          
  AgentID int, New int,Total int, [Open] int,Closed int, Pending int ,Resolved int,         
  UnResolved int,  
  InTime int, ExTime int,  group_name varchar(max), Agent_name varchar(max)         
 )          
   
    
           
           
 while((@Min <= @Max) and @Min>0 and @Max > 0)          
   Begin          
    select @UserID = Userid From #tmptbl1 where RowNum = @Min         
    insert into #tmpMaintbl1  exec Serv_GetAgentTicketStatus @UserID,@fmdate,@todate          
    set @Min = @Min + 1          
   End           
           
 select * From #tmpMaintbl1          
           
 drop table #tmptbl1          
 drop table #tmpMaintbl1           
 End



