/* ============================================================
   Procedure: [dbo].[Serv_GetTotalValidTicketIDs]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_GetTotalValidTicketIDs]    
as    
Begin    
 Declare @TicketCount int = 0      
 Declare @i int = 1    
 Declare @TicketID bigint,@ParentID bigint;     
   
  
     
select ROW_NUMBER() OVER (ORDER BY TicketID DESC) AS RowID,* into #TicketCollections from      Serv_TicketMaster where Status not in (2,4,5) and isnull(spam,0) = 0 and deleted = 0    
    
 select @TicketCount = Count(*) from #TicketCollections    
     
     
 while( @i <= @TicketCount)    
 Begin    
         
  select @TicketID = TicketID,@ParentID = ParentID  from #TicketCollections where RowID = @i    
         
   select ss.[SLAId]
      ,ss.[ParentID]
      ,ss.[SLA_Name]
      ,ss.[SLA_Desc]
      ,ss.[DateCreated]
      ,ss.[Active]
      ,ss.[ord_no]
      ,AR.[appl_id]
      ,Ar.[Apply_to]
      ,Ar.[Apply_val] ,ROW_NUMBER() OVER (ORDER BY ss.ord_no DESC) AS RowID into #TempSLA1     
   from  Serv_SLA_Setting SS  left outer join  [Serv_SLA_ApplyRule](nolock) AR    
    on   SS.SLAId = Ar.SLAID where ss.ParentID = @ParentID order by ss.ord_no       
       
   declare @RowNum int ,@MaxRowNum int    
       
   select @RowNum = MIN(RoWID) ,@MaxRowNum = MAX(RowID) from #TempSLA1    
   while(@RowNum <= @MaxRowNum )    
      Begin    
     declare @result int = 0    
           declare @slaid as bigint    
           select @slaid = slaid from #TempSLA1 where RowID =@RowNum    
           if(exists(select 'x' from Serv_SLA_ApplyRule where SLAID = @slaid))     
   begin    
       
     exec Serv_apply_slarule @TicketID,@slaid, @result     
                 
   --         end    
   --         else    
   --           begin    
   --         --    exec Serv_ApplyEmailRule    
   end    
   if @result = 1    
    break;    
            set @RowNum = @RowNum +1;    
      End    
       
       
     
 set @i = @i +1;    
drop table #TempSLA1  

 End     
    
    
drop table #TicketCollections 
 
End


GO

