/* ============================================================
   Procedure: [dbo].[Serv_GroupTotalStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec Serv_GroupTotalStatus @GroupidID=1016,@fmdate='2022-12-01',@todate='2022-12-31'
CREATE   PROCEDURE [dbo].[Serv_GroupTotalStatus]        
(                
  @GroupidID bigint,                
  @fmdate date,                
  @todate date                 
)                
as                
Begin                

 -- declare @GroupidID bigint=1154,@fmdate date='2022-10-01',@todate date='2022-10-31'

 declare @UserID int = 0;                
 select @UserID = Userid from Serv_Agent_Mast where Group_id = @GroupidID  
 
  Declare @new int = 0, @total int = 0 , @open int = 0, @close int = 0,@Resolve int = 0, @pending int = 0,
  @WaitCustomer int=0, @WaitParty int=0, @intime int = 0, @extime int = 0 ,@UnResolved int =0, @DueToday int, @unassigned int                   
                 
  select @total = COUNT(distinct TicketID) 
  from Serv_TicketMaster(nolock) tm inner join Serv_Agent_Mast(nolock) am            
  on (am.Userid = tm.AssignTo or am.Group_id = tm.Assign_Group) 
  where  Group_id = @GroupidID and convert(date,tm.Date_Created) between @fmdate and @todate            
              
  select @New =COUNT(distinct TicketID)  
  from Serv_TicketMaster(nolock) tm inner join Serv_Agent_Mast(nolock) am            
  on (am.Userid = tm.AssignTo or am.Group_id = tm.Assign_Group) 
  where  Group_id = @GroupidID and Status = 0 and convert(date,tm.Date_Created) between @fmdate and @todate
              
  select @Open =COUNT(distinct TicketID) 
  from Serv_TicketMaster(nolock) tm inner join Serv_Agent_Mast(nolock) am
  on (am.Userid = tm.AssignTo or am.Group_id = tm.Assign_Group) 
  where  Group_id = @GroupidID and Status = 1 and convert(date,tm.Date_Created) between @fmdate and @todate
                 
  select @close =COUNT(distinct TicketID) 
  from Serv_TicketMaster(nolock) tm inner join Serv_Agent_Mast(nolock) am
  on (am.Userid = tm.AssignTo or am.Group_id = tm.Assign_Group) 
  where  Group_id = @GroupidID and  Status = 2 and  convert(date,tm.Date_Created) between @fmdate and @todate
                
  select @pending = COUNT(distinct TicketID) 
  from Serv_TicketMaster(nolock) tm inner join Serv_Agent_Mast(nolock) am
  on (am.Userid = tm.AssignTo or am.Group_id = tm.Assign_Group) 
  where  Group_id = @GroupidID and Status = 3  and convert(date,tm.Date_Created) between @fmdate and @todate
                
  select @Resolve = COUNT(distinct TicketID) 
  from Serv_TicketMaster(nolock) tm inner join Serv_Agent_Mast(nolock) am
  on (am.Userid = tm.AssignTo or am.Group_id = tm.Assign_Group) 
  where Group_id = @GroupidID and Status = 4  and convert(date,tm.Date_Created) between @fmdate and @todate
                  
  select @WaitCustomer = COUNT(distinct TicketID) 
  from Serv_TicketMaster(nolock) tm inner join Serv_Agent_Mast(nolock) am
  on (am.Userid = tm.AssignTo or am.Group_id = tm.Assign_Group) 
  where Group_id = @GroupidID and Status = 5  and convert(date,tm.Date_Created) between @fmdate and @todate
                  
  select @WaitParty = COUNT(distinct TicketID) 
  from Serv_TicketMaster(nolock) tm inner join Serv_Agent_Mast(nolock) am
  on (am.Userid = tm.AssignTo or am.Group_id = tm.Assign_Group) 
  where Group_id = @GroupidID and Status = 8  and convert(date,tm.Date_Created) between @fmdate and @todate
                  
  select @intime = Count(distinct stm.TicketID) 
  from Serv_TicketMaster(nolock) STM inner join Serv_TicketTimelyPRM (nolock) STTP 
  on stm.TicketID = STTP.TicketID inner join Serv_Agent_Mast(nolock) am
  on (am.Userid = stm.AssignTo or am.Group_id = stm.Assign_Group) 
  where  Group_id = @GroupidID and CONVERT(date,STTP.RSLVWithinDate) >= CONVERT(date,STM.resolved_dt)
              
                   
  select @extime = Count(distinct stm.TicketID) 
  from Serv_TicketMaster(nolock) STM inner join Serv_TicketTimelyPRM (nolock) STTP 
  on stm.TicketID = STTP.TicketID inner join Serv_Agent_Mast(nolock) am
  on (am.Userid = stm.AssignTo or am.Group_id = stm.Assign_Group) 
  where  Group_id = @GroupidID and CONVERT(date,STTP.RSLVWithinDate) < CONVERT(date,STM.resolved_dt)
                   
           
  select @UnResolved = Count(distinct tm.TicketID)
  from Serv_TicketMaster(nolock) tm inner join Serv_Agent_Mast(nolock) am
  on (am.Userid = tm.AssignTo or am.Group_id = tm.Assign_Group) 
  where tm.Status <> 2 and convert(date,tm.Date_Created) between @fmdate and @todate and am.Group_id = @GroupidID --tm.Assign_Group = @GroupidID     

  select @DueToday = Count(distinct tm.TicketID)
  from Serv_TicketMaster(nolock) tm inner join Serv_Agent_Mast(nolock) am
  on (am.Userid = tm.AssignTo or am.Group_id = tm.Assign_Group) 
  where tm.Status <> 2 and convert(date,tm.Date_Created) = CONVERT(date,GETDATE()) and am.Group_id = @GroupidID --tm.Assign_Group = @GroupidID     

  select @unassigned = Count(distinct tm.TicketID)
  from Serv_TicketMaster(nolock) tm inner join Serv_Agent_Mast(nolock) am
  on (am.Userid = tm.AssignTo or am.Group_id = tm.Assign_Group) 
  where isnull(tm.AssignTo,0) = 0  and  ISNULL(tm.Assign_Group,0) = 0 AND tm.STATUS NOT IN (2, 4) AND   
   convert(date,tm.Date_Created) between @fmdate and @todate and am.Group_id = @GroupidID
                  
  select  @GroupidID Group_id, @total as Total, @New as New, @Open as [Open], @close as [Closed], 
  		@pending as Pending, @Resolve as Resolved, @WaitCustomer as WaitCustomer, 
  		@WaitParty as WaitThirdParty, @UnResolved as UnResolved, @intime as InTime, @extime as ExTime, @DueToday DueToday, @unassigned as unassigned,
  		Group_Name
  from Serv_Group_Mast gm
  where Groupid = @GroupidID
                
                  
                       
end       



GO

/* ============================================================
   Procedure: [dbo].[Serv_GroupTotalStatus_INTDateTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_GroupTotalStatus_INTDateTime] --1,'2018-01-01','2018-05-10'           
(          
  @GroupidID bigint,          
  @fmdate date,          
  @todate date           
)          
as          
Begin          
          
 declare @UserID int = 0;          
 select @UserID = Userid from Serv_Agent_Mast where Group_id = @GroupidID           
  Declare @new int = 0, @total int = 0 , @open int = 0, @close int = 0,@Resolve int = 0,          
  @pending int = 0, @wait int = 0, @intime int = 0, @extime int = 0 ,@UnResolved int =0           
              
           
  select @total =COUNT(*) from Serv_TicketMaster tm inner join Serv_Agent_Mast am      
  on am.Userid = tm.AssignTo where  Group_id = @GroupidID       
  and convert(date,tm.Date_Created) between @fmdate and @todate      
        
  select @New =COUNT(*)  from Serv_TicketMaster tm inner join Serv_Agent_Mast am      
  on am.Userid = tm.AssignTo where  Group_id = @GroupidID       
  and Status = 0 and convert(date,tm.Date_Created)       
  between @fmdate and @todate          
        
  select @Open =COUNT(*)  from Serv_TicketMaster tm inner join Serv_Agent_Mast am      
  on am.Userid = tm.AssignTo where  Group_id = @GroupidID       
  and Status = 1 and convert(date,tm.Date_Created)       
  between @fmdate and @todate       
           
  select @close =COUNT(*)  from Serv_TicketMaster tm inner join Serv_Agent_Mast am      
  on am.Userid = tm.AssignTo where  Group_id = @GroupidID       
  and  Status = 2 and  convert(date,tm.Date_Created)       
  between @fmdate and @todate           
          
  select @pending = COUNT(*)  from Serv_TicketMaster tm inner join Serv_Agent_Mast am      
  on am.Userid = tm.AssignTo where  Group_id = @GroupidID       
  and  Status = 3  and convert(date,tm.Date_Created)       
  between @fmdate and @todate            
          
  select @Resolve = COUNT(*)  from Serv_TicketMaster tm inner join Serv_Agent_Mast am      
  on am.Userid = tm.AssignTo where  Group_id = @GroupidID       
  and  Status = 4  and convert(date,tm.Date_Created)       
  between @fmdate and @todate         
            
  select @intime = Count(*) from Serv_TicketMaster(nolock) STM       
  inner join Serv_TicketTimelyPRM (nolock)          
       STTP on stm.TicketID = STTP.TicketID        
       inner join Serv_Agent_Mast am      
  on am.Userid = stm.AssignTo where  Group_id = @GroupidID       
  and  CONVERT(date,STTP.RSLVWithinDate) >= CONVERT(date,STM.resolved_dt)      
        
             
  select @extime = Count(*) from Serv_TicketMaster(nolock) STM       
  inner join Serv_TicketTimelyPRM (nolock)          
       STTP on stm.TicketID = STTP.TicketID inner join Serv_Agent_Mast am      
  on am.Userid = stm.AssignTo where  Group_id = @GroupidID and      
   CONVERT(date,STTP.RSLVWithinDate) < CONVERT(date,STM.resolved_dt)      
             
     
  select @UnResolved =Count(*) from Serv_TicketMaster where Status <> 2 and     
   convert(date,Date_Created) between @fmdate and @todate and AssignTo = @UserID                   
            
select @GroupidID Group_id,@total as Total ,@New as New ,        
@Open as [Open],@close as [Closed],@pending as Pending,@Resolve as Resolved,@UnResolved as UnResolved, @intime as InTime,@extime as ExTime,Group_Name        
from Serv_Group_Mast gm        
where Groupid = @GroupidID          
          
            
                 
end           
          
 --select * from Serv_TicketMaster            
 -- select COUNT(*) as 'New' from Serv_TicketMaster where Status =1 and AssignTo = 335 group by AssignTo
 
 



GO

/* ============================================================
   Procedure: [dbo].[Serv_insert_Category_mast]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Serv_insert_Category_mast]  
(
 @TicketCategoryId bigint,   
 @ParentID bigint,   
 @TicketCategoryName nvarchar(300)='',  
 @IsActive bit=true,  
 @flOpt varchar(10)='Insert'     
)  
AS  
   
begin  
  
if @flOpt = 'Insert'   
begin   
  if(not exists(select 'x' from Serv_TicketCategory_Mast where TicketCategoryName = @TicketCategoryName and ParentId = @ParentId))  
   Begin  
  INSERT INTO Serv_TicketCategory_Mast  
           (ParentId, TicketCategoryName,IsActive)  
     VALUES  
           (@ParentId, @TicketCategoryName,@IsActive)  
     select 'Inserted' resp  
  End  
  else  
    Begin  
      select 'Category Already Exists' resp   
     
    End  
    
    
end  
if @flOpt = 'Edit'   
begin  
 if EXISTS(select 1 from Serv_TicketCategory_Mast where TicketCategoryName = @TicketCategoryName and TicketCategoryId <> @TicketCategoryId)  
  select 'Category already exist' resp  
 else  
 update Serv_TicketCategory_Mast  
  set IsActive=@IsActive, TicketCategoryName = @TicketCategoryName  
  where ParentId=@ParentId and TicketCategoryId= @TicketCategoryId 
  select 'Updated' resp  
end  
  
end  




GO

