	@Active bit=true,
	@flOpt varchar(10)='Insert'   
)
AS
	
begin

if @flOpt = 'Insert' 
begin	
  if(not exists(select 'x' from Serv_Role_mast where RoleDesc = @RoleDesc and ParentId = @ParentId            ))
   Begin
 	INSERT INTO Serv_Role_mast
           (ParentId, RoleDesc,Active)
     VALUES
           (@ParentId, @RoleDesc,@Active)
     select 'Inserted' resp
  End
  else
    Begin
      select 'Role Already Exists' resp 
   
    End
  
  
end
if @flOpt = 'Edit' 
begin
	if EXISTS(select 1 from Serv_Role_mast where RoleDesc = @RoleDesc and RoleId <> @RoleId)
