-- exec Serv_Insert_TicketMaster @TicketID=2906,@User_id=2167,@ParentID=32222,@Requester=N'hkjh@fd.in',@Subject=N'india uutuutu',@Description=N'<div class="col-md-3"><h5>Ticket</h5><p class="text-justify">This is your support tickets panel. You can view, raise and manage  your support tickets from here. To report a new issue, you can create a  new ticket, while to view updates on existing tickets or to add a  reply/remark to an existing ticket, you can open the ticket and add your  response.</p></div>',@Priority=1,@Remarks=N'',@Status=0,@Ticket_Response=0,@Ticket_type=1,@Raisedby=N'2167',@req_reply=1,@AssignTo=0,@Assign_Group=0,@assign_by=0,@tkt_Source='Manual',@opt='Insert'  
CREATE   PROCEDURE [dbo].[Serv_Insert_TicketMaster]  
(  
 @TicketID        BIGINT,  
 @User_id         BIGINT,  
 @ParentID        BIGINT,  
 @Requester       NVARCHAR(100),  
 @Subject         NVARCHAR(250),  
 @Description     NVARCHAR(MAX),  
 @Priority        INT,  
 @Remarks         NVARCHAR(MAX),  
 @Status          INT,  
 @Ticket_Response INT           = 0,  
 @Ticket_type     INT           = 1,  
 @Raisedby        NVARCHAR(100),  
 @req_reply       INT           = 1,  
 @AssignTo        BIGINT,  
 @Assign_Group    BIGINT,  
 @assign_by       BIGINT,  
 @tkt_Source      VARCHAR(20),  
 @opt             VARCHAR(10)   = 'Insert'  
)  
AS  
BEGIN  
  
 -- DECLARE @TicketID bigint=0, @User_id bigint=2326, @ParentID bigint=36950, @Requester nvarchar(100)=N'testigkit19@gmail.com', @Subject nvarchar(250)=N'error', @Description nvarchar(max)=N'<p>error find</p>', @Priority int=1, @Remarks nvarchar(max)=N'',@Status int=0, @Ticket_Response int=0, @Ticket_type int=1, @Raisedby nvarchar(100)=N'2326', @req_reply int=1, @AssignTo bigint=0, @Assign_Group bigint=0, @assign_by bigint=0, @tkt_Source Varchar(20)='Manual', @opt varchar(10)='Insert'    
  
 DECLARE @TicketNo NVARCHAR(16), @prifix NVARCHAR(15), @curNo INT, @TicketHistoryId bigint, 
 @roweff INT;  
 SET @roweff = 0;  
  
 --select @TicketNo,  @prifix+REPLACE(STR(MONTH(getdate()),2), SPACE(1), '0')+                                              
 --REPLACE(STR(day(getdate()),2), SPACE(1), '0')                                              
 --+cast(year(getdate()) as varchar(4))                                              
 --+ REPLACE(STR(@curNo+1, 7), SPACE(1), '0')        
  
 IF(@opt = 'Insert')  
 BEGIN  
  
  IF NOT EXISTS(SELECT * FROM   Serv_ticket_AutoNo WHERE  [ParentId] = @ParentID AND [prefix] NOT LIKE 'T%')  
  BEGIN  
   INSERT INTO Serv_ticket_AutoNo( [ParentId], user_id, [prefix], [curr_no] )  
   VALUES                        (@ParentID, @ParentID, CONVERT(VARCHAR(8), @ParentID) + '_', 0)  
  END;  
  
  --BEGIN TRANSACTION TRAN1                                              
  SELECT @prifix = [prefix], @curNo = [curr_no]  
  FROM   Serv_ticket_AutoNo WITH(UPDLOCK)  
  WHERE  [ParentId] = @ParentID AND [prefix] NOT LIKE 'T%';  
  
  UPDATE Serv_ticket_AutoNo SET [curr_no] = [curr_no] + 1  
  WHERE [ParentId] = @ParentID AND [prefix] NOT LIKE 'T%';  
  --COMMIT TRANSACTION                                              
  SELECT @TicketNo = @prifix + REPLACE(STR(@curNo + 1, 7), SPACE(1), '0');  
  
  INSERT INTO Serv_TicketMaster  
  (User_id, [ParentID], [TicketNo], [Subject], [Description], [Priority], [Requester], [Ticket_type], [AssignTo],  
  [Assign_Group], [Assignedby], [AssignedDateTime], [Source] )  
  VALUES (@User_id, @ParentID, @TicketNo, @Subject, @Description, @Priority, @Requester, @Ticket_type, @AssignTo,  
  @Assign_Group, @assign_by, GETDATE(), @tkt_Source);  
  
  SELECT @TicketID = SCOPE_IDENTITY();  
  
  /*******************************/  
  exec serv_Raise_emailNotification_support1 @TicketID, @ParentID, @Assign_Group, @User_id, @AssignTo, 'New Ticket Created','Requester'     
  EXEC Serv_Process_Ticket_Dispatch_support_withnoselection @ParentID, @TicketID;  
  /*******************************/  
  
  INSERT INTO dbo.Serv_TicketHistory  
  ([TicketID], [ParentID], User_id, [SubmittedDate], STATUS, [HistoryDate], [Remarks], [Priority], [raisedby],  
  [TransferredTo], [Assign_Group], [Ticket_type])  
  VALUES (@TicketID, @ParentID, @User_id, GETDATE(), 0, GETDATE(), @Description, @Priority, @Raisedby,   
  @AssignTo, @Assign_Group, @Ticket_type);  
  
  SELECT @roweff = @@ROWCOUNT; 
  select @TicketHistoryId=SCOPE_IDENTITY(); 
  --exec Serv_Process_Ticket_Dispatch @ParentID,@TicketID                    
 END;  
  
 IF(@opt = 'Edit')  
 BEGIN  
  UPDATE Serv_TicketMaster SET [Remarks] = @Remarks, STATUS=@Status, [Priority] = @Priority WHERE [TicketID] = @TicketID;  
  
  INSERT INTO dbo.Serv_TicketHistory  
  ([TicketID], [ParentID], User_id, [SubmittedDate], STATUS, [HistoryDate], [Remarks], [Priority], [Ticket_Response],  
   [raisedby], [Ticket_type], [TransferredTo], [Assign_Group])  
  SELECT [TicketID], [ParentID], User_id, GETDATE(), STATUS, GETDATE(), @Remarks, [Priority], @Ticket_Response,  
    @Raisedby, [Ticket_type], [AssignTo], [Assign_Group]  
  FROM   Serv_TicketMaster  
  WHERE  [TicketID] = @TicketID;  
  
  SELECT @roweff = @@ROWCOUNT;  
  select @TicketHistoryId=SCOPE_IDENTITY();
  /* start Lead activity*/  
  
 BEGIN TRY  
  
  DECLARE @UserID_LDACTV BIGINT= @User_id;  
  DECLARE @ParentID_LDACTV BIGINT= @ParentID;  
  DECLARE @kit19UserID BIGINT= 0;  
  DECLARE @TicketID_LDACTV BIGINT= @TicketID;  
  DECLARE @TicketTitle_LDACTV NVARCHAR(500)= '';  
  DECLARE @TicketCreationDate NVARCHAR(50)= '';  
  DECLARE @LeadID_LDACTV BIGINT= 0;  
  
  SELECT TOP 1 @TicketCreationDate = CAST([Date_Created] AS NVARCHAR(50)), @TicketTitle_LDACTV = ISNULL([Subject], '')  
  FROM         serv_Ticketmaster  
  WHERE        [TicketID] = ISNULL(@TicketID_LDACTV, 0);  
  
  SELECT TOP 1 @LeadID_LDACTV = ISNULL([LeadID], 0)  
  FROM         Serv_User_Detail  
  WHERE        [ser_user_id] = @UserID_LDACTV;  
  
  IF( EXISTS(SELECT 1 FROM   Serv_User_Master WHERE  [Service_id] = @UserID_LDACTV AND [kit19_User] = 1) )  
  BEGIN  
   SELECT @kit19UserID = ISNULL([kit19_id], 0)  
   FROM   Serv_User_Master  
   WHERE  [Service_id] = @UserID_LDACTV;  
  END;  
  ELSE  
  BEGIN  
   SET @kit19UserID = @ParentID_LDACTV;  
  END;  
  
  CREATE TABLE #tblEventDescrb  
  (  
   [EVNT_Description] NVARCHAR(MAX)  
  );  
  
  IF( ISNULL(@LeadID_LDACTV, 0) > 0 )  
  BEGIN  
   INSERT INTO #tblEventDescrb  
   EXEC Usp_EventTemplate_DynamicVarReplacement  
   'Lead updates ticket', @kit19UserID, '', '', @LeadID_LDACTV,  
   '', NULL, 0, 0, '', '', 0, '', 0, NULL, NULL, NULL, NULL, NULL,  
   NULL, NULL, @TicketTitle_LDACTV, NULL, @TicketCreationDate,  
   NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, NULL, NULL,  
   NULL, 0, NULL, NULL, NULL, 0, NULL, NULL;  
  
   DECLARE @evntMessage NVARCHAR(MAX)= '';  
   SELECT @evntMessage = ISNULL([EVNT_Description], '')  
   FROM   #tblEventDescrb;  
  
   IF( @evntMessage <> '' )  
   BEGIN  
    EXEC UspSaveLeadActivity_withid @LeadID_LDACTV, @kit19UserID,  
    @ParentID_LDACTV, @evntMessage, 'Lead updates ticket','Serv_TicketHistory',@TicketHistoryId;  
   END;  
  END;  
 END TRY  
 BEGIN CATCH  
  EXEC usp_InsertErrorInfo;  
 END CATCH;  
  
  IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence        
  BEGIN  
   DROP TABLE #tblEventDescrb;  
  END;  
  
  /* End Lead activity */  
  
 END;  
  
 IF(@opt = 'Re Open')  
 BEGIN  
  UPDATE Serv_TicketMaster SET STATUS = @Status, [Remarks] = @Remarks WHERE [TicketID] = @TicketID;  
  
  INSERT INTO dbo.Serv_TicketHistory  
  ([TicketID], [ParentID], User_id, [SubmittedDate], STATUS, [HistoryDate], [Remarks], [Priority],   
  [raisedby], [Ticket_type])  
  SELECT [TicketID], [ParentID], User_id, GETDATE(), @Status, GETDATE(), @Remarks, [Priority],   
  @Raisedby, [Ticket_type]  
  FROM   Serv_TicketMaster  
  WHERE  [TicketID] = @TicketID;  
  SELECT @roweff = @@ROWCOUNT;  
 END;  
  
 --if (@opt = 'Insert' or   @Ticket_Response = 1)                                     
 BEGIN  
  ------ This will create a random number between 1 and 999                                    
  DECLARE @Random INT;  
  DECLARE @Upper INT;  
  DECLARE @Lower INT;  
  
  DECLARE @BatchID BIGINT;  
  
  SET @Lower = 1; ---- The lowest random number                                    
  SET @Upper = 10000; ---- The highest random number                                    
  SELECT @Random = ROUND(( ( @Upper - @Lower - 1 ) * RAND() + @Lower ),0);  
  --SELECT @Random                                    
  INSERT INTO               GetBatchRecord( User_id, [RandNum])  
  VALUES                    (@User_ID, @Random);  
  SELECT @BatchID = MAX([BatchID])  
  FROM   GetBatchRecord WITH(NOLOCK)  
  WHERE  User_id = @User_ID AND [RandNum] = @Random;  
  
  DELETE FROM GetBatchRecord  
  WHERE       User_id = @User_ID AND [RandNum] = @Random;  
  
  SET @Subject = '#Ticket No:' + @TicketNo + '# ' + @Subject;  
  
  /* End Creation of batchid */  
  
  /* Insert into table for Mail */  
  DECLARE @ToEmailID NVARCHAR(200)= '', @FromMailID NVARCHAR(200)= '';  
   
  SELECT @ToEmailID = [Email]  
  FROM   dbo.Serv_User_Detail  
  WHERE  User_id = @User_ID;  
  
  SELECT @FromMailID = [virtual_mail]  
  FROM   serv_user_domain  
  WHERE  [ParentID] = @ParentID;  
  
  --IF( @opt = 'Insert' )  
  --BEGIN  
   --exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'New Ticket Created','Agent'                          
   --exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'New Ticket Created','Requester'                       
   --if @Assign_Group > 0                      
   --begin                      
   --exec serv_Raise_emailNotification @TicketID,@ParentID,@groupid, @User_ID,@User_ID,'Ticket Assigned to Group','Requester'                      
   --exec serv_Raise_emailNotification @TicketID,@ParentID,@Assign_Group, @User_ID,@User_ID,'Ticket Assigned to Group','Agent'                      
   --end                      
   --IF @AssignTo > 0  
   --BEGIN  
    --exec serv_Raise_emailNotification @TicketID,@ParentID,@AssignTo, @User_ID,@AssignTo,'Ticket Assigned to Agent','Agent'                   
   --END;  
  
   --DECLARE @balance INT= 0  
   --SELECT TOP 1 @balance = ISNULL([balance], 0)  
