/* ============================================================
   Procedure: [dbo].[Serv_Insert_TicketMaster_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext Serv_Insert_TicketMaster        
        
CREATE   PROCEDURE [dbo].[Serv_Insert_TicketMaster_new]                                            
(                                            
@TicketID bigint,                                             
@User_id bigint,                                             
@ParentID bigint,                                            
@Requester nvarchar(100),                                            
@Subject nvarchar(250),                                             
@Description nvarchar(max),                                              
@Priority int,                                            
@Remarks nvarchar(max),                                            
@Status int,                                         
@Ticket_Response int =0,                            
@Ticket_type int = 1,                          
@Raisedby nvarchar(100) ,                        
@req_reply int=1,                  
@AssignTo bigint,                        
@Assign_Group bigint,              
@assign_by bigint,          
@tkt_Source Varchar(20) ,          
                                   
@opt varchar(10) = 'Insert'                            
                                           
)                                            
AS                                            
begin                                            
declare @TicketNo nvarchar(16),                                            
@prifix nvarchar(15),                                             
@curNo int, @roweff int ,@tickethistoryid bigint                                           
set @roweff =0                                      
  if not EXISTs(select * from Serv_ticket_AutoNo where ParentId = @ParentID and prefix not like 'T%')                                                        
  insert into Serv_ticket_AutoNo (ParentId, user_id, prefix, curr_no)                                                         
    values (@ParentID,@ParentID,Convert(varchar(8),@ParentID)+'_',0 )                                               
                                              
BEGIN TRANSACTION TRAN1                                            
                                            
select @prifix = prefix, @curNo= curr_no                                             
 from Serv_ticket_AutoNo WITH (UPDLOCK) where ParentId = @ParentID  and prefix not like 'T%'                                             
 update Serv_ticket_AutoNo set curr_no= curr_no+1                                             
 where user_id = @User_id                                            
COMMIT TRANSACTION                                            
                                              
select @TicketNo = @prifix+REPLACE(STR(@curNo+1, 7), SPACE(1), '0')                                            
                                            
--select @TicketNo,  @prifix+REPLACE(STR(MONTH(getdate()),2), SPACE(1), '0')+                                            
--REPLACE(STR(day(getdate()),2), SPACE(1), '0')                                            
--+cast(year(getdate()) as varchar(4))                                            
--+ REPLACE(STR(@curNo+1, 7), SPACE(1), '0')                                            
if (@opt = 'Insert')                                           
Begin                                           
 insert into Serv_TicketMaster                                             
  (User_id, ParentID, TicketNo, Subject, Description, Priority,Requester,Ticket_type,AssignTo, Assign_Group, Assignedby,AssignedDateTime,Source )                                            
  values (@User_id, @ParentID, @TicketNo, @Subject, @Description, @Priority,@Requester,              
  @Ticket_type,                
  @AssignTo, @Assign_Group, @assign_by, GETDATE(), @tkt_Source)                                            
                                          
 select @TicketID = SCOPE_IDENTITY()                                          
 insert into dbo.Serv_TicketHistory (TicketID, ParentID,User_id, SubmittedDate, Status,                                           
 HistoryDate, Remarks, Priority,raisedby ,TransferredTo, Assign_Group,Ticket_type ) values                                           
 (@TicketID,@ParentID, @User_id, GETDATE(), 0,GETDATE(),@Description,@Priority,@Raisedby,                
 @AssignTo, @Assign_Group,@Ticket_type )                                       
                                      
select @roweff = @@ROWCOUNT                            
select @tickethistoryid=scope_identity()                
--exec Serv_Process_Ticket_Dispatch @ParentID,@TicketID                  
                                      
end                                           
if (@opt = 'Edit')                                            
begin                                   
 Update Serv_TicketMaster set Remarks =@Remarks,Status=@Status,Priority =  @Priority          
     where TicketID = @TicketID                                          
                                            
 insert into dbo.Serv_TicketHistory (TicketID, ParentID,User_id, SubmittedDate, Status,                                           
 HistoryDate, Remarks, Priority, Ticket_Response,raisedby,Ticket_type )                                           
 select TicketID,ParentID, User_id, GETDATE(), Status,GETDATE(),                                          
 @Remarks,Priority,@Ticket_Response,@Raisedby, Ticket_type from Serv_TicketMaster where TicketID = @TicketID                                          
 select @roweff = @@ROWCOUNT       
 select @tickethistoryid=scope_identity()  
     
     
 /* start Lead activity*/    
    
Begin try    
    
    
 Declare @UserID_LDACTV bigint = @User_id    
 Declare @ParentID_LDACTV bigint = @ParentID    
     
 Declare @kit19UserID bigint = 0     
     
     
  Declare @TicketID_LDACTV bigint = @TicketID     
  Declare @TicketTitle_LDACTV nvarchar(500) = ''    
  Declare @TicketCreationDate nvarchar(50) = ''    
    
  Select top 1  @TicketCreationDate = cast(Date_Created as nvarchar(50)) , @TicketTitle_LDACTV = isnull(Subject,'')  from serv_Ticketmaster where TicketID = isnull(@TicketID_LDACTV,0)      
      
  Declare @LeadID_LDACTV bigint = 0    
  Select top 1 @LeadID_LDACTV = isnull(LeadID,0)  from Serv_User_Detail where ser_user_id = @UserID_LDACTV    
     
   if(exists(select 1 from Serv_User_Master where Service_id = @UserID_LDACTV and kit19_User = 1))    
       Begin    
        select @kit19UserID = isnull(kit19_id,0)  from Serv_User_Master where Service_id = @UserID_LDACTV    
    End    
 else    
    Begin    
       set  @kit19UserID = @ParentID_LDACTV     
    End    
    
    
    
  create table #tblEventDescrb    
   (    
     EVNT_Description nvarchar(max)     
   )    
    
  if( isnull(@LeadID_LDACTV,0) > 0)    
   Begin    
        
   insert into #tblEventDescrb    
      exec  Usp_EventTemplate_DynamicVarReplacement 'Lead updates ticket',@kit19UserID,'','',@LeadID_LDACTV,'',null    
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,@TicketTitle_LDACTV,null    
   ,@TicketCreationDate,null,null,null,null,null,null,null,    
   0,0,0,null,null,null,0,null,null,null,0,null,null    
         
   declare @evntMessage nvarchar(max) = ''     
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb    
     
   if(@evntMessage <> '')    
   Begin    
   exec UspSaveLeadActivity_withid @LeadID_LDACTV,@kit19UserID,@ParentID_LDACTV,@evntMessage,    'Lead updates ticket','Serv_TicketHistory',@tickethistoryid    
   end    
    
    
   End      
    
   end try     
   Begin catch    
    
    exec usp_InsertErrorInfo    
    
   End catch    
    
   IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence      
   Begin      
        DROP TABLE #tblEventDescrb      
   End      
       
    
   /* End Lead activity */    
     
     
     
                                
end                                           
if (@opt = 'Re Open')                             
begin                                          
 Update Serv_TicketMaster set Status= @Status, Remarks =@Remarks                                            
  where TicketID = @TicketID                                         
                                            
 insert into dbo.Serv_TicketHistory (TicketID, ParentID,User_id, SubmittedDate, Status,         HistoryDate, Remarks, Priority,raisedby,Ticket_type)   
  select TicketID,ParentID, User_id, GETDATE(), @Status,GETDATE(),                                          
  @Remarks,Priority,@Raisedby, Ticket_type from Serv_TicketMaster where TicketID = @TicketID                                       
  select @roweff = @@ROWCOUNT              
  select @tickethistoryid=scope_identity()                             
  
end                                    
                                  
--if (@opt = 'Insert' or   @Ticket_Response = 1)                                   
begin                                  
------ This will create a random number between 1 and 999                                  
DECLARE @Random INT;                                  
  DECLARE @Upper INT;                                  
  DECLARE @Lower INT                                  
                                    
  Declare @BatchID bigint                                  
                                    
  SET @Lower = 1 ---- The lowest random number                                  
  SET @Upper = 10000 ---- The highest random number                                  
  SELECT @Random = ROUND(((@Upper - @Lower -1) * RAND() + @Lower), 0)                                  
  --SELECT @Random                                  
                                  
     insert into GetBatchRecord (User_id,RandNum)                                          
        values(@User_ID,@Random)                                          
   select @BatchID = scope_identity()                                          
        delete from GetBatchRecord  where BatchID=@BatchID                                   
                                     
  set @Subject = '#Ticket No:'+@TicketNo+'# '+@Subject                                     
    /* End Creation of batchid */                                  
  /* Insert into table for Mail */                                  
  Declare @ToEmailID nvarchar(200) = '',@FromMailID nvarchar(200) = ''                                  
  select @ToEmailID =Email from dbo.Serv_User_Detail where User_id = @User_ID                                  
  select @FromMailID =virtual_mail from serv_user_domain where ParentID=@ParentID                                   
                          
if (@opt = 'Insert')            
begin                         
exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'New Ticket Created','Agent'                        
exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'New Ticket Created','Requester'                     
                
if @Assign_Group > 0                    
begin                    
 --exec serv_Raise_emailNotification @TicketID,@ParentID,@groupid, @User_ID,@User_ID,'Ticket Assigned to Group','Requester'                    
 exec serv_Raise_emailNotification @TicketID,@ParentID,@Assign_Group, @User_ID,@User_ID,'Ticket Assigned to Group','Agent'                    
end                    
if @AssignTo > 0                    
 exec serv_Raise_emailNotification @TicketID,@ParentID,@AssignTo, @User_ID,@AssignTo,'Ticket Assigned to Agent','Agent'                 
                         
 declare @balance int =0                   
 SELECT TOP 1 @balance=isnull(balance,0) FROM   MailCreditDetails with(nolock) WHERE  --m_id = @m_id  AND                     
 USER_ID = @ParentID  ORDER BY credit_id       DESC                      
                     
 --if @balance > 20                    
 --begin                         
 -- insert into CloneEmailsFilter(                                  
 --   Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName                                  
--   ,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID                                  
 --   ,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime                                  
 --   ,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source                                  
 -- )                                  
 --  values( @FromMailID,@ToEmailID,@Subject,'',     
 --  'we Received your Request and will revert back soon.', GETDATE(),@ParentID,@ParentID,@FromMailID,                                  
 -- @BatchID,2,'','','','we Received your Request and will revert back soon.',1,0,1,                                  
 -- 'TicketManagement'                                         
 --   )                            
 -- end                  
end                        
else                           
begin                        
if @Status=4                         
exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'Agent Solves the Ticket','Requester'                        
                        
if @Status=2                         
exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'Agent Closes the Ticket','Requester'                        
        if (@opt = 'Edit')                        
exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'Requester Replies to Ticket','Agent'                        
                        
                        
                        
                        
                      
 /* Insert into table for Mail */                         
 end                            
end                                  
                                  
select @roweff  rslt, @TicketID ticketid ,@tickethistoryid tickethistoryid  
                                          
                                          
                                            
end 


GO

/* ============================================================
   Procedure: [dbo].[Serv_Insert_TicketMaster_ravi]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Serv_Insert_TicketMaster_ravi]                                    
(                                    
@TicketID bigint,                                     
@User_id bigint,                                     
@ParentID bigint,                                    
@Requester nvarchar(100),                                    
@Subject nvarchar(250),                                     
@Description nvarchar(max),                                      
@Priority int,                                    
@Remarks nvarchar(max),                                    
@Status int,                                 
@Ticket_Response int =0,                    
@Ticket_type int = 1,                  
@Raisedby nvarchar(100) ,                
@req_reply int=1,          
@AssignTo bigint,                
@Assign_Group bigint,      
@assign_by bigint,  
@tkt_Source Varchar(20) ,  
                           
@opt varchar(10) = 'Insert'                    
                                   
)                                    
AS                                    
--begin
begin transaction   
	declare @error_number as int,@error_message as varchar(max)	
	BEGIN TRY  
	
	Set NOCOUNT OFF                              
		declare @TicketNo nvarchar(16),                                    
		@prifix nvarchar(15),                                     
		@curNo int, @roweff int                                    
		set @roweff =0                              
		if not EXISTs(select * from Serv_ticket_AutoNo_ravi where ParentId = @ParentID)                                    
		insert into Serv_ticket_AutoNo_ravi (ParentId, user_id, prefix, curr_no)                                     
		  values (@ParentID,@User_id,'T'+REPLACE(STR(month(getdate()), 2), SPACE(1), '0')            
		+REPLACE(STR(day(getdate()), 2), SPACE(1), '0')+str(year(getdate()),4),0 )                                    
                                      
		--BEGIN TRANSACTION TRAN1                                    
                                    
		select @prifix = prefix, @curNo= curr_no                                     
		 from Serv_ticket_AutoNo_ravi WITH (UPDLOCK) where ParentId = @ParentID                                    
			update Serv_ticket_AutoNo_ravi set curr_no= curr_no+1                               
				where ParentId = @ParentID  
				
				if (@@error<>0)
					begin
						rollback transaction
						return
			   end                                  
		--COMMIT TRANSACTION                                    
                                      
		select @TicketNo = @prifix+REPLACE(STR(@curNo+1, 7), SPACE(1), '0')                                    
                                    
		--select @TicketNo,  @prifix+REPLACE(STR(MONTH(getdate()),2), SPACE(1), '0')+                                    
		--REPLACE(STR(day(getdate()),2), SPACE(1), '0')                                    
		--+cast(year(getdate()) as varchar(4))                                    
		--+ REPLACE(STR(@curNo+1, 7), SPACE(1), '0')                                    
		if (@opt = 'Insert')                                   
		Begin                                   
		 insert into Serv_TicketMaster                                     
		  (User_id, ParentID, TicketNo, Subject, Description, Priority,Requester,Ticket_type,AssignTo, Assign_Group, Assignedby,AssignedDateTime,Source )                                    
		  values (@User_id, @ParentID, @TicketNo, @Subject, @Description, @Priority,@Requester,      
		  @Ticket_type,        
		  @AssignTo, @Assign_Group, @assign_by, GETDATE(), @tkt_Source)     
		  
		  	if (@@error<>0)
			 begin
				rollback transaction
				return
			end                                                                 
                                  
		 select @TicketID = SCOPE_IDENTITY()                                  
		 insert into dbo.Serv_TicketHistory (TicketID, ParentID,User_id, SubmittedDate, Status,                                   
		 HistoryDate, Remarks, Priority,raisedby ,TransferredTo, Assign_Group,Ticket_type ) values                                   
		 (@TicketID,@ParentID, @User_id, GETDATE(), 0,GETDATE(),@Description,@Priority,@Raisedby,        
		 @AssignTo, @Assign_Group,@Ticket_type )      
		 if (@@error<>0)
			 begin
				rollback transaction
				return
			end                                                                                              
                              
		select @roweff = @@ROWCOUNT                                  
		--exec Serv_Process_Ticket_Dispatch @ParentID,@TicketID          
                              
		end                                   
		if (@opt = 'Edit')                                    
		begin                           
		 Update Serv_TicketMaster set Remarks =@Remarks,Status=@Status,Priority =  @Priority  
			 where TicketID = @TicketID                                  
                                    
		 insert into dbo.Serv_TicketHistory (TicketID, ParentID,User_id, SubmittedDate, Status,                                   
		 HistoryDate, Remarks, Priority, Ticket_Response,raisedby,Ticket_type )                                   
		 select TicketID,ParentID, User_id, GETDATE(), Status,GETDATE(),                                  
		 @Remarks,Priority,@Ticket_Response,@Raisedby, Ticket_type from Serv_TicketMaster where TicketID = @TicketID                                  
		 select @roweff = @@ROWCOUNT                          

		 if (@@error<>0)
			 begin
				rollback transaction
				return
		 end                                                                                              
		end                                   
		if (@opt = 'Re Open')                     
		begin                                  
		 Update Serv_TicketMaster set Status= @Status, Remarks =@Remarks                                    
		  where TicketID = @TicketID                                 
                                    
		 insert into dbo.Serv_TicketHistory (TicketID, ParentID,User_id, SubmittedDate, Status,         HistoryDate, Remarks, Priority,raisedby,Ticket_type)                                   
		  select TicketID,ParentID, User_id, GETDATE(), @Status,GETDATE(),                                  
		  @Remarks,Priority,@Raisedby, Ticket_type from Serv_TicketMaster where TicketID = @TicketID                               
		  select @roweff = @@ROWCOUNT    
		  
			if (@@error<>0)
			 begin
				rollback transaction
				return
			end                                                                                                                          
		end                            
                          
		--if (@opt = 'Insert' or   @Ticket_Response = 1)                           
		begin                          
		------ This will create a random number between 1 and 999                          
		DECLARE @Random INT;                          
		  DECLARE @Upper INT;                          
		  DECLARE @Lower INT                          
                            
		  Declare @BatchID bigint                          
                            
		  SET @Lower = 1 ---- The lowest random number                          
		  SET @Upper = 10000 ---- The highest random number                          
		  SELECT @Random = ROUND(((@Upper - @Lower -1) * RAND() + @Lower), 0)                          
		  --SELECT @Random                          
                          
			 insert into GetBatchRecord (User_id,RandNum)                                  
				values(@User_ID,@Random)                                  
		   select @BatchID = max(BatchID)  from GetBatchRecord With (Nolock)                           
		   where User_id=@User_ID and RandNum=@Random                                  
				delete from GetBatchRecord  where User_id=@User_ID and RandNum=@Random   
				
			if (@@error<>0)
			 begin
				rollback transaction
				return
			end                                                                                                                                                  
                             
		  set @Subject = '#Ticket No:'+@TicketNo+'# '+@Subject                             
			/* End Creation of batchid */                          
		  /* Insert into table for Mail */                          
		  Declare @ToEmailID nvarchar(200) = '',@FromMailID nvarchar(200) = ''                          
		  select @ToEmailID =Email from dbo.Serv_User_Detail where User_id = @User_ID                          
		  select @FromMailID =virtual_mail from serv_user_domain where ParentID=@ParentID                           
                  
		if (@opt = 'Insert')                                   
		begin                 
		exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'New Ticket Created','Agent'                
		exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'New Ticket Created','Requester'             
        
		if @Assign_Group > 0            
		begin            
		 --exec serv_Raise_emailNotification @TicketID,@ParentID,@groupid, @User_ID,@User_ID,'Ticket Assigned to Group','Requester'            
		 exec serv_Raise_emailNotification @TicketID,@ParentID,@Assign_Group, @User_ID,@User_ID,'Ticket Assigned to Group','Agent'            
		end            
		if @AssignTo > 0            
		 exec serv_Raise_emailNotification @TicketID,@ParentID,@AssignTo, @User_ID,@AssignTo,'Ticket Assigned to Agent','Agent'         
                 
		 declare @balance int =0           
		 SELECT TOP 1 @balance=isnull(balance,0) FROM   MailCreditDetails with(nolock) WHERE  --m_id = @m_id  AND             
		 USER_ID = @ParentID  ORDER BY credit_id       DESC              
             
		 --if @balance > 20            
		 --begin                 
		 -- insert into CloneEmailsFilter(                          
		 --   Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName                          
		 --   ,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID                          
		 --   ,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime                          
		 --   ,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source                          
		 -- )                          
		 --  values( @FromMailID,@ToEmailID,@Subject,'',                  
		 --  'we Received your Request and will revert back soon.', GETDATE(),@ParentID,@ParentID,@FromMailID,                          
		 -- @BatchID,2,'','','','we Received your Request and will revert back soon.',1,0,1,                          
		 -- 'TicketManagement'                                 
		 --   )                    
		 -- end          
		end                
		else                   
		begin                
		if @Status=4                 
		exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'Agent Solves the Ticket','Requester'                
                
		if @Status=2                 
		exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'Agent Closes the Ticket','Requester'                
				if (@opt = 'Edit')                
		exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'Requester Replies to Ticket','Agent'                
                
                
                
                
              
		 /* Insert into table for Mail */                 
		 end                    
		end                          
                          
		select @roweff  rslt, @TicketID ticketid                                
                                  
                                  
                                    
		--end 
END TRY
BEGIN CATCH
    SELECT @error_number=ERROR_NUMBER(),@error_message=ERROR_MESSAGE()
		rollback transaction
	return
   
END CATCH
COMMIT TRANSACTION 



GO

/* ============================================================
   Procedure: [dbo].[Serv_Insert_TicketMaster_support]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec Serv_Insert_TicketMaster_support @TicketID=0,@ser_user_id=2179,@ParentID=32222,@Requester=N'mayank.nigam@pelsoftlabs.in',@Subject=N'Subject',@Description=N'<p><span style="color: #343a40; font-family: Roboto, sans-serif; font-size: 14px;">Description</span></p>', @Priority=1,@Remarks=N'',@Status=0,@Ticket_Response=0,@Ticket_type=1,@TicketCategoryId=1,@Raisedby=N'2179',@req_reply=0,@AssignTo=0,@Assign_Group=0,@assign_by=2179,@tkt_Source='Manual',@opt='Insert'      
CREATE   PROCEDURE [dbo].[Serv_Insert_TicketMaster_support]      
(                                                                        
 @TicketID bigint,    
 --@User_id bigint,    
 @ser_user_id bigint,    
 @ParentID bigint,    
 @Requester nvarchar(100),    
 @Subject nvarchar(250),    
 @Description nvarchar(max),    
 @Priority int,    
 @Remarks nvarchar(max),    
 @Status int,    
 @Ticket_Response int =0,    
 @Ticket_type int = 1,    
 @TicketCategoryId int = 1,    
 @Raisedby nvarchar(100) ,    
 @req_reply int=1,    
 @AssignTo bigint,    
 @Assign_Group bigint,    
 @assign_by bigint,    
 @tkt_Source Varchar(20) ,    
 @opt varchar(10) = 'Insert'    
)                                                                        
AS                                                                        
Begin                                   
                             
DECLARE @error_number AS INT, @error_message AS VARCHAR(MAX);    
   
 declare @tickethistory table(id int identity(1,1),tickethistoryid bigint)  
--BEGIN TRY                                      
--begin transaction                                       
--declare @TicketID bigint=0,@ser_user_id bigint=2556,@ParentID bigint=37540,@Requester nvarchar(100)=N'',@Subject nvarchar(250)=N'test Subject',@Description nvarchar(max)=N'<p>test content</p>',@Priority int=1,@Remarks nvarchar(max)=N'',@Status int=0,@Ticket_Response int=0,@Ticket_type int=1,@Raisedby nvarchar(100)=N'2556',@req_reply int=0,@AssignTo bigint=0,@Assign_Group bigint=0,@assign_by bigint=2556,@tkt_Source Varchar(20)='Manual',@opt varchar(10)='Insert'      
    
SET NOCOUNT OFF;    
DECLARE @TicketNo NVARCHAR(16), @TicketHistoryID BIGINT, @prifix NVARCHAR(15), @curNo INT, @roweff INT;    
SET @roweff = 0;    
    
IF( @opt = 'Insert' )    
BEGIN    
 IF NOT EXISTS(SELECT * FROM Serv_ticket_AutoNo WHERE [ParentId] = @ParentID AND [prefix] NOT LIKE 'T%')    
 BEGIN    
  INSERT INTO Serv_ticket_AutoNo( [ParentId], user_id, [prefix], [curr_no] )    
  VALUES                        (@ParentID, @ParentID, CONVERT(VARCHAR(8), @ParentID) + '_', 0)    
 END;    
    
 --BEGIN TRANSACTION TRAN1                                                                        
 SELECT @prifix = [prefix], @curNo = [curr_no]    
 FROM Serv_ticket_AutoNo WITH(UPDLOCK)    
 WHERE [ParentId] = @ParentID AND [prefix] NOT LIKE 'T%';    
    
 UPDATE Serv_ticket_AutoNo SET [curr_no] = [curr_no] + 1    
 WHERE [ParentId] = @ParentID AND [prefix] NOT LIKE 'T%';    
    
 -- if (@@error<>0)                                    
 --  begin      
 --print '1:- rollback transaction'      
 --   rollback transaction      
 --   return                                    
 --   end              
 --COMMIT TRANSACTION                             
 --Declare @length int                        
 --set   @length = len(@curNo)              
    
 SELECT @TicketNo = @prifix + REPLACE(STR(@curNo + 1, 7), SPACE(1), '0');    
    
 --select @TicketNo,  @prifix+REPLACE(STR(MONTH(getdate()),2), SPACE(1), '0')+ REPLACE(STR(day(getdate()),2), SPACE(1), '0')      +cast(year(getdate()) as varchar(4)) + REPLACE(STR(@curNo+1, 7), SPACE(1), '0')                                              
  
                   
 INSERT INTO Serv_TicketMaster    
  (User_id,[ParentID],[TicketNo],[Subject],[Description],[Priority],[Requester],[Ticket_type], TicketCategoryId,[AssignTo],    
  [Assign_Group],[Assignedby],[AssignedDateTime],[Source],[update_date] )    
 VALUES(@ser_user_id, @ParentID, @TicketNo, @Subject, @Description,@Priority, @Requester, @Ticket_type, @TicketCategoryId, @AssignTo,    
  @Assign_Group,@assign_by, GETDATE(), @tkt_Source, GETDATE());    
 --select * from Serv_TicketMaster where User_id=2179  --2349      
 --if (@@error<>0)                                    
 --   begin                                    
 -- print '2:- rollback transaction'     -- rollback transaction      
 -- return      
 --end                                                                               
 SELECT @TicketID = SCOPE_IDENTITY();    
    
 /*******************************/    
 PRINT 'Serv_Insert_TicketMaster_support: @ParentID- ' + CAST(@ParentID AS VARCHAR) + ', @TicketID- ' + CAST(@TicketID AS VARCHAR);    
 exec serv_Raise_emailNotification_support1 @TicketID, @ParentID, @Assign_Group, @ser_user_id, @AssignTo, 'New Ticket Created','Requester'       
 EXEC Serv_Process_Ticket_Dispatch_support_withnoselection @ParentID, @TicketID;    
    
 /*******************************/    
    
 INSERT INTO dbo.Serv_TicketHistory    
 ([TicketID],[ParentID],User_id,[SubmittedDate],STATUS,[HistoryDate],[Remarks],[Priority],[raisedby],[TransferredTo],    
  [Assign_Group], [Ticket_type], TicketCategoryId)  output inserted.TicketHistoryID into @tickethistory  
 VALUES(@TicketID, @ParentID, @ser_user_id, GETDATE(), 0, GETDATE(), @Description, @Priority, @Raisedby, @AssignTo,    
 @Assign_Group, @Ticket_type, @TicketCategoryId);    
    
 --SELECT @TicketHistoryID = (SELECT MAX([TicketHistoryID]) FROM [Serv_TicketHistory] WHERE  [TicketID] = @TicketID);    
    
 -- select * from Serv_TicketHistory where TicketID = 2349      
 --if (@@error<>0)      
 --begin      
 -- print '3:- rollback transaction'      
 -- rollback transaction      
 -- return      
 --end       
 SELECT @roweff = @@ROWCOUNT;    
 SELECT top 1 @TicketHistoryID = max(tickethistoryid) from @tickethistory;  
 delete from @tickethistory    
-- SELECT @TicketHistoryID = (SELECT MAX([TicketHistoryID]) FROM [Serv_TicketHistory] WHERE  [TicketID] = @TicketID);    
 --exec Serv_Process_Ticket_Dispatch @ParentID,@TicketID                                              
END;    
    
IF( @opt = 'Edit' )    
BEGIN    
 UPDATE Serv_TicketMaster SET [Remarks] = @Remarks, STATUS = @Status, [Priority] = @Priority, [update_date] = GETDATE()    
 WHERE [TicketID] = @TicketID;    
    
 UPDATE Serv_TicketMaster SET [resolved_dt] = GETDATE()    
 WHERE [TicketID] = @TicketID AND STATUS = 4;    
    
 INSERT INTO dbo.Serv_TicketHistory    
 ([TicketID],[ParentID],User_id,[SubmittedDate],STATUS,[HistoryDate],[Remarks],[Priority],[Ticket_Response],[raisedby],    
  [Ticket_type], TicketCategoryId, [TransferredTo], [Assign_Group] )  output inserted.TicketHistoryID into @tickethistory  
 SELECT [TicketID],[ParentID], User_id,GETDATE(), STATUS, GETDATE(), @Remarks, [Priority], @Ticket_Response, @Raisedby,    
  [Ticket_type], @TicketCategoryId, [AssignTo], [Assign_Group]    
 FROM   Serv_TicketMaster    
 WHERE  [TicketID] = @TicketID;    
    
 SELECT @roweff = @@ROWCOUNT;    
  
 SELECT top 1 @TicketHistoryID = max(tickethistoryid) from @tickethistory;  
 delete from @tickethistory  
 --SELECT @TicketHistoryID = (SELECT MAX([TicketHistoryID]) FROM [Serv_TicketHistory] WHERE  [TicketID] = @TicketID);    
    
 --if (@@error<>0)                                    
 -- begin                                    
 --print '4:- rollback transaction'      
 -- rollback transaction                                    
 -- return                                    
 --end                     
END;    
    
IF( @opt = 'Re Open' )    
BEGIN    
 UPDATE Serv_TicketMaster SET STATUS = @Status, [Remarks] = @Remarks    
 WHERE [TicketID] = @TicketID;    
    
 UPDATE Serv_TicketMaster SET [resolved_dt] = NULL    
 WHERE [TicketID] = @TicketID AND STATUS <> 4 AND [resolved_dt] IS NOT NULL;    
    
 INSERT INTO dbo.Serv_TicketHistory    
 ([TicketID],[ParentID],User_id,[SubmittedDate],STATUS,[HistoryDate],[Remarks],[Priority],[raisedby],[Ticket_type], TicketCategoryId)  output inserted.TicketHistoryID into @tickethistory  
 SELECT [TicketID],[ParentID],User_id,GETDATE(),@Status,GETDATE(),@Remarks,[Priority],@Raisedby,[Ticket_type], TicketCategoryId FROM   Serv_TicketMaster    
 WHERE  [TicketID] = @TicketID;    
    
 SELECT @roweff = @@ROWCOUNT;    
     
 SELECT top 1 @TicketHistoryID = max(tickethistoryid) from @tickethistory;  
 delete from @tickethistory  
 --SELECT @TicketHistoryID = (SELECT MAX([TicketHistoryID]) FROM [Serv_TicketHistory] WHERE  [TicketID] = @TicketID);    
    
 --if (@@error<>0)                                    
 -- begin                                    
 --print '5:- rollback transaction'      
 -- rollback transaction                                    
 -- return                                    
 --end                                                                                                                                                              
END;    
    
SELECT @roweff AS [rslt], @TicketID AS [ticketid], @TicketHistoryID AS [TicketHistoryID];    
    
