    --SELECT @Random                                                              
                                   
    insert into GetBatchRecord (User_id,RandNum)      
    values(@ser_user_id,@Random)                                                                      
     select @BatchID = max(BatchID)  from GetBatchRecord(Nolock)      
     where User_id=@ser_user_id and RandNum=@Random      
      
    delete from GetBatchRecord  where User_id=@ser_user_id and RandNum=@Random                                       
                                        
   if (@@error<>0)                                    
    begin                                    
    rollback transaction                                    
    return                                    
   end                                                        
                                                                 
    set @Subject = '#Ticket No:'+@TicketNo+'# '+@Subject                                
   /* End Creation of batchid */                                                              
    /* Insert into table for Mail */                                                      
    Declare @ToEmailID nvarchar(200) = '',@FromMailID nvarchar(200) = ''                                                              
    select @ToEmailID =Email from dbo.Serv_User_Detail where User_id = @ser_user_id                                                              
    select @FromMailID =virtual_mail from serv_user_domain where ParentID=@ParentID                                              */    
    
