/* Start Lead activity Lead raises ticket  */    
    
BEGIN TRY 

 DECLARE @UserID_LDACTV BIGINT= @ser_user_id;    
 DECLARE @ParentID_LDACTV BIGINT= @ParentID;    
    
 DECLARE @kit19UserID BIGINT= 0;    
    
 DECLARE @TicketTypeID_LDACTV INT= @Ticket_type;    
 DECLARE @TicketPriorityID_LDACTV INT= @Priority;    
    
 DECLARE @TicketType_LDACTV NVARCHAR(200)= '';    
 DECLARE @TicketPriority_LDACTV NVARCHAR(200)= '';    
    
 DECLARE @TicketTitle_LDACTV NVARCHAR(500)= @Subject;    
    
 DECLARE @LeadID_LDACTV BIGINT= 0;    
 SELECT TOP 1 @LeadID_LDACTV = ISNULL([LeadID], 0) FROM Serv_User_Detail WHERE [ser_user_id] = @UserID_LDACTV;    
    
 IF( EXISTS(SELECT 1 FROM   Serv_User_Master WHERE  [Service_id] = @UserID_LDACTV AND [kit19_User] = 1) )    
 BEGIN    
  SELECT @kit19UserID = ISNULL([kit19_id], 0) FROM   Serv_User_Master WHERE  [Service_id] = @UserID_LDACTV;    
 END;    
 ELSE    
 BEGIN    
  SET @kit19UserID = @ParentID_LDACTV;    
 END;    
    
 --select * from Serv_User_Detail             
 SELECT TOP 1 @TicketType_LDACTV = ISNULL([Type_Desc], '')    
 FROM         Serv_TicketType_Mast    
 WHERE        Type_ID = ISNULL(@TicketTypeID_LDACTV, 0);    
     
 SELECT TOP 1 @TicketPriority_LDACTV = ISNULL([Priority_Desc], '')    
 FROM         Serv_Priority_Mast    
 WHERE        [Priority_ID] = ISNULL(@TicketPriorityID_LDACTV, 0);    
    
 CREATE TABLE #tblEventDescrb    
 (    
  [EVNT_Description] NVARCHAR(MAX)    
 );    
    

 IF( ISNULL(@LeadID_LDACTV, 0) > 0 )    
 BEGIN    
  INSERT INTO #tblEventDescrb    
  EXEC Usp_EventTemplate_DynamicVarReplacement 'Lead raises ticket',    
  @kit19UserID, '', '', @LeadID_LDACTV, '', NULL, 0, 0, '', '', 0,    
  '', 0, NULL, NULL, NULL, NULL, NULL, NULL, @TicketType_LDACTV,    
  @TicketTitle_LDACTV, @TicketPriority_LDACTV, NULL, NULL, NULL,    
  NULL, NULL, NULL, NULL, NULL, 0, 0, 0, NULL, NULL, NULL, 0, NULL,    
  NULL, NULL, 0, NULL, NULL;    
    
  DECLARE @evntMessage NVARCHAR(MAX)= '';    
  SELECT @evntMessage = ISNULL([EVNT_Description], '')    
  FROM   #tblEventDescrb;    
    
  IF( @evntMessage <> '' )    
  BEGIN   
  
   EXEC UspSaveLeadActivity_withid @LeadID_LDACTV, @kit19UserID,    
   @ParentID_LDACTV, @evntMessage, 'Lead raises ticket','Serv_TicketHistory',@TicketHistoryID;    
  END;    
    
 END;    
END TRY    
BEGIN CATCH    
 EXEC usp_insertErrorInfo;    
END CATCH;    
    
IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence              
BEGIN    
 DROP TABLE #tblEventDescrb;    
END;    
    
 --Drop table #tblEventDescrb            
 /* End Lead activity Lead raises ticket  */    
    
 --COMMIT TRANSACTION       
End 




GO

/* ============================================================
   Procedure: [dbo].[Serv_Insert_TicketMaster1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[Serv_Insert_TicketMaster1]                                      
(                                      
@TicketID bigint,                                       
@User_id bigint,                                       
@ParentID bigint,                                      
@Requester nvarchar(100),                                      
@Subject nvarchar(250),                                       
@Description nvarchar(max),                                        
@Priority int,                                      
@Remarks nvarchar(max),                                      
@Status int,                                   
@Ticket_Response int =0,                      
@Ticket_type int = 1,                    
@Raisedby nvarchar(100) ,                  
@req_reply int=1,            
@AssignTo bigint,                  
@Assign_Group bigint,        
@assign_by bigint,    
@tkt_Source Varchar(20) ,    
                             
@opt varchar(10) = 'Insert'                      
                                     
)                                      
AS                                      
--begin  
begin transaction     
 declare @error_number as int,@error_message as varchar(max)   
 BEGIN TRY    
   
 Set NOCOUNT OFF                                
  declare @TicketNo nvarchar(16),                                      
  @prifix nvarchar(15),                                       
  @curNo int, @roweff int                                      
  set @roweff =0                                
  if not EXISTs(select * from Serv_ticket_AutoNo where ParentId = @ParentID)                                      
  insert into Serv_ticket_AutoNo (ParentId, user_id, prefix, curr_no)                                       
    values (@ParentID,@User_id,'T'+REPLACE(STR(month(getdate()), 2), SPACE(1), '0')              
  +REPLACE(STR(day(getdate()), 2), SPACE(1), '0')+str(year(getdate()),4),0 )                                      
                                        
  --BEGIN TRANSACTION TRAN1                                      
                                      
  select @prifix = prefix, @curNo= curr_no                                       
   from Serv_ticket_AutoNo WITH (UPDLOCK) where ParentId = @ParentID                                      
   update Serv_ticket_AutoNo set curr_no= curr_no+1                                 
    where ParentId = @ParentID    
      
    if (@@error<>0)  
     begin  
      rollback transaction  
      return  
      end                                    
  --COMMIT TRANSACTION                                      
                                        
  select @TicketNo = @prifix+REPLACE(STR(@curNo+1, 7), SPACE(1), '0')                                      
                                      
  --select @TicketNo,  @prifix+REPLACE(STR(MONTH(getdate()),2), SPACE(1), '0')+                                      
  --REPLACE(STR(day(getdate()),2), SPACE(1), '0')                                      
  --+cast(year(getdate()) as varchar(4))                                      
  --+ REPLACE(STR(@curNo+1, 7), SPACE(1), '0')                                      
  if (@opt = 'Insert')                                     
  Begin                                     
   insert into Serv_TicketMaster                                       
    (User_id, ParentID, TicketNo, Subject, Description, Priority,Requester,Ticket_type,AssignTo, Assign_Group, Assignedby,AssignedDateTime,Source, update_date)                                      
    values (@User_id, @ParentID, @TicketNo, @Subject, @Description, @Priority,@Requester,        
    @Ticket_type,          
    @AssignTo, @Assign_Group, @assign_by, GETDATE(), @tkt_Source,getdate())       
      
     if (@@error<>0)  
    begin  
    rollback transaction  
    return  
   end         
                                    
   select @TicketID = SCOPE_IDENTITY()                                    
   insert into dbo.Serv_TicketHistory (TicketID, ParentID,User_id, SubmittedDate, Status,                                     
   HistoryDate, Remarks, Priority,raisedby ,TransferredTo, Assign_Group,Ticket_type ) values                                     
   (@TicketID,@ParentID, @User_id, GETDATE(), 0,GETDATE(),@Description,@Priority,@Raisedby,          
   @AssignTo, @Assign_Group,@Ticket_type )        
   if (@@error<>0)  
    begin  
    rollback transaction  
    return  
   end                                                                                                
                                
  select @roweff = @@ROWCOUNT                                    
  --exec Serv_Process_Ticket_Dispatch @ParentID,@TicketID            
                                
  end                                     
  if (@opt = 'Edit')                                      
  begin                             
   Update Serv_TicketMaster set Remarks =@Remarks,Status=@Status,Priority =  @Priority,update_date=getdate()    
    where TicketID = @TicketID                                    
                                      
   insert into dbo.Serv_TicketHistory (TicketID, ParentID,User_id, SubmittedDate, Status,                                     
   HistoryDate, Remarks, Priority, Ticket_Response,raisedby,Ticket_type )                                     
   select TicketID,ParentID, User_id, GETDATE(), Status,GETDATE(),                                    
   @Remarks,Priority,@Ticket_Response,@Raisedby, Ticket_type from Serv_TicketMaster where TicketID = @TicketID                                    
   select @roweff = @@ROWCOUNT                            
  
   if (@@error<>0)  
    begin  
    rollback transaction  
    return  
   end                                                                                                
  end                                     
  if (@opt = 'Re Open')                       
  begin                                    
   Update Serv_TicketMaster set Status= @Status, Remarks =@Remarks                                      
    where TicketID = @TicketID                                   
                                      
   insert into dbo.Serv_TicketHistory (TicketID, ParentID,User_id, SubmittedDate, Status,         HistoryDate, Remarks, Priority,raisedby,Ticket_type)                                     
    select TicketID,ParentID, User_id, GETDATE(), @Status,GETDATE(),                                    
    @Remarks,Priority,@Raisedby, Ticket_type from Serv_TicketMaster where TicketID = @TicketID                                 
    select @roweff = @@ROWCOUNT      
      
   if (@@error<>0)  
    begin  
    rollback transaction  
    return  
   end                                                                                                                            
  end                              
                            
  --if (@opt = 'Insert' or   @Ticket_Response = 1)                             
  begin                            
  ------ This will create a random number between 1 and 999                            
  DECLARE @Random INT;                            
    DECLARE @Upper INT;                            
    DECLARE @Lower INT                            
                              
    Declare @BatchID bigint                            
                              
    SET @Lower = 1 ---- The lowest random number                            
    SET @Upper = 10000 ---- The highest random number                            
    SELECT @Random = ROUND(((@Upper - @Lower -1) * RAND() + @Lower), 0)                            
    --SELECT @Random                            
                            
    insert into GetBatchRecord (User_id,RandNum)                                   
    values(@User_ID,@Random)                                    
     select @BatchID = max(BatchID)  from GetBatchRecord With (Nolock)                             
     where User_id=@User_ID and RandNum=@Random                                    
    delete from GetBatchRecord  where User_id=@User_ID and RandNum=@Random     
      
   if (@@error<>0)  
    begin  
    rollback transaction  
    return  
   end                                                                                                                                                    
                               
    set @Subject = '#Ticket No:'+@TicketNo+'# '+@Subject                               
   /* End Creation of batchid */                            
    /* Insert into table for Mail */                            
    Declare @ToEmailID nvarchar(200) = '',@FromMailID nvarchar(200) = ''                            
    select @ToEmailID =Email from dbo.Serv_User_Detail where User_id = @User_ID                            
    select @FromMailID =virtual_mail from serv_user_domain where ParentID=@ParentID                             
                    
  if (@opt = 'Insert')                                     
  begin                   
  exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'New Ticket Created','Agent'                  
  exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'New Ticket Created','Requester'               
          
  if @Assign_Group > 0              
  begin              
   --exec serv_Raise_emailNotification @TicketID,@ParentID,@groupid, @User_ID,@User_ID,'Ticket Assigned to Group','Requester'              
   exec serv_Raise_emailNotification @TicketID,@ParentID,@Assign_Group, @User_ID,@User_ID,'Ticket Assigned to Group','Agent'              
  end              
  if @AssignTo > 0              
   exec serv_Raise_emailNotification @TicketID,@ParentID,@AssignTo, @User_ID,@AssignTo,'Ticket Assigned to Agent','Agent'           
                   
   declare @balance int =0             
   SELECT TOP 1 @balance=isnull(balance,0) FROM   MailCreditDetails with(nolock) WHERE  --m_id = @m_id  AND               
   USER_ID = @ParentID  ORDER BY credit_id       DESC                
               
   --if @balance > 20              
   --begin                   
   -- insert into CloneEmailsFilter(                            
   --   Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName                            
   --   ,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID                            
   --   ,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime                            
   --   ,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source                            
   -- )                            
   --  values( @FromMailID,@ToEmailID,@Subject,'',                    
   --  'we Received your Request and will revert back soon.', GETDATE(),@ParentID,@ParentID,@FromMailID,                            
   -- @BatchID,2,'','','','we Received your Request and will revert back soon.',1,0,1,                            
   -- 'TicketManagement'                                   
   --   )                      
   -- end            
  end                  
  else                     
  begin                  
  if @Status=4                   
  exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'Agent Solves the Ticket','Requester'                  
                  
  if @Status=2                   
  exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'Agent Closes the Ticket','Requester'                  
    if (@opt = 'Edit')                  
  exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'Requester Replies to Ticket','Agent'                  
                
                  
                  
                  
                
   /* Insert into table for Mail */                   
   end                      
  end                            
                            
  select @roweff  rslt, @TicketID ticketid                                  
                                    
                                    
                                      
  --end   
END TRY  
BEGIN CATCH  
    SELECT @error_number=ERROR_NUMBER(),@error_message=ERROR_MESSAGE()  
  rollback transaction  
 return  
     
END CATCH  
COMMIT TRANSACTION 



GO

/* ============================================================
   Procedure: [dbo].[Serv_Insert_TicketMaster1_SUPPORT]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext Serv_Insert_TicketMaster  
  
CREATE   PROCEDURE [dbo].[Serv_Insert_TicketMaster1_SUPPORT]                                      
(                                      
@TicketID bigint,                                       
@User_id bigint,                                       
@ParentID bigint,                                      
@Requester nvarchar(100),                                      
@Subject nvarchar(250),                                       
@Description nvarchar(max),                                        
@Priority int,                                      
@Remarks nvarchar(max),                                      
@Status int,                                   
@Ticket_Response int =0,                      
@Ticket_type int = 1,                    
@Raisedby nvarchar(100) ,                  
@req_reply int=1,            
@AssignTo bigint,                  
@Assign_Group bigint,        
@assign_by bigint,    
@tkt_Source Varchar(20) ,    
                             
@opt varchar(10) = 'Insert'                      
                                     
)                                      
AS                                      
begin                                      
declare @TicketNo nvarchar(16),                                      
@prifix nvarchar(15),                                       
@curNo int, @roweff int                                      
set @roweff =0                                
if not EXISTs(select * from Serv_ticket_AutoNo where ParentId = @ParentID)                                      
insert into Serv_ticket_AutoNo (ParentId, user_id, prefix, curr_no)                                       
  values (@ParentID,@User_id,'T'+REPLACE(STR(month(getdate()), 2), SPACE(1), '0')              
+REPLACE(STR(day(getdate()), 2), SPACE(1), '0')+str(year(getdate()),4),0 )                                      
                                        
BEGIN TRANSACTION TRAN1                                      
                                      
select @prifix = prefix, @curNo= curr_no                                       
 from Serv_ticket_AutoNo WITH (UPDLOCK) where user_id = @User_id                                      
 update Serv_ticket_AutoNo set curr_no= curr_no+1                                       
 where ParentId = @ParentID                                     
COMMIT TRANSACTION                                      
                                        
select @TicketNo = @prifix+REPLACE(STR(@curNo+1, 7), SPACE(1), '0')                                      
                                      
--select @TicketNo,  @prifix+REPLACE(STR(MONTH(getdate()),2), SPACE(1), '0')+                                      
--REPLACE(STR(day(getdate()),2), SPACE(1), '0')                                      
--+cast(year(getdate()) as varchar(4))                                      
--+ REPLACE(STR(@curNo+1, 7), SPACE(1), '0')                                      
if (@opt = 'Insert')                                     
Begin                                     
 insert into Serv_TicketMaster                                       
  (User_id, ParentID, TicketNo, Subject, Description, Priority,Requester,Ticket_type,AssignTo, Assign_Group, Assignedby,AssignedDateTime,Source )                                      
  values (@User_id, @ParentID, @TicketNo, @Subject, @Description, @Priority,@Requester,        
  @Ticket_type,          
  @AssignTo, @Assign_Group, @assign_by, GETDATE(), @tkt_Source)                                      
                                    
 select @TicketID = SCOPE_IDENTITY()                                    
 insert into dbo.Serv_TicketHistory (TicketID, ParentID,User_id, SubmittedDate, Status,                                     
 HistoryDate, Remarks, Priority,raisedby ,TransferredTo, Assign_Group,Ticket_type ) values                                     
 (@TicketID,@ParentID, @User_id, GETDATE(), 0,GETDATE(),@Description,@Priority,@Raisedby,          
 @AssignTo, @Assign_Group,@Ticket_type )                                 
                                
select @roweff = @@ROWCOUNT                                    
--exec Serv_Process_Ticket_Dispatch @ParentID,@TicketID            
                                
end                                     
if (@opt = 'Edit')                                      
begin                             
 Update Serv_TicketMaster set Remarks =@Remarks,Status=@Status,Priority =  @Priority    
     where TicketID = @TicketID                                    
                                      
 insert into dbo.Serv_TicketHistory (TicketID, ParentID,User_id, SubmittedDate, Status,                                     
 HistoryDate, Remarks, Priority, Ticket_Response,raisedby,Ticket_type )                                     
 select TicketID,ParentID, User_id, GETDATE(), Status,GETDATE(),                                    
 @Remarks,Priority,@Ticket_Response,@Raisedby, Ticket_type from Serv_TicketMaster where TicketID = @TicketID                                    
 select @roweff = @@ROWCOUNT                            
end                                     
if (@opt = 'Re Open')                       
begin                                    
 Update Serv_TicketMaster set Status= @Status, Remarks =@Remarks                                      
  where TicketID = @TicketID                                   
                                      
 insert into dbo.Serv_TicketHistory (TicketID, ParentID,User_id, SubmittedDate, Status,         HistoryDate, Remarks, Priority,raisedby,Ticket_type)                                     
  select TicketID,ParentID, User_id, GETDATE(), @Status,GETDATE(),                                    
  @Remarks,Priority,@Raisedby, Ticket_type from Serv_TicketMaster where TicketID = @TicketID                                 
  select @roweff = @@ROWCOUNT                                   
end                              
                            
--if (@opt = 'Insert' or   @Ticket_Response = 1)                             
begin                            
------ This will create a random number between 1 and 999                            
DECLARE @Random INT;                            
  DECLARE @Upper INT;                            
  DECLARE @Lower INT                            
                              
  Declare @BatchID bigint                            
                              
  SET @Lower = 1 ---- The lowest random number                            
  SET @Upper = 10000 ---- The highest random number                            
  SELECT @Random = ROUND(((@Upper - @Lower -1) * RAND() + @Lower), 0)                            
  --SELECT @Random                            
                            
     insert into GetBatchRecord (User_id,RandNum)                                    
        values(@User_ID,@Random)                                    
   select @BatchID = max(BatchID)  from GetBatchRecord With (Nolock)                             
   where User_id=@User_ID and RandNum=@Random                                    
        delete from GetBatchRecord  where User_id=@User_ID and RandNum=@Random                             
                               
  set @Subject = '#Ticket No:'+@TicketNo+'# '+@Subject                               
    /* End Creation of batchid */                            
  /* Insert into table for Mail */                            
  Declare @ToEmailID nvarchar(200) = '',@FromMailID nvarchar(200) = ''                            
  select @ToEmailID =Email from dbo.Serv_User_Detail where User_id = @User_ID                            
  select @FromMailID =virtual_mail from serv_user_domain where ParentID=@ParentID                             
                    
if (@opt = 'Insert')                                 
begin                   
exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'New Ticket Created','Agent'                  
exec serv_Raise_emailNotification @TicketID,@ParentID,0 , @User_ID,@User_ID,'New Ticket Created','Requester'               
          
if @Assign_Group > 0              
