 declare @balance int =0             
 SELECT TOP 1 @balance=isnull(balance,0) FROM   MailCreditDetails with(nolock) WHERE  --m_id = @m_id  AND               
 USER_ID = @ParentID  ORDER BY credit_id       DESC                
               
 --if @balance > 20              
