CREATE   PROCEDURE [dbo].[Serv_InsertUpdateSLAResponse]
(
   @SLAResp_ID bigint,
   @SLAID bigint ,
   @ParentID bigint ,
   @Priority_ID int,
   @Respond_val int,
   @Respond_Unit nvarchar(10),
   @Respond_Sec bigint,
   @resolve_val int,
   @resolve_unit nvarchar(10),
   @resolve_Sec bigint,
   @Operational_val int,
   @Operational_unit nvarchar(10),
   @Operational_Sec bigint,
   @Escalation_email bit,
   @resp_Freq nvarchar(50),
   @Assign_Agent bigint,
   @Option nvarchar(50),
   @resp_remind_freq nvarchar(50), 
   @resp_assignd bigint, 
   @resolution_remind_freq nvarchar(50),
   @resolution_assignd bigint
)


as
Begin
   if(@Option = 'Insert')
      Begin
  insert into Serv_SLA_Response(SLAID,ParentID,Priority_ID,Respond_val,Respond_Unit
     ,Respond_Sec,resolve_val,resolve_unit ,resolve_Sec,Operational_val,Operational_unit
     ,Operational_Sec,Escalation_email,resp_Freq ,Assign_Agent,
     resp_remind_freq, resp_assignd, resolution_remind_freq, resolution_assignd) 
     values(@SLAID,@ParentID,@Priority_ID,@Respond_val,@Respond_Unit
     ,@Respond_Sec,@resolve_val,@resolve_unit ,@resolve_Sec,@Operational_val,
     @Operational_unit,@Operational_Sec,@Escalation_email,@resp_Freq ,@Assign_Agent,
     @resp_remind_freq, @resp_assignd, @resolution_remind_freq, @resolution_assignd
     )   
     
     select 'Record Saved'
     
      End 
   else if(@Option = 'Update')
      Begin
        update Serv_SLA_Response set SLAID = @SLAID ,ParentID = @ParentID ,
        Priority_ID = @Priority_ID,Respond_val = @Respond_val,Respond_Unit =
     @Respond_Unit ,Respond_Sec = @Respond_Sec ,resolve_val = @Respond_val,
     resolve_unit = @resolve_unit ,resolve_Sec = @resolve_Sec,
     Operational_val =     @Operational_val ,Operational_unit = @Operational_unit,
     Operational_Sec = @Operational_Sec,Escalation_email = @Escalation_email,
     resp_Freq = @resp_Freq ,Assign_Agent = @Assign_Agent,
     resp_remind_freq=@resp_remind_freq, resp_assignd=@resp_assignd, 
     resolution_remind_freq=@resolution_remind_freq, resolution_assignd=@resolution_assignd
      where  SLAResp_ID = @SLAResp_ID
     
     select 'Record Saved'
              
      End         
End


GO

/* ============================================================
   Procedure: [dbo].[Serv_InsertUpdateSLASettingDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_InsertUpdateSLASettingDetails]      
(      
 @SLAID bigint,      
 @ParentID bigint,      
 @SLA_Name nvarchar(100),      
 @SLA_Desc nvarchar(max),      
 @Option nvarchar(20)      
)      
as      
Begin      
            
            
    
   if(@Option = 'Insert')      
       Begin      
    if(not exists(select 'x' from Serv_SLA_Setting where ParentID = @ParentID and SLA_Name = @SLA_Name))      
          Begin      
              
            declare @orderNo int = 0;   
  select top 1 @orderNo = isnull(ord_no,0)  from Serv_SLA_Setting  where ParentID = @ParentID  order by ord_no desc   
              
            insert into Serv_SLA_Setting(ParentID,SLA_Name,SLA_Desc) values(@ParentID,@SLA_Name,@SLA_Desc)       
             select @SLAID = SCOPE_IDENTITY()   
                                        
             set @orderNo = @orderNo + 1   
               
             update Serv_SLA_Setting set ord_no = @orderNo where SLAID =@SLAID  
                
              
            select 'Record Saved',@SLAID as ID        
                  
          End      
        else      
            Begin      
             select 'Setting Name Already Exists'           
            End      
                 
                
                
       End      
 else if(@Option = 'Update')      
  Begin      
   if(not exists(select 'x' from Serv_SLA_Setting where ParentID = @ParentID and SLA_Name = @SLA_Name and         SLAID <> @SLAID  ))      
      Begin      
        update Serv_SLA_Setting set ParentID = @ParentID,SLA_Name = @SLA_Name,SLA_Desc = @SLA_Desc where       
        SLAID = @SLAID      
         
        select 'Record Saved',@SLAID as ID      
               
      End      
   else      
       Begin      
        select 'Setting Name Already Exists'      
       End      
                      
  End        
End


GO

/* ============================================================
   Procedure: [dbo].[Serv_InsertUser_Detail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_InsertUser_Detail]                
(                
  @ParentID bigint,                
  @Login_id nvarchar(100),                 
  @Pwd nvarchar(100),                 
  @Name nvarchar(100),                 
  @Mobile nvarchar(20),                 
  @Email nvarchar(100),                 
  @Company nvarchar(100),                 
  @Country nvarchar(100),                 
  @City nvarchar(100),                 
  @State nvarchar(100),                 
  @Address nvarchar(Max)='',                 
  @Zip int,                 
  @Option nvarchar(50)='Insert'                
)                
--ser_user_id, , Status, Date_Created                
--dbo.Serv_User_Detail                
                
as                
Begin           
                
declare  @oldpwd nvarchar(100)=''            
if @Pwd=''            
 set @pwd= ROUND((2998+ 25678)* RAND(),0)            
              
declare @ser_user_id bigint                
if(@Option = 'Insert')                
 Begin                
 --if(not exists (select 'x' from Serv_Group_Mast where ParentID = @ParentID and Group_Name = @Group_Name ))                
  Begin                
  insert into Serv_User_Detail(ParentId,  Login_id, Pwd, Name, Mobile,                
 Email, Company, Country, City, State, Address, Zip)                 
  values(@ParentId,  @Name, @Pwd, @Name, @Mobile,                
 @Email, @Company, @Country, @City, @State, @Address, @Zip)                
               
select @ser_user_id = SCOPE_IDENTITY()                
            
update Serv_User_Detail set User_id= @ser_user_id where             
       ser_user_id = @ser_user_id            
                
if(not exists (select 'x' from Serv_User_Master where ParentID = @ParentID             
   and Email_id = @Email ))                
 begin              
 insert into Serv_User_Master (ParentID, Email_id,Service_User,Service_id)                
 Values (@ParentID, @Email, 1, @ser_user_id)                
 declare @leadid bigint    
            
if not EXISTS(select 'x' from userleads(nolock) where @email in 
(isnull(EmailID,'1'),isnull(EmailID1,'1'),isnull(EmailID2,'1')) and parentid=@parentid)               
 begin                
    DECLARE @Leadno BIGINT = isnull((select MAX(LeadNo)                                           
  FROM   UserLeads(nolock) WHERE  ParentID = @ParentId),0)+1                 
      
declare @SourceID bigint      
select @SourceID=SourceID      
 from UserSourceSettings                      
     where NAME='ServiceTicketSignup' and UserID= @ParentID            
             
Insert into userleads (LeadNo,PersonName,EmailID,      
    AssignedTo,SourceName,ParentID,                        
   Remarks,CreatedOn,CreatedBy,enquirysource)                              
select @leadno,@Name,@Email,@ParentId,        
   @SourceID,@ParentId,'Lead Added from New signup in Support Ticket',GETDATE(),@ParentId,25                         
   set @leadid=scope_identity()     
     
   exec Usp_insertdefaultfollowup @parentid,@leadid  
  --@Sourceid,@MediumID              
  end      
  else  
  begin  
  select @leadid=id from userleads(nolock) where @email in (isnull(EmailID,'1'),isnull(EmailID1,'1'),isnull(EmailID2,'1'))   
  and ParentID =@ParentID  
  end    
  
update Serv_User_Detail set LEADID=@leadid where             
       ser_user_id = @ser_user_id           
end                
 else                
 update Serv_User_Master set Service_User = 1, Service_id=@ser_user_id                
 where ParentID=@ParentID and Email_id =@email                
                      
  End                
  select 'Record Saved' ,@ser_user_id userid              
 --else                
 --  Begin                      
 --   select 'Group Name Already Exists'                
 --   End                
                    
   end                 
  else if(@Option = 'Update')                  
    Begin                
  --if(not exists (select 'x' from Serv_Group_Mast where ParentID = @ParentID and Group_Name = @Group_Name and GroupID <> @GroupID ))                
     Begin                
      select          
      @oldpwd =  Pwd from Serv_User_Detail where  ParentId = @ParentId and Email=@Email           
                  
       update Serv_User_Detail set --User_id = @User_id, Login_id,                 
       Pwd=@Pwd, Name=@Name, Mobile=@Mobile,                
  Country=@Country, City=@City, State=@State, Address=@Address, Zip=@Zip                
        where  ParentId = @ParentId and Email=@Email                
        select 'Record Saved'                              
     End                
    --else                
    -- Begin                   
    --   select 'Group Name Already exist'                
    -- end                
end           
if(@Option = 'Update')          
 begin          
 if @oldpwd != @Pwd          
 exec serv_Raise_emailNotification 0,@ParentID,0 , @ser_user_id,@ser_user_id,'Password Reset Email','Agent'          
    exec serv_Raise_emailNotification 0,@ParentID,0 , @ser_user_id,@ser_user_id,'Password Reset Email','Requester'            
 end               
if(@Option = 'Insert')             
begin           
 exec serv_Raise_emailNotification 0,@ParentID,0 , @ser_user_id,@ser_user_id,'User Activation Email','Agent'          
    exec serv_Raise_emailNotification 0,@ParentID,0 , @ser_user_id,@ser_user_id,'User Activation Email','Requester'                  
           
                      
            
end            
End 


GO

