      update Serv_User_Detail set --User_id = @User_id, Login_id,                 
      Pwd=@Pwd, Name=@Name, Mobile=@Mobile,                
    Country=@Country, City=@City, State=@State, Address=@Address, Zip=@Zip                
    where  ParentId = @ParentId and Email=@Email                
    select 'Record Saved'                              
    End                
   --else                
   -- Begin                   
   --   select 'Group Name Already exist'                
   -- end                
  end           
  if(@Option = 'Update')          
   begin          
   if @oldpwd != @Pwd          
