CREATE   PROCEDURE [dbo].[Serv_Merg_Ticket]          
(          
@tTicketID bigint,           
@sTicketID bigint,      
@raisedby  nvarchar(100) =''       
)          
AS          
begin          
declare @tTicketNo nvarchar(16), @sTicketNo nvarchar(16),         
@prifix nvarchar(15),           
@curNo int ,@User_ID bigint,     
@ParentID bigint         
    
select @User_ID = User_ID, @ParentID= ParentID, @tTicketNo= TicketNo from     
Serv_TicketMaster  where TicketID = @tTicketID     
    
select @sTicketNo= TicketNo from     
Serv_TicketMaster  where TicketID = @sTicketID     
         
update Serv_TicketMaster  set Status=2, Note= 'Merg with '+@sTicketNo      
 where TicketID = @tTicketID      
      
update Serv_TicketMaster  set  Note= @tTicketNo+'Merg here'      
 where TicketID = @sTicketID      
       
insert into dbo.Serv_TicketHistory       
 (TicketID, user_id, ParentID, ResponseTime, SubmittedDate, Note, Status, HistoryDate, TransferredTo, Remarks, Priority, Transfered_from, Activity_lavel, Assign_Group,    
 raisedby)      
select @tTicketID, user_id, ParentID, ResponseTime, SubmittedDate, Note, Status, HistoryDate, TransferredTo, Remarks, Priority, Transfered_from, Activity_lavel, Assign_Group,@raisedby      
 from Serv_TicketHistory where TicketID = @tTicketID      
      
insert into Serv_Ticket_Merg (ticket1_id, merg_ticket,merg_by) values       
 (@sTicketID,@tTicketID, @raisedby)      
    
    
       
select @@ROWCOUNT mrow,'Updated' resp      
declare @balance int =0 
SELECT TOP 1 @balance=isnull(balance,0) FROM   MailCreditDetails with(nolock) WHERE  --m_id = @m_id  AND   
USER_ID = @ParentID  ORDER BY credit_id       DESC    
  
if @balance > 20      
begin            
---- This will create a random number between 1 and 999            

DECLARE @Random INT;            
  DECLARE @Upper INT;            
  DECLARE @Lower INT            
              
  Declare @BatchID bigint            
              
  SET @Lower = 1 ---- The lowest random number            
  SET @Upper = 10000 ---- The highest random number            
  SELECT @Random = ROUND(((@Upper - @Lower -1) * RAND() + @Lower), 0)            
  --SELECT @Random            
    
            
     insert into GetBatchRecord (User_id,RandNum)                    
        values(@User_ID,@Random)                    
   select @BatchID = max(BatchID)  from GetBatchRecord With (Nolock)             
   where User_id=@User_ID and RandNum=@Random                    
        delete from GetBatchRecord  where User_id=@User_ID and RandNum=@Random             
               
      
    /* End Creation of batchid */            
  /* Insert into table for Mail */            
  Declare @ToEmailID nvarchar(200) = '',@FromMailID nvarchar(200) = ''            
  select @ToEmailID =Email from dbo.Serv_User_Detail where User_id = @User_ID            
  select @FromMailID =virtual_mail from serv_user_domain where ParentID=@ParentID             
 insert into CloneEmailsFilter(            
   Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName            
   ,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID            
   ,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime            
   ,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source            
    )            
  values( @FromMailID,@ToEmailID,'Ticket Merged','',    
 'Ticket No: ' +@sTicketNo +'is merged with '+ @tTicketNo, GETDATE(),@ParentID,@ParentID,@FromMailID,            
    @BatchID,2,'','','',    
 'Ticket No: ' +@sTicketNo +'is merged with '+ @tTicketNo, 1,0,1,            
    'TicketManagement'                   
      )              
 /* Insert into table for Mail */            
end     
    
end 


