/* ============================================================
   Procedure: [dbo].[Serv_mob_GetTicketMaster_supportRemarkNoteTicketId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec Serv_mob_GetTicketMaster_supportRemarkNoteTicketId 41979, 'Both', '', 0,2
-- 'Remark', 'Note', 'Both'
CREATE   PROCEDURE [dbo].[Serv_mob_GetTicketMaster_supportRemarkNoteTicketId]   
(
 @TicketId bigint --41979
 ,@Type varchar(10)
 ,@FilterText nvarchar(255) = ''
 ,@OffsetValue int  = 0
 ,@PageSize int  = 30                  
)  
AS                                                                            
Begin
if(@Type = 'Remark')
Begin
select count(hst.TicketHistoryID) over() as TotalRow, * from (
select TicketHistoryID, Remarks, SubmittedDate, HistoryDate, user_id from Serv_TicketHistory hst where hst.TicketID = @TicketId and Remarks != ''
)hst 
order by hst.TicketHistoryID desc
 OFFSET @OffsetValue Rows FETCH NEXT @PageSize ROWS ONLY     
End
Else if(@Type = 'Note')
Begin
select count(hst.TicketHistoryID) over() as TotalRow, * from (
select TicketHistoryID, Note, SubmittedDate, HistoryDate, user_id from Serv_TicketHistory hst where hst.TicketID = @TicketId and Note != ''
)hst 
order by hst.TicketHistoryID desc
 OFFSET @OffsetValue Rows FETCH NEXT @PageSize ROWS ONLY     
End
Else if(@Type = 'Both')
Begin
select count(hst.TicketHistoryID) over() as TotalRow, * from (
select TicketHistoryID, Remarks, Note, SubmittedDate, HistoryDate, user_id from Serv_TicketHistory hst where hst.TicketID = @TicketId 
)hst 
order by hst.TicketHistoryID desc
 OFFSET @OffsetValue Rows FETCH NEXT @PageSize ROWS ONLY     
End
End



GO

