/* ============================================================
   Procedure: [dbo].[Serv_mob_Update_Ticket_status_support]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Serv_mob_Update_Ticket_status_support]                              
(                              
@TicketID bigint,                               
@Remarks nvarchar(max) ='',                    
@Note nvarchar(max) ='',                              
@assign_id bigint,                          
@groupid bigint,                          
@Priority int,                         
@raisedby  bigint,                        
@Status  int,            
@ticket_type int                           
)                             
                
                
AS                              
begin                              
declare @TicketNo nvarchar(16),                              
@prifix nvarchar(15),                               
@curNo int ,  
@tickethistoryid bigint                             
                         
declare @User_ID bigint,                         
@ParentID bigint, @Subject  nvarchar(max) ='',                        
@agent nvarchar(100), @group  nvarchar(100)                         
                        
select @User_ID = User_ID, @ParentID= ParentID, @TicketNo= TicketNo ,                        
 @Subject = Subject from                         
Serv_TicketMaster  where TicketID = @TicketID                         
                        
select @agent =Name , @group = Group_Name from Serv_User_Detail um inner join                        
--Serv_Agent_Mast am on um.User_id = am.Userid      
Serv_Agent_Mast am on um.ser_user_id = am.Userid      
 inner join Serv_Group_Mast gm                        
on gm.Groupid = am.Group_id                        
                        
                          
--declare @assign_id bigint =0, @groupid as int=0                         
                          
--select @assign_id = User_id from  Serv_User_Detail where                           
--Login_id = @AssignTo                          
                          
--select @groupid =Groupid from  Serv_Group_Mast where Group_Name = @Assign_Group                          
                          
insert into dbo.Serv_TicketHistory (TicketID, ParentID,User_id, SubmittedDate, Status,         HistoryDate, Remarks, Priority, Assign_Group,TransferredTo, Transfered_from, raisedby,                    
Note,ticket_type)                         
 select TicketID, ParentID, User_id, GETDATE(), @Status,GETDATE(),@Remarks,Priority,                        
  @groupid, @assign_id, AssignTo ,@raisedby, @Note, @ticket_type                          
 from Serv_TicketMaster where TicketID = @TicketID    
   
 select @TicketHistoryID = (select max(TicketHistoryID) from Serv_TicketHistory where  TicketID = @TicketID)                         
                          
update Serv_TicketMaster  set Remarks =@Remarks,                          
AssignTo=@assign_id, Assign_Group =@groupid,                          
Priority=@Priority, Status=@Status  ,AssignedDateTime = GETDATE(), Assignedby = @raisedby,update_date = GETDATE(), update_by = @raisedby                       
where TicketID = @TicketID            
    
Update Serv_TicketMaster set resolved_dt = getdate()            
    where TicketID = @TicketID     and Status  = 4            
     
Update Serv_TicketMaster set resolved_dt = NULL            
    where TicketID = @TicketID     and Status  <> 4    AND  resolved_dt     is not null    
                        
                          
select @@ROWCOUNT mrow,'Updated' resp, @TicketID TicketId, @tickethistoryid TicketHistoryId                         
--if @Status=4                       
--exec serv_Raise_emailNotification_support @TicketID,@ParentID,0 , @User_ID,@User_ID,'Agent Solves the Ticket','Requester'                      
                      
--if @Status=2                       
--exec serv_Raise_emailNotification_support @TicketID,@ParentID,0 , @User_ID,@User_ID,'Agent Closes the Ticket','Requester'                      
                      
--if @groupid > 0                      
--begin                      
-- exec serv_Raise_emailNotification_support @TicketID,@ParentID,@groupid, @User_ID,@User_ID,'Ticket Assigned to Group','Agent'                      
--end                      
--if @assign_id > 0                      
-- exec serv_Raise_emailNotification_support @TicketID,@ParentID,@groupid,@User_ID, @assign_id,'Ticket Assigned to Agent','Agent'                      
                      
                          
end 




GO

