/* ============================================================
   Procedure: [dbo].[Serv_Process_Ticket_Dispatch]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_Process_Ticket_Dispatch]          
(          
@ParentID bigint,          
@ticketid bigint          
)          
          
AS          
BEGIN          
          
          
DECLARE @LoopCounter INT , @MaxId INT,           
        @sqlstr as nvarchar(max)           
          
SELECT @LoopCounter = min(TResp_Rule_Id) , @MaxId = max(TResp_Rule_Id)           
FROM Serv_Ticket_Dispatch           
where ParentID = @ParentID           
          
WHILE(@LoopCounter IS NOT NULL          
      AND @LoopCounter <= @MaxId)          
BEGIN          
 declare @Ruleid bigint          
 declare @Rule_Match_type int          
           
 SELECT @Ruleid = TResp_Rule_Id,  @Rule_Match_type =  Rule_Match_type           
 FROM Serv_Ticket_Dispatch           
 where ParentID = @ParentID and TResp_Rule_Id = @LoopCounter          
           
 declare @rsult int =0          
 if exists(select 1 from Serv_Ticket_Dispatch_Filter          
  where TResp_Rule_Id = @Ruleid)          
  begin   
    select @Ruleid , @Rule_Match_type, @ticketid     
   exec Serv_Aoto_Dispatcher @Ruleid , @Rule_Match_type, @ticketid,@rsult output   
        
   if @rsult = 1          
             
   break;          
  end          
          
   SET @LoopCounter  = @LoopCounter  + 1                  
END     
  select 'Processed' resp      
  exec Serv_updateTicketSLA @ticketid, @ParentID      
  select 'Processed' resp        
END 


