/* ============================================================
   Procedure: [dbo].[Serv_Process_Ticket_Dispatch_support_withnoselection]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_Process_Ticket_Dispatch_support_withnoselection]                  
(                  
@ParentID bigint,                  
@ticketid bigint                  
)                  
AS                  
BEGIN                  
DECLARE @LoopCounter INT , @MaxId INT,                   
        @sqlstr as nvarchar(max)                   

create table #Rulesbyorder(id int identity(1,1),TResp_Rule_Id bigint)

insert into #Rulesbyorder(TResp_Rule_Id)
select TResp_Rule_Id FROM Serv_Ticket_Dispatch  (nolock)  
where ParentID = @ParentID order by ord_no

declare @min int,@max int
select @min=min(id),@max=max(id) from #Rulesbyorder
      
SELECT @LoopCounter =TResp_Rule_Id FROM #Rulesbyorder    where id=@min
--select @MaxId = TResp_Rule_Id FROM #Rulesbyorder where id=@max                  
                  
WHILE(@LoopCounter IS NOT NULL                  
      AND @min <= @Max)                  
BEGIN                 
 SELECT @LoopCounter =TResp_Rule_Id FROM #Rulesbyorder    where id=@min
 declare @Ruleid bigint                  
 declare @Rule_Match_type int                  
                   
 SELECT @Ruleid = TResp_Rule_Id,  @Rule_Match_type =  Rule_Match_type                   
 FROM Serv_Ticket_Dispatch   (nolock)                
 where ParentID = @ParentID and TResp_Rule_Id = @LoopCounter                  
                   
 declare @rsult int =0                  
 if exists(select 1 from Serv_Ticket_Dispatch_Filter                  
  where TResp_Rule_Id = @Ruleid)                  
  begin           
    --select @Ruleid , @Rule_Match_type, @ticketid             
   exec Serv_Aoto_Dispatcher_Support @Ruleid , @Rule_Match_type, @ticketid,@rsult output           
                
   if @rsult = 1                  
                     
   break;                  
  end                  
         
	set @min=@min+1	          
  -- SET @LoopCounter  = @LoopCounter  + 1                          
END             
  Print 'Processed' --resp              
  exec Serv_updateTicketSLA @ticketid, @ParentID              
  Print 'Processed' --resp                
END 


