/* ============================================================
   Procedure: [dbo].[Serv_ProcessAutoAssigninMails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_ProcessAutoAssigninMails]                  
AS                  
BEGIN                  
DECLARE @Counter INT, @MinId BIGINT ,@ticketid bigint, @parentid bigint                 
select * into #tobeautoassigned from serv_ticketmails(nolock) where isautoassignprocessed=0
select @counter=count(1),@minid=min(id) from #tobeautoassigned 
while @counter>0
begin
select @minid=min(id) from #tobeautoassigned
select @parentid=parentid,@ticketid=ticketid from #tobeautoassigned where id=@MinId
if nullif(@parentid,0) is not null and nullif(@ticketid,0) is not null
begin
exec Serv_Process_Ticket_Dispatch_support_withnoselection @parentid,@ticketid
end
update serv_ticketmails set isautoassignprocessed=1 where id=@MinId
delete from #tobeautoassigned where id=@MinId
set @Counter=@counter-1
end
end     


GO

