CREATE   PROCEDURE [dbo].[serv_Raise_emailNotification_support]                                
(                                                                        
@ticketid bigint,                                                                        
@parentid bigint,                                                                        
@groupid bigint,                                                                        
--@userid bigint,                                                     
@ser_user_id bigint,                                              
@Agentid bigint,                                                                        
@event varchar(100),                                                                        
@type varchar(100)                                                                        
)                                                                        
as                                                                         
begin                                                                        
                                                                        
                                      
Declare @compsubject nvarchar(max)='',                                                                        
 @compbody nvarchar(max)=''                                                                        
Declare @subject nvarchar(max)='',                                                                        
 @body nvarchar(max)='', @rexist int =0,@activityid int =0                                                                        
Declare @ToEmailID nvarchar(max) = '',@FromMailID nvarchar(max) = ''                         
Declare @Agent bigint                     
Declare @TicketNo varchar(25)                       
                        
Set    @Agent = (select Userid from serv_agent_mast where agent_id = @Agentid)                     
set    @TicketNo = (select TicketNo from Serv_TicketMaster where TicketID = @ticketid)                     
                                                                         
if @type = 'Agent'                                                                          
select @activityid=Activity_id from Serv_Activity_Mast                                                                         
where Activity_Desc = @event and Access =0  and  parentid = @parentid                                                                     
else                                                            
 select @activityid=Activity_id from Serv_Activity_Mast                                                                         
where Activity_Desc = @event and Access =1   and  parentid = @parentid                                                                        
          
if (@event not in ('User Activation Email','Password Reset Email','Signup'))            
begin                                                   
exec serv_Raise_smsNotification_support                                                         
@ticketid , @parentid ,@groupid ,@ser_user_id ,@Agentid ,                                                      
@event ,@type                                                                         
end          
                                                                        
if @activityid = 0                                                                        
return;                                             
                                      
                                                          
                                                                        
if @type = 'Agent'                                       
BEGIN                                                                       
 select @rexist= COUNT(*), @body = max(N_Body),@subject = max(N_Sub),                                                                        
   @ToEmailID= max(Email_ID)         
   from Serv_Notification_Agent                                                        
 where ParentID = @parentid  and Activity_Id=@activityid and Active =1                                         
 IF (@ToEmailID IS NULL OR @ToEmailID = '')                                      
 BEGIN                                      
 set @ToEmailID = (Select Email from Serv_User_Detail where ser_user_id = @ser_user_id )--and ParentId = @parentid)                         
