/* ============================================================
   Procedure: [dbo].[serv_Raise_emailNotification_support12345]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--EXEC [serv_Raise_emailNotification_support12345] 1182,335,0 , 593,593,'Agent Closes the Ticket','Requester' 
CREATE   PROCEDURE [dbo].[serv_Raise_emailNotification_support12345]                            
(                                                                    
@ticketid bigint,                                                                    
@parentid bigint,                                                                    
@groupid bigint,                                                                    
--@userid bigint,                                                 
@ser_user_id bigint,                                          
@Agentid bigint,                                                                    
@event varchar(100),                                                                    
@type varchar(100)                                                                    
)                                                                    
as                                                                     
begin                                                                    
                                                                    
                                  
Declare @compsubject nvarchar(max)='',                                                                    
 @compbody nvarchar(max)=''                                                                    
Declare @subject nvarchar(max)='',                                                                    
 @body nvarchar(max)='', @rexist int =0,@activityid int =0                                                                    
Declare @ToEmailID nvarchar(max) = '',@FromMailID nvarchar(max) = ''                     
Declare @Agent bigint                 
Declare @TicketNo varchar(25)                   
                    
Set    @Agent = (select Userid from serv_agent_mast where agent_id = @Agentid)                 
set    @TicketNo = (select TicketNo from Serv_TicketMaster where TicketID = @ticketid)                 
                                                                     
if @type = 'Agent'                                                                      
select @activityid=Activity_id from Serv_Activity_Mast                                                                     
where Activity_Desc = @event and Access =0  and  parentid = @parentid                                                                 
else                                                        
 select @activityid=Activity_id from Serv_Activity_Mast                                                                     
where Activity_Desc = @event and Access =1   and  parentid = @parentid                                                                    
      
--if (@event not in ('User Activation Email','Password Reset Email','Signup'))        
--begin                                               
--exec serv_Raise_smsNotification_support                                                     
--@ticketid , @parentid ,@groupid ,@ser_user_id ,@Agentid ,                                                  
--@event ,@type                                                                     
--end      
                                                                    
if @activityid = 0                                                                    
return;                                         
                                  
                                                      
                                                                    
if @type = 'Agent'                                   
BEGIN                                                                   
 select @rexist= COUNT(*), @body = max(N_Body),@subject = max(N_Sub),                                                                    
   @ToEmailID= max(Email_ID)                                                             
   from Serv_Notification_Agent                                                    
 where ParentID = @parentid  and Activity_Id=@activityid and Active =1                                     
 IF (@ToEmailID IS NULL OR @ToEmailID = '')                                  
 BEGIN                                  
 set @ToEmailID = (Select Email from Serv_User_Detail where ser_user_id = @ser_user_id)-- and ParentId = @parentid)                     
 set @ToEmailID = @ToEmailID +','+(Select Email from Serv_User_Detail where ser_user_id = @Agentid)-- and ParentId = @parentid)                                 
 END                                  
 ELSE                                  
 BEGIN                                  
  set @ToEmailID = @ToEmailID +','  +(Select Email from Serv_User_Detail where ser_user_id = @ser_user_id)-- and ParentId = @parentid)                                                              
  set @ToEmailID = @ToEmailID +','+(Select Email from Serv_User_Detail where ser_user_id = @Agentid)-- and ParentId = @parentid)                        
  END                                  
END                                                               
else                                                                    
 begin                                                                    
 select @ToEmailID= Email from dbo.Serv_User_Detail where ser_user_id = @ser_user_id --and ParentID = @parentid                  
 set @ToEmailID = @ToEmailID +','+(Select Email from Serv_User_Detail where ser_user_id = @Agentid)-- and ParentId = @parentid)                   
                                                                      
 select @rexist= COUNT(*),@body = max(N_Body),@subject = max(N_Sub)                                                                    
    from Serv_Notification_Requester                                                                    
  where ParentID = @parentid and Activity_Id=@activityid  and Active =1                                                                    
 end                                  
if @rexist <=0                                                                    
 return;                                                                    
else                         
                                                                    
declare @link_Account as bigint, @balance as int=0                                                              
                                                                  
                                                                    
select @FromMailID= virtual_mail,@link_Account=link_Account from dbo.serv_user_domain                                                                     
 where ParentID = @parentid                                                                     
                                                                    
declare @spos int =0 --,  @subject varchar(max)                                                                    
 Declare @fld varchar(max)=''                                                                  
declare @tbl varchar(max)=''                                                      
declare @word table (fldval varchar (Max))                                                        
                                                     
                                                     
--select @subject                                                                     
while LEN(@subject) > 0                                                                    
begin                                                                    
 --Declare @compsubject varchar(max)='',                                                                    
 --@compbody varchar(max)=''                                                                    
                                                     
 select @spos = CHARINDEX( '#' , @subject , 0 )                                               
 if @spos=0                             
 begin                                                          
 set @compsubject = @compsubject+' '+@subject        
 break;                                                          
 end                                                                    
 set @compsubject =@compsubject+ SUBSTRING(@subject,0,@spos)                                                                    
 set @subject = SUBSTRING(@subject,@spos+1,LEN(@subject)-@spos)              
 select @spos = CHARINDEX( '#' , @subject , 0 )                                                                    
 set @fld = SUBSTRING(@subject,0,@spos)            
 set @subject = SUBSTRING(@subject,@spos+1,LEN(@subject)-@spos)                                                                    
 select @spos = CHARINDEX( '.' , @fld , 0 )                                                                    
 set @tbl = SUBSTRING(@fld,0,@spos)                                                           
 set @fld = SUBSTRING(@fld,@spos+1,LEN(@fld)-@spos)                                                                    
 insert @word                                                                    
 exec get_serv_notification_val1 @ticketid,                                                                    
   @parentid ,@groupid ,@ser_user_id,@Agentid, @tbl, @fld, @type        
                                                          
 select @fld=isnull(fldval,'') from @word                                                                    
 set @compsubject = @compsubject+' '+@fld+' '                                                                    
 declare @sqlstr varchar(max)=''                                                                    
 --set @sqlstr = 'Select '+@fld+' from '+@tbl+' where ticketid='+'123'                                                                    
 --select @sqlstr                                                                    
 delete From @word                                                                    
end                                                 
--select @body                                                                    
while LEN(@body) > 0                                                                    
begin                                                                    
                                                                 
 select @spos = CHARINDEX( '#' , @body , 0 )                                                                     
if @spos=0                                                          
 begin                                                          
 set @compbody =@compbody+' '+@body                                                          
 break;                                 
 end                                                            
 set @compbody =@compbody+ SUBSTRING(@body,0,@spos)                                                                    
 set @body = SUBSTRING(@body,@spos+1,LEN(@body)-@spos)                            
 select @spos = CHARINDEX( '#' , @body , 0 )                                                                    
 set @fld = SUBSTRING(@body,0,@spos)                                                                    
 set @body = SUBSTRING(@body,@spos+1,LEN(@body)-@spos)                                                                    
                                                                     
 select @spos = CHARINDEX( '.' , @fld , 0 )                                                                    
 set @tbl = SUBSTRING(@fld,0,@spos)                                                      
 set @fld = SUBSTRING(@fld,@spos+1,LEN(@fld)-@spos)                                                                    
 --select @spos,@compsubject, @body, @fld,@tbl                                                                
 insert @word                                
 exec get_serv_notification_val1  @ticketid,                                                                    
    @parentid ,@groupid ,@ser_user_id,@Agentid, @tbl, @fld ,@type                                                                   
 select @fld=fldval from @word                                                                    
                                
 set @compbody = @compbody+' '+@fld+' '                                                                    
 delete From @word                                                                    
 --declare @sqlstr varchar(max)=''                                                                    
 --set @sqlstr = 'Select '+@fld+' from '+@tbl+' where ticketid='+'123'                                                               
 --select @sqlstr                                                                    
                                                               
end      
                                                   
select @body= @compbody, @subject = @compsubject                                                                    
---- This will create a random number between 1 and 999                                                                          
select ROW_NUMBER() over( order by item) rno,* into #nomobile                                                    
from dbo.SplitString(@ToEmailID, ',')                                                  
                                                
Declare @email_cnt as int =0                                                
select @email_cnt = COUNT(*) from #nomobile                               
                        
                                         
                                           
                                                         
SELECT TOP 1 @balance=isnull(balance,0) FROM   MailCreditDetails with(nolock) WHERE  --m_id = @m_id  AND                                                               
USER_ID = @link_Account  ORDER BY credit_id DESC                                                                
                                                    
--if (@balance-@email_cnt) < 0 and (@event != 'User Activation Email'   or   @event != 'Signup')                                               
--  Begin                                                    
--     select 'Balance is not sufficient'                                                    
--  End                                                    
                                                      
                                                              
                                                
                                                              
DECLARE @Random INT;                                                                          
  DECLARE @Upper INT;                                                                          
  DECLARE @Lower INT                                                                          
                    
  Declare @BatchID bigint                                                                          
                                                                            
                   
      begin tran                                                                    
     insert into GetBatchRecord (User_id,RandNum)                                                                                  
        values(@ser_user_id,@ser_user_id)                                                                                  
   select @BatchID = SCOPE_IDENTITY()                          
                                  
        delete from GetBatchRecord  where BatchID=@BatchID                                  
   commit                                                                       
if (@balance-@email_cnt) > 0                                  
begin                   
                                             
  --insert into CloneEmailsFilter(                                                                          
  --  Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName                                                                          
  --  ,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID                                                                          
  --,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime                                                                          
  --  ,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source                                                                          
  --   )                                                                          
     select @FromMailID,item,@Subject,'',@body                                                                    
      , GETDATE(),@ParentID,@ParentID,@FromMailID,                                                                          
     @BatchID,2,'','','',@body ,1,0,1,                                                    
     'Ticket Management'  from #nomobile                              
                                                                    
                                                        
                                                                         
                                            
end                 
else                
begin                
                
set @Subject = 'Insufficient Balance'     
if (@TicketID > 0 )    
begin               
set @body = 'Due to insuficient balance, Not able to send Ticket details on Mail but Ticket has been generated on Support portal with Ticket No:'+@TicketNo                
end    
else    
begin    
set @body = 'Due to insuficient balance, Not able to send details on Mail.'    
end                
    
                
                
select @FromMailID= virtual_mail from dbo.serv_user_domain                                                                     
 where ParentID = 335             
 insert into CloneEmailsFilter(                                                                          
    Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName                                                                          
    ,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID                                                                          
  ,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime                                                              
    ,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source                                                                          
     )                
  select @FromMailID,item,@Subject,'',@body                                                                    
      , GETDATE(),335,335,@FromMailID,                                                                          
     @BatchID,2,'','','',@body ,1,0,1,                                                                        
     'Ticket Management'  from #nomobile                
                
end                                                                   
end 


GO

