/* ============================================================
   Procedure: [dbo].[serv_Raise_smsNotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec serv_Raise_emailNotification @ticketid=0,@parentid=335,@groupid=0,@userid=14,@Agentid=0,@event='Password Reset Email',@type='Requester'
--exec serv_Raise_emailNotification @ticketid=34,@parentid=335,@groupid=0,@userid=14,@Agentid=14,@event='New Ticket Created',@type='Agent'
CREATE   PROCEDURE serv_Raise_smsNotification
(
	@ticketid BIGINT,
	@parentid BIGINT,
	@groupid  BIGINT,
	@userid   BIGINT,
	@Agentid  BIGINT,
	@event    VARCHAR(100),
	@type     VARCHAR(100)
)
AS
BEGIN

-- declare @ticketid bigint=42129,@parentid bigint=37540,@groupid bigint=0,@userid bigint=2556,@Agentid bigint=2556,@event varchar(100)='New Ticket Created',@type varchar(100)='Requester'

	DECLARE @compsubject NVARCHAR(MAX)= '', @compbody NVARCHAR(MAX)= '', @isunicode BIT, @SenderID NVARCHAR(250)= '';
	DECLARE @subject NVARCHAR(MAX)= '', @body NVARCHAR(MAX)= '', @rexist INT= 0, @activityid INT= 0;
	DECLARE @ToMobile_No NVARCHAR(MAX)= '', @FrommobileID NVARCHAR(MAX)='';

	if object_id('tempdb..#nomobile') is not null begin drop table #nomobile end

	IF @type = 'Agent'
	BEGIN
		SELECT @activityid = [Activity_id] FROM Serv_Activity_Mast WHERE [Activity_Desc] = @event AND [Access] = 0 AND [ParentID] = @parentid;
	END
	ELSE
	BEGIN
		SELECT @activityid = [Activity_id] FROM Serv_Activity_Mast WHERE [Activity_Desc] = @event AND [Access] = 1 AND [ParentID] = @parentid;
	END;

	-- select * from Serv_Activity_Mast where ParentID=32222 and Access =1 and Activity_Desc = @event  
	IF @activityid = 0
	BEGIN
		RETURN;
	END;

	IF @type = 'Agent'
	BEGIN
		SELECT @rexist = COUNT(*) FROM Serv_SMS_Notification_Agent WHERE [ParentID] = @parentid AND [Activity_Id] = @activityid
			   AND [IsSMSActive] = 1;

		-- select * from Serv_SMS_Notification_Agent where ParentID = 32222 and IsSMSActive =1 and Activity_Id=@activityid  
		-- select * from Serv_SMS_Notification_Agent where ParentID = 37540 and IsSMSActive =1 and Activity_Id=@activityid  
		-- update Serv_SMS_Notification_Agent set senderid='KITKIT' where ParentID = 37540 and IsSMSActive =1  
		SELECT @body = [N_MSG_Body], @isunicode = ISNULL([isunicode], 0), @SenderID = ISNULL([SenderID], '')
				--, @ToMobile_No = [Mobile_No]
		FROM   Serv_SMS_Notification_Agent
		WHERE  [ParentID] = @parentid AND [Activity_Id] = @activityid AND [IsSMSActive] = 1;

		SELECT @ToMobile_No = LTRIM(RTRIM([Mobile]))
		FROM   dbo.Serv_User_Detail
		WHERE  User_id = @Agentid AND [ParentID] = @parentid;
	END;
	ELSE
	BEGIN
		SELECT @ToMobile_No = LTRIM(RTRIM([Mobile]))
		FROM   dbo.Serv_User_Detail
		WHERE  User_id = @userid AND [ParentID] = @parentid;

		-- select * from Serv_SMS_Notification_Requester where ParentID = 37540 and IsSMSActive =1 and Activity_Id=@activityid  
		-- update Serv_SMS_Notification_Requester set senderid='KITKIT' where ParentID = 37540 and IsSMSActive =1  
		SELECT @rexist = COUNT(*)
		FROM   dbo.Serv_SMS_Notification_Requester
		WHERE  [ParentID] = @parentid AND [Activity_Id] = @activityid AND [IsSMSActive] = 1;

		SELECT @body = [N_MSG_Body], @isunicode = ISNULL([isunicode], 0), @SenderID = ISNULL([SenderID], '')
		FROM   dbo.Serv_SMS_Notification_Requester
		WHERE  [ParentID] = @parentid AND [Activity_Id] = @activityid AND [IsSMSActive] = 1;

		IF @ToMobile_No = ''
		BEGIN
			print 'MobileNo Blank'
			RETURN;
		END;
	END;

	IF @rexist <= 0
	BEGIN
		RETURN;
	END

	DECLARE @link_Account AS BIGINT, @balance AS INT= 0;

	SELECT @link_Account = [SMS_Link_Account] FROM dbo.serv_user_domain	WHERE  [ParentID] = @parentid;

	DECLARE @spos INT= 0;                               
	DECLARE @fld VARCHAR(MAX)= '';
	DECLARE @tbl VARCHAR(MAX)= '';
	DECLARE @word TABLE
	(
		[fldval] VARCHAR(MAX)
	);

	--select @body                              
	WHILE LEN(@body) > 0
	BEGIN
		SELECT @spos = CHARINDEX('#', @body, 0);

		IF @spos = 0
		BEGIN
			SET @compbody = @compbody + ' ' + @body;
			BREAK;
		END;

		SET @compbody = @compbody + SUBSTRING(@body, 0, @spos);
		SET @body = SUBSTRING(@body, @spos + 1, LEN(@body) - @spos);
		SELECT @spos = CHARINDEX('#', @body, 0);
		SET @fld = SUBSTRING(@body, 0, @spos);
		SET @body = SUBSTRING(@body, @spos + 1, LEN(@body) - @spos);

		SELECT @spos = CHARINDEX('.', @fld, 0);
		SET @tbl = SUBSTRING(@fld, 0, @spos);
		SET @fld = SUBSTRING(@fld, @spos + 1, LEN(@fld) - @spos);

		INSERT INTO @word
		EXEC get_serv_notification_val_support1 @ticketid, @parentid, @groupid, @userid, @Agentid, @tbl, @fld, @type;

		SELECT @fld = ISNULL([fldval], '') FROM   @word;
		SET @compbody = @compbody + ' ' + @fld + ' ';
		DELETE FROM @word;
	END;

	print '@body = ' + @body
	print '@compbody = ' + @compbody
	SELECT @body = @compbody;

	---- This will create a random number between 1 and 999                                    
	SELECT ROW_NUMBER() OVER(ORDER BY [item]) AS [rno],* INTO [#nomobile] FROM   dbo.SplitString(@ToMobile_No, ',');

	DECLARE @maxrow BIGINT, @minrow BIGINT;
	SELECT @maxrow = MAX([rno]), @minrow = MIN([rno])
	FROM   #nomobile;

	DECLARE @CurrentBalance BIGINT= (SELECT TOP 1 ISNULL([cd].[Balance], 0)
									 FROM         Credit_Details AS cd
									 WHERE        [cd].[User_ID] = @link_Account
									 ORDER BY [cd].[Credit_ID] DESC);

	SELECT @maxrow = ( CASE WHEN @isunicode = 0	AND LEN(@body) <= 160 THEN 1
							WHEN @isunicode = 0 AND LEN(@body) > 160 THEN CEILING(LEN(@body) / CAST(153 AS FLOAT))
							WHEN @isunicode = 1 AND LEN(@body) <= 70 THEN 1
							ELSE CEILING(LEN(@body) / CAST(67 AS FLOAT))
					   END ) * @maxrow;

	SET @CurrentBalance = @CurrentBalance - @maxrow;
	print '@CurrentBalance: ' + cast(@CurrentBalance as varchar)

	IF @CurrentBalance <= 0
	BEGIN
		print 'Balance is not sufficient';
	END;
	ELSE
	BEGIN
		DECLARE @Random INT;
		DECLARE @Upper INT;
		DECLARE @Lower INT;
		DECLARE @BatchID BIGINT;

		SET @Lower = 1; ---- The lowest random number    
		SET @Upper = 10000; ---- The highest random number                                    
		SELECT @Random = ROUND(( ( @Upper - @Lower - 1 ) * RAND() + @Lower ),0);

		INSERT INTO GetBatchRecord( User_id, [RandNum] )
		VALUES                    (@userid, @Random);

		SELECT @BatchID = MAX([BatchID]) FROM GetBatchRecord WITH(NOLOCK) WHERE  User_id = @userid AND [RandNum] = @Random;
		DELETE FROM GetBatchRecord WHERE User_id = @userid AND [RandNum] = @Random;
		
		print '@SenderID: ' + @SenderID
		INSERT INTO CloneMessageDeliveryStatus(
		[BatchID], [Mobile], [Message],	[MessageStatus], [SenderID], [MessageInsertDate], [ScheduledDate], [ScheduledTime],
		[SmppID], [U_ID], [IsUniCode], [IsDnd],	[IsAirtel], [MobileSubSet],	[ValidNo], [IsPrority],	[IsAllowDND], [DBType] )
		SELECT @BatchID, [item], @body, NULL, @SenderID, GETDATE(), '', '', (SELECT TOP 1 [ud].[SmppID] FROM [User_Detail] AS [ud] WHERE [ud].[User_ID] = @link_Account) AS [SmppID], @link_Account, @IsUniCode, 0, 0, 0, 1, 1, 0, 0
		FROM #nomobile;
		print 'MessageID: ' + cast(scope_identity() as varchar)
		--while @minrow <= @maxrow
		--begin
		-- declare @mobile as varchar(100) =''
		-- select @mobile= item from #nomobile where rno = @minrow
		-- INSERT INTO CloneMessageDeliveryStatus
		--    (BatchID, Mobile, Message, MessageStatus, SenderID,
		--   MessageInsertDate, ScheduledDate, ScheduledTime,
		--   SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,
		--   ValidNo, IsPrority, IsAllowDND, DBType)
		--  select @BatchID, @mobile, @body, null, @SenderID,
		--   GETDATE(), '', '',
		--   (
		--     SELECT TOP 1 ud.SmppID
		--     FROM   User_Detail AS ud
		--     WHERE  ud.[User_ID] = @link_Account
		--    )   AS SmppID, @link_Account, @IsUniCode, 0, 0, 0,
		--   1, 1, 0, 0
		-- set @minrow= @minrow+1
		--end
		-- select 'sms sent successfully'
		/* Insert into table for Mail */
	END;

END;  



