 SET @ToMobile_No = @ToMobile_No +','+(Select Mobile from Serv_User_Detail where ser_user_id = @Agentid and ParentId = @parentid)                         
 select @rexist= COUNT(*)                                                       
    from dbo.Serv_SMS_Notification_Requester                                                     
  where ParentID = @parentid and Activity_Id=@activityid  and IsSMSActive =1                
                                                       
 select @body =N_MSG_Body, @isunicode = isnull(isunicode,0),                                    
 @SenderID = isnull(SenderID,'')                                                          
