  when @isunicode=1 and len(@body)<=70 then 1                                     
  else ceiling(LEN(@body)/cast(67 as float)) end )*@maxrow                                    
                                    
 set @CurrentBalance = @CurrentBalance-@maxrow                                     
if @CurrentBalance <= 0                                      
  Begin                                      
     --select 'Balance is not sufficient'      
 DECLARE @Random INT;                                                            
