   Procedure: [dbo].[Serv_Resaller_Account]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_Resaller_Account]  
(                          
@ParentID bigint,                      
@User_id bigint,                      
@VDomainName nvarchar(100),                        
 @VirtualDomainDetails nvarchar(200),                        
 @VEmailIDName nvarchar(100),                        
 @VirtualEmailIDDetails nvarchar(200),                
 @link_Account bigint,            
 @SMS_Link_Account bigint                           
)                          
AS                          
BEGIN           
                  
if exists (select * from serv_user_domain where ParentID = @ParentID)                      
begin                      
 update serv_user_domain set link_Account = @link_Account,SMS_Link_Account=@SMS_Link_Account where ParentID= @ParentID              
 select 'Account link Saved'                      
 return ;                      
end               
if exists (select * from serv_user_domain where                        
VDomain_Name = @VDomainName)                      
begin                      
 select 'Virtual Domain Details Already Exists'                      
 return ;                      
end               
                   
declare @email_id nvarchar(250)='', @ser_user_id bigint =0, @CompnayName as nvarchar(100)                      
 if not exists(select 'x' from Serv_User_Master where ParentId = @ParentID)                        
 begin         
                               
 select @email_id = EMail, @CompnayName=CompnayName                       
  from user_detail where ParentId = @ParentID                       
                     
 if exists( select 1 from user_detail where  User_id = @User_id and ParentID = @ParentID)                     
 begin               
 print 11               
 insert into Serv_User_Detail(ParentId, User_id,Name, Login_id, Pwd,  Mobile,                              
  Email, Company, Country, City, State, Address, Zip,country_code,Last_Login_date, User_id_old)                               
    select ParentId,user_id, EMail, EMail,                               
     Pwd, null,EMail, null,Country,  City, State,  Address ,  Pincode,CountryCode,GETDATE(), User_id                              
     from user_detail where  User_id = @User_id and ParentID = @ParentID                       
                       
 select @ser_user_id = SCOPE_IDENTITY()   
  
 update Serv_User_Detail set User_id=@ser_user_id where ser_user_id=@ser_user_id  
  
  insert into Serv_User_Master (ParentID,Email_id,Service_User,Service_id, kit19_id, kit19_User )   
  Values (@ParentID, @email_id, 1 ,@ser_user_id, 1, @User_id)                       
                       
  insert into serv_user_domain(ParentId,VDomain_Name,virtual_domain,VEmailID_Name,virtual_mail,link_Account,SMS_Link_Account)  
  values(@ParentID,@VDomainName,@VirtualDomainDetails,@VEmailIDName,@VirtualEmailIDDetails, @link_Account,@SMS_Link_Account)  
  
  
  if not exists(select 1 from usersourcesettings(nolock) where userid=@parentid  
 and name='ServiceTicketSignup'  
 )   
  begin 

	  INSERT INTO UserSourceSettings                            
		 (NAME, UserID, IsEditable,IsActive,CreatedDate,ModifiedDate,ModifiedBy )                            
	   VALUES                            
		 (                            
		'ServiceTicketSignup',                            
		@ParentID,                            
		0,                            
		1,                            
		GETDATE(),                            
		GETDATE(),                            
		335                            
	   )                       
   end                      
                                   
 exec Serv_DefaultEntryCreation @ParentID, @User_id, @CompnayName                      
                       
 select 'Record Saved'                      
end                    
else                    
   select 'Parent Details Not Found'                     
 end                      
end  


GO

