/* ============================================================
   Procedure: [dbo].[Serv_SelectAfterFrequencies]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_SelectAfterFrequencies]   
(  
@id int =0,  
@opt int =1  
)   
as    
Begin  
if @opt = -1  
 select * from Serv_SLA_Freq where Freq_Val < 0  order by val_sec desc   
else  
begin  
 if @id =0  
  select * from Serv_SLA_Freq where Freq_Val >= 0  order by val_sec asc   
 else  
 begin  
  -- select * from Serv_SLA_Freq where Freq_Val >= 0 and val_sec > (select r.val_sec from Serv_SLA_Freq r where r.Freq_id = @id)  order by val_sec asc   
  if(@id >= 0)
  Begin
	select * from Serv_SLA_Freq where  val_sec >  @id  order by val_sec asc   
  End
  Else
  Begin
	select * from Serv_SLA_Freq where  val_sec <  @id  order by val_sec desc   
  End
 end   
end  
End



GO

