/* ============================================================
   Procedure: [dbo].[Serv_Split_Ticket]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Serv_Split_Ticket]          
(          
@TicketID bigint,           
@User_id bigint,           
@ParentID bigint,          
@Subject1 nvarchar(100) ='',  
@Subject2 nvarchar(100) ='',       
@Description1 nvarchar(max),  
@Description2 nvarchar(max),  
@assign1 bigint,   
@assign2 bigint,   
@status1 bigint,   
@status2 bigint,    
@Priority1 bigint,   
@Priority2 bigint,        
@raisedby  nvarchar(100) =''        
)          
AS          
begin          
declare @TicketNo1 nvarchar(16),@TicketNo2 nvarchar(16), @oTicketNo nvarchar(16),         
@prifix nvarchar(15),           
@curNo int          
    
select @oTicketNo= TicketNo from     
Serv_TicketMaster  where TicketID = @TicketID           
  
update Serv_TicketMaster set status = 2 where TicketID = @TicketID   
      
declare @newticket1 as bigint ,@newticket2 as bigint      
      
if not EXISTs(select * from Serv_ticket_AutoNo where user_id = @User_id)          
insert into Serv_ticket_AutoNo (ParentId, user_id, prefix, curr_no)           
  values (@ParentID,@User_id,'T',0 )          
            
BEGIN TRANSACTION TRAN1          
          
select @prifix = prefix, @curNo= curr_no           
 from Serv_ticket_AutoNo WITH (UPDLOCK) where user_id = @User_id          
   
 update Serv_ticket_AutoNo set curr_no= curr_no+1           
 where user_id = @User_id          
COMMIT TRANSACTION          
   
            
select @TicketNo1 = @prifix+ REPLACE(STR(@curNo+1, 7), SPACE(1), '0')      
BEGIN TRANSACTION TRAN1          
          
select @prifix = prefix, @curNo= curr_no           
 from Serv_ticket_AutoNo WITH (UPDLOCK) where user_id = @User_id          
   
 update Serv_ticket_AutoNo set curr_no= curr_no+1           
 where user_id = @User_id          
COMMIT TRANSACTION  
  
select @TicketNo2 = @prifix+ REPLACE(STR(@curNo+1, 7), SPACE(1), '0')    
     
insert into Serv_TicketMaster           
  (User_id, ParentID, TicketNo, Subject, Description, Priority,Requester, Status,       
  AssignTo )          
  select @User_id, @ParentID, @TicketNo1, @Subject1, @Description1, @Priority1, @raisedby, @Status1,      
  @assign1      
 select @newticket1 = SCOPE_IDENTITY()       
   
 insert into dbo.Serv_TicketHistory       
 (TicketID, user_id, ParentID, ResponseTime, SubmittedDate, Note, Status, HistoryDate, TransferredTo, Remarks, Priority, Transfered_from, Activity_lavel, Assign_Group, raisedby)      
select @newticket1, user_id, ParentID, ResponseTime, SubmittedDate, Note, Status, HistoryDate, TransferredTo, Remarks, Priority, Transfered_from, Activity_lavel, Assign_Group, @raisedby    
 from Serv_TicketHistory where TicketID = @TicketID    
  
insert into Serv_TicketMaster           
  (User_id, ParentID, TicketNo, Subject, Description, Priority,Requester, Status,       
  AssignTo )          
  select @User_id, @ParentID, @TicketNo2, @Subject2, @Description2, @Priority2, @raisedby, @Status2,      
  @assign2      
 select @newticket2 = SCOPE_IDENTITY()       
   
 insert into dbo.Serv_TicketHistory       
 (TicketID, user_id, ParentID, ResponseTime, SubmittedDate, Note, Status, HistoryDate, TransferredTo, Remarks, Priority, Transfered_from, Activity_lavel, Assign_Group, raisedby)      
select @newticket2, user_id, ParentID, ResponseTime, SubmittedDate, Note, Status, HistoryDate, TransferredTo, Remarks, Priority, Transfered_from, Activity_lavel, Assign_Group, @raisedby    
 from Serv_TicketHistory where TicketID = @TicketID    
      
update Serv_TicketMaster  set Note = 'splited into ticket No'+      
 @TicketNo1 +' and '+  @TicketNo2      
 where TicketID = @TicketID        
        
    
      
insert into Serv_Ticket_Split (ticketid,splited_tktID,splited_tktID2,splitby) values       
 (@TicketID,@newticket1,@newticket2, @raisedby)      
       
select @@ROWCOUNT mrow,'Updated' resp      

declare @balance int =0 
SELECT TOP 1 @balance=isnull(balance,0) FROM   MailCreditDetails with(nolock) WHERE  --m_id = @m_id  AND   
USER_ID = @ParentID  ORDER BY credit_id       DESC    
  
if @balance > 20    
begin            
---- This will create a random number between 1 and 999            
DECLARE @Random INT;            
  DECLARE @Upper INT;            
  DECLARE @Lower INT            
              
  Declare @BatchID bigint            
       
  SET @Lower = 1 ---- The lowest random number            
  SET @Upper = 10000 ---- The highest random number            
  SELECT @Random = ROUND(((@Upper - @Lower -1) * RAND() + @Lower), 0)            
  --SELECT @Random            
    
            
     insert into GetBatchRecord (User_id,RandNum)                    
        values(@User_ID,@Random)                    
   select @BatchID = max(BatchID)  from GetBatchRecord With (Nolock)             
   where User_id=@User_ID and RandNum=@Random                    
        delete from GetBatchRecord  where User_id=@User_ID and RandNum=@Random             
               
      
    /* End Creation of batchid */            
  /* Insert into table for Mail */            
  Declare @ToEmailID nvarchar(200) = '',@FromMailID nvarchar(200) = ''            
  select @ToEmailID =Email from dbo.Serv_User_Detail where User_id = @User_ID            
  select @FromMailID =virtual_mail from serv_user_domain where ParentID=@ParentID             
 insert into CloneEmailsFilter(            
   Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName            
   ,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID            
   ,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime            
   ,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source            
    )            
  values( @FromMailID,@ToEmailID,@Subject1,'',    
 'Ticket No: ' +@oTicketNo +'splited into '+ @TicketNo1 +' and '+@TicketNo2    
 , GETDATE(),@ParentID,@ParentID,@FromMailID,            
    @BatchID,2,'','','',    
 'Ticket No: ' +@oTicketNo +'splited into '+ @TicketNo1 +' and '+@TicketNo2,1,0,1,            
    'TicketManagement'                   
      )              
 /* Insert into table for Mail */            
end     
     
      
end 


GO

