/* ============================================================
   Procedure: [dbo].[Serv_Ticket_Feedback_Check]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC Serv_Ticket_Feedback_Check       
(          
@ticketid NVARCHAR(50)      
)          
as          
begin          
          
declare @ticket bigint    
    
set @ticket = (select distinct TicketID from serv_tickethistory     
WHERE TicketHistoryID = convert(bigint,left(SUBSTRING(@ticketid,CHARINDEX('_',@ticketid,CHARINDEX('_',@ticketid)+1)+1,(((LEN(@ticketid))-CHARINDEX('_', REVERSE(@ticketid)))-CHARINDEX('_',@ticketid))),CHARINDEX('_',SUBSTRING(@ticketid,CHARINDEX('_',@ticketid,CHARINDEX('_',@ticketid)+1)+1,(((LEN(@ticketid))-CHARINDEX('_', REVERSE(@ticketid)))-CHARINDEX('_',@ticketid))))-1)))      
          
          
IF EXISTS ( SELECT '*' FROM Serv_ticket_feedback_tbl WHERE TICKETID = @ticket)
BEGIN          
Select 'Your feedback is already submitted.'
end                   
          
end


GO

/* ============================================================
   Procedure: [dbo].[SERV_TICKET_FEEDBACK_RPT]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
CREATE   PROC SERV_TICKET_FEEDBACK_RPT          
(          
@PARENTID BIGINT          
)          
AS          
BEGIN         
DECLARE @FEEDBACKDATE DATETIME        
        
SELECT DISTINCT  U.CREATEDDATE, M.TICKETNO, U.DOMAINURL, U.SHORTURL,    
M.Description, M.Remarks,M.Note,          
(SELECT NAME FROM SERV_USER_DETAIL WHERE SER_USER_ID = M.USER_ID ) AS CUSTOMERNAME,          
(SELECT NAME FROM SERV_USER_DETAIL WHERE SER_USER_ID = M.UPDATE_BY) AS AGENTNAME,         
isnull((select RATING from SERV_TICKET_FEEDBACK_TBL where TICKETHISTORYID = H.TICKETHISTORYID), '') RATING,          
isnull((SELECT COMMENTS from SERV_TICKET_FEEDBACK_TBL where TICKETHISTORYID = H.TICKETHISTORYID),'') COMMENTS,        
@FEEDBACKDATE AS FEEDBACKDATE,M.TICKETID,        
isnull((SELECT COUNT(IPADDRESS) FROM SERV_TICKET_URL_TRACK WHERE LONG_URL =U.DOMAINURL),0) AS CUSTOMERVISITS           
into #temp        
FROM SERV_TICKET_URL_LINK U (NOLOCK)          
INNER JOIN SERV_TICKETMASTER M (NOLOCK)         
ON M.TICKETID = U.TICKETID         
INNER JOIN SERV_TICKETHISTORY H (NOLOCK)         
ON  H.TICKETID = M.TICKETID          
AND H.USER_ID = M.USER_ID          
AND H.PARENTID = M.PARENTID          
WHERE M.PARENTID = @PARENTID          
AND U.DOMAINURL LIKE '%fEEDBACK%'        
        
UPDATE A        
SET A.FEEDBACKDATE = B.SUBMITDATE        
FROM #temp A         
INNER JOIN SERV_TICKETMASTER M         
ON  A.TICKETID = M.TICKETID         
INNER JOIN SERV_TICKETHISTORY H         
ON  H.TICKETID = M.TICKETID          
AND H.USER_ID = M.USER_ID          
AND H.PARENTID = M.PARENTID          
INNER JOIN SERV_TICKET_FEEDBACK_TBL B        
ON H.TICKETHISTORYID = B.TICKETHISTORYID         
        
SELECT DISTINCT t.*,l.VisitDate   
FROM #temp t(nolock)     
left outer join   SERV_TICKET_URL_TRACK l(nolock)       
on t.DOMAINURL = l.LONG_URL    
    
        
DROP TABLE #temp        
        
        
          
END    


GO


